def _serve_cards_page(filename: str, *, page_mode: str | None = None, title: str | None = None, heading: str | None = None, base_path: str | None = None):
    # Server-render the default date so the page never boots with a blank date input
    # (some browsers can reject programmatic input[type=date] assignment).
    try:
        from datetime import datetime, timedelta
        from flask import Response as _Resp

        now = None
        try:
            from zoneinfo import ZoneInfo
            now = datetime.now(ZoneInfo("America/New_York"))
        except Exception:
            # Windows dev machines often lack the IANA tz database unless tzdata is installed.
            # Fall back to local time rather than returning a blank date.
            now = datetime.now()

        base = now - timedelta(days=1) if now.hour < 6 else now
        ymd = base.strftime("%Y-%m-%d")

        html = (WEB_DIR / filename).read_text(encoding="utf-8")
        # Only skip injection if the datePicker itself already has a value.
        has_date_value = (
            'id="datePicker" value="' in html
            or "id='datePicker' value='" in html
            or 'id="datePicker" value=' in html
            or "id='datePicker' value=" in html
        )
        if 'id="datePicker"' in html and not has_date_value:
            html = html.replace(
                '<input type="date" id="datePicker" />',
                f'<input type="date" id="datePicker" value="{ymd}" />',
            )
            html = html.replace(
                '<input type="date" id="datePicker"/>',
                f'<input type="date" id="datePicker" value="{ymd}"/>',
            )
            html = html.replace(
                '<input type="date" id="datePicker">',
                f'<input type="date" id="datePicker" value="{ymd}">',
            )

        if filename == "cards.html":
            if title:
                html = re.sub(r"<title>.*?</title>", f"<title>{title}</title>", html, count=1, flags=re.IGNORECASE | re.DOTALL)
            if heading:
                html = re.sub(r"<h1>.*?</h1>", f"<h1>{heading}</h1>", html, count=1, flags=re.IGNORECASE | re.DOTALL)
            if page_mode:
                html = re.sub(
                    r'data-page-mode="[^"]*"',
                    f'data-page-mode="{page_mode}"',
                    html,
                    count=1,
                    flags=re.IGNORECASE,
                )
            if base_path is not None:
                html = re.sub(
                    r'data-cards-base-path="[^"]*"',
                    f'data-cards-base-path="{base_path}"',
                    html,
                    count=1,
                    flags=re.IGNORECASE,
                )

        resp = _Resp(html, mimetype="text/html")
        resp.headers["Cache-Control"] = "no-store, max-age=0"
        return resp
    except Exception:
        try:
            import traceback

            print(f"serve_cards_page({filename}) HTML injection failed:\n" + traceback.format_exc())
        except Exception:
            pass
        return send_from_directory(str(WEB_DIR), filename)


def _response_json_value(resp: Any) -> tuple[dict[str, Any] | None, int | None]:
    response_obj = resp
    status_code = None
    if isinstance(resp, tuple):
        if resp:
            response_obj = resp[0]
        if len(resp) >= 2:
            try:
                status_code = int(resp[1])
            except Exception:
                status_code = None
    try:
        if hasattr(response_obj, "status_code"):
            status_code = int(getattr(response_obj, "status_code"))
    except Exception:
        pass
    payload_obj = None
    try:
        if hasattr(response_obj, "get_json"):
            payload_obj = response_obj.get_json(silent=True)
    except Exception:
        payload_obj = None
    if isinstance(payload_obj, dict):
        return payload_obj, status_code
    return None, status_code


def _redirect_with_request_params(target: str, *, extra_params: dict[str, Any] | None = None, drop_params: set[str] | None = None):
    params: list[tuple[str, str]] = []
    drop = {str(k) for k in (drop_params or set())}
    for key, values in request.args.lists():
        if key in drop:
            continue
        for value in values:
            params.append((str(key), str(value)))

    for key, value in (extra_params or {}).items():
        params = [(existing_key, existing_value) for existing_key, existing_value in params if existing_key != key]
        if value is None:
            continue
        if isinstance(value, (list, tuple)):
            for item in value:
                params.append((str(key), str(item)))
        else:
            params.append((str(key), str(value)))

    query = urlencode(params, doseq=True)
    return redirect(f"{target}?{query}" if query else target)


@lru_cache(maxsize=1)
def _betting_card_v2_team_assets() -> dict[str, dict[str, Any]]:
    out: dict[str, dict[str, Any]] = {}
    rows = []
    for fp in (WEB_DIR / "assets" / "teams_wnba.json", WEB_DIR / "assets" / "teams_nba.json"):
        try:
            rows = json.loads(fp.read_text(encoding="utf-8"))
        except Exception:
            rows = []
        if isinstance(rows, list) and rows:
            break
    if not isinstance(rows, list):
        return out
    for row in rows:
        if not isinstance(row, dict):
            continue
        tri = str(row.get("tricode") or "").strip().upper()
        if not tri:
            continue
        out[tri] = {
            "id": _safe_int(row.get("id")),
            "name": str(row.get("name") or tri).strip(),
        }
    return out


