def _season_betting_card_player_position(date_str: str, player_name: str, team_tri: str, player_id: Any = None) -> str | None:
    roster = _season_betting_card_roster_positions(date_str)
    if roster is None or roster.empty:
        return None
    team_key = str(team_tri or "").strip().upper()
    player_key = _norm_player_name(player_name)
    pid_val = _safe_int(player_id)
    try:
        if pid_val is not None and "player_id" in roster.columns:
            match = roster[pd.to_numeric(roster["player_id"], errors="coerce") == float(pid_val)]
            if team_key and "team" in match.columns:
                match = match[match["team"].astype(str).str.upper().str.strip() == team_key]
            if not match.empty:
                pos = str(match.iloc[0].get("position") or "").strip().upper()
                return pos or None
        match = roster.copy()
        if team_key and "team" in match.columns:
            match = match[match["team"].astype(str).str.upper().str.strip() == team_key]
        if player_key and "_pkey" in match.columns:
            match = match[match["_pkey"].astype(str).str.upper().str.strip() == player_key]
        if not match.empty:
            pos = str(match.iloc[0].get("position") or "").strip().upper()
            return pos or None
    except Exception:
        return None
    return None


def _season_betting_card_expected_minutes(date_str: str, player_name: str, team_tri: str, player_id: Any = None) -> float | None:
    mins = _season_betting_card_expected_minutes_frame(date_str)
    team_key = str(team_tri or "").strip().upper()
    player_key = _norm_player_name(player_name)
    pid_val = _safe_int(player_id)
    try:
        if isinstance(mins, pd.DataFrame) and not mins.empty:
            match = mins.copy()
            if pid_val is not None and "player_id" in match.columns:
                pid_match = match[pd.to_numeric(match["player_id"], errors="coerce") == float(pid_val)]
                if team_key and "team_tri" in pid_match.columns:
                    pid_match = pid_match[pid_match["team_tri"].astype(str).str.upper().str.strip() == team_key]
                if not pid_match.empty:
                    minute_val = _safe_float(pid_match.iloc[0].get("exp_min_mean"))
                    if minute_val is not None and minute_val > 0:
                        return minute_val
            if team_key and "team_tri" in match.columns:
                match = match[match["team_tri"].astype(str).str.upper().str.strip() == team_key]
            if player_key and "player_name" in match.columns:
                match = match[match["player_name"].astype(str).map(_norm_player_name) == player_key]
            if not match.empty:
                minute_val = _safe_float(match.iloc[0].get("exp_min_mean"))
                if minute_val is not None and minute_val > 0:
                    return minute_val
    except Exception:
        pass

    logs = _load_best_bets_player_logs_frame()
    if logs is None or logs.empty:
        return None
    try:
        end = pd.to_datetime(str(date_str or ""), errors="coerce")
        if pd.isna(end):
            return None
        subset = logs[(logs["player_key"] == player_key) & (logs["team_abbr"] == team_key)].copy()
        subset = subset[subset["game_date"].notna() & (subset["game_date"] < end)].copy()
        if subset.empty:
            return None
        mins_series = pd.to_numeric(subset["min"], errors="coerce").replace([np.inf, -np.inf], np.nan).dropna().head(10)
        if mins_series.empty:
            return None
        return float(mins_series.mean())
    except Exception:
        return None


def _season_betting_card_position_rate_value(row: dict[str, Any], market_key: str) -> float | None:
    if not isinstance(row, dict):
        return None
    market = str(market_key or "").strip().lower()
    direct = _safe_float(row.get(f"_{market}_pm"))
    if direct is not None:
        return direct
    combos = {
        "pra": ("pts", "reb", "ast"),
        "pr": ("pts", "reb"),
        "pa": ("pts", "ast"),
        "ra": ("reb", "ast"),
        "stocks": ("stl", "blk"),
    }
    parts = combos.get(market)
    if not parts:
        return None
    nums = [_safe_float(row.get(f"_{part}_pm")) for part in parts]
    if any(num is None for num in nums):
        return None
    return float(sum(float(num) for num in nums if num is not None))


def _season_betting_card_position_context(
    date_str: str,
    opponent_tri: str | None,
    position: str | None,
    market_key: str,
    expected_minutes: float | None,
) -> dict[str, Any]:
    empty = {
        "position": str(position or "").strip().upper() or None,
        "position_allowed_avg": None,
        "position_allowed_rank": None,
        "position_allowed_rate": None,
        "position_games": None,
        "position_minutes_basis": expected_minutes,
    }
    opp_key = str(opponent_tri or "").strip().upper()
    pos_key = str(position or "").strip().upper()
    if not opp_key or pos_key not in {"G", "F", "C"}:
        return empty
    ctx = _season_betting_card_opp_position_rates(date_str)
    if ctx is None or ctx.empty:
        return empty
    try:
        pos_df = ctx[ctx["_pos"].astype(str).str.upper().str.strip() == pos_key].copy()
        if pos_df.empty:
            return empty
        pos_df["_rate"] = pos_df.apply(lambda row: _season_betting_card_position_rate_value(row.to_dict(), market_key), axis=1)
        pos_df = pos_df[pos_df["_rate"].notna()].copy()
        if pos_df.empty:
            return empty
        pos_df = pos_df.sort_values("_rate", ascending=True).reset_index(drop=True)
        pos_df["_rank"] = np.arange(1, len(pos_df) + 1)
        match = pos_df[pos_df["_opp"].astype(str).str.upper().str.strip() == opp_key]
        if match.empty:
            return empty
        match_row = match.iloc[0].to_dict()
        rate_val = _safe_float(match_row.get("_rate"))
        est_avg = None
        if rate_val is not None and expected_minutes is not None and expected_minutes > 0:
            est_avg = float(rate_val) * float(expected_minutes)
        return {
            "position": pos_key,
            "position_allowed_avg": est_avg,
            "position_allowed_rank": _safe_int(match_row.get("_rank")),
            "position_allowed_rate": rate_val,
            "position_games": _safe_int(match_row.get("_n")),
            "position_minutes_basis": expected_minutes,
        }
    except Exception:
        return empty


def _season_betting_card_prop_context(
    *,
    date_str: str,
    player_name: str,
    team_tri: str,
    opponent_tri: str | None,
    market_key: str,
    side: str | None,
    line_value: float | None,
    home_flag: bool | None,
    matchup_ctx: dict[str, Any] | None,
    source_row: dict[str, Any],
    player_id: Any = None,
) -> dict[str, Any]:
    history_ctx = _best_bets_prop_history_context(
        date_str=date_str,
        player_name=player_name,
        team_tri=team_tri,
        opponent=opponent_tri,
        market=market_key,
        home_flag=home_flag,
        line_value=line_value,
    )
    allowed_values, allowed_ranks = _compute_team_allowed_stats(date_str, days_back=21)
    opponent_key = str(opponent_tri or "").strip().upper()
    opp_allowed_avg = _season_betting_card_allowed_stat_value(allowed_values.get(opponent_key, {}), market_key)
    opp_allowed_rank = _season_betting_card_allowed_rank_value(allowed_ranks.get(opponent_key, {}), market_key)
    player_position = _season_betting_card_player_position(date_str, player_name, team_tri, player_id=player_id)
    expected_minutes = _season_betting_card_expected_minutes(date_str, player_name, team_tri, player_id=player_id)
    position_ctx = _season_betting_card_position_context(date_str, opponent_tri, player_position, market_key, expected_minutes)

    league_def = _safe_float((matchup_ctx or {}).get("league_def_rtg"))
    opp_def = None
    own_off = None
    opp_recent_allowed = None
    if isinstance(matchup_ctx, dict):
        if str(matchup_ctx.get("home_tri") or "").strip().upper() == team_tri:
            own_off = _safe_float(matchup_ctx.get("home_off_rtg"))
            opp_def = _safe_float(matchup_ctx.get("away_def_rtg"))
            opp_recent_allowed = _safe_float(matchup_ctx.get("away_recent_allowed_pts"))
        elif str(matchup_ctx.get("away_tri") or "").strip().upper() == team_tri:
            own_off = _safe_float(matchup_ctx.get("away_off_rtg"))
            opp_def = _safe_float(matchup_ctx.get("home_def_rtg"))
            opp_recent_allowed = _safe_float(matchup_ctx.get("home_recent_allowed_pts"))

    baseline = _safe_float(source_row.get("model_baseline"))
    if baseline is None:
        baseline = _safe_float(source_row.get("top_play_baseline"))
    if baseline is None:
        baseline = _safe_float(source_row.get("sim_mu"))
    price = _safe_float(source_row.get("odds"))
    if price is None:
        price = _safe_float(source_row.get("price"))
    p_win = _safe_float(source_row.get("p_win"))
    if p_win is None:
        p_win = _safe_float(source_row.get("prob_calib"))
    if p_win is None:
        p_win = _safe_float(source_row.get("probability"))
    if p_win is None:
        p_win = _safe_float(source_row.get("win_prob"))
    if p_win is None:
        p_win = _safe_float(source_row.get("model_prob"))
    if p_win is None:
        p_win = _safe_float(source_row.get("prob"))
    ev_pct = _safe_float(source_row.get("ev_pct"))
    if ev_pct is None:
        ev = _safe_float(source_row.get("ev"))
        if ev is not None:
            ev_pct = float(ev) * 100.0
    if p_win is None:
        p_win = _best_bets_prob_from_ev(_safe_float(source_row.get("ev")), price)
    implied_prob = _safe_float(source_row.get("implied_prob"))
    if implied_prob is None:
        implied_prob = _american_to_implied_prob(price)
    prob_edge = _safe_float(source_row.get("prob_edge"))
    if prob_edge is None and p_win is not None and implied_prob is not None:
        prob_edge = float(p_win) - float(implied_prob)
    consensus = _safe_float(source_row.get("top_play_consensus"))
    line_adv = _safe_float(source_row.get("top_play_line_adv"))
    opponent_vs_line = None
    if opp_allowed_avg is not None and line_value is not None:
        try:
            opponent_vs_line = float(opp_allowed_avg) - float(line_value)
            if str(side or "").strip().upper() == "UNDER":
                opponent_vs_line = float(line_value) - float(opp_allowed_avg)
        except Exception:
            opponent_vs_line = None

    return {
        "side": side,
        "team_tri": team_tri,
        "opponent_tri": opponent_tri,
        "history": history_ctx,
        "matchup": {
            "opponent_allowed_avg": opp_allowed_avg,
            "opponent_allowed_rank": opp_allowed_rank,
            "opponent_recent_allowed": opp_recent_allowed,
            "opponent_def_rtg": opp_def,
            "league_def_rtg": league_def,
            "team_off_rtg": own_off,
            "opponent_vs_line": opponent_vs_line,
            "window_days": 21,
            "position": position_ctx.get("position"),
            "position_allowed_avg": position_ctx.get("position_allowed_avg"),
            "position_allowed_rank": position_ctx.get("position_allowed_rank"),
            "position_allowed_rate": position_ctx.get("position_allowed_rate"),
            "position_games": position_ctx.get("position_games"),
            "position_minutes_basis": position_ctx.get("position_minutes_basis"),
        },
        "model": {
            "baseline": baseline,
            "win_prob": p_win,
            "prob_edge": prob_edge,
            "ev_pct": ev_pct,
            "consensus": consensus,
            "line_adv": line_adv,
            "line": line_value,
        },
    }


def _season_betting_card_prop_summary(
    *,
    opponent_tri: str | None,
    market_label: str,
    line_value: float | None,
    insights: dict[str, Any],
) -> str | None:
    history = insights.get("history") if isinstance(insights.get("history"), dict) else {}
    matchup = insights.get("matchup") if isinstance(insights.get("matchup"), dict) else {}
    model = insights.get("model") if isinstance(insights.get("model"), dict) else {}
    parts: list[str] = []
    market_text = str(market_label or "stat").strip().lower() or "stat"
    side = str(insights.get("side") or model.get("side") or "").strip().upper()

    def _fmt_value(value: float | None) -> str | None:
        if value is None:
            return None
        return f"{value:.1f}"

    def _verb_for_side(kind: str = "base") -> str:
        if side == "UNDER":
            return "stays below" if kind == "base" else "suppresses"
        return "clears" if kind == "base" else "boosts"

    baseline = _safe_float(model.get("baseline"))
    line_adv = _safe_float(model.get("line_adv"))
    prob_edge = _safe_float(model.get("prob_edge"))
    ev_pct = _safe_float(model.get("ev_pct"))
    if baseline is not None and line_value is not None:
        delta = baseline - line_value
        if side == "UNDER":
            delta = line_value - baseline
        lead = f"Model {_verb_for_side()} the line at {_fmt_value(baseline)} versus {_fmt_value(line_value)}"
        if abs(delta) >= 0.05:
            lead += f" ({delta:+.1f})"
        parts.append(lead)
    elif baseline is not None:
        parts.append(f"Model projects {_fmt_value(baseline)} {market_text}")

    trend_clauses: list[str] = []
    for key, label in (("last5_avg", "last five"), ("last10_avg", "last 10"), ("season_avg", "season")):
        value = _safe_float(history.get(key))
        if value is not None:
            trend_clauses.append(f"{label} {_fmt_value(value)}")
    if trend_clauses:
        parts.append(f"Form check: {', '.join(trend_clauses[:3])}")

    opponent_avg = _safe_float(history.get("opponent_avg"))
    opponent_games = int(history.get("opponent_games") or 0)
    if opponent_avg is not None and opponent_games > 0:
        parts.append(f"Against {opponent_tri or 'this opponent'}, he has averaged {_fmt_value(opponent_avg)} across {opponent_games} meeting{'s' if opponent_games != 1 else ''}")
    opp_allowed_avg = _safe_float(matchup.get("opponent_allowed_avg"))
    opponent_vs_line = _safe_float(matchup.get("opponent_vs_line"))
    if opp_allowed_avg is not None and line_value is not None:
        rank = _safe_int(matchup.get("opponent_allowed_rank"))
        clause = f"{opponent_tri or 'The opponent'} {_verb_for_side('matchup')} this market, allowing {_fmt_value(opp_allowed_avg)} {market_text}"
        if rank is not None:
            clause += f" ({rank}/30 matchup rank)"
        if opponent_vs_line is not None and abs(opponent_vs_line) >= 0.05:
            clause += f" and sitting {opponent_vs_line:+.1f} versus this line"
        parts.append(clause)
    position = str(matchup.get("position") or "").strip().upper()
    position_avg = _safe_float(matchup.get("position_allowed_avg"))
    position_rank = _safe_int(matchup.get("position_allowed_rank"))
    if position and position_avg is not None:
        parts.append(f"Versus {position}s, the matchup is {_fmt_value(position_avg)} {market_text}{f' ({position_rank}/30)' if position_rank is not None else ''}")

    market_edge_bits: list[str] = []
    if prob_edge is not None and abs(prob_edge) >= 0.001:
        market_edge_bits.append(f"win edge {prob_edge * 100:+.1f}pp")
    if ev_pct is not None and abs(ev_pct) >= 0.05:
        market_edge_bits.append(f"EV {ev_pct:+.1f}%")
    if line_adv is not None and abs(line_adv) >= 0.05:
        market_edge_bits.append(f"line edge {line_adv:+.1f}")
    if market_edge_bits:
        parts.append(f"Market view: {', '.join(market_edge_bits[:3])}")

    return ". ".join(parts[:4]) if parts else None


def _season_betting_card_selection_key(row: dict[str, Any], home_tri: str, away_tri: str, home_name: str, away_name: str) -> str:
    raw = str(row.get("selection") or row.get("side") or "").strip()
    if not raw:
        return ""
    raw_key = raw.lower()
    home_keys = {"home", home_tri.lower(), home_name.lower()}
    away_keys = {"away", away_tri.lower(), away_name.lower()}
    if raw_key in home_keys:
        return "home"
    if raw_key in away_keys:
        return "away"
    if raw_key in {"over", "under"}:
        return raw_key
    return raw_key


def _season_betting_card_display_pick(row: dict[str, Any], bucket: str, home_tri: str, away_tri: str, home_name: str, away_name: str) -> str:
    for key in ("display_pick", "label", "pick_label"):
        text = str(row.get(key) or "").strip()
        if text:
            return text

    selection = _season_betting_card_selection_key(row, home_tri, away_tri, home_name, away_name)
    line = _safe_float(row.get("market_line"))
    if line is None:
        line = _safe_float(row.get("line"))
    market = _season_betting_card_market_label(bucket, str(row.get("market") or ""))
    if bucket == "ml":
        team = home_tri if selection == "home" else away_tri if selection == "away" else selection.upper()
        return f"{team or 'Team'} ML"
    if bucket == "totals":
        side = selection.upper() if selection in {"over", "under"} else "TOTAL"
        return f"{side} {line:.1f}" if line is not None else side
    if bucket == "spreads":
        team = home_tri if selection == "home" else away_tri if selection == "away" else selection.upper()
        if line is None:
            return f"{team or 'Team'} Spread"
        sign_line = f"{line:+.1f}" if not float(line).is_integer() else f"{int(line):+d}"
        return f"{team or 'Team'} {sign_line}"
    player = str(row.get("player") or row.get("player_name") or "Player").strip()
    side = selection.upper() if selection in {"over", "under"} else selection.title()
    if line is None:
        return f"{player} {market}"
    shown_line = f"{line:.1f}" if not float(line).is_integer() else f"{int(line)}"
    return f"{player} {side} {shown_line} {market}".strip()


def _playable_prop_audit_line_key(value: Any) -> float | None:
    line_val = _safe_float(value)
    if line_val is None:
        return None
    return round(float(line_val), 4)


@lru_cache(maxsize=1)
def _latest_playable_prop_coverage_audit_lookup() -> dict[str, Any]:
    out = {
        "audit_date": None,
        "by_id_exact": {},
        "by_name_exact": {},
        "by_name": {},
    }
    try:
        candidates: list[tuple[str, Path]] = []
        for path in DATA_PROCESSED_DIR.glob("playable_prop_coverage_audit_*.csv"):
            match = re.match(r"^playable_prop_coverage_audit_(\d{4}-\d{2}-\d{2})\.csv$", path.name)
            if match:
                candidates.append((str(match.group(1) or "").strip(), path))
        if not candidates:
            return out
        audit_date, audit_path = max(candidates, key=lambda item: item[0])
        use_columns = {
            "date",
            "team_abbr",
            "player_name",
            "player_id",
            "market",
            "side",
            "line",
            "playable_sleeve",
            "source_name",
            "unresolved_reason",
            "provider_anomaly_likely",
            "audit_classification",
            "coverage_subtype",
            "team_present_in_source",
            "market_supported_by_source",
            "player_name_present_any_team",
            "player_id_present_any_team",
        }
        audit_df = pd.read_csv(audit_path, usecols=lambda col: str(col).strip() in use_columns)
        if audit_df is None or audit_df.empty:
            return out
        by_id_exact: dict[tuple[str, str, int, str, str, float | None], dict[str, Any]] = {}
        by_name_exact: dict[tuple[str, str, str, str, str, float | None], dict[str, Any]] = {}
        by_name: dict[tuple[str, str, str, str, str], dict[str, Any]] = {}
        for _, raw_row in audit_df.iterrows():
            date_key = str(raw_row.get("date") or "").strip()
            team_abbr = str(raw_row.get("team_abbr") or "").strip().upper()
            player_name = str(raw_row.get("player_name") or "").strip()
            player_key = _norm_player_name(player_name)
            player_id = _safe_int(raw_row.get("player_id"))
            market = str(raw_row.get("market") or "").strip().lower()
            side = str(raw_row.get("side") or "").strip().lower()
            line_key = _playable_prop_audit_line_key(raw_row.get("line"))
            if not date_key or not team_abbr or not market or not side:
                continue
            summary = {
                "audit_date": audit_date,
                "source_name": str(raw_row.get("source_name") or "").strip() or None,
                "unresolved_reason": str(raw_row.get("unresolved_reason") or "").strip().lower() or None,
                "audit_classification": str(raw_row.get("audit_classification") or "").strip().lower() or None,
                "coverage_subtype": str(raw_row.get("coverage_subtype") or "").strip().lower() or None,
                "playable_sleeve": str(raw_row.get("playable_sleeve") or "").strip().lower() or None,
                "provider_anomaly_likely": bool(raw_row.get("provider_anomaly_likely")),
                "team_present_in_source": bool(raw_row.get("team_present_in_source")),
                "market_supported_by_source": bool(raw_row.get("market_supported_by_source")),
                "player_name_present_any_team": bool(raw_row.get("player_name_present_any_team")),
                "player_id_present_any_team": bool(raw_row.get("player_id_present_any_team")),
            }
            if player_id is not None:
                by_id_exact[(date_key, team_abbr, player_id, market, side, line_key)] = summary
            if player_key:
                by_name_exact[(date_key, team_abbr, player_key, market, side, line_key)] = summary
                by_name.setdefault((date_key, team_abbr, player_key, market, side), summary)
        out["audit_date"] = audit_date
        out["by_id_exact"] = by_id_exact
        out["by_name_exact"] = by_name_exact
        out["by_name"] = by_name
        return out
    except Exception:
        return out


def _lookup_playable_prop_unresolved_audit(
    date_str: Any,
    team_tri: Any,
    player_name: Any,
    player_id: Any,
    market: Any,
    side: Any,
    line: Any,
) -> dict[str, Any] | None:
    lookup = _latest_playable_prop_coverage_audit_lookup()
    date_key = str(date_str or "").strip()
    team_abbr = str(team_tri or "").strip().upper()
    market_key = str(market or "").strip().lower()
    side_key = str(side or "").strip().lower()
    line_key = _playable_prop_audit_line_key(line)
    if not date_key or not team_abbr or not market_key or not side_key:
        return None
    player_id_key = _safe_int(player_id)
    if player_id_key is not None:
        audit_row = (lookup.get("by_id_exact") or {}).get((date_key, team_abbr, player_id_key, market_key, side_key, line_key))
        if isinstance(audit_row, dict):
            return dict(audit_row)
    player_key = _norm_player_name(player_name)
    if player_key:
        audit_row = (lookup.get("by_name_exact") or {}).get((date_key, team_abbr, player_key, market_key, side_key, line_key))
        if isinstance(audit_row, dict):
            return dict(audit_row)
        audit_row = (lookup.get("by_name") or {}).get((date_key, team_abbr, player_key, market_key, side_key))
        if isinstance(audit_row, dict):
            return dict(audit_row)
    return None


def _season_betting_card_settlement(row: dict[str, Any]) -> dict[str, Any] | None:
    existing = row.get("settlement") if isinstance(row.get("settlement"), dict) else {}
    unresolved_audit = row.get("unresolved_audit") if isinstance(row.get("unresolved_audit"), dict) else {}
    result = str(existing.get("result") or row.get("result") or "").strip().lower()
    actual = existing.get("actual") if existing.get("actual") is not None else row.get("actual")
    pending_reason = str(existing.get("pending_reason") or row.get("pending_reason") or row.get("unresolved_reason") or unresolved_audit.get("unresolved_reason") or "").strip().lower() or None
    audit_classification = str(existing.get("audit_classification") or row.get("audit_classification") or unresolved_audit.get("audit_classification") or "").strip().lower() or None
    coverage_subtype = str(existing.get("coverage_subtype") or row.get("coverage_subtype") or unresolved_audit.get("coverage_subtype") or "").strip().lower() or None
    profit_u = _safe_float(existing.get("profit_u"))
    if profit_u is None:
        profit_u = _safe_float(existing.get("profit_units"))
    if profit_u is None:
        profit_u = _safe_float(row.get("profit_u"))
    if profit_u is None:
        profit_u = _safe_float(row.get("profit_units"))
    if profit_u is None:
        price = _safe_float(row.get("odds"))
        if price is None:
            price = _safe_float(row.get("price"))
        if price is not None:
            profit_u = _ll_profit_units(float(price), result)
    if result not in {"win", "loss", "push"} and actual is None and profit_u is None and not pending_reason and not audit_classification and not coverage_subtype:
        return None
    settlement = {
        "result": result if result in {"win", "loss", "push"} else "pending",
        "actual": actual,
        "profit_u": profit_u,
    }
    if pending_reason:
        settlement["pending_reason"] = pending_reason
    if audit_classification:
        settlement["audit_classification"] = audit_classification
    if coverage_subtype:
        settlement["coverage_subtype"] = coverage_subtype
    return settlement


def _season_betting_card_normalize_row(
    row: dict[str, Any],
    home_tri: str,
    away_tri: str,
    home_name: str,
    away_name: str,
    team_side: str | None = None,
    date_str: str | None = None,
    matchup_ctx: dict[str, Any] | None = None,
    include_prop_insights: bool = False,
) -> dict[str, Any]:
    source_row = row if isinstance(row, dict) else {}
    effective_row = _season_betting_card_effective_prop_row(source_row)
    market_source = effective_row.get("market") if effective_row.get("market") is not None else source_row.get("market")
    bucket = _season_betting_card_market_bucket(market_source)
    market_key = str(market_source or "").strip().lower()
    line_value = _safe_float(effective_row.get("market_line")) if effective_row.get("market_line") is not None else _safe_float(effective_row.get("line"))
    odds_value = _safe_float(effective_row.get("odds")) if effective_row.get("odds") is not None else _safe_float(effective_row.get("price"))
    model_prob = _safe_float(effective_row.get("prob_calib")) if effective_row.get("prob_calib") is not None else _safe_float(effective_row.get("probability")) if effective_row.get("probability") is not None else _safe_float(effective_row.get("win_prob"))
    if model_prob is None:
        model_prob = _safe_float(effective_row.get("p_win"))
    if model_prob is None:
        model_prob = _safe_float(effective_row.get("model_prob"))
    if model_prob is None:
        model_prob = _safe_float(effective_row.get("prob"))
    if model_prob is None:
        odds_for_prob = _safe_float(effective_row.get("odds")) if effective_row.get("odds") is not None else _safe_float(effective_row.get("price"))
        model_prob = _best_bets_prob_from_ev(_safe_float(effective_row.get("ev")), odds_for_prob)
    reason_arrays: list[str] = []
    for key in ("reasons", "basketball_reasons", "market_reasons", "model_reasons", "top_play_reasons", "sim_reasons"):
        values = effective_row.get(key)
        if not isinstance(values, list):
            continue
        for item in values:
            text = str(item or "").strip()
            if text and text not in reason_arrays:
                reason_arrays.append(text)
    player_name = str(effective_row.get("player") or effective_row.get("player_name") or source_row.get("player") or source_row.get("player_name") or "").strip() or None
    player_id = effective_row.get("player_id") if effective_row.get("player_id") is not None else source_row.get("player_id")
    selection = _season_betting_card_selection_key(effective_row, home_tri, away_tri, home_name, away_name)
    side = str(effective_row.get("side") or selection or "").strip().upper() or None
    team_tri = home_tri if team_side == "home" else away_tri if team_side == "away" else str(effective_row.get("team") or effective_row.get("team_tri") or "").strip().upper() or None
    opponent_tri = away_tri if team_tri == home_tri else home_tri if team_tri == away_tri else None
    home_flag = True if team_tri == home_tri and team_tri else False if team_tri == away_tri and team_tri else None
    prop_insights = None
    if include_prop_insights and bucket == "player_props" and date_str and player_name and team_tri and market_key:
        prop_insights = _season_betting_card_prop_context(
            date_str=date_str,
            player_name=player_name,
            team_tri=team_tri,
            opponent_tri=opponent_tri,
            market_key=market_key,
            side=side,
            line_value=line_value,
            home_flag=home_flag,
            matchup_ctx=matchup_ctx,
            source_row=effective_row,
            player_id=player_id,
        )
    reason_summary = str(
        effective_row.get("basketball_summary")
        or effective_row.get("reason_summary")
        or effective_row.get("why_explain")
        or source_row.get("reason_summary")
        or source_row.get("why_explain")
        or ""
    ).strip() or None
    if bucket == "player_props" and prop_insights:
        reason_summary = _season_betting_card_prop_summary(
            opponent_tri=opponent_tri,
            market_label=_season_betting_card_market_label(bucket, market_key),
            line_value=line_value,
            insights=prop_insights,
        ) or reason_summary
    unresolved_audit = effective_row.get("unresolved_audit") if isinstance(effective_row.get("unresolved_audit"), dict) else source_row.get("unresolved_audit") if isinstance(source_row.get("unresolved_audit"), dict) else {}
    unresolved_reason = str(effective_row.get("unresolved_reason") or source_row.get("unresolved_reason") or unresolved_audit.get("unresolved_reason") or "").strip().lower() or None
    audit_classification = str(effective_row.get("audit_classification") or source_row.get("audit_classification") or unresolved_audit.get("audit_classification") or "").strip().lower() or None
    coverage_subtype = str(effective_row.get("coverage_subtype") or source_row.get("coverage_subtype") or unresolved_audit.get("coverage_subtype") or "").strip().lower() or None
    return {
        "market": bucket,
        "market_key": market_key,
        "market_label": _season_betting_card_market_label(bucket, market_key),
        "market_family_label": _season_betting_card_market_family_label(bucket),
        "card_bucket": str(effective_row.get("card_bucket") or source_row.get("card_bucket") or "official").strip().lower() or "official",
        "portfolio_selected": bool(effective_row.get("portfolio_selected") if effective_row.get("portfolio_selected") is not None else source_row.get("portfolio_selected")),
        "portfolio_rank": _safe_int(effective_row.get("portfolio_rank") if effective_row.get("portfolio_rank") is not None else source_row.get("portfolio_rank")),
        "portfolio_score": _safe_float(effective_row.get("portfolio_score") if effective_row.get("portfolio_score") is not None else source_row.get("portfolio_score")),
        "stake_amount": _safe_float(effective_row.get("stake_amount") if effective_row.get("stake_amount") is not None else source_row.get("stake_amount")),
        "stake_units": _safe_float(effective_row.get("stake_units") if effective_row.get("stake_units") is not None else source_row.get("stake_units")),
        "stake_pct": _safe_float(effective_row.get("stake_pct") if effective_row.get("stake_pct") is not None else source_row.get("stake_pct")),
        "playable_sleeve": str(effective_row.get("playable_sleeve") or source_row.get("playable_sleeve") or "").strip().lower() or None,
        "selection": selection,
        "display_pick": _season_betting_card_display_pick(effective_row, bucket, home_tri, away_tri, home_name, away_name),
        "market_line": line_value,
        "odds": odds_value,
        "edge": _safe_float(effective_row.get("edge")),
        "ev": _safe_float(effective_row.get("ev")),
        "ev_pct": _safe_float(effective_row.get("ev_pct")),
        "model_prob": model_prob,
        "player_name": player_name,
        "player_id": _safe_int(player_id),
        "team_side": team_side or None,
        "team_tri": team_tri,
        "opponent_tri": opponent_tri,
        "reason_summary": reason_summary,
        "reasons": reason_arrays,
        "basketball_reasons": [str(item).strip() for item in (effective_row.get("basketball_reasons") or []) if str(item).strip()] if isinstance(effective_row.get("basketball_reasons"), list) else [],
        "market_reasons": [str(item).strip() for item in (effective_row.get("market_reasons") or []) if str(item).strip()] if isinstance(effective_row.get("market_reasons"), list) else [],
        "model_reasons": [str(item).strip() for item in (effective_row.get("model_reasons") or []) if str(item).strip()] if isinstance(effective_row.get("model_reasons"), list) else [],
        "top_play_reasons": [str(item).strip() for item in (effective_row.get("top_play_reasons") or []) if str(item).strip()] if isinstance(effective_row.get("top_play_reasons"), list) else [],
        "insights": prop_insights,
        "unresolved_reason": unresolved_reason,
        "audit_classification": audit_classification,
        "coverage_subtype": coverage_subtype,
        "unresolved_audit": dict(unresolved_audit) if unresolved_audit else None,
        "settlement": _season_betting_card_settlement(effective_row),
    }


def _season_betting_card_result_stats(rows: list[dict[str, Any]]) -> dict[str, Any]:
    wins = 0
    losses = 0
    pushes = 0
    stake_u = 0.0
    profit_u = 0.0
    settled = 0
    for row in rows:
        settlement = row.get("settlement") if isinstance(row.get("settlement"), dict) else None
        result = str((settlement or {}).get("result") or "").strip().lower()
        if result not in {"win", "loss", "push"}:
            continue
        settled += 1
        stake_u += 1.0
        if result == "win":
            wins += 1
        elif result == "loss":
            losses += 1
        else:
            pushes += 1
        profit_val = _safe_float((settlement or {}).get("profit_u"))
        if profit_val is not None:
            profit_u += float(profit_val)
    return {
        "n": settled,
        "wins": wins,
        "losses": losses,
        "pushes": pushes,
        "stake_u": round(stake_u, 3),
        "profit_u": round(profit_u, 3),
        "roi": round(profit_u / stake_u, 4) if stake_u > 0 else None,
    }


def _season_betting_card_unresolved_breakdown(rows: list[dict[str, Any]]) -> dict[str, int]:
    counts: dict[str, int] = {}
    for row in rows:
        settlement = row.get("settlement") if isinstance(row.get("settlement"), dict) else {}
        result = str((settlement or {}).get("result") or "").strip().lower()
        if result in {"win", "loss", "push"}:
            continue
        unresolved_audit = row.get("unresolved_audit") if isinstance(row.get("unresolved_audit"), dict) else {}
        key = str(
            row.get("coverage_subtype")
            or settlement.get("coverage_subtype")
            or unresolved_audit.get("coverage_subtype")
            or row.get("audit_classification")
            or settlement.get("audit_classification")
            or unresolved_audit.get("audit_classification")
            or row.get("unresolved_reason")
            or settlement.get("pending_reason")
            or unresolved_audit.get("unresolved_reason")
            or "pending"
        ).strip().lower() or "pending"
        counts[key] = int(counts.get(key) or 0) + 1
    return counts


def _season_betting_card_merge_stats(rows: list[dict[str, Any]]) -> dict[str, Any]:
    out = {"n": 0, "wins": 0, "losses": 0, "pushes": 0, "stake_u": 0.0, "profit_u": 0.0}
    for row in rows:
        out["n"] += int(row.get("n") or 0)
        out["wins"] += int(row.get("wins") or 0)
        out["losses"] += int(row.get("losses") or 0)
        out["pushes"] += int(row.get("pushes") or 0)
        out["stake_u"] += float(row.get("stake_u") or 0.0)
        out["profit_u"] += float(row.get("profit_u") or 0.0)
    out["stake_u"] = round(out["stake_u"], 3)
    out["profit_u"] = round(out["profit_u"], 3)
    out["roi"] = round(out["profit_u"] / out["stake_u"], 4) if out["stake_u"] > 0 else None
    return out


def _season_betting_card_result_block(stats: dict[str, Any] | None) -> dict[str, Any]:
    if not isinstance(stats, dict):
        return {"combined": {}}
    return {"combined": dict(stats)}


def _season_betting_card_selected_counts(rows: list[dict[str, Any]]) -> dict[str, int]:
    counts = {"combined": 0, "totals": 0, "ml": 0, "spreads": 0, "player_props": 0}
    for row in rows:
        bucket = str(row.get("market") or "").strip().lower()
        counts["combined"] += 1
        if bucket in counts:
            counts[bucket] += 1
        else:
            counts["player_props"] += 1
    return counts


def _season_betting_card_matchup(game: dict[str, Any], status: dict[str, str]) -> dict[str, Any]:
    live = game.get("live_status") if isinstance(game.get("live_status"), dict) else {}
    score = live.get("score") if isinstance(live.get("score"), dict) else {}
    away_score = _safe_int(score.get("away"))
    if away_score is None:
        away_score = _safe_int(live.get("away_score"))
    home_score = _safe_int(score.get("home"))
    if home_score is None:
        home_score = _safe_int(live.get("home_score"))
    return {
        "isLive": bool(live.get("is_live")),
        "isFinal": bool(live.get("is_final")),
        "displayState": str(status.get("detailed") or status.get("abstract") or "").strip(),
        "score": {
            "away": away_score,
            "home": home_score,
        },
    }


def _season_betting_card_bucket_to_results(bucket: dict[str, Any] | None) -> dict[str, Any]:
    row = bucket if isinstance(bucket, dict) else {}
    n = int(row.get("resolved") or 0)
    stake_u = float(row.get("stake_total") or 0.0)
    profit_u = float(row.get("profit_total") or 0.0)
    return {
        "n": n,
        "wins": int(row.get("wins") or 0),
        "losses": int(row.get("losses") or 0),
        "pushes": int(row.get("pushes") or 0),
        "stake_u": round(stake_u, 3),
        "profit_u": round(profit_u, 3),
        "roi": round(profit_u / stake_u, 4) if stake_u > 0 else None,
    }


def _season_betting_card_day_row_from_recap(item: dict[str, Any]) -> dict[str, Any]:
    games = item.get("games") if isinstance(item.get("games"), dict) else {}
    props = item.get("props") if isinstance(item.get("props"), dict) else {}
    game_picks = [row for row in (games.get("picks") or []) if isinstance(row, dict)]
    prop_picks = [row for row in (props.get("picks") or []) if isinstance(row, dict)]
    selected_counts = {
        "combined": len(game_picks) + len(prop_picks),
        "totals": 0,
        "ml": 0,
        "spreads": 0,
        "player_props": len(prop_picks),
    }
    for row in game_picks:
        market = str(row.get("market") or "").strip().upper()
        if market in {"ML", "MONEYLINE"}:
            selected_counts["ml"] += 1
        elif market in {"TOTAL", "TOTALS", "OU"}:
            selected_counts["totals"] += 1
        elif market in {"ATS", "SPREAD", "SPREADS"}:
            selected_counts["spreads"] += 1

    combined = _season_betting_card_merge_stats(
        [
            _season_betting_card_bucket_to_results((games.get("buckets") or {}).get("Overall") if isinstance(games.get("buckets"), dict) else None),
            _season_betting_card_bucket_to_results((props.get("buckets") or {}).get("Overall") if isinstance(props.get("buckets"), dict) else None),
        ]
    )
    unresolved_n = max(0, int(selected_counts["combined"] - int(combined.get("n") or 0)))
    date_str = str(item.get("date") or "").strip()
    return {
        "date": date_str,
        "month": date_str[:7] if len(date_str) >= 7 else "",
        "selected_counts": selected_counts,
        "results": {"combined": combined},
        "unresolved_n": unresolved_n,
    }


def _season_betting_card_fetch_recap_items(date_strs: list[str]) -> list[dict[str, Any]]:
    dates = [str(date_str).strip() for date_str in (date_strs or []) if str(date_str).strip()]
    if not dates:
        return []

    ttl_sec = _season_betting_card_cache_ttl_seconds()
    cache_key = "|".join(dates)
    cached = _season_betting_card_cache_get(_season_betting_card_recap_cache, cache_key, ttl_sec)
    if isinstance(cached, list):
        return [dict(item) for item in cached if isinstance(item, dict)]

    params = urlencode(
        {
            "since": dates[0],
            "until": dates[-1],
            "include_legacy": 1,
            "include_picks": 0,
        }
    )
    try:
        with app.test_request_context(f"/api/betting-recap?{params}"):
            payload, status_code = _response_json_value(_recommendations_recaps())
        if status_code and status_code >= 400:
            return []
        items = payload.get("items") if isinstance(payload, dict) else []
        if not isinstance(items, list):
            return []
        by_date = {
            str(item.get("date") or "").strip(): item
            for item in items
            if isinstance(item, dict) and str(item.get("date") or "").strip()
        }
        resolved = [by_date[date_str] for date_str in dates if date_str in by_date]
        _season_betting_card_cache_set(_season_betting_card_recap_cache, cache_key, resolved)
        return resolved
    except Exception:
        return []


def _season_betting_card_day_payload(
    season: int,
    date_str: str,
    profile: str,
    *,
    include_prop_insights: bool = False,
) -> dict[str, Any] | None:
    artifact_payload = _season_betting_card_load_artifact(
        _season_betting_card_day_artifact_candidates(
            season,
            profile,
            date_str,
            include_prop_insights=include_prop_insights,
        )
    )
    if isinstance(artifact_payload, dict):
        return artifact_payload

    ttl_sec = _season_betting_card_cache_ttl_seconds()
    cache_key = f"{int(season)}|{str(profile or '').strip().lower()}|{str(date_str or '').strip()}|{1 if include_prop_insights else 0}"
    cached = _season_betting_card_cache_get(_season_betting_card_day_cache, cache_key, ttl_sec)
    if isinstance(cached, dict):
        return cached

    cards_payload = _season_betting_card_fetch_cards_payload(date_str)
    if not isinstance(cards_payload, dict):
        return None

    payload = _season_betting_card_day_payload_from_cards(
        season,
        date_str,
        profile,
        cards_payload,
        include_games=True,
        include_prop_insights=include_prop_insights,
    )
    if isinstance(payload, dict):
        _season_betting_card_cache_set(_season_betting_card_day_cache, cache_key, payload)
    return payload


def _season_betting_card_day_payload_from_cards(
    season: int,
    date_str: str,
    profile: str,
    cards_payload: dict[str, Any],
    *,
    include_games: bool,
    include_prop_insights: bool,
) -> dict[str, Any]:

    games_out: list[dict[str, Any]] = []
    official_day_rows: list[dict[str, Any]] = []
    playable_day_rows: list[dict[str, Any]] = []
    source_games = [game for game in (cards_payload.get("games") or []) if isinstance(game, dict)]
    game_context = _load_best_bets_game_context(date_str) if include_prop_insights else {}

    for index, game in enumerate(source_games):
        home_tri = str(game.get("home_tri") or "").strip().upper()
        away_tri = str(game.get("away_tri") or "").strip().upper()
        home_name = str(game.get("home_name") or home_tri or "Home").strip()
        away_name = str(game.get("away_name") or away_tri or "Away").strip()
        matchup_ctx = _best_bets_ctx_for_matchup(game_context, home=home_name, away=away_name)
        away = _betting_card_v2_team_meta(away_tri, away_name)
        home = _betting_card_v2_team_meta(home_tri, home_name)
        odds = game.get("odds") if isinstance(game.get("odds"), dict) else {}
        game_date = str(odds.get("commence_time") or "").strip()
        status = _betting_card_v2_status(game)
        official_rows: list[dict[str, Any]] = []
        playable_rows: list[dict[str, Any]] = []

        for raw_row in (game.get("game_market_recommendations") or []):
            if isinstance(raw_row, dict):
                normalized_row = _season_betting_card_normalize_row(
                    raw_row,
                    home_tri,
                    away_tri,
                    home_name,
                    away_name,
                    date_str=date_str,
                    matchup_ctx=matchup_ctx,
                    include_prop_insights=include_prop_insights,
                )
                if str(normalized_row.get("card_bucket") or "").strip().lower() == "playable":
                    playable_rows.append(normalized_row)
                else:
                    normalized_row["card_bucket"] = "official"
                    official_rows.append(normalized_row)

        prop_map = game.get("prop_recommendations") if isinstance(game.get("prop_recommendations"), dict) else {}
        for team_side in ("away", "home"):
            for raw_row in (prop_map.get(team_side) or []):
                if isinstance(raw_row, dict):
                    if str(raw_row.get("card_bucket") or "").strip().lower() == "discard":
                        continue
                    normalized_row = _season_betting_card_normalize_row(
                        raw_row,
                        home_tri,
                        away_tri,
                        home_name,
                        away_name,
                        team_side=team_side,
                        date_str=date_str,
                        matchup_ctx=matchup_ctx,
                        include_prop_insights=include_prop_insights,
                    )
                    if str(normalized_row.get("card_bucket") or "").strip().lower() == "playable":
                        playable_rows.append(normalized_row)
                    else:
                        normalized_row["card_bucket"] = "official"
                        official_rows.append(normalized_row)

        official_day_rows.extend(official_rows)
        playable_day_rows.extend(playable_rows)
        if not include_games:
            continue

        all_game_rows = list(official_rows) + list(playable_rows)
        market_groups = {
            "totals": next((row for row in official_rows if str(row.get("market")) == "totals"), None),
            "ml": next((row for row in official_rows if str(row.get("market")) == "ml"), None),
            "spreads": next((row for row in official_rows if str(row.get("market")) == "spreads"), None),
            "playerProps": [row for row in official_rows if str(row.get("market")) == "player_props"],
            "playablePlayerProps": [row for row in playable_rows if str(row.get("market")) == "player_props"],
        }
        official_results = _season_betting_card_result_stats(official_rows)
        playable_results = _season_betting_card_result_stats(playable_rows)
        all_results = _season_betting_card_result_stats(all_game_rows)
        game_pk = _safe_int((game.get("sim") or {}).get("game_id") if isinstance(game.get("sim"), dict) else None)
        if game_pk is None:
            game_pk = index + 1
        games_out.append(
            {
                "game_pk": game_pk,
                "game_date": game_date or None,
                "start_time": _betting_card_v2_start_time(game_date),
                "away": away,
                "home": home,
                "status": status,
                "matchup": _season_betting_card_matchup(game, status),
                "betting": {
                    "officialRows": official_rows,
                    "playableRows": playable_rows,
                    "allRows": all_game_rows,
                    "markets": market_groups,
                    "results": {
                        "combined": official_results,
                    },
                    "playable_results": {
                        "combined": playable_results,
                    },
                    "all_results": {
                        "combined": all_results,
                    },
                    "counts": {
                        "official": int(len(official_rows)),
                        "playable": int(len(playable_rows)),
                        "combined": int(len(all_game_rows)),
                        "player_props": int(sum(1 for row in official_rows if str(row.get("market")) == "player_props")),
                        "playable_player_props": int(sum(1 for row in playable_rows if str(row.get("market")) == "player_props")),
                    },
                    "flags": {
                        "hasOfficialRecommendations": bool(official_rows),
                        "hasPlayableCandidates": bool(playable_rows),
                        "hasAnyRecommendations": bool(all_game_rows),
                    },
                },
            }
        )

    all_day_rows = list(official_day_rows) + list(playable_day_rows)
    results = _season_betting_card_result_stats(official_day_rows)
    playable_results = _season_betting_card_result_stats(playable_day_rows)
    all_results = _season_betting_card_result_stats(all_day_rows)
    unresolved_n = max(0, int(len(official_day_rows) - int(results.get("n") or 0)))
    playable_unresolved_n = max(0, int(len(playable_day_rows) - int(playable_results.get("n") or 0)))
    all_unresolved_n = max(0, int(len(all_day_rows) - int(all_results.get("n") or 0)))
    playable_unresolved_breakdown = _season_betting_card_unresolved_breakdown(playable_day_rows)
    all_unresolved_breakdown = _season_betting_card_unresolved_breakdown(all_day_rows)
    return _to_jsonable(
        {
            "season": int(season),
            "date": date_str,
            "profile": profile,
            "source_kind": "api_cards_v2",
            "cap_profile": profile,
            "cards_url": f"/?date={date_str}",
            "pregame_portfolio": dict(cards_payload.get("pregame_portfolio") or {}) if isinstance(cards_payload.get("pregame_portfolio"), dict) else None,
            "games": games_out,
            "results": {
                "combined": results,
            },
            "playable_results": {
                "combined": playable_results,
            },
            "all_results": {
                "combined": all_results,
            },
            "selected_counts": _season_betting_card_selected_counts(official_day_rows),
            "playable_selected_counts": _season_betting_card_selected_counts(playable_day_rows),
            "all_selected_counts": _season_betting_card_selected_counts(all_day_rows),
            "summary": {
                "unresolved_n": unresolved_n,
                "playable_unresolved_n": playable_unresolved_n,
                "playable_unresolved_breakdown": playable_unresolved_breakdown,
                "all_unresolved_n": all_unresolved_n,
                "all_unresolved_breakdown": all_unresolved_breakdown,
            },
            "unresolved_n": unresolved_n,
            "playable_unresolved_n": playable_unresolved_n,
            "playable_unresolved_breakdown": playable_unresolved_breakdown,
            "all_unresolved_n": all_unresolved_n,
            "all_unresolved_breakdown": all_unresolved_breakdown,
        }
    )


def _season_betting_card_manifest(season: int, profile: str, requested_date: str | None = None) -> dict[str, Any]:
    artifact_payload = _season_betting_card_load_artifact(
        _season_betting_card_manifest_artifact_candidates(season, profile, requested_date=requested_date)
    )
    if isinstance(artifact_payload, dict):
        return artifact_payload

    ttl_sec = _season_betting_card_cache_ttl_seconds()
    cache_key = f"{int(season)}|{str(profile or '').strip().lower()}|{str(requested_date or '').strip()}"
    cached = _season_betting_card_cache_get(_season_betting_card_manifest_cache, cache_key, ttl_sec)
    if isinstance(cached, dict):
        return cached

    candidate_dates = _season_betting_card_candidate_dates(season, requested_date=requested_date)
    days_full: list[dict[str, Any]] = []
    recap_items = _season_betting_card_fetch_recap_items(candidate_dates)
    recap_by_date: dict[str, dict[str, Any]] = {}
    for item in recap_items:
        if isinstance(item, dict):
            day_row = _season_betting_card_day_row_from_recap(item)
            date_key = str(day_row.get("date") or "").strip()
            if date_key:
                recap_by_date[date_key] = day_row

    for date_str in candidate_dates:
        recap_row = recap_by_date.get(str(date_str))
        day_payload = None
        needs_full_cards = str(date_str) == str(requested_date or "") or not isinstance(recap_row, dict)
        if needs_full_cards:
            cards_payload = _season_betting_card_fetch_cards_payload(date_str)
            if isinstance(cards_payload, dict):
                day_payload = _season_betting_card_day_payload_from_cards(
                    season,
                    date_str,
                    profile,
                    cards_payload,
                    include_games=False,
                    include_prop_insights=False,
                )
        if isinstance(day_payload, dict):
            days_full.append(day_payload)
            continue
        if isinstance(recap_row, dict):
            days_full.append(
                {
                    "season": int(season),
                    "date": recap_row.get("date"),
                    "profile": profile,
                    "results": recap_row.get("results"),
                    "playable_results": {"combined": {}},
                    "all_results": recap_row.get("results"),
                    "selected_counts": recap_row.get("selected_counts"),
                    "playable_selected_counts": {"combined": 0, "totals": 0, "ml": 0, "spreads": 0, "player_props": 0},
                    "all_selected_counts": recap_row.get("selected_counts"),
                    "summary": {
                        "unresolved_n": int(recap_row.get("unresolved_n") or 0),
                        "playable_unresolved_n": 0,
                        "all_unresolved_n": int(recap_row.get("unresolved_n") or 0),
                    },
                    "unresolved_n": int(recap_row.get("unresolved_n") or 0),
                    "playable_unresolved_n": 0,
                    "all_unresolved_n": int(recap_row.get("unresolved_n") or 0),
                }
            )

    day_rows: list[dict[str, Any]] = []
    month_counts: dict[str, int] = {}
    result_rows: list[dict[str, Any]] = []
    playable_result_rows: list[dict[str, Any]] = []
    all_result_rows: list[dict[str, Any]] = []
    total_counts = {"combined": 0, "totals": 0, "ml": 0, "spreads": 0, "player_props": 0}
    playable_total_counts = {"combined": 0, "totals": 0, "ml": 0, "spreads": 0, "player_props": 0}
    all_total_counts = {"combined": 0, "totals": 0, "ml": 0, "spreads": 0, "player_props": 0}
    unresolved_total = 0
    playable_unresolved_total = 0
    all_unresolved_total = 0
    playable_unresolved_breakdown_total: dict[str, int] = {}
    all_unresolved_breakdown_total: dict[str, int] = {}
    day_profits: list[tuple[str, float]] = []

    for day in days_full:
        date_str = str(day.get("date") or "").strip()
        month_key = date_str[:7] if len(date_str) >= 7 else ""
        if month_key:
            month_counts[month_key] = month_counts.get(month_key, 0) + 1
        counts = day.get("selected_counts") if isinstance(day.get("selected_counts"), dict) else {}
        playable_counts = day.get("playable_selected_counts") if isinstance(day.get("playable_selected_counts"), dict) else {}
        all_counts = day.get("all_selected_counts") if isinstance(day.get("all_selected_counts"), dict) else {}
        for key in total_counts:
            total_counts[key] += int(counts.get(key) or 0)
            playable_total_counts[key] += int(playable_counts.get(key) or 0)
            all_total_counts[key] += int(all_counts.get(key) or 0)
        unresolved_n = int(day.get("unresolved_n") or ((day.get("summary") or {}).get("unresolved_n") if isinstance(day.get("summary"), dict) else 0) or 0)
        playable_unresolved_n = int(day.get("playable_unresolved_n") or ((day.get("summary") or {}).get("playable_unresolved_n") if isinstance(day.get("summary"), dict) else 0) or 0)
        all_unresolved_n = int(day.get("all_unresolved_n") or ((day.get("summary") or {}).get("all_unresolved_n") if isinstance(day.get("summary"), dict) else 0) or 0)
        playable_unresolved_breakdown = day.get("playable_unresolved_breakdown") if isinstance(day.get("playable_unresolved_breakdown"), dict) else ((day.get("summary") or {}).get("playable_unresolved_breakdown") if isinstance(day.get("summary"), dict) and isinstance((day.get("summary") or {}).get("playable_unresolved_breakdown"), dict) else {})
        all_unresolved_breakdown = day.get("all_unresolved_breakdown") if isinstance(day.get("all_unresolved_breakdown"), dict) else ((day.get("summary") or {}).get("all_unresolved_breakdown") if isinstance(day.get("summary"), dict) and isinstance((day.get("summary") or {}).get("all_unresolved_breakdown"), dict) else {})
        unresolved_total += unresolved_n
        playable_unresolved_total += playable_unresolved_n
        all_unresolved_total += all_unresolved_n
        for key, value in playable_unresolved_breakdown.items():
            playable_unresolved_breakdown_total[str(key)] = int(playable_unresolved_breakdown_total.get(str(key)) or 0) + int(value or 0)
        for key, value in all_unresolved_breakdown.items():
            all_unresolved_breakdown_total[str(key)] = int(all_unresolved_breakdown_total.get(str(key)) or 0) + int(value or 0)
        combined = ((day.get("results") or {}).get("combined")) if isinstance(day.get("results"), dict) else {}
        playable_combined = ((day.get("playable_results") or {}).get("combined")) if isinstance(day.get("playable_results"), dict) else {}
        all_combined = ((day.get("all_results") or {}).get("combined")) if isinstance(day.get("all_results"), dict) else {}
        if isinstance(combined, dict):
            result_rows.append(combined)
            day_profits.append((date_str, float(combined.get("profit_u") or 0.0)))
        if isinstance(playable_combined, dict):
            playable_result_rows.append(playable_combined)
        if isinstance(all_combined, dict):
            all_result_rows.append(all_combined)
        day_rows.append(
            {
                "date": date_str,
                "month": month_key,
                "selected_counts": counts,
                "playable_selected_counts": playable_counts,
                "all_selected_counts": all_counts,
                "results": {"combined": combined},
                "playable_results": _season_betting_card_result_block(playable_combined if isinstance(playable_combined, dict) else None),
                "all_results": _season_betting_card_result_block(all_combined if isinstance(all_combined, dict) else None),
                "unresolved_n": unresolved_n,
                "playable_unresolved_n": playable_unresolved_n,
                "playable_unresolved_breakdown": playable_unresolved_breakdown,
                "all_unresolved_n": all_unresolved_n,
                "all_unresolved_breakdown": all_unresolved_breakdown,
            }
        )

    merged = _season_betting_card_merge_stats(result_rows)
    merged_playable = _season_betting_card_merge_stats(playable_result_rows)
    merged_all = _season_betting_card_merge_stats(all_result_rows)
    mean_u = None
    median_u = None
    best_day = {}
    worst_day = {}
    if day_profits:
        profits_only = [profit for _, profit in day_profits]
        mean_u = round(sum(profits_only) / len(profits_only), 3)
        sorted_profits = sorted(profits_only)
        mid = len(sorted_profits) // 2
        if len(sorted_profits) % 2:
            median_val = sorted_profits[mid]
        else:
            median_val = (sorted_profits[mid - 1] + sorted_profits[mid]) / 2.0
        median_u = round(median_val, 3)
        best_date, best_profit = max(day_profits, key=lambda item: item[1])
        worst_date, worst_profit = min(day_profits, key=lambda item: item[1])
        best_day = {"date": best_date, "profit_u": round(best_profit, 3)}
        worst_day = {"date": worst_date, "profit_u": round(worst_profit, 3)}

    first_date = day_rows[0]["date"] if day_rows else None
    last_date = day_rows[-1]["date"] if day_rows else None
    months = [{"month": month, "days": count} for month, count in sorted(month_counts.items())]
    payload = _to_jsonable(
        {
            "season": int(season),
            "profile": profile,
            "available_profiles": ["retuned"],
            "meta": {
                "first_date": first_date,
                "last_date": last_date,
                "partial": False,
            },
            "summary": {
                "cards": len(day_rows),
                "results": {"combined": merged},
                "combined": merged,
                "playable_results": {"combined": merged_playable},
                "all_results": {"combined": merged_all},
                "daily": {
                    "mean_u": mean_u,
                    "median_u": median_u,
                    "best_day": best_day,
                    "worst_day": worst_day,
                },
                "selected_counts": total_counts,
                "playable_selected_counts": playable_total_counts,
                "all_selected_counts": all_total_counts,
                "settled_recommendations": int(merged.get("n") or 0),
                "playable_settled_recommendations": int(merged_playable.get("n") or 0),
                "all_settled_recommendations": int(merged_all.get("n") or 0),
                "unresolved_recommendations": unresolved_total,
                "playable_unresolved_recommendations": playable_unresolved_total,
                "playable_unresolved_breakdown": playable_unresolved_breakdown_total,
                "all_unresolved_recommendations": all_unresolved_total,
                "all_unresolved_breakdown": all_unresolved_breakdown_total,
            },
            "months": months,
            "days": day_rows,
        }
    )
    if isinstance(payload, dict):
        _season_betting_card_cache_set(_season_betting_card_manifest_cache, cache_key, payload)
    return payload


@app.route("/api/cards-v2")
def api_cards_v2():
    section = str(request.args.get("section") or "all").strip().lower() or "all"
    if section not in {"all", "games", "props"}:
        return jsonify(
            {
                "error": "unknown cards-v2 section",
                "section": section,
                "allowed": ["all", "games", "props"],
            }
        ), 400

    cards_payload, status_code = _response_json_value(api_cards())
    if status_code and status_code >= 400:
        return jsonify(_to_jsonable(cards_payload or {"error": "failed to build cards-v2"})), status_code
    if not isinstance(cards_payload, dict):
        return jsonify({"error": "failed to build cards-v2"}), 500
    return jsonify(_betting_card_payload_v2(cards_payload, section))


@app.route("/api/season/<int:season>/betting-card")
def api_season_betting_card_manifest(season: int):
    profile = str(request.args.get("profile") or "retuned").strip().lower() or "retuned"
    requested_date = str(request.args.get("date") or "").strip() or None
    return jsonify(_season_betting_card_manifest(season, profile, requested_date=requested_date))


@app.route("/api/season/<int:season>/betting-card/day/<date_str>")
def api_season_betting_card_day(season: int, date_str: str):
    profile = str(request.args.get("profile") or "retuned").strip().lower() or "retuned"
    include_prop_insights = str(request.args.get("include_prop_insights") or "").strip().lower() in {"1", "true", "yes", "on"}
    day_payload = _season_betting_card_day_payload(
        season,
        date_str,
        profile,
        include_prop_insights=include_prop_insights,
    )
    if not isinstance(day_payload, dict):
        return jsonify({"error": "day not found", "date": date_str, "season": season}), 404
    return jsonify(day_payload)


