def _maybe_fetch_remote_processed(fname: str) -> Optional[Path]:
    """Optionally fetch a processed artifact from GitHub raw if missing locally.

    Controlled by env var ALLOW_REMOTE_ARTIFACTS in {"1","true","yes"}.
    Saves to data/processed/<fname> on success and returns that Path.
    """
    try:
        allow = str(os.environ.get("ALLOW_REMOTE_ARTIFACTS", "0")).strip().lower() in {"1", "true", "yes"}
        if not allow:
            return None
        # Only allow safe filenames under processed/
        if not fname or "/" in fname or ".." in fname:
            return None
        out = DATA_PROCESSED_DIR / fname
        if out.exists():
            return out
        repo = os.environ.get("GITHUB_REPOSITORY") or "mostgood1/WNBA-Betting"
        branch = os.environ.get("GIT_BRANCH") or os.environ.get("RENDER_GIT_BRANCH") or "main"
        url = f"https://raw.githubusercontent.com/{repo}/{branch}/data/processed/{fname}"
        try:
            import requests as _rq  # type: ignore
        except Exception:
            return None
        try:
            r = _rq.get(url, timeout=8, headers={
                "User-Agent": "wnba-betting/props-backend",
                "Accept": "text/csv,application/octet-stream,*/*",
            })
            if r.status_code != 200 or not r.content:
                return None
            out.parent.mkdir(parents=True, exist_ok=True)
            with out.open("wb") as f:
                f.write(r.content)
            return out
        except Exception:
            return None
    except Exception:
        return None


def _number(x):
    try:
        if pd.isna(x):
            return None
        v = float(x)
        if not np.isfinite(v):
            return None
        return v
    except Exception:
        return None


def _json_primitive(x):
    """Convert numpy/pandas scalars and datetimes to native JSON-serializable types.

    Strict mode: coerce NaN/Inf to None so JSON is valid (browsers reject NaN/Infinity).
    """
    try:
        # Normalize pandas/NumPy NA first (including plain float('nan'))
        try:
            if x is None:
                return None
            # pandas/NumPy NA detection
            try:
                if pd.isna(x):
                    return None
            except Exception:
                pass
            # Explicitly guard floats for NaN/Inf
            if isinstance(x, float):
                if not np.isfinite(x):
                    return None
                return float(x)
            # NumPy numeric scalars
            if isinstance(x, np.floating):
                xv = float(x)
                if not np.isfinite(xv):
                    return None
                return xv
            if isinstance(x, np.integer):
                return int(x)
        except Exception:
            pass

        # Primitive JSON-safe types
        if isinstance(x, (str, bool, int)):
            return x
        # numpy scalar -> python scalar
        if isinstance(x, np.generic):
            try:
                return x.item()
            except Exception:
                pass
        # datetime-like -> ISO string
        if isinstance(x, (datetime,)):
            try:
                return x.isoformat()
            except Exception:
                return str(x)
        # pandas timestamp
        try:
            import pandas as _pd  # local alias
            if isinstance(x, _pd.Timestamp):
                return x.to_pydatetime().isoformat()
        except Exception:
            pass
        # numpy datetime64
        try:
            if isinstance(x, (np.datetime64,)):
                return str(x)
        except Exception:
            pass
        return x
    except Exception:
        return x


def _to_jsonable(obj):
    """Recursively convert container of dict/list/tuple/numpy/pandas scalars to JSONable primitives."""
    try:
        if isinstance(obj, dict):
            return {str(k): _to_jsonable(v) for k, v in obj.items()}
        if isinstance(obj, (list, tuple, set)):
            return [ _to_jsonable(v) for v in obj ]
        # numpy arrays -> lists
        try:
            if isinstance(obj, np.ndarray):
                return [ _to_jsonable(v) for v in obj.tolist() ]
        except Exception:
            pass
        return _json_primitive(obj)
    except Exception:
        return obj


def _normalize_team_str(x: str) -> str:
    # Best effort normalization: uppercase tricode if given, else strip
    try:
        return str(x).strip()
    except Exception:
        return str(x)


def _implied_prob_american(o: Any) -> Optional[float]:
    try:
        if o is None or (isinstance(o, float) and not np.isfinite(o)):
            return None
        o = float(o)
        if o == 0:
            return None
        if o > 0:
            return 100.0 / (o + 100.0)
        return (-o) / ((-o) + 100.0)
    except Exception:
        return None


def _american_to_b(o: Any) -> Optional[float]:
    try:
        o = float(o)
        return (o / 100.0) if o > 0 else (100.0 / abs(o))
    except Exception:
        return None


def _ev_from_prob_and_american(p: Optional[float], odds: Any) -> Optional[float]:
    if p is None:
        return None
    b = _american_to_b(odds)
    if b is None:
        return None
    try:
        return p * b - (1 - p)
    except Exception:
        return None


def _has_games_for_date(date_str: str, verbose: bool = False) -> bool:
    """Return True if there are league games on the given date.

    Preference order:
    1) nba_api ScoreboardV2 (if available)
    2) Bovada odds feed (if available)
    """
    # First try nba_api ScoreboardV2
    try:
        if _scoreboardv2 is not None:
            sb = _scoreboardv2.ScoreboardV2(game_date=date_str, day_offset=0, timeout=30)
            nd = sb.get_normalized_dict()
            gh = pd.DataFrame(nd.get("GameHeader", []))
            if not gh.empty and len(gh) > 0:
                return True
    except Exception as e:
        if verbose:
            print(f"[_has_games_for_date] scoreboard error: {e}")
    # Fallback to Bovada odds (pass date string for consistency)
    try:
        if _fetch_bovada_odds_current is not None:
            # Prefer passing the canonical YYYY-MM-DD string to avoid timezone/type pitfalls
            o = _fetch_bovada_odds_current(str(date_str), verbose=False)
            if isinstance(o, pd.DataFrame) and not o.empty:
                return True
    except Exception as e:
        if verbose:
            print(f"[_has_games_for_date] bovada error: {e}")
    # Last-resort: check the processed WNBA schedule JSON for this season.
    try:
        sched = _processed_schedule_json_path(date_str)
        if sched.exists():
            sdf = pd.read_json(sched)
            if not sdf.empty:
                if "date_est" in sdf.columns:
                    have = bool(sdf["date_est"].astype(str).str[:10].eq(str(date_str)).sum())
                    if have:
                        return True
                if "date_utc" in sdf.columns:
                    sdf["date_utc"] = pd.to_datetime(sdf["date_utc"], errors="coerce").dt.date.astype(str)
                have = bool((sdf.get("date_utc") == str(date_str)).sum())
                if have:
                    return True
    except Exception:
        pass
    return False


