def _load_refresh_oddsapi_props_meta(*, persist_stale: bool = False) -> dict[str, Any]:
    try:
        meta = _load_cron_meta_snapshot()
        refresh_meta = meta.get("last_refresh_oddsapi_props") if isinstance(meta.get("last_refresh_oddsapi_props"), dict) else {}
        if not isinstance(refresh_meta, dict):
            return {}
        refresh_meta = dict(refresh_meta)
        if persist_stale and _mark_refresh_oddsapi_props_stale(refresh_meta):
            try:
                _cron_meta_update("refresh_oddsapi_props", refresh_meta)
            except Exception:
                pass
        return refresh_meta
    except Exception:
        return {}


def _run_detached_refresh_oddsapi_props_from_env() -> None:
    payload_raw = (os.environ.get("WNBA_BETTING_ODDSAPI_PROPS_JOB") or os.environ.get("NBA_BETTING_ODDSAPI_PROPS_JOB") or "").strip()
    if not payload_raw:
        raise RuntimeError("missing WNBA_BETTING_ODDSAPI_PROPS_JOB payload")
    payload = json.loads(payload_raw)
    _oddsapi_props_refresh_job(
        date_str=str(payload.get("date_str") or ""),
        regions=str(payload.get("regions") or "us"),
        bookmakers=str(payload.get("bookmakers") or ""),
        markets=str(payload.get("markets") or ""),
        do_edges=bool(payload.get("do_edges")),
        do_export=bool(payload.get("do_export")),
        do_push=bool(payload.get("do_push")),
        log_file=Path(str(payload.get("log_file") or "")),
        started_at=str(payload.get("started_at") or ""),
    )


def _launch_refresh_oddsapi_props_detached(
    *,
    date_str: str,
    regions: str,
    bookmakers: str,
    markets: str,
    do_edges: bool,
    do_export: bool,
    do_push: bool,
    log_file: Path,
    started_at: str,
) -> tuple[bool, str | None]:
    try:
        py = _resolve_python()
        env = dict(os.environ)
        existing_pythonpath = str(env.get("PYTHONPATH") or "").strip()
        env["PYTHONPATH"] = str(SRC_DIR) if not existing_pythonpath else f"{SRC_DIR}{os.pathsep}{existing_pythonpath}"
        env.setdefault("PYTHONUNBUFFERED", "1")
        payload = json.dumps({
            "date_str": date_str,
            "regions": regions,
            "bookmakers": bookmakers,
            "markets": markets,
            "do_edges": bool(do_edges),
            "do_export": bool(do_export),
            "do_push": bool(do_push),
            "log_file": str(log_file),
            "started_at": started_at,
        })
        env["WNBA_BETTING_ODDSAPI_PROPS_JOB"] = payload
        env["NBA_BETTING_ODDSAPI_PROPS_JOB"] = payload
        popen_kwargs: dict[str, Any] = {
            "cwd": str(BASE_DIR),
            "env": env,
            "stdin": subprocess.DEVNULL,
            "stderr": subprocess.STDOUT,
            "start_new_session": True,
        }
        if os.name == "nt":
            creationflags = int(getattr(subprocess, "DETACHED_PROCESS", 0)) | int(getattr(subprocess, "CREATE_NEW_PROCESS_GROUP", 0))
            if creationflags:
                popen_kwargs["creationflags"] = creationflags
        log_file.parent.mkdir(parents=True, exist_ok=True)
        with log_file.open("a", encoding="utf-8", errors="ignore") as out:
            out.write(f"[{datetime.utcnow().isoformat(timespec='seconds')}] Launching detached refresh-oddsapi-props process\n")
            out.flush()
            popen_kwargs["stdout"] = out
            launcher = (
                f"import sys; sys.path.insert(0, {str(SRC_DIR)!r}); "
                "from nba_betting.refresh_oddsapi_props_job import main; "
                "raise SystemExit(main())"
            )
            subprocess.Popen(
                [str(py), "-c", launcher],
                **popen_kwargs,
            )
        return True, None
    except Exception as exc:
        return False, str(exc)


def _refresh_oddsapi_props_background_mode() -> str:
    running_on_render = bool(os.getenv("RENDER") or os.getenv("RENDER_EXTERNAL_URL") or os.getenv("RENDER_SERVICE_ID"))
    if running_on_render:
        return "process"
    raw = str(os.environ.get("ODDSAPI_PROPS_BACKGROUND_MODE") or "auto").strip().lower()
    if raw in {"thread", "process", "detached"}:
        return "thread" if raw == "thread" else "process"
    return "process"


def _launch_refresh_oddsapi_props_background(
    *,
    date_str: str,
    regions: str,
    bookmakers: str,
    markets: str,
    do_edges: bool,
    do_export: bool,
    do_push: bool,
    log_file: Path,
    started_at: str,
) -> tuple[bool, str | None, str]:
    mode = _refresh_oddsapi_props_background_mode()
    if mode == "thread":
        try:
            log_file.parent.mkdir(parents=True, exist_ok=True)
            with log_file.open("a", encoding="utf-8", errors="ignore") as out:
                out.write(f"[{datetime.utcnow().isoformat(timespec='seconds')}] Launching threaded refresh-oddsapi-props worker\n")
                out.flush()

            def _job() -> None:
                try:
                    from nba_betting.refresh_oddsapi_props_job import run_refresh_oddsapi_props_job

                    run_refresh_oddsapi_props_job(
                        date_str=date_str,
                        regions=regions,
                        bookmakers=bookmakers,
                        markets=markets,
                        do_edges=bool(do_edges),
                        do_export=bool(do_export),
                        do_push=bool(do_push),
                        log_file=log_file,
                        started_at=started_at or None,
                    )
                except Exception as exc:
                    try:
                        with log_file.open("a", encoding="utf-8", errors="ignore") as out:
                            out.write(f"[{datetime.utcnow().isoformat(timespec='seconds')}] Threaded refresh worker failed: {type(exc).__name__}: {exc}\n")
                            out.write(traceback.format_exc(limit=25) + "\n")
                    except Exception:
                        pass

            thread = threading.Thread(
                target=_job,
                name=f"refresh-oddsapi-props-{date_str}",
                daemon=True,
            )
            thread.start()
            return True, None, mode
        except Exception as exc:
            return False, str(exc), mode

    launched, launch_error = _launch_refresh_oddsapi_props_detached(
        date_str=date_str,
        regions=regions,
        bookmakers=bookmakers,
        markets=markets,
        do_edges=bool(do_edges),
        do_export=bool(do_export),
        do_push=bool(do_push),
        log_file=log_file,
        started_at=started_at,
    )
    return launched, launch_error, mode


def _active_player_logs_paths() -> list[Path]:
    return [
        DATA_PROCESSED_DIR / "player_logs.parquet",
        DATA_PROCESSED_DIR / "player_logs.csv",
    ]


def _file_is_fresh(path: Path, *, max_age_minutes: int) -> bool:
    try:
        if not path.exists() or path.stat().st_size <= 0:
            return False
        if path.suffix.lower() == ".csv":
            if _count_csv_rows_quick(path) <= 0:
                return False
        elif path.suffix.lower() == ".parquet":
            df = pd.read_parquet(path)
            if not isinstance(df, pd.DataFrame) or df.empty:
                return False
        if max_age_minutes <= 0:
            return True
        age_s = max(0.0, time.time() - float(path.stat().st_mtime))
        return age_s <= (float(max_age_minutes) * 60.0)
    except Exception:
        return False


def _player_logs_artifact_exists_with_rows(path: Path) -> bool:
    try:
        if not path.exists() or path.stat().st_size <= 0:
            return False
        if path.suffix.lower() == ".csv":
            return _count_csv_rows_quick(path) > 0
        if path.suffix.lower() == ".parquet":
            df = pd.read_parquet(path)
            return isinstance(df, pd.DataFrame) and not df.empty
        return True
    except Exception:
        return False


def _player_logs_ready(*, max_age_minutes: int) -> bool:
    for path in _active_player_logs_paths():
        if _file_is_fresh(path, max_age_minutes=max_age_minutes):
            return True
    return False


def _ensure_player_logs_for_props_refresh(
    *,
    date_str: str,
    py: str,
    env: dict[str, str],
    log_file: Path,
) -> tuple[bool, str | None]:
    raw_max_age = (os.environ.get("REFRESH_PLAYER_LOGS_MAX_AGE_HOURS") or os.environ.get("DAILY_PLAYER_LOGS_MAX_AGE_HOURS") or "12").strip()
    try:
        max_age_minutes = int(max(0.0, float(raw_max_age) * 60.0))
    except Exception:
        max_age_minutes = 12 * 60

    if _player_logs_ready(max_age_minutes=max_age_minutes):
        return True, None

    # On Render, a full fetch-player-logs run can be expensive enough to destabilize
    # the web process. If any prior player_logs artifact already exists, accept it even
    # if it is older than the freshness target.
    if any(_player_logs_artifact_exists_with_rows(path) for path in _active_player_logs_paths()):
        return True, None

    allow_fetch_on_miss = (os.environ.get("REFRESH_PLAYER_LOGS_FETCH_ON_MISS") or "0").strip().lower() in {"1", "true", "yes"}
    if not allow_fetch_on_miss:
        return False, "player_logs not found; run fetch-player-logs"

    season_str = _season_str_from_year(_season_year_for_date(date_str))
    rc_logs = _run_to_file(
        [str(py), "-m", "nba_betting.cli", "fetch-player-logs", "--seasons", season_str],
        log_file,
        cwd=BASE_DIR,
        env=env,
        timeout_s=15 * 60,
    )
    if int(rc_logs) != 0:
        return False, f"fetch-player-logs failed with exit code {int(rc_logs)}"
    if not any(_player_logs_artifact_exists_with_rows(path) for path in _active_player_logs_paths()):
        return False, "player_logs missing after fetch-player-logs"
    return True, None


def _oddsapi_props_refresh_job(
    *,
    date_str: str,
    regions: str,
    bookmakers: str,
    markets: str,
    do_edges: bool,
    do_export: bool,
    do_push: bool,
    log_file: Path,
    started_at: str | None = None,
) -> None:
    """Background job for refresh-oddsapi-props.

    Runs the same subprocess steps as the synchronous endpoint, but out-of-band so
    the HTTP request can return quickly (avoid proxy/gunicorn timeouts).
    """
    _prime_oddsapi_props_job_state(
        date_str=date_str,
        regions=regions,
        bookmakers=bookmakers,
        markets=markets,
        do_edges=do_edges,
        do_export=do_export,
        do_push=do_push,
        log_file=log_file,
        running=True,
        started_at=started_at,
    )

    try:
        started = time.time()
        py = _resolve_python()
        env = dict(os.environ)
        env["PYTHONPATH"] = str(SRC_DIR)
        run_edges = bool(do_edges)
        run_export = bool(do_export)

        try:
            from nba_betting.config import paths as _paths  # type: ignore

            raw_fp = _paths.data_raw / f"odds_nba_player_props_{date_str}.csv"
            edges_fp = _paths.data_processed / f"props_edges_{date_str}.csv"
            rec_fp = _paths.data_processed / f"props_recommendations_{date_str}.csv"
        except Exception:
            raw_fp = DATA_RAW_DIR / f"odds_nba_player_props_{date_str}.csv"
            edges_fp = DATA_PROCESSED_DIR / f"props_edges_{date_str}.csv"
            rec_fp = DATA_PROCESSED_DIR / f"props_recommendations_{date_str}.csv"

        _oddsapi_props_job_state["snapshot_path"] = str(raw_fp)
        _oddsapi_props_job_state["edges_path"] = str(edges_fp)
        _oddsapi_props_job_state["recs_path"] = str(rec_fp)

        def _persist_progress(*, running: bool = True, ok: bool | None = None, error: str | None = None) -> None:
            try:
                payload = {
                    "date": date_str,
                    "regions": regions,
                    "bookmakers": (bookmakers or None),
                    "markets": markets,
                    "run_edges": bool(do_edges),
                    "run_export": bool(do_export),
                    "run_push": bool(do_push),
                    "running": bool(running),
                    "ok": ok,
                    "log_file": str(log_file),
                    "started_at": _oddsapi_props_job_state.get("started_at"),
                    "ended_at": _oddsapi_props_job_state.get("ended_at"),
                    "phase": _oddsapi_props_job_state.get("phase"),
                    "phase_started_at": _oddsapi_props_job_state.get("phase_started_at"),
                    "heartbeat_at": _oddsapi_props_job_state.get("heartbeat_at"),
                    "rc_snapshot": _oddsapi_props_job_state.get("rc_snapshot"),
                    "rc_edges": _oddsapi_props_job_state.get("rc_edges"),
                    "rc_export": _oddsapi_props_job_state.get("rc_export"),
                    "snapshot_rows": _oddsapi_props_job_state.get("snapshot_rows"),
                    "edges_rows": _oddsapi_props_job_state.get("edges_rows"),
                    "recs_rows": _oddsapi_props_job_state.get("recs_rows"),
                    "snapshot": _oddsapi_props_job_state.get("snapshot_path"),
                    "snapshot_path": _oddsapi_props_job_state.get("snapshot_path"),
                    "edges": _oddsapi_props_job_state.get("edges_path"),
                    "edges_path": _oddsapi_props_job_state.get("edges_path"),
                    "recs": _oddsapi_props_job_state.get("recs_path"),
                    "recs_path": _oddsapi_props_job_state.get("recs_path"),
                    "duration_s": _oddsapi_props_job_state.get("duration_s"),
                }
                if error:
                    payload["error"] = error
                elif _oddsapi_props_job_state.get("error"):
                    payload["error"] = _oddsapi_props_job_state.get("error")
                _cron_meta_update("refresh_oddsapi_props", payload)
            except Exception:
                pass

        def _touch_progress() -> None:
            _oddsapi_props_job_state["heartbeat_at"] = datetime.utcnow().isoformat()
            _persist_progress(running=True, ok=None, error=_oddsapi_props_job_state.get("error"))

        _persist_progress(running=True, ok=None)

        # 1) Snapshot player props to data/raw
        snap_cmd = [str(py), "-m", "nba_betting.cli", "odds-snapshots-props", "--date", date_str, "--regions", regions]
        if bookmakers:
            snap_cmd += ["--bookmakers", bookmakers]
        if markets:
            snap_cmd += ["--markets", markets]
        rc_snap = _run_to_file(snap_cmd, log_file, cwd=BASE_DIR, env=env, timeout_s=15 * 60, heartbeat_cb=_touch_progress)
        _oddsapi_props_job_state["heartbeat_at"] = datetime.utcnow().isoformat()
        _oddsapi_props_job_state["rc_snapshot"] = int(rc_snap)
        _oddsapi_props_job_state["snapshot_rows"] = int(_count_csv_rows_quick(raw_fp))
        if int(_oddsapi_props_job_state["snapshot_rows"] or 0) <= 0:
            run_edges = False
            run_export = False
            _oddsapi_props_job_state["rc_edges"] = None if do_edges else _oddsapi_props_job_state.get("rc_edges")
            _oddsapi_props_job_state["rc_export"] = None if do_export else _oddsapi_props_job_state.get("rc_export")
            _oddsapi_props_job_state["phase"] = "finalizing"
            _oddsapi_props_job_state["phase_started_at"] = datetime.utcnow().isoformat()
        elif run_edges:
            _oddsapi_props_job_state["phase"] = "edges"
            _oddsapi_props_job_state["phase_started_at"] = datetime.utcnow().isoformat()
            _oddsapi_props_job_state["rc_edges"] = -1
        elif run_export:
            _oddsapi_props_job_state["phase"] = "export"
            _oddsapi_props_job_state["phase_started_at"] = datetime.utcnow().isoformat()
            _oddsapi_props_job_state["rc_export"] = -1
        else:
            _oddsapi_props_job_state["phase"] = "finalizing"
            _oddsapi_props_job_state["phase_started_at"] = datetime.utcnow().isoformat()
        _persist_progress(running=True, ok=None)

        # 2) Optionally compute props edges from OddsAPI
        rc_edges = None
        if run_edges:
            player_logs_ok, player_logs_error = _ensure_player_logs_for_props_refresh(
                date_str=date_str,
                py=str(py),
                env=env,
                log_file=log_file,
            )
            _oddsapi_props_job_state["heartbeat_at"] = datetime.utcnow().isoformat()
            if not player_logs_ok:
                rc_edges = 1
                run_export = False
                _oddsapi_props_job_state["rc_edges"] = int(rc_edges)
                _oddsapi_props_job_state["rc_export"] = None if do_export else _oddsapi_props_job_state.get("rc_export")
                _oddsapi_props_job_state["error"] = player_logs_error
                _oddsapi_props_job_state["phase"] = "finalizing"
                _oddsapi_props_job_state["phase_started_at"] = datetime.utcnow().isoformat()
                _persist_progress(running=True, ok=None, error=player_logs_error)
            else:
                edges_cmd = [str(py), "-m", "nba_betting.cli", "props-edges", "--date", date_str, "--source", "oddsapi", "--mode", "current"]
                if bookmakers:
                    edges_cmd += ["--bookmakers", bookmakers]
                rc_edges = _run_to_file(edges_cmd, log_file, cwd=BASE_DIR, env=env, timeout_s=20 * 60, heartbeat_cb=_touch_progress)
                _oddsapi_props_job_state["heartbeat_at"] = datetime.utcnow().isoformat()
                _oddsapi_props_job_state["rc_edges"] = int(rc_edges)
                _oddsapi_props_job_state["edges_rows"] = int(_count_csv_rows_quick(edges_fp))
                if int(rc_edges) != 0:
                    run_export = False
                    _oddsapi_props_job_state["rc_export"] = None if do_export else _oddsapi_props_job_state.get("rc_export")
                    _oddsapi_props_job_state["error"] = f"props-edges failed with exit code {int(rc_edges)}"
                elif int(_oddsapi_props_job_state["snapshot_rows"] or 0) > 0 and int(_oddsapi_props_job_state["edges_rows"] or 0) <= 0:
                    run_export = False
                    _oddsapi_props_job_state["rc_export"] = None if do_export else _oddsapi_props_job_state.get("rc_export")
                    _oddsapi_props_job_state["error"] = "props-edges produced zero rows after a non-empty snapshot"
                if run_export:
                    _oddsapi_props_job_state["phase"] = "export"
                    _oddsapi_props_job_state["phase_started_at"] = datetime.utcnow().isoformat()
                    _oddsapi_props_job_state["rc_export"] = -1
                else:
                    _oddsapi_props_job_state["phase"] = "finalizing"
                    _oddsapi_props_job_state["phase_started_at"] = datetime.utcnow().isoformat()
                _persist_progress(running=True, ok=None, error=_oddsapi_props_job_state.get("error"))

        # 3) Optionally export props recommendations
        rc_export = None
        if run_export:
            export_cmd = [str(py), "-m", "nba_betting.cli", "export-props-recommendations", "--date", date_str]
            rc_export = _run_to_file(export_cmd, log_file, cwd=BASE_DIR, env=env, timeout_s=10 * 60, heartbeat_cb=_touch_progress)
            _oddsapi_props_job_state["heartbeat_at"] = datetime.utcnow().isoformat()
            _oddsapi_props_job_state["rc_export"] = int(rc_export)
            _oddsapi_props_job_state["recs_rows"] = int(_count_csv_rows_quick(rec_fp))
            _oddsapi_props_job_state["phase"] = "finalizing"
            _oddsapi_props_job_state["phase_started_at"] = datetime.utcnow().isoformat()
            _persist_progress(running=True, ok=None, error=_oddsapi_props_job_state.get("error"))

        snap_rows = _count_csv_rows_quick(raw_fp)
        edges_rows = _count_csv_rows_quick(edges_fp)
        rec_rows = _count_csv_rows_quick(rec_fp)
        _oddsapi_props_job_state["snapshot_rows"] = int(snap_rows)
        _oddsapi_props_job_state["edges_rows"] = int(edges_rows)
        _oddsapi_props_job_state["recs_rows"] = int(rec_rows)
        _oddsapi_props_job_state["snapshot_path"] = str(raw_fp)
        _oddsapi_props_job_state["edges_path"] = str(edges_fp)
        _oddsapi_props_job_state["recs_path"] = str(rec_fp)

        if run_edges and int(snap_rows) > 0 and int(edges_rows) <= 0 and not _oddsapi_props_job_state.get("error"):
            _oddsapi_props_job_state["error"] = "props-edges produced zero rows after a non-empty snapshot"

        ok = (int(rc_snap) == 0) and (rc_edges in (None, 0)) and (rc_export in (None, 0)) and not bool(_oddsapi_props_job_state.get("error"))
        ended = time.time()
        _oddsapi_props_job_state["phase"] = "done"
        _oddsapi_props_job_state["phase_started_at"] = datetime.utcnow().isoformat()
        _oddsapi_props_job_state["heartbeat_at"] = datetime.utcnow().isoformat()
        _oddsapi_props_job_state["duration_s"] = float(max(0.0, ended - started))
        _oddsapi_props_job_state["ok"] = bool(ok)
        _persist_progress(running=False, ok=bool(ok), error=_oddsapi_props_job_state.get("error"))

        # Cron meta best-effort
        try:
            _cron_meta_update(
                "refresh_oddsapi_props",
                {
                    "date": date_str,
                    "regions": regions,
                    "bookmakers": (bookmakers or None),
                    "markets": markets,
                    "run_edges": bool(run_edges),
                    "run_export": bool(run_export),
                    "run_push": bool(do_push),
                    "running": False,
                    "ok": bool(ok),
                    "rc_snapshot": int(rc_snap),
                    "snapshot_rows": int(snap_rows),
                    "snapshot": str(raw_fp),
                    "rc_edges": (int(rc_edges) if rc_edges is not None else None),
                    "edges_rows": int(edges_rows),
                    "edges": str(edges_fp),
                    "rc_export": (int(rc_export) if rc_export is not None else None),
                    "recs_rows": int(rec_rows),
                    "recs": str(rec_fp),
                    "log_file": str(log_file),
                    "started_at": _oddsapi_props_job_state.get("started_at"),
                    "ended_at": datetime.utcnow().isoformat(),
                    "duration_s": _oddsapi_props_job_state.get("duration_s"),
                    "error": _oddsapi_props_job_state.get("error"),
                },
            )
        except Exception:
            pass

        if do_push:
            try:
                _ = _git_commit_and_push(msg=f"refresh-oddsapi-props {date_str}")
            except Exception:
                pass

    except Exception as e:
        _oddsapi_props_job_state["phase"] = "failed"
        _oddsapi_props_job_state["phase_started_at"] = datetime.utcnow().isoformat()
        _oddsapi_props_job_state["heartbeat_at"] = datetime.utcnow().isoformat()
        _oddsapi_props_job_state["ok"] = False
        _oddsapi_props_job_state["error"] = f"{type(e).__name__}: {e}"
        tb = traceback.format_exc(limit=25)
        try:
            with Path(log_file).open("a", encoding="utf-8", errors="ignore") as out:
                out.write(f"[{datetime.utcnow().isoformat(timespec='seconds')}] Exception: {type(e).__name__}: {e}\n")
                out.write(tb + "\n")
        except Exception:
            pass
        try:
            _persist_progress(running=False, ok=False, error=f"{type(e).__name__}: {e}")
            _cron_meta_update(
                "refresh_oddsapi_props",
                {
                    "date": date_str,
                    "regions": regions,
                    "bookmakers": (bookmakers or None),
                    "markets": markets,
                    "run_edges": bool(do_edges),
                    "run_export": bool(do_export),
                    "run_push": bool(do_push),
                    "running": False,
                    "ok": False,
                    "error": f"{type(e).__name__}: {e}",
                    "log_file": str(log_file),
                    "started_at": _oddsapi_props_job_state.get("started_at"),
                    "ended_at": datetime.utcnow().isoformat(),
                },
            )
        except Exception:
            pass
    finally:
        _oddsapi_props_job_state["ended_at"] = datetime.utcnow().isoformat()
        _oddsapi_props_job_state["running"] = False


def _tail_text_file(fp: Path, *, max_lines: int = 200, max_bytes: int = 64_000) -> list[str]:
    """Best-effort tail of a UTF-8-ish log file without reading the whole thing."""
    try:
        if max_lines <= 0:
            return []
        if not fp.exists():
            return []
        size = fp.stat().st_size
        start = int(max(0, size - int(max_bytes)))
        with fp.open("rb") as f:
            f.seek(start)
            chunk = f.read()
        text = chunk.decode("utf-8", errors="ignore")
        lines = text.splitlines()
        if len(lines) > max_lines:
            lines = lines[-max_lines:]
        return [str(x) for x in lines]
    except Exception:
        return []


def _append_log(line: str) -> None:
    try:
        ts = datetime.utcnow().isoformat(timespec="seconds")
        msg = f"[{ts}] {line.rstrip()}"
        _job_state["logs"].append(msg)
        if len(_job_state["logs"]) > 1000:
            del _job_state["logs"][:-500]
        try:
            lf = _job_state.get("log_file")
            if lf:
                with open(lf, "a", encoding="utf-8", errors="ignore") as f:
                    f.write(msg + "\n")
        except Exception:
            pass
    except Exception:
        pass


def _ensure_logs_dir() -> Path:
    """Return a writable logs directory.

    Prefer the persistent data disk when configured (Render), then repo-local
    logs/ for local development, then /tmp.
    """
    candidates: list[Path] = []
    try:
        candidates.append(DATA_DIR / "logs")
    except Exception:
        pass
    try:
        candidates.append(BASE_DIR / "logs")
    except Exception:
        pass
    try:
        candidates.append(Path("/tmp") / "nba_betting_logs")
    except Exception:
        pass

    for p in candidates:
        try:
            p.mkdir(parents=True, exist_ok=True)
            # Verify we can write a small file.
            test_fp = p / ".write_test"
            test_fp.write_text("ok", encoding="utf-8")
            try:
                test_fp.unlink(missing_ok=True)  # type: ignore[arg-type]
            except Exception:
                try:
                    if test_fp.exists():
                        test_fp.unlink()
                except Exception:
                    pass
            return p
        except Exception:
            continue

    # Last resort: return BASE_DIR even if unwritable (callers should handle failures).
    return BASE_DIR


def _count_csv_rows_quick(p: Optional[Path]) -> int:
    """Return number of data rows in a CSV quickly without loading via pandas.

    Counts newline characters and subtracts 1 for header if present. Returns 0 on error.
    """
    try:
        if not p or (not p.exists()) or (not p.is_file()):
            return 0
        # Fast newline count in chunks
        nl = 0
        with p.open('rb') as f:
            while True:
                chunk = f.read(1024 * 1024)
                if not chunk:
                    break
                nl += chunk.count(b"\n")
        # If file has at least one line, subtract header
        return max(0, nl - 1)
    except Exception:
        return 0


def _count_props_recommendation_play_rows(p: Optional[Path]) -> int:
    try:
        if not p or (not p.exists()) or (not p.is_file()):
            return 0
        import ast
        import csv as _csv

        def _parse_obj(raw: object) -> object:
            if isinstance(raw, (list, dict)):
                return raw
            s = str(raw or "").strip()
            if not s or s.lower() in {"nan", "none", "null"}:
                return None
            try:
                return json.loads(s)
            except Exception:
                try:
                    return ast.literal_eval(s)
                except Exception:
                    return None

        rows = 0
        with p.open("r", encoding="utf-8", newline="") as handle:
            reader = _csv.DictReader(handle)
            if not reader.fieldnames:
                return 0
            plays_col = next((name for name in reader.fieldnames if str(name).strip().lower() == "plays"), None)
            if not plays_col:
                return 0
            for row in reader:
                plays = _parse_obj((row or {}).get(plays_col))
                if isinstance(plays, list) and plays:
                    rows += 1
        return int(rows)
    except Exception:
        return 0


def _prune_invalid_props_recommendations_artifact(
    edges_path: Optional[Path],
    recommendations_path: Optional[Path],
    log_cb=None,
) -> bool:
    try:
        if int(_count_csv_rows_quick(edges_path) or 0) > 0:
            return False
        if not recommendations_path or (not recommendations_path.exists()) or (not recommendations_path.is_file()):
            return False
        if int(_count_csv_rows_quick(recommendations_path) or 0) <= 0:
            return False
        playable_rows = int(_count_props_recommendation_play_rows(recommendations_path) or 0)
        if playable_rows > 0:
            if callable(log_cb):
                log_cb(
                    f"Preserving existing same-day line-bearing props recommendations despite missing props_edges (playable_rows={playable_rows})."
                )
            return False
        recommendations_path.unlink(missing_ok=True)
        if callable(log_cb):
            log_cb(
                "Removed same-day props recommendations because props_edges is missing/empty and the artifact only contained model-only cards."
            )
        return True
    except Exception as exc:
        if callable(log_cb):
            log_cb(f"Failed to prune invalid props recommendations artifact: {exc}")
        return False


def _find_fallback_odds_for_date(date_str: str) -> Optional[Path]:
    """Return best available non-Bovada odds file for the given date, if any.

    Preference order:
      1) closing_lines_{date}.csv
      2) odds_{date}.csv
      3) market_{date}.csv
    """
    candidates = [
        DATA_PROCESSED_DIR / f"closing_lines_{date_str}.csv",
        DATA_PROCESSED_DIR / f"odds_{date_str}.csv",
        DATA_PROCESSED_DIR / f"market_{date_str}.csv",
    ]
    for p in candidates:
        try:
            if p.exists() and p.is_file():
                return p
        except Exception:
            continue
    return None


def _git_commit_and_push(msg: str) -> tuple[bool, str]:
    """Commit and push changes to the current branch.

    Auth methods:
    - GH_TOKEN or GIT_PAT env: used to set a push URL for 'origin' without altering fetch URL.
    - GH_NAME/GH_EMAIL env: configure git user identity.
    Returns (ok, detail).
    """
    try:
        managed_force_add_patterns = [
            "data/processed/cards_props_snapshot_*.json",
            "data/processed/cards_sim_detail_*.json",
            "data/processed/games_predictions_*.json",
            "data/processed/recommendations_slate_*.json",
            "data/processed/props_recommendations_top_by_game_*.json",
            "data/processed/smart_sim_*.json",
            "data/processed/master_data_*.json",
            "data/processed/master_data_latest.json",
            "data/processed/league_status_*.csv",
            "data/processed/pregame_expected_minutes_*.csv",
            "data/processed/smartsim_player_scenarios_*.csv",
            "data/processed/oddsapi_player_props_*.csv",
        ]
        env = {**os.environ}
        # Configure identity if provided
        name = os.environ.get("GH_NAME") or os.environ.get("GIT_NAME")
        email = os.environ.get("GH_EMAIL") or os.environ.get("GIT_EMAIL") or "github-actions[bot]@users.noreply.github.com"
        if name:
            subprocess.run(["git", "config", "user.name", name], cwd=str(BASE_DIR), check=False)
        if email:
            subprocess.run(["git", "config", "user.email", email], cwd=str(BASE_DIR), check=False)
        # Determine current branch (detached HEAD -> use env/default)
        try:
            branch = subprocess.check_output(["git", "rev-parse", "--abbrev-ref", "HEAD"], cwd=str(BASE_DIR), text=True).strip()
        except Exception:
            branch = "HEAD"
        if not branch or branch == "HEAD":
            branch = os.environ.get("GIT_BRANCH", "main")
        # Set push URL with token if present (support multiple env var names)
        token = (
            os.environ.get("GH_TOKEN")
            or os.environ.get("GIT_PAT")
            or os.environ.get("GITHUB_TOKEN")
            or os.environ.get("GH")
        )
        push_url_set = False
        origin = None
        if token:
            try:
                origin = subprocess.check_output(["git", "remote", "get-url", "origin"], cwd=str(BASE_DIR), text=True).strip()
            except Exception:
                origin = None
            try:
                # If origin missing, try to add it from environment
                if not origin:
                    # Prefer GIT_REMOTE_URL, else construct from GITHUB_REPOSITORY; finally project-specific default
                    env_url = os.environ.get("GIT_REMOTE_URL") or None
                    if not env_url:
                        gh_repo = os.environ.get("GITHUB_REPOSITORY")  # e.g., owner/repo
                        if gh_repo and "/" in gh_repo:
                            env_url = f"https://github.com/{gh_repo}.git"
                    # Project-specific fallback (safe for this deployment)
                    if not env_url:
                        env_url = "https://github.com/mostgood1/WNBA-Betting.git"
                    if env_url:
                        subprocess.run(["git", "remote", "add", "origin", env_url], cwd=str(BASE_DIR), check=False)
                        origin = env_url
                url = origin or ""
                # Normalize SSH origin to HTTPS for token auth
                # e.g., git@github.com:owner/repo.git -> https://github.com/owner/repo.git
                if url.startswith("git@github.com:"):
                    path = url.split(":", 1)[1]
                    if not path.endswith(".git"):
                        path += ".git"
                    url = f"https://github.com/{path}"
                elif url.startswith("ssh://git@github.com/"):
                    path = url.split("github.com/", 1)[1]
                    if not path.endswith(".git"):
                        path += ".git"
                    url = f"https://github.com/{path}"
                elif url.startswith("https://"):
                    # already https
                    url = url
                # Embed token if https and not already credentialed
                if url.startswith("https://"):
                    # Strip any existing creds
                    without_scheme = url[len("https://"):]
                    if "@" in without_scheme:
                        without_scheme = without_scheme.split("@", 1)[1]
                    # Use a safe username for token auth
                    gh_user = (
                        os.environ.get("GH_USERNAME")
                        or os.environ.get("GH_NAME")
                        or os.environ.get("GIT_NAME")
                        or "x-access-token"
                    )
                    tokenized = f"https://{gh_user}:{token}@{without_scheme}"
                    try:
                        # Set both fetch and push URLs to ensure pulls work on private repos
                        subprocess.run(["git", "remote", "set-url", "origin", tokenized], cwd=str(BASE_DIR), check=False)
                        subprocess.run(["git", "remote", "set-url", "--push", "origin", tokenized], cwd=str(BASE_DIR), check=False)
                        push_url_set = True
                    except Exception:
                        push_url_set = False
            except Exception:
                push_url_set = False
        # Stage only data artifacts to avoid committing runtime files or secrets
        try:
            subprocess.run(["git", "add", "data/processed"], cwd=str(BASE_DIR), check=False)
            for pattern in managed_force_add_patterns:
                for artifact in BASE_DIR.glob(pattern):
                    if artifact.is_file():
                        subprocess.run([
                            "git",
                            "add",
                            "-f",
                            str(artifact.relative_to(BASE_DIR)),
                        ], cwd=str(BASE_DIR), check=False)
            # Legacy root CSVs
            for pat in ("predictions_*.csv", "props_*.csv", "recon_*.csv"):
                subprocess.run(["bash", "-lc", f"git add -- {pat} 2>/dev/null || true"], cwd=str(BASE_DIR), check=False)
        except Exception:
            # Fallback to add -A only if selective add failed
            subprocess.run(["git", "add", "-A"], cwd=str(BASE_DIR), check=False)
        # Commit (allow empty to create a heartbeat commit if needed)
        subprocess.run(["git", "commit", "-m", msg, "--allow-empty"], cwd=str(BASE_DIR), check=False)
        # Optional pull --rebase only if on a real branch and remote exists
        try:
            if origin and branch and branch not in ("HEAD", ""):
                subprocess.run(["git", "pull", "--rebase", "origin", branch], cwd=str(BASE_DIR), check=False)
        except Exception:
            pass
        # Push if we have a remote
        ok = False
        if origin:
            rc_main = subprocess.run([
                "git", "push", "origin", f"HEAD:{branch}"
            ], cwd=str(BASE_DIR), check=False, capture_output=True, text=True)
            if rc_main.returncode == 0:
                ok = True
                detail = (
                    f"pushed to {branch}; remote={'ok' if bool(origin) else 'missing'}; "
                    f"push_url={'set' if push_url_set else 'default'}; rc_main={rc_main.returncode}"
                )
            else:
                # Fallback: push to an artifacts branch (for repos with protected main)
                alt_branch = os.environ.get("GIT_BRANCH_ALT", "data-artifacts")
                rc_alt = subprocess.run([
                    "git", "push", "origin", f"HEAD:{alt_branch}"
                ], cwd=str(BASE_DIR), check=False, capture_output=True, text=True)
                ok = (rc_alt.returncode == 0)
                # Heuristic error hint
                stderr_all = (rc_main.stderr or "") + "\n" + (rc_alt.stderr or "")
                hint = ""
                low = stderr_all.lower()
                if any(x in low for x in ["permission", "denied", "auth", "forbidden", "not allowed", "sso", "requires authentication"]):
                    hint = "; hint=auth/permission-denied-or-sso"
                if any(x in low for x in ["protected branch", "gh006", "pre-receive hook declined", "require signed commits", "status checks"]):
                    hint += "; hint=branch-protection"
                if any(x in low for x in ["non-fast-forward", "fetch first", "update rejected"]):
                    hint += "; hint=non-fast-forward (pull --rebase needed)"
                # Truncate stderr to last few lines for context
                lines = [ln for ln in (stderr_all.strip().splitlines() or [""]) if ln.strip()]
                err_snip = "\n".join(lines[-3:])[:500]
                detail = (
                    f"pushed to {branch if rc_main.returncode==0 else alt_branch} (fallback={'yes' if rc_main.returncode!=0 else 'no'}); "
                    f"remote={'ok' if bool(origin) else 'missing'}; push_url={'set' if push_url_set else 'default'}; "
                    f"rc_main={rc_main.returncode}; rc_alt={(rc_alt.returncode if 'rc_alt' in locals() else 'n/a')}{hint}; err='{err_snip}'"
                )
        else:
            detail = f"pushed to {branch}; remote=missing; push_url={'set' if push_url_set else 'default'}"
        return ok, detail
    except Exception as e:
        return False, f"git push error: {e}"


@app.route("/api/cron/git-diag", methods=["POST", "GET"])
def api_cron_git_diag():
    """Return git diagnostics to help debug push issues.

    Requires CRON_TOKEN or admin fallback. Does not expose secrets.
    """
    if not _debug_routes_enabled():
        return jsonify({"error": "disabled"}), 404
    if not _cron_auth_ok(request):
        return jsonify({"error": "unauthorized"}), 401
    def _safe_run(cmd: list[str]) -> str:
        try:
            out = subprocess.check_output(cmd, cwd=str(BASE_DIR), text=True, stderr=subprocess.STDOUT)
            return out.strip()
        except Exception as e:
            return f"(error running {' '.join(cmd)}: {e})"
    data = {
        "have_gh_token": bool(os.environ.get("GH_TOKEN") or os.environ.get("GIT_PAT") or os.environ.get("GITHUB_TOKEN") or os.environ.get("GH")),
        "gh_name": os.environ.get("GH_NAME") or os.environ.get("GIT_NAME"),
        "gh_email": os.environ.get("GH_EMAIL") or os.environ.get("GIT_EMAIL"),
        "git_branch": _safe_run(["git", "rev-parse", "--abbrev-ref", "HEAD"]),
        "git_head": _safe_run(["git", "rev-parse", "HEAD"]),
        "remote_v": _safe_run(["git", "remote", "-v"]).splitlines()[-4:],
        "status": _safe_run(["git", "status", "-sb"]).splitlines()[:10],
        "branch_vv": _safe_run(["git", "branch", "-vv"]).splitlines()[-10:],
        "ls_remote_heads": _safe_run(["git", "ls-remote", "--heads", "origin"]).splitlines()[-10:],
    }
    return jsonify(data)


def _run_to_file(
    cmd: list[str] | str,
    log_fp: Path,
    cwd: Path | None = None,
    env: dict | None = None,
    timeout_s: int | None = None,
    heartbeat_cb: Callable[[], None] | None = None,
    heartbeat_every_s: int = 15,
) -> int:
    if isinstance(cmd, list):
        popen_cmd = cmd
    else:
        popen_cmd = shlex.split(cmd)
    with log_fp.open("a", encoding="utf-8", errors="ignore") as out:
        out.write(f"[{datetime.utcnow().isoformat(timespec='seconds')}] Starting: {' '.join(popen_cmd)}\n")
        out.flush()
        proc = subprocess.Popen(
            popen_cmd,
            cwd=str(cwd) if cwd else None,
            env={**os.environ, **(env or {})},
            stdout=out,
            stderr=subprocess.STDOUT,
            text=True,
            bufsize=1,
            universal_newlines=True,
        )
        started_wait = time.monotonic()
        try:
            while True:
                try:
                    if heartbeat_cb:
                        wait_timeout = float(max(1, int(heartbeat_every_s)))
                        if timeout_s is not None:
                            remaining = float(timeout_s) - (time.monotonic() - started_wait)
                            if remaining <= 0:
                                raise subprocess.TimeoutExpired(popen_cmd, timeout_s)
                            wait_timeout = min(wait_timeout, remaining)
                        proc.wait(timeout=wait_timeout)
                    elif timeout_s is not None:
                        proc.wait(timeout=timeout_s)
                    else:
                        proc.wait()
                    break
                except subprocess.TimeoutExpired:
                    elapsed = time.monotonic() - started_wait
                    if heartbeat_cb and (timeout_s is None or elapsed < float(timeout_s)):
                        try:
                            heartbeat_cb()
                        except Exception:
                            pass
                        continue
                    raise
        except subprocess.TimeoutExpired:
            try:
                out.write(f"[{datetime.utcnow().isoformat(timespec='seconds')}] Timeout after {timeout_s}s; terminating...\n")
                out.flush()
            except Exception:
                pass
            try:
                proc.terminate()
            except Exception:
                pass
            try:
                proc.wait(timeout=30)
            except Exception:
                try:
                    proc.kill()
                except Exception:
                    pass
            try:
                out.write(f"[{datetime.utcnow().isoformat(timespec='seconds')}] Killed due to timeout\n")
                out.flush()
            except Exception:
                pass
            return 124
        out.write(f"[{datetime.utcnow().isoformat(timespec='seconds')}] Exited with code {proc.returncode}\n")
        out.flush()
        return int(proc.returncode)


def _parse_async_job_iso(ts: Any) -> datetime | None:
    try:
        text = str(ts or "").strip()
        if not text:
            return None
        if text.endswith("Z"):
            text = text[:-1] + "+00:00"
        parsed = datetime.fromisoformat(text)
        if parsed.tzinfo is not None:
            parsed = parsed.astimezone(timezone.utc).replace(tzinfo=None)
        return parsed
    except Exception:
        return None


def _refresh_oddsapi_props_phase_timeout_s(phase: Any) -> int:
    name = str(phase or "").strip().lower()
    if name == "snapshot":
        return 15 * 60
    if name == "edges":
        return 20 * 60
    if name == "export":
        return 10 * 60
    if name == "finalizing":
        return 5 * 60
    return 20 * 60


def _refresh_oddsapi_props_heartbeat_timeout_s() -> int:
    raw = str(os.environ.get("REFRESH_ODDSAPI_PROPS_HEARTBEAT_STALE_S") or "180").strip()
    try:
        return int(max(0.0, float(raw)))
    except Exception:
        return 180


def _mark_refresh_oddsapi_props_stale(payload: dict[str, Any]) -> bool:
    try:
        if not bool(payload.get("running")):
            return False
        phase = str(payload.get("phase") or "").strip().lower()
        heartbeat_at = _parse_async_job_iso(payload.get("heartbeat_at"))
        phase_anchor = (
            _parse_async_job_iso(payload.get("phase_started_at"))
            or _parse_async_job_iso(payload.get("started_at"))
        )
        if heartbeat_at is None and phase_anchor is None:
            return False
        now = datetime.utcnow()
        heartbeat_age_s = max(0, int((now - heartbeat_at).total_seconds())) if heartbeat_at is not None else None
        phase_age_s = max(0, int((now - phase_anchor).total_seconds())) if phase_anchor is not None else None

        stale_error = None
        heartbeat_allowed_s = _refresh_oddsapi_props_heartbeat_timeout_s()
        if heartbeat_age_s is not None and heartbeat_allowed_s > 0 and heartbeat_age_s > heartbeat_allowed_s:
            stale_error = f"refresh_oddsapi_props lost heartbeat during {phase or 'unknown'} phase after {heartbeat_age_s}s"

        phase_allowed_s = _refresh_oddsapi_props_phase_timeout_s(phase) + 120
        if stale_error is None and phase_age_s is not None and phase_age_s > phase_allowed_s:
            stale_error = f"refresh_oddsapi_props became stale during {phase or 'unknown'} phase after {phase_age_s}s"

        if stale_error is None:
            return False

        payload["running"] = False
        payload["ok"] = False
        payload["ended_at"] = now.isoformat()
        started_at = _parse_async_job_iso(payload.get("started_at"))
        if started_at is not None:
            payload["duration_s"] = int(max(0, (now - started_at).total_seconds()))
        if phase == "snapshot" and payload.get("rc_snapshot") == -1:
            payload["rc_snapshot"] = 124
        elif phase == "edges" and payload.get("rc_edges") == -1:
            payload["rc_edges"] = 124
        elif phase == "export" and payload.get("rc_export") == -1:
            payload["rc_export"] = 124
        if not payload.get("error"):
            payload["error"] = stale_error
        return True
    except Exception:
        return False


@app.route("/api/cron/refresh-oddsapi-props/status", methods=["GET"])
def api_cron_refresh_oddsapi_props_status():
    """Status endpoint for async refresh-oddsapi-props.

    Auth: CRON_TOKEN or ADMIN_KEY.
    Query:
      - tail (optional): N lines of log tail to include (default 0)
    """
    if not (_cron_auth_ok(request) or _admin_auth_ok(request)):
        return jsonify({"error": "unauthorized"}), 401
    tail_n = 0
    try:
        tail_n = int(request.args.get("tail", "0") or 0)
    except Exception:
        tail_n = 0

    payload = dict(_oddsapi_props_job_state)
    if not isinstance(payload.get("last"), dict):
        payload["last"] = {}

    try:
        has_live_state = bool(
            payload.get("running")
            or payload.get("started_at")
            or payload.get("ended_at")
            or payload.get("log_file")
            or payload.get("error")
            or (payload.get("ok") is not None)
            or any(
                payload.get(k) is not None
                for k in (
                    "rc_snapshot",
                    "rc_edges",
                    "rc_export",
                    "snapshot_rows",
                    "edges_rows",
                    "recs_rows",
                    "snapshot_path",
                    "edges_path",
                    "recs_path",
                    "duration_s",
                )
            )
            or bool(payload.get("last"))
        )
    except Exception:
        has_live_state = False

    refresh_meta = _load_refresh_oddsapi_props_meta(persist_stale=True)
    if refresh_meta and (bool(refresh_meta.get("running")) or not has_live_state):
        payload.update(_refresh_oddsapi_props_payload_from_meta(refresh_meta))
        payload["status_source"] = "cron_meta"
    else:
        payload["status_source"] = "memory"

    _mark_refresh_oddsapi_props_stale(payload)

    if tail_n > 0:
        try:
            lf = payload.get("log_file")
            if lf:
                payload["log_tail"] = _tail_text_file(Path(str(lf)), max_lines=min(2000, max(1, tail_n)))
        except Exception:
            pass
    return jsonify(payload), 200


def _invalidate_uploaded_props_derived_artifacts(date_str: str) -> dict[str, Any]:
    removed_files: list[str] = []
    cache_keys_removed: list[str] = []

    candidate_files = [
        DATA_PROCESSED_DIR / f"cards_props_snapshot_{date_str}.json",
        DATA_PROCESSED_DIR / f"props_recommendations_top_by_game_{date_str}.json",
        DATA_PROCESSED_DIR / f"recommendations_slate_{date_str}.json",
        DATA_PROCESSED_DIR / f"best_edges_props_{date_str}.csv",
    ]

    for path in candidate_files:
        try:
            if path.exists():
                path.unlink()
                removed_files.append(str(path))
        except Exception:
            continue

    cache_prefixes = (
        f"recs_slate_prob:{date_str}:",
        f"props_edges:{date_str}:",
        f"props_recommendations_lines:{date_str}:",
        f"period_lines:{date_str}:",
    )
    try:
        for cache_key in list(_live_processed_cache.keys()):
            if not isinstance(cache_key, str):
                continue
            if any(cache_key.startswith(prefix) for prefix in cache_prefixes):
                _live_processed_cache.pop(cache_key, None)
                cache_keys_removed.append(cache_key)
    except Exception:
        pass

    return {
        "removed_files": removed_files,
        "removed_cache_keys": cache_keys_removed,
    }


@app.route("/api/cron/upload-props-refresh-artifacts", methods=["POST"])
def api_cron_upload_props_refresh_artifacts():
    """Upload precomputed props refresh artifacts to the live Render disk.

    Auth: CRON_TOKEN or ADMIN_KEY.
    Multipart form fields:
      - date: YYYY-MM-DD
      - snapshot: odds_nba_player_props_<date>.csv
    Optional form fields:
            - predictions: props_predictions_<date>.csv
            - edges: props_edges_<date>.csv
            - recommendations: props_recommendations_<date>.csv
      - regions, bookmakers, markets, started_at, ended_at, duration_s

        Side effects on the active data root:
            - append current snapshot rows to odds_nba_player_props_history_<date>.csv
            - preserve earliest-seen props in odds_nba_player_props_opening_<date>.*
                        - when edges are present, enrich props_edges_<date>.csv with opening and movement columns
                        - when edges are present, emit props_movement_signals_<date>.csv for significant moves
    """
    if not (_cron_auth_ok(request) or _admin_auth_ok(request)):
        return jsonify({"error": "unauthorized"}), 401

    raw_date = str(request.form.get("date") or request.args.get("date") or "").strip()
    if not raw_date:
        raw_date = _parse_date_param(request, default_to_today=False) or ""
    if not raw_date:
        return jsonify({"error": "missing date"}), 400

    try:
        date_str = str(pd.to_datetime(raw_date).date())
    except Exception:
        return jsonify({"error": f"invalid date: {raw_date}"}), 400

    snapshot_file = request.files.get("snapshot")
    predictions_file = request.files.get("predictions")
    edges_file = request.files.get("edges")
    recommendations_file = request.files.get("recommendations")
    if snapshot_file is None:
        return jsonify({"error": "missing upload files", "missing": ["snapshot"]}), 400

    snapshot_path = DATA_RAW_DIR / f"odds_nba_player_props_{date_str}.csv"
    snapshot_alias_path = DATA_PROCESSED_DIR / f"oddsapi_player_props_{date_str}.csv"
    predictions_path = DATA_PROCESSED_DIR / f"props_predictions_{date_str}.csv"
    edges_path = DATA_PROCESSED_DIR / f"props_edges_{date_str}.csv"
    recommendations_path = DATA_PROCESSED_DIR / f"props_recommendations_{date_str}.csv"
    uploaded_files = {
        "snapshot": True,
        "predictions": predictions_file is not None,
        "edges": edges_file is not None,
        "recommendations": recommendations_file is not None,
    }

    def _write_upload(file_obj, target: Path) -> int:
        target.parent.mkdir(parents=True, exist_ok=True)
        try:
            file_obj.stream.seek(0)
        except Exception:
            pass
        file_obj.save(str(target))
        try:
            return int(target.stat().st_size)
        except Exception:
            return 0

    try:
        upload_bytes = {"snapshot": _write_upload(snapshot_file, snapshot_path)}
        if predictions_file is not None:
            upload_bytes["predictions"] = _write_upload(predictions_file, predictions_path)
        if edges_file is not None:
            upload_bytes["edges"] = _write_upload(edges_file, edges_path)
        if recommendations_file is not None:
            upload_bytes["recommendations"] = _write_upload(recommendations_file, recommendations_path)
        try:
            snapshot_alias_path.parent.mkdir(parents=True, exist_ok=True)
            shutil.copyfile(snapshot_path, snapshot_alias_path)
            snapshot_alias_rows = int(_count_csv_rows_quick(snapshot_alias_path))
            snapshot_alias_error = None
            if snapshot_alias_error:
                return jsonify({
                    "ok": False,
                    "error": f"failed to materialize processed snapshot alias: {snapshot_alias_error}",
                    "date": date_str,
                }), 500
        except Exception as exc:
            return jsonify({
                "ok": False,
                "error": f"failed to materialize processed snapshot alias: {exc}",
                "date": date_str,
            }), 500
    except Exception as exc:
        return jsonify({"ok": False, "error": f"failed to write upload: {exc}"}), 500

    snapshot_rows = int(_count_csv_rows_quick(snapshot_path))
    snapshot_alias_rows = int(_count_csv_rows_quick(snapshot_alias_path))
    predictions_rows = int(_count_csv_rows_quick(predictions_path))
    edges_rows = int(_count_csv_rows_quick(edges_path))
    recs_rows = int(_count_csv_rows_quick(recommendations_path))

    if snapshot_rows <= 0:
        return jsonify({
            "ok": False,
            "error": "uploaded snapshot has zero rows",
            "date": date_str,
            "snapshot_rows": snapshot_rows,
        }), 400
    if predictions_file is not None and predictions_rows <= 0:
        return jsonify({
            "ok": False,
            "error": "uploaded predictions have zero rows",
            "date": date_str,
            "predictions_rows": predictions_rows,
        }), 400
    if edges_file is not None and edges_rows <= 0:
        return jsonify({
            "ok": False,
            "error": "uploaded edges have zero rows",
            "date": date_str,
            "edges_rows": edges_rows,
        }), 400
    if recommendations_file is not None and recs_rows <= 0:
        return jsonify({
            "ok": False,
            "error": "uploaded recommendations have zero rows",
            "date": date_str,
            "recs_rows": recs_rows,
        }), 400

    upload_mode = "snapshot-only"
    movement_meta: dict[str, Any] = {
        "opening_rows": 0,
        "opening_path": None,
        "history_appended_rows": 0,
        "history_path": None,
        "rows_with_opening": 0,
        "significant_rows": 0,
        "fast_rows": 0,
        "signals_rows": 0,
        "signals_path": None,
    }

    try:
        from nba_betting.props_movement import persist_props_snapshot_tracking, sync_props_movement_artifacts  # type: ignore

        if edges_file is not None or int(edges_rows or 0) > 0:
            movement_meta = sync_props_movement_artifacts(
                date_str=date_str,
                snapshot_path=snapshot_path,
                edges_path=edges_path,
                raw_dir=DATA_RAW_DIR,
                processed_dir=DATA_PROCESSED_DIR,
            )
            upload_mode = "full" if (predictions_file is not None and edges_file is not None and recommendations_file is not None) else "partial"
        else:
            snapshot_df = _read_csv_if_exists(snapshot_path)
            movement_meta.update(
                persist_props_snapshot_tracking(
                    snapshot_df if isinstance(snapshot_df, pd.DataFrame) else pd.DataFrame(),
                    date_str,
                    raw_dir=DATA_RAW_DIR,
                )
            )
        snapshot_rows = int(_count_csv_rows_quick(snapshot_path))
        edges_rows = int(_count_csv_rows_quick(edges_path))
        try:
            from nba_betting.props_edges import invalidate_opening_props_cache as _invalidate_opening_props_cache  # type: ignore

            _invalidate_opening_props_cache(date_str)
        except Exception:
            pass
    except Exception as exc:
        return jsonify({"ok": False, "error": f"failed to persist props movement tracking: {exc}"}), 500

    started_at = str(request.form.get("started_at") or "").strip() or datetime.utcnow().isoformat()
    ended_at = str(request.form.get("ended_at") or "").strip() or datetime.utcnow().isoformat()
    duration_raw = str(request.form.get("duration_s") or "").strip()
    try:
        duration_s = float(duration_raw) if duration_raw else None
    except Exception:
        duration_s = None

    refresh_meta = {
        "date": date_str,
        "regions": str(request.form.get("regions") or "us").strip() or "us",
        "bookmakers": str(request.form.get("bookmakers") or "").strip() or None,
        "markets": str(request.form.get("markets") or "").strip(),
        "run_edges": bool(uploaded_files["edges"]),
        "run_export": bool(uploaded_files["recommendations"]),
        "run_push": False,
        "running": False,
        "ok": True,
        "log_file": None,
        "started_at": started_at,
        "ended_at": ended_at,
        "phase": "done",
        "phase_started_at": ended_at,
        "heartbeat_at": ended_at,
        "rc_snapshot": 0,
        "rc_edges": 0 if uploaded_files["edges"] else None,
        "rc_export": 0 if uploaded_files["recommendations"] else None,
        "snapshot_rows": snapshot_rows,
        "snapshot_alias_rows": snapshot_alias_rows,
        "predictions_rows": predictions_rows,
        "edges_rows": edges_rows,
        "recs_rows": recs_rows,
        "opening_rows": movement_meta.get("opening_rows"),
        "opening_path": movement_meta.get("opening_path"),
        "history_appended_rows": movement_meta.get("history_appended_rows"),
        "history_path": movement_meta.get("history_path"),
        "movement_rows": movement_meta.get("rows_with_opening"),
        "movement_significant_rows": movement_meta.get("significant_rows"),
        "movement_fast_rows": movement_meta.get("fast_rows"),
        "movement_signals_path": movement_meta.get("signals_path"),
        "snapshot_path": str(snapshot_path),
        "snapshot_alias_path": str(snapshot_alias_path),
        "predictions_path": str(predictions_path),
        "edges_path": str(edges_path),
        "recs_path": str(recommendations_path),
        "duration_s": duration_s,
        "error": None,
        "source": "github-actions-upload",
        "upload_mode": upload_mode,
        "uploaded_files": uploaded_files,
    }

    try:
        _cron_meta_update("refresh_oddsapi_props", refresh_meta)
    except Exception as exc:
        return jsonify({"ok": False, "error": f"failed to update cron meta: {exc}"}), 500

    _oddsapi_props_job_state.update(_refresh_oddsapi_props_payload_from_meta(refresh_meta))

    invalidation_meta = _invalidate_uploaded_props_derived_artifacts(date_str)

    return jsonify({
        "ok": True,
        "date": date_str,
        "upload_mode": upload_mode,
        "uploaded_files": uploaded_files,
        "snapshot_rows": snapshot_rows,
        "snapshot_alias_rows": snapshot_alias_rows,
        "predictions_rows": predictions_rows,
        "edges_rows": edges_rows,
        "recs_rows": recs_rows,
        "opening_rows": movement_meta.get("opening_rows"),
        "history_appended_rows": movement_meta.get("history_appended_rows"),
        "movement": movement_meta,
        "uploads": upload_bytes,
        "snapshot_path": str(snapshot_path),
        "snapshot_alias_path": str(snapshot_alias_path),
        "predictions_path": str(predictions_path),
        "edges_path": str(edges_path),
        "recs_path": str(recommendations_path),
        "invalidated": invalidation_meta,
    }), 200


def _ensure_game_models(log_fp: Path | None = None) -> tuple[bool, dict]:
    """Ensure core game models exist; if missing, build features (if needed) and train.

    Returns (ok, info) where info includes rc_build/rc_train and paths.
    """
    try:
        models_dir = BASE_DIR / "models"
        need = [
            models_dir / "win_prob.joblib",
            models_dir / "spread_margin.joblib",
            models_dir / "totals.joblib",
            models_dir / "halves_models.joblib",
            models_dir / "quarters_models.joblib",
            models_dir / "feature_columns.joblib",
        ]
        have_all = all(p.exists() for p in need)
        if have_all:
            return True, {"skipped": True}
        # Choose python exe
        py = os.environ.get("PYTHON", (os.environ.get("VIRTUAL_ENV") or "") + "/bin/python")
        if not py or not Path(str(py)).exists():
            py_win = (Path(os.environ.get("VIRTUAL_ENV") or "") / "Scripts" / "python.exe")
            py = str(py_win) if py_win.exists() else "python"
        env = {"PYTHONPATH": str(SRC_DIR)}
        logs_dir = _ensure_logs_dir(); stamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
        lf = Path(log_fp) if log_fp else (logs_dir / f"cron_train_autofix_{stamp}.log")
        # Build features only if missing
        feats = DATA_PROCESSED_DIR / "features.parquet"
        rc_build = 0
        if not feats.exists():
            rc_build = _run_to_file([str(py), "-m", "nba_betting.cli", "build-features"], lf, cwd=BASE_DIR, env=env)
        rc_train = _run_to_file([str(py), "-m", "nba_betting.cli", "train"], lf, cwd=BASE_DIR, env=env)
        ok = (int(rc_build) == 0 and int(rc_train) == 0)
        return ok, {"rc_build": int(rc_build), "rc_train": int(rc_train), "log_file": str(lf)}
    except Exception as e:
        return False, {"error": str(e)}

def _quick_have_game_models() -> bool:
    """Fast check for presence of required game model artifacts without training.

    Used to decide whether to defer heavy training to background for async cron calls.
    """
    try:
        models_dir = BASE_DIR / "models"
        need = [
            models_dir / "win_prob.joblib",
            models_dir / "spread_margin.joblib",
            models_dir / "totals.joblib",
            models_dir / "halves_models.joblib",
            models_dir / "quarters_models.joblib",
            models_dir / "feature_columns.joblib",
        ]
        return all(p.exists() for p in need)
    except Exception:
        return False

def _ensure_props_models(log_fp: Path | None = None) -> tuple[bool, dict]:
    """Ensure props model artifacts exist; if missing, build features and train.

    Returns (ok, info) where info includes rc_build/rc_train and paths.
    """
    try:
        models_dir = BASE_DIR / "models"
        need = [
            models_dir / "props_models.joblib",
            models_dir / "props_feature_columns.joblib",
        ]
        have_all = all(p.exists() for p in need)
        if have_all:
            return True, {"skipped": True}
        # Choose python exe
        py = os.environ.get("PYTHON", (os.environ.get("VIRTUAL_ENV") or "") + "/bin/python")
        if not py or not Path(str(py)).exists():
            py_win = (Path(os.environ.get("VIRTUAL_ENV") or "") / "Scripts" / "python.exe")
            py = str(py_win) if py_win.exists() else "python"
        env = {"PYTHONPATH": str(SRC_DIR)}
        logs_dir = _ensure_logs_dir(); stamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
        lf = Path(log_fp) if log_fp else (logs_dir / f"cron_props_train_autofix_{stamp}.log")
        # Build props features first (uses player_logs)
        rc_build = _run_to_file([str(py), "-m", "nba_betting.cli", "build-props-features"], lf, cwd=BASE_DIR, env=env)
        rc_train = _run_to_file([str(py), "-m", "nba_betting.cli", "train-props"], lf, cwd=BASE_DIR, env=env)
        ok = (int(rc_build) == 0 and int(rc_train) == 0)
        return ok, {"rc_build": int(rc_build), "rc_train": int(rc_train), "log_file": str(lf)}
    except Exception as e:
        return False, {"error": str(e)}


def _admin_auth_ok(req) -> bool:
    key = os.environ.get("ADMIN_KEY")
    if not key:
        # If no key configured, allow only local loopback requests by default.
        #
        # IMPORTANT: Do NOT automatically allow private RFC1918 ranges here.
        # On hosted setups behind a reverse proxy (e.g., Render), Flask's
        # req.remote_addr can be the proxy's internal IP (often 10.*), which
        # would unintentionally grant admin access to the public internet.
        #
        # Local-dev convenience: set ADMIN_ALLOW_LAN=1 to allow private LAN IPs.
        try:
            host = (req.remote_addr or "").strip()
            if host in {"127.0.0.1", "::1", "::ffff:127.0.0.1"}:
                return True
            allow_lan = (os.environ.get("ADMIN_ALLOW_LAN") or "").strip().lower() in {"1", "true", "yes", "on"}
            if allow_lan:
                if host.startswith("192.168.") or host.startswith("10."):
                    return True
                if host.startswith("172."):
                    try:
                        parts = host.split(".")
                        if len(parts) >= 2:
                            second = int(parts[1])
                            if 16 <= second <= 31:
                                return True
                    except Exception:
                        pass
            return False
        except Exception:
            return False
    return (req.args.get("key") == key) or (req.headers.get("X-Admin-Key") == key)


def _cron_auth_ok(req) -> bool:
    """Cron auth using CRON_TOKEN. Accepts:
    - Authorization: Bearer <token>
    - X-Cron-Token: <token>
    - ?token=<token>
    If CRON_TOKEN is unset, fall back to admin auth policy for local/dev.
    """
    token = os.environ.get("CRON_TOKEN")
    if not token:
        # fall back to admin auth (local dev convenience)
        return _admin_auth_ok(req)
    auth = (req.headers.get("Authorization") or "").strip()
    if auth.lower().startswith("bearer ") and auth.split(" ", 1)[1] == token:
        return True
    if (req.headers.get("X-Cron-Token") == token) or (req.args.get("token") == token):
        return True
    return False

def _debug_routes_enabled() -> bool:
    """Return True if debug/maintenance routes should be enabled.

    Controlled by ADMIN_ENABLE_DEBUG_ROUTES or DEBUG env vars.
    Defaults to False on servers like Render.
    """
    val = os.environ.get("ADMIN_ENABLE_DEBUG_ROUTES") or os.environ.get("DEBUG")
    if val is None:
        return False
    s = str(val).strip().lower()
    return s in {"1", "true", "yes", "on"}

@app.route("/api/cron/push-test", methods=["POST"])  # lightweight diagnostics
def api_cron_push_test():
    if not _debug_routes_enabled():
        return jsonify({"error": "disabled"}), 404
    if not _cron_auth_ok(request):
        return jsonify({"error": "unauthorized"}), 401
    # Stage a no-op commit and attempt push (allow-empty)
    ok, detail = _git_commit_and_push(msg="push-test heartbeat")
    return jsonify({"pushed": bool(ok), "detail": detail})


def _season_year_for_date(date_str: str) -> int:
    d = datetime.strptime(date_str, "%Y-%m-%d").date()
    return d.year


def _season_str_from_year(season_year: int) -> str:
    return str(int(season_year))


def _daily_update_job(do_push: bool, date_str: str | None = None, mode: str = "full") -> None:
    _job_state["running"] = True
    _job_state["started_at"] = datetime.utcnow().isoformat()
    _job_state["ended_at"] = None
    _job_state["ok"] = None
    _job_state["logs"] = []
    logs_dir = _ensure_logs_dir()
    stamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
    log_file = logs_dir / f"web_daily_update_{stamp}.log"
    _job_state["log_file"] = str(log_file)
    try:
        date_str = date_str or _default_us_slate_date_str()
        mode = (mode or "full").strip().lower()
        is_lookahead = (mode == "lookahead")

        _append_log(f"Starting daily update (mode={mode}, date={date_str})...")
        if is_lookahead:
            _append_log("Look-ahead mode: reusing local cached inputs and prioritizing fast future-slate generation.")

        # Resolve python executable (prefer current interpreter on servers)
        import sys as _sys
        py = os.environ.get("PYTHON")
        if not py:
            py = _sys.executable
        if not py or not Path(str(py)).exists():
            py_posix = (os.environ.get("VIRTUAL_ENV") or "") + "/bin/python"
            if py_posix and Path(py_posix).exists():
                py = py_posix
            else:
                py_win = (Path(os.environ.get("VIRTUAL_ENV") or "") / "Scripts" / "python.exe")
                py = str(py_win) if py_win.exists() else "python"

        env = {"PYTHONPATH": str(SRC_DIR)}
        season_year = _season_year_for_date(date_str)
        season_str = _season_str_from_year(season_year)
        season_end_year = season_year + 1

        def _env_int(names: list[str], default: int) -> int:
            for name in names:
                try:
                    raw = os.environ.get(name)
                except Exception:
                    raw = None
                if raw is None:
                    continue
                raw_s = str(raw).strip()
                if not raw_s:
                    continue
                try:
                    return int(raw_s)
                except Exception:
                    continue
            return int(default)

        cpu_count = int(os.cpu_count() or 1)
        default_lookahead_workers = 1 if cpu_count <= 2 else min(4, max(2, cpu_count // 2))
        lookahead_smartsim_workers = max(1, _env_int([
            "DAILY_LOOKAHEAD_SMARTSIM_WORKERS",
            "DAILY_SMARTSIM_WORKERS",
            "SMARTSIM_WORKERS",
            "SMART_SIM_WORKERS",
        ], default_lookahead_workers))
        lookahead_smartsim_n_sims = max(1, _env_int([
            "DAILY_LOOKAHEAD_SMARTSIM_NSIMS",
            "DAILY_SMARTSIM_NSIMS",
        ], 2000))
        default_props_bookmakers = _player_prop_bookmakers_csv(None, env_name="PLAYER_PROP_BOOKMAKERS") or ""
        default_props_bookmakers_label = default_props_bookmakers or "all-us-region-books"

        def _run_shared_props_refresh_step() -> tuple[int, dict[str, Any]]:
            try:
                from nba_betting.refresh_oddsapi_props_job import run_refresh_oddsapi_props_job as _worker_run_refresh  # type: ignore
            except Exception as exc:
                _append_log(f"Failed to import refresh_oddsapi_props_job helpers: {exc}")
                return 1, {"error": str(exc)}

            worker_log = logs_dir / f"web_refresh_oddsapi_props_{date_str}_{stamp}.log"
            _append_log(
                "Using shared OddsAPI props refresh worker "
                f"(bookmakers={default_props_bookmakers_label}, log={worker_log})"
            )
            state = _worker_run_refresh(
                date_str=str(date_str),
                regions="us",
                bookmakers=default_props_bookmakers,
                markets="",
                do_edges=True,
                do_export=True,
                do_push=False,
                log_file=worker_log,
                started_at=datetime.utcnow().isoformat(),
            ) or {}

            raw_snapshot_fp = DATA_RAW_DIR / f"odds_nba_player_props_{date_str}.csv"
            alias_snapshot_fp = DATA_PROCESSED_DIR / f"oddsapi_player_props_{date_str}.csv"
            edges_local_fp = DATA_PROCESSED_DIR / f"props_edges_{date_str}.csv"
            rec_local_fp = DATA_PROCESSED_DIR / f"props_recommendations_{date_str}.csv"

            snapshot_rows = int(_count_csv_rows_quick(raw_snapshot_fp) or 0)
            alias_rows = int(_count_csv_rows_quick(alias_snapshot_fp) or 0)
            edges_rows = int(_count_csv_rows_quick(edges_local_fp) or 0)
            rec_rows = int(_count_csv_rows_quick(rec_local_fp) or 0)
            rc = 0
            worker_error = str((state or {}).get("error") or "").strip()
            if worker_error:
                rc = 1
                _append_log(f"Shared props refresh worker error: {worker_error}")
            elif snapshot_rows > 0 and alias_rows <= 0:
                rc = 1
                _append_log("Shared props refresh wrote snapshot rows but no processed oddsapi_player_props alias.")
            elif snapshot_rows > 0 and edges_rows <= 0:
                rc = 1
                _append_log("Shared props refresh wrote snapshot rows but props_edges remained empty.")
            elif snapshot_rows > 0 and rec_rows <= 0:
                rc = 1
                _append_log("Shared props refresh wrote snapshot rows but props_recommendations remained empty.")

            _append_log(
                "Shared props refresh summary: "
                f"snapshot_rows={snapshot_rows}, alias_rows={alias_rows}, edges_rows={edges_rows}, rec_rows={rec_rows}"
            )
            return rc, dict(state or {})

        # Build a date-based pipeline aligned with scripts/daily_update.ps1
        steps: list[tuple[str, list[str], bool]] = []
        # (label, cmd, required)
        if not is_lookahead:
            steps.append((
                "fetch-injuries",
                [str(py), "-m", "nba_betting.cli", "fetch-injuries"],
                False,
            ))
            steps.append((
                "fetch-rosters",
                [str(py), "-m", "nba_betting.cli", "fetch-rosters", "--season", str(season_year)],
                False,
            ))
            steps.append((
                "fetch-player-logs",
                [str(py), "-m", "nba_betting.cli", "fetch-player-logs", "--seasons", season_str],
                False,
            ))
        else:
            _append_log("Look-ahead mode: skipping fetch-injuries, fetch-rosters, and fetch-player-logs (already refreshed by the main daily run).")
        steps.append((
            "build-league-status",
            [str(py), "-m", "nba_betting.cli", "build-league-status", "--date", date_str],
            False,
        ))
        steps.append((
            "check-dressed",
            [str(py), "-m", "nba_betting.cli", "check-dressed", "--date", date_str],
            True,
        ))
        steps.append((
            "predict-date",
            [str(py), "-m", "nba_betting.cli", "predict-date", "--date", date_str],
            True,
        ))
        steps.append((
            "odds-snapshots",
            [str(py), "-m", "nba_betting.cli", "odds-snapshots", "--date", date_str],
            False,
        ))
        steps.append((
            "simulate-games",
            [str(py), "-m", "nba_betting.cli", "simulate-games", "--date", date_str],
            False,
        ))

        # SmartSim distributions for today's slate (writes per-game smart_sim_<date>_<HOME>_<AWAY>.json)
        # Keep consistent with scripts/daily_update.ps1; allow skipping via env.
        skip_smartsim = str(os.environ.get("DAILY_SKIP_SMARTSIM") or "").strip().lower() in {"1", "true", "yes"}
        if (mode in {"full", "pipeline", "props", "lookahead"}) and not skip_smartsim:
            steps.append((
                "fetch-advanced-stats",
                [str(py), "-m", "nba_betting.cli", "fetch-advanced-stats", "--season", str(season_end_year), "--as-of", date_str],
                False,
            ))
            if not is_lookahead:
                n_sims = str(os.environ.get("DAILY_SMARTSIM_NSIMS") or "2000").strip() or "2000"
                smartsim_cmd = [str(py), "-m", "nba_betting.cli", "smart-sim-date", "--date", date_str, "--n-sims", n_sims]
                max_games = str(os.environ.get("DAILY_SMARTSIM_MAX_GAMES") or "").strip()
                if max_games:
                    smartsim_cmd += ["--max-games", max_games]
                steps.append(("smart-sim-date", smartsim_cmd, False))
        if mode in {"full", "pipeline", "props", "lookahead"}:
            predict_props_cmd = [str(py), "-m", "nba_betting.cli", "predict-props", "--date", date_str]
            if skip_smartsim:
                predict_props_cmd.append("--no-use-smart-sim")
            elif is_lookahead:
                predict_props_cmd += [
                    "--smart-sim-workers",
                    str(lookahead_smartsim_workers),
                    "--smart-sim-n-sims",
                    str(lookahead_smartsim_n_sims),
                ]
            steps.append((
                "predict-props",
                predict_props_cmd,
                False,
            ))
            steps.append((
                "refresh-oddsapi-props",
                [],
                False,
            ))
            steps.append((
                "export-recommendations",
                [str(py), "-m", "nba_betting.cli", "export-recommendations", "--date", date_str],
                False,
            ))

        props_preds_fp = DATA_PROCESSED_DIR / f"props_predictions_{date_str}.csv"
        edges_fp = DATA_PROCESSED_DIR / f"props_edges_{date_str}.csv"
        rec_fp = DATA_PROCESSED_DIR / f"props_recommendations_{date_str}.csv"
        props_snapshot_fp = DATA_RAW_DIR / f"odds_nba_player_props_{date_str}.csv"
        props_snapshot_alias_fp = DATA_PROCESSED_DIR / f"oddsapi_player_props_{date_str}.csv"

        rc_total = 0
        had_required_failure = False
        optional_failures: list[str] = []
        for label, cmd, required in steps:
            if label == "refresh-oddsapi-props":
                _append_log(f"Running step: {label}")
                rc, _state = _run_shared_props_refresh_step()
                rc_total += int(rc)
                _append_log(f"Exit code ({label}): {rc}")
                if rc != 0:
                    if required:
                        had_required_failure = True
                        _append_log(f"Stopping early: required step failed ({label})")
                        break
                    optional_failures.append(label)
                continue
            _append_log(f"Running step: {label}")
            _append_log(f"Cmd: {' '.join(cmd)}")
            rc = _run_to_file(cmd, log_file, cwd=BASE_DIR, env=env)
            rc_total += int(rc)
            _append_log(f"Exit code ({label}): {rc}")
            if rc != 0:
                if required:
                    had_required_failure = True
                    _append_log(f"Stopping early: required step failed ({label})")
                    break
                optional_failures.append(label)

        ok = not had_required_failure
        if not is_lookahead and mode in {"full", "pipeline", "props"}:
            require_props_lines = str(os.environ.get("DAILY_REQUIRE_PROPS_LINES") or "1").strip().lower() in {"1", "true", "yes"}
            props_pred_rows = int(_count_csv_rows_quick(props_preds_fp) or 0)
            props_snapshot_rows = int(_count_csv_rows_quick(props_snapshot_fp) or 0)
            props_snapshot_alias_rows = int(_count_csv_rows_quick(props_snapshot_alias_fp) or 0)
            edges_rows = int(_count_csv_rows_quick(edges_fp) or 0)
            rec_rows = int(_count_csv_rows_quick(rec_fp) or 0)

            if edges_rows <= 0:
                _prune_invalid_props_recommendations_artifact(edges_fp, rec_fp, log_cb=_append_log)
                rec_rows = int(_count_csv_rows_quick(rec_fp) or 0)

            if require_props_lines and props_pred_rows > 0 and props_snapshot_rows > 0:
                if props_snapshot_alias_rows <= 0:
                    ok = False
                    optional_failures.append("props-snapshot-alias-artifact")
                    _append_log("Marking daily update failed: raw props snapshot exists but processed oddsapi_player_props alias is missing or empty.")
                if edges_rows <= 0:
                    ok = False
                    optional_failures.append("props-edges-artifact")
                    _append_log("Marking daily update failed: props_predictions exists but props_edges artifact is missing or empty.")
                if rec_rows <= 0:
                    ok = False
                    optional_failures.append("props-recommendations-artifact")
                    _append_log("Marking daily update failed: props_predictions exists but props_recommendations artifact is missing or empty.")

        if optional_failures:
            _append_log(f"Optional step failures: {', '.join(optional_failures)}")
        _append_log(f"Daily update finished. ok={ok} (rc_total={rc_total})")
        # Optional: push updates back to Git if requested and configured
        if ok and do_push:
            try:
                _append_log("Committing and pushing daily update artifacts via _git_commit_and_push...")
                okp, detail = _git_commit_and_push(msg="daily-update")
                _append_log(f"Git push {'ok' if okp else 'failed'}: {detail}")
            except Exception as e:  # noqa: BLE001
                _append_log(f"Git push error: {e}")
        _job_state["ok"] = ok
    except Exception as e:  # noqa: BLE001
        _append_log(f"Daily update exception: {e}")
        _job_state["ok"] = False
    finally:
        _job_state["ended_at"] = datetime.utcnow().isoformat()
        _job_state["running"] = False


