@app.route("/api/data-status")
def api_data_status():
    """Quick status for a date: counts for predictions, game_odds, props edges, and recon.

    Query: ?date=YYYY-MM-DD (defaults to the current US local slate date)
    """
    d = _parse_date_param(request)
    if not d:
        return jsonify({"error": "missing date"}), 400
    out: Dict[str, Any] = {"date": d}
    try:
        # Predictions
        p = _find_predictions_for_date(d)
        out["predictions_path"] = str(p) if p else None
        out["predictions_rows"] = _count_csv_rows_quick(p) if p else 0
    except Exception:
        out["predictions_rows"] = 0
    try:
        # Game odds
        go = _find_game_odds_for_date(d)
        out["game_odds_path"] = str(go) if go else None
        out["game_odds_rows"] = _count_csv_rows_quick(go) if go else 0
    except Exception:
        out["game_odds_rows"] = 0
    try:
        # Props
        pe = DATA_PROCESSED_DIR / f"props_edges_{d}.csv"
        out["props_edges_path"] = str(pe) if pe.exists() else None
        out["props_edges_rows"] = _count_csv_rows_quick(pe) if pe.exists() else 0
    except Exception:
        out["props_edges_rows"] = 0

    # If no explicit date was provided and nothing exists for computed today,
    # fall back to previous day (helps avoid UTC-next-day issues)
    try:
        if ("date" not in request.args and "d" not in request.args):
            if (out.get("predictions_rows", 0) == 0 and out.get("game_odds_rows", 0) == 0 and out.get("props_edges_rows", 0) == 0):
                prev = (pd.to_datetime(d) - pd.Timedelta(days=1)).date().isoformat()
                p = _find_predictions_for_date(prev)
                go = _find_game_odds_for_date(prev)
                pe = DATA_PROCESSED_DIR / f"props_edges_{prev}.csv"
                if (p or go or pe.exists()):
                    out["date"] = prev
                    out["predictions_path"] = str(p) if p else None
                    out["predictions_rows"] = _count_csv_rows_quick(p) if p else 0
                    out["game_odds_path"] = str(go) if go else None
                    out["game_odds_rows"] = _count_csv_rows_quick(go) if go else 0
                    out["props_edges_path"] = str(pe) if pe.exists() else None
                    out["props_edges_rows"] = _count_csv_rows_quick(pe) if pe.exists() else 0
    except Exception:
        pass
    try:
        # Recon
        rg = DATA_PROCESSED_DIR / f"recon_games_{d}.csv"
        out["recon_games_path"] = str(rg) if rg.exists() else None
        out["recon_games_rows"] = _count_csv_rows_quick(rg) if rg.exists() else 0
    except Exception:
        out["recon_games_rows"] = 0
    return jsonify(out)


@app.route("/api/predictions")
def api_predictions():
    d = _parse_date_param(request)
    if not d:
        return jsonify({"error": "missing date"}), 400
    p = _find_predictions_for_date(d)
    if not p:
        return jsonify(_to_jsonable({"date": d, "rows": []}))
    try:
        df = pd.read_csv(p)
        # Try to merge odds if available
        q = _find_game_odds_for_date(d)
        if q is not None:
            try:
                o = pd.read_csv(q)
                if "date" in o.columns:
                    o["date"] = pd.to_datetime(o["date"], errors="coerce").dt.date
                if "date" in df.columns:
                    df["date"] = pd.to_datetime(df["date"], errors="coerce").dt.date
                on = ["date", "home_team", "visitor_team"]
                if all(c in df.columns for c in on) and all(c in o.columns for c in on):
                    df = df.merge(o, on=on, how="left", suffixes=("", "_odds"))
                    # Compute implied and edges if possible
                    if "home_ml" in df.columns and "home_win_prob" in df.columns:
                        df["home_implied_prob"] = df["home_ml"].apply(_implied_prob_american)
                        df["edge_win"] = df["home_win_prob"].astype(float) - df["home_implied_prob"].astype(float)
                    if "home_spread" in df.columns and "pred_margin" in df.columns:
                        df["market_home_margin"] = -pd.to_numeric(df["home_spread"], errors="coerce")
                        df["edge_spread"] = pd.to_numeric(df["pred_margin"], errors="coerce") - df["market_home_margin"]
                    if "total" in df.columns and "pred_total" in df.columns:
                        df["edge_total"] = pd.to_numeric(df["pred_total"], errors="coerce") - pd.to_numeric(df["total"], errors="coerce")
            except Exception:
                pass
        # Return compact JSON
        rows = df.fillna("").to_dict(orient="records")
        return jsonify(_to_jsonable({"date": d, "rows": rows}))
    except Exception as e:  # noqa: BLE001
        return jsonify({"error": str(e)}), 500


def _american_to_decimal(amer: Any) -> float | None:
    try:
        a = float(amer)
    except Exception:
        return None
    if not np.isfinite(a) or a == 0:
        return None
    if a > 0:
        return 1.0 + (a / 100.0)
    return 1.0 + (100.0 / abs(a))


def _american_to_implied_prob(amer: Any) -> float | None:
    try:
        a = float(amer)
    except Exception:
        return None
    if not np.isfinite(a) or a == 0:
        return None
    if a > 0:
        return float(100.0 / (a + 100.0))
    return float(abs(a) / (abs(a) + 100.0))


def _ev_from_prob_and_american(p: float | None, amer: Any) -> float | None:
    """Return expected value per 1 unit staked.

    EV = p*(dec-1) - (1-p)
    """
    if p is None:
        return None
    try:
        p = float(p)
    except Exception:
        return None
    if not np.isfinite(p):
        return None
    p = float(max(0.0, min(1.0, p)))
    dec = _american_to_decimal(amer)
    if dec is None:
        return None
    return float(p * (dec - 1.0) - (1.0 - p))


def _safe_float(x: Any) -> float | None:
    try:
        v = float(x)
        return float(v) if np.isfinite(v) else None
    except Exception:
        return None


def _processed_path_candidates(fname: str, *, prefer_repo: bool = False) -> list[Path]:
    try:
        raw_name = str(fname or "").strip()
        if not raw_name or "/" in raw_name or "\\" in raw_name or ".." in raw_name:
            return []
        primary = REPO_DATA_PROCESSED_DIR if prefer_repo else DATA_PROCESSED_DIR
        secondary = DATA_PROCESSED_DIR if prefer_repo else REPO_DATA_PROCESSED_DIR
        candidates: list[Path] = []
        seen: set[str] = set()
        for root in (primary, secondary):
            try:
                path = root / raw_name
                key = str(path)
                if key in seen:
                    continue
                seen.add(key)
                candidates.append(path)
            except Exception:
                continue
        return candidates
    except Exception:
        return []


def _load_smart_sim_files_for_date(date_str: str, prefix: str | None = None) -> list[Path]:
    try:
        pref = str(prefix or os.environ.get("SMART_SIM_PREFIX") or "smart_sim").strip() or "smart_sim"
        patterns: list[Path] = []
        seen_names: set[str] = set()
        for root in (REPO_DATA_PROCESSED_DIR, DATA_PROCESSED_DIR):
            try:
                for path in sorted(root.glob(f"{pref}_{date_str}_*.json")):
                    name = str(path.name or "")
                    if not name or name in seen_names:
                        continue
                    seen_names.add(name)
                    patterns.append(path)
            except Exception:
                continue
        return patterns
    except Exception:
        return []


def _smart_sim_matchup_from_path(date_str: str, path: Path, prefix: str | None = None) -> tuple[str, str] | None:
    try:
        pref = str(prefix or os.environ.get("SMART_SIM_PREFIX") or "smart_sim").strip() or "smart_sim"
        stem = str(path.stem or "")
        marker = f"{pref}_{date_str}_"
        if not stem.startswith(marker):
            return None
        tail = stem[len(marker):]
        parts = tail.split("_")
        if len(parts) < 2:
            return None
        home_tri = str(parts[0] or "").strip().upper()
        away_tri = str(parts[1] or "").strip().upper()
        if len(home_tri) != 3 or len(away_tri) != 3:
            return None
        return home_tri, away_tri
    except Exception:
        return None


def _smart_sim_authoritative_matchups_for_date(date_str: str) -> set[tuple[str, str]]:
    out: set[tuple[str, str]] = set()

    try:
        odds_map = _load_game_odds_map(date_str)
        out = {
            (str(home_tri or "").strip().upper(), str(away_tri or "").strip().upper())
            for home_tri, away_tri in odds_map.keys()
            if str(home_tri or "").strip() and str(away_tri or "").strip()
        }
    except Exception:
        out = set()

    if out:
        return out

    pred_path = DATA_PROCESSED_DIR / f"predictions_{date_str}.csv"
    if not pred_path.exists():
        try:
            _maybe_fetch_remote_processed(pred_path.name)
        except Exception:
            pass

    try:
        df = _read_csv_if_exists(pred_path)
        if df is None or not isinstance(df, pd.DataFrame) or df.empty:
            return out

        def _tri(raw: Any) -> str:
            val = str(raw or "").strip()
            if not val:
                return ""
            tri = _get_tricode(val)
            return str(tri or val).strip().upper()

        for home_col, away_col in (("home_team", "visitor_team"), ("home", "away")):
            if home_col not in df.columns or away_col not in df.columns:
                continue
            for _, row in df.iterrows():
                home_tri = _tri(row.get(home_col))
                away_tri = _tri(row.get(away_col))
                if home_tri and away_tri:
                    out.add((home_tri, away_tri))
            if out:
                break
    except Exception:
        return out

    return out


def _load_smart_sim_files_for_authoritative_slate(date_str: str, prefix: str | None = None) -> list[Path]:
    files = _load_smart_sim_files_for_date(date_str, prefix=prefix)
    allowed_matchups = _smart_sim_authoritative_matchups_for_date(date_str)
    if not allowed_matchups:
        return files

    try:
        pref = str(prefix or os.environ.get("SMART_SIM_PREFIX") or "smart_sim").strip() or "smart_sim"
        existing_matchups = {
            matchup
            for matchup in (
                _smart_sim_matchup_from_path(date_str, fp, prefix=prefix)
                for fp in files
            )
            if matchup is not None
        }
        for home_tri, away_tri in sorted(allowed_matchups - existing_matchups):
            _maybe_fetch_remote_processed(f"{pref}_{date_str}_{home_tri}_{away_tri}.json")
        files = _load_smart_sim_files_for_date(date_str, prefix=prefix)
    except Exception:
        pass

    if not files:
        return files

    filtered: list[Path] = []
    for fp in files:
        matchup = _smart_sim_matchup_from_path(date_str, fp, prefix=prefix)
        if matchup is None or matchup in allowed_matchups:
            filtered.append(fp)
    return filtered


def _app_lookahead_days(default: int = 1) -> int:
    try:
        raw = os.environ.get("APP_LOOKAHEAD_DAYS")
        if raw is None or str(raw).strip() == "":
            raw = os.environ.get("DAILY_LOOKAHEAD_DAYS")
        if raw is None or str(raw).strip() == "":
            return max(0, min(7, int(default)))
        return max(0, min(7, int(str(raw).strip())))
    except Exception:
        try:
            return max(0, min(7, int(default)))
        except Exception:
            return 1


def _find_next_available_processed_date_file(
    stem: str,
    start_date_str: str,
    max_ahead: int | None = None,
    suffix: str = ".csv",
) -> tuple[Optional[str], Optional[Path]]:
    try:
        import datetime as _dt

        try:
            start = _dt.date.fromisoformat(str(start_date_str))
        except Exception:
            return None, None

        lookahead = _app_lookahead_days() if max_ahead is None else int(max_ahead)
        lookahead = max(0, min(7, int(lookahead)))
        for i in range(1, lookahead + 1):
            cand = start + _dt.timedelta(days=i)
            name = f"{stem}_{cand.isoformat()}{suffix}"
            fp = DATA_PROCESSED_DIR / name
            if not fp.exists():
                try:
                    _maybe_fetch_remote_processed(name)
                except Exception:
                    pass
            if fp.exists():
                return cand.isoformat(), fp
    except Exception:
        pass
    return None, None


def _find_next_available_smart_sim_date(
    start_date_str: str,
    max_ahead: int | None = None,
    prefix: str | None = None,
) -> tuple[Optional[str], list[Path]]:
    try:
        import datetime as _dt

        try:
            start = _dt.date.fromisoformat(str(start_date_str))
        except Exception:
            return None, []

        lookahead = _app_lookahead_days() if max_ahead is None else int(max_ahead)
        lookahead = max(0, min(7, int(lookahead)))
        for i in range(1, lookahead + 1):
            cand = start + _dt.timedelta(days=i)
            files = _load_smart_sim_files_for_authoritative_slate(cand.isoformat(), prefix=prefix)
            if files:
                return cand.isoformat(), files
    except Exception:
        pass
    return None, []


def _load_game_odds_map(date_str: str) -> dict[tuple[str, str], dict[str, Any]]:
    out: dict[tuple[str, str], dict[str, Any]] = {}
    try:
        p = _find_game_odds_for_date(date_str)
        if not p:
            return out
        df = pd.read_csv(p)
        if df is None or df.empty:
            return out

        def _tri(x: Any) -> str:
            t = _get_tricode(str(x))
            return (t or str(x or "").strip().upper()).strip().upper()

        for _, r in df.iterrows():
            ht = _tri(r.get("home_team"))
            at = _tri(r.get("visitor_team"))
            if not ht or not at:
                continue
            out[(ht, at)] = r.to_dict()
    except Exception:
        return out
    return out


def _load_predictions_rows_map(date_str: str) -> dict[tuple[str, str], dict[str, Any]]:
    out: dict[tuple[str, str], dict[str, Any]] = {}
    pred_path = _find_predictions_for_date(date_str)

    def _tri(raw: Any) -> str:
        val = str(raw or "").strip()
        if not val:
            return ""
        tri = _get_tricode(val)
        return str(tri or val).strip().upper()

    if pred_path is None:
        json_path = DATA_PROCESSED_DIR / f"games_predictions_{date_str}.json"
        if not json_path.exists():
            try:
                _maybe_fetch_remote_processed(json_path.name)
            except Exception:
                pass
        payload = _read_json_if_exists(json_path)
        games = payload.get("games") if isinstance(payload, dict) else None
        for game in games or []:
            try:
                if not isinstance(game, dict):
                    continue
                predictions = game.get("predictions") if isinstance(game.get("predictions"), dict) else {}
                periods = predictions.get("periods") if isinstance(predictions.get("periods"), dict) else {}
                halves = periods.get("halves") if isinstance(periods.get("halves"), dict) else {}
                home_tri = _tri(game.get("home_team") or game.get("home"))
                away_tri = _tri(game.get("visitor_team") or game.get("away_team") or game.get("away"))
                if not home_tri or not away_tri:
                    continue
                h1 = halves.get("h1") if isinstance(halves.get("h1"), dict) else {}
                h2 = halves.get("h2") if isinstance(halves.get("h2"), dict) else {}
                out[(home_tri, away_tri)] = {
                    "date": game.get("date") or date_str,
                    "home_team": game.get("home_team") or home_tri,
                    "visitor_team": game.get("visitor_team") or away_tri,
                    "home_win_prob": _safe_float(predictions.get("win_prob")),
                    "home_win_prob_cal": _safe_float(predictions.get("win_prob")),
                    "pred_margin": _safe_float(predictions.get("spread")),
                    "spread_margin": _safe_float(predictions.get("spread")),
                    "pred_total": _safe_float(predictions.get("total")),
                    "totals": _safe_float(predictions.get("total")),
                    "halves_h1_win": _safe_float(h1.get("win")),
                    "halves_h1_margin": _safe_float(h1.get("margin")),
                    "halves_h1_total": _safe_float(h1.get("total")),
                    "halves_h2_win": _safe_float(h2.get("win")),
                    "halves_h2_margin": _safe_float(h2.get("margin")),
                    "halves_h2_total": _safe_float(h2.get("total")),
                }
            except Exception:
                continue
        return out
    try:
        df = pd.read_csv(pred_path)
        if df is None or df.empty:
            return out

        for _, row in df.iterrows():
            home_raw = row.get("home_team") if row.get("home_team") is not None else row.get("home")
            away_raw = row.get("visitor_team")
            if away_raw is None:
                away_raw = row.get("away_team") if row.get("away_team") is not None else row.get("away")
            home_tri = _tri(home_raw)
            away_tri = _tri(away_raw)
            if home_tri and away_tri:
                out[(home_tri, away_tri)] = row.to_dict()
    except Exception:
        return out
    return out


def _build_fallback_smart_sim_object(
    date_str: str,
    home_tri: str,
    away_tri: str,
    prediction_row: dict[str, Any] | None,
    odds_row: dict[str, Any] | None,
) -> dict[str, Any] | None:
    if not isinstance(prediction_row, dict):
        return None

    pred_margin = _safe_float(
        prediction_row.get("spread_margin")
        if prediction_row.get("spread_margin") is not None
        else prediction_row.get("pred_margin")
    )
    total_mean = _safe_float(
        prediction_row.get("totals")
        if prediction_row.get("totals") is not None
        else prediction_row.get("pred_total")
    )
    home_win_prob = _safe_float(
        prediction_row.get("home_win_prob_cal")
        if prediction_row.get("home_win_prob_cal") is not None
        else (
            prediction_row.get("home_win_prob")
            if prediction_row.get("home_win_prob") is not None
            else prediction_row.get("home_win_prob_iso")
        )
    )

    home_mean = None
    away_mean = None
    if total_mean is not None and pred_margin is not None:
        try:
            home_mean = float((float(total_mean) + float(pred_margin)) / 2.0)
            away_mean = float((float(total_mean) - float(pred_margin)) / 2.0)
        except Exception:
            home_mean = None
            away_mean = None

    periods: dict[str, Any] = {}
    for src, dst in (("quarters_q1", "q1"), ("quarters_q2", "q2"), ("quarters_q3", "q3"), ("quarters_q4", "q4"), ("halves_h1", "h1"), ("halves_h2", "h2")):
        win_val = _safe_float(prediction_row.get(f"{src}_win"))
        margin_val = _safe_float(prediction_row.get(f"{src}_margin"))
        total_val = _safe_float(prediction_row.get(f"{src}_total"))
        if win_val is None and margin_val is None and total_val is None:
            continue
        periods[dst] = {
            "p_home_win": win_val,
            "margin_mean": margin_val,
            "total_mean": total_val,
        }

    odds = odds_row or {}

    return {
        "home": home_tri,
        "away": away_tri,
        "date": date_str,
        "game_id": f"{away_tri}@{home_tri}",
        "mode": "prediction_fallback",
        "context": {
            "fallback_source": "predictions_csv",
            "fallback_reason": "missing_smart_sim",
        },
        "market": {
            "market_home_spread": _safe_float(odds.get("home_spread")),
            "market_total": _safe_float(odds.get("total")),
        },
        "score": {
            "p_home_win": home_win_prob,
            "p_home_cover": None,
            "p_total_over": None,
            "home_mean": home_mean,
            "away_mean": away_mean,
            "total_mean": total_mean,
            "margin_mean": pred_margin,
        },
        "periods": periods,
        "players": {"home": [], "away": []},
    }


def _load_props_predictions_map(date_str: str) -> dict[int, dict[str, Any]]:
    out: dict[int, dict[str, Any]] = {}
    p = DATA_PROCESSED_DIR / f"props_predictions_{date_str}.csv"
    if not p.exists():
        try:
            _maybe_fetch_remote_processed(p.name)
        except Exception:
            pass
    try:
        df = _read_csv_if_exists(p)
        if df is None or not isinstance(df, pd.DataFrame) or df.empty:
            return out
        if "player_id" not in df.columns:
            return out
        df = df.copy()
        df["player_id"] = pd.to_numeric(df["player_id"], errors="coerce")
        df = df.dropna(subset=["player_id"]).copy()
        # last row wins
        for _, r in df.iterrows():
            try:
                pid = int(float(r.get("player_id")))
            except Exception:
                continue
            out[pid] = r.to_dict()
        return out
    except Exception:
        return out


def _load_props_recommendations_by_team(date_str: str) -> dict[str, list[dict[str, Any]]]:
    """Load prop recommendations keyed by TEAM_TRICODE.

    Source: data/processed/props_recommendations_YYYY-MM-DD.csv

    The CSV stores python-literal strings like "[{'market': 'ast', ...}]" in columns
    such as plays/top_play. We parse these into structured JSON-safe objects.
    """
    out: dict[str, list[dict[str, Any]]] = {}
    p = DATA_PROCESSED_DIR / f"props_recommendations_{date_str}.csv"
    edges_path = DATA_PROCESSED_DIR / f"props_edges_{date_str}.csv"
    if not p.exists():
        try:
            _maybe_fetch_remote_processed(p.name)
        except Exception:
            pass
    try:
        def _load_from_edges_fallback(df: pd.DataFrame | None) -> dict[str, list[dict[str, Any]]]:
            fallback_out: dict[str, list[dict[str, Any]]] = {}
            if df is None or not isinstance(df, pd.DataFrame) or df.empty:
                return fallback_out

            grouped_rows: dict[tuple[str, str], list[dict[str, Any]]] = {}
            for _, edge_row in df.iterrows():
                try:
                    team = str(edge_row.get("team") or "").strip().upper()
                    player = str(edge_row.get("player") or edge_row.get("player_name") or "").strip()
                    market = str(edge_row.get("stat") or edge_row.get("market") or "").strip().lower()
                    side = str(edge_row.get("side") or "").strip().lower()
                    if not team or not player or not market or not side:
                        continue

                    ev = _safe_float(edge_row.get("ev"))
                    ev_pct = _safe_float(edge_row.get("ev_pct"))
                    if ev_pct is None and ev is not None:
                        ev_pct = float(ev) * 100.0

                    grouped_rows.setdefault((team, player), []).append(
                        {
                            "market": market,
                            "side": side,
                            "line": _safe_float(edge_row.get("line")),
                            "price": _safe_float(edge_row.get("price")),
                            "edge": _safe_float(edge_row.get("edge")),
                            "ev": ev,
                            "ev_pct": ev_pct,
                            "book": _canonical_bookmaker_key(edge_row.get("bookmaker") or edge_row.get("bookmaker_title")) or None,
                            "implied_prob": _safe_float(edge_row.get("implied_prob")),
                            "model_prob": _safe_float(edge_row.get("model_prob")),
                            "player": player,
                            "player_name": player,
                            "team": team,
                            "home_team": None if pd.isna(edge_row.get("home_team")) else edge_row.get("home_team"),
                            "away_team": None if pd.isna(edge_row.get("away_team")) else edge_row.get("away_team"),
                        }
                    )
                except Exception:
                    continue

            def _play_sort_key(play: dict[str, Any]) -> tuple[float, float, float, float]:
                return (
                    float(_safe_float(play.get("ev_pct")) or float("-inf")),
                    float(_safe_float(play.get("edge")) or float("-inf")),
                    float(_safe_float(play.get("price")) or float("-inf")),
                    float(_safe_float(play.get("line")) or float("-inf")),
                )

            for (team, player), plays in grouped_rows.items():
                normalized_plays = sorted(
                    [dict(play) for play in plays if isinstance(play, dict)],
                    key=_play_sort_key,
                    reverse=True,
                )
                if not normalized_plays:
                    continue
                top_play = dict(normalized_plays[0])
                fallback_out.setdefault(team, []).append(
                    {
                        "player": player,
                        "team": team,
                        "plays": normalized_plays,
                        "top_play": top_play,
                        "top_play_reasons": [],
                        "top_play_explain": None,
                        "top_play_baseline": None,
                        "top_play_consensus": _safe_float(top_play.get("line")),
                        "top_play_line_adv": _safe_float(top_play.get("edge")),
                    }
                )

            for team in list(fallback_out.keys()):
                try:
                    fallback_out[team].sort(
                        key=lambda rr: _safe_float(((rr.get("top_play") or {}) if isinstance(rr.get("top_play"), dict) else {}).get("ev_pct"))
                        or float("-inf"),
                        reverse=True,
                    )
                except Exception:
                    pass
            return fallback_out

        df = _read_csv_if_exists(p)
        if df is None or not isinstance(df, pd.DataFrame) or df.empty:
            edges_df = _read_csv_if_exists(edges_path)
            if edges_df is None or not isinstance(edges_df, pd.DataFrame) or edges_df.empty:
                edges_json_path = DATA_PROCESSED_DIR / f"props_edges_{date_str}.json"
                if not edges_json_path.exists():
                    try:
                        _maybe_fetch_remote_processed(edges_json_path.name)
                    except Exception:
                        pass
                edges_payload = _read_json_if_exists(edges_json_path)
                edges_rows = edges_payload.get("edges") if isinstance(edges_payload, dict) else None
                if isinstance(edges_rows, list) and edges_rows:
                    try:
                        edges_df = pd.DataFrame(edges_rows)
                    except Exception:
                        edges_df = None
            return _load_from_edges_fallback(edges_df)

        import ast

        def _parse_lit(x: Any):
            try:
                if x is None:
                    return None
                if isinstance(x, float) and np.isnan(x):
                    return None
                s = str(x).strip()
                if not s or s.lower() == "nan":
                    return None
                return ast.literal_eval(s)
            except Exception:
                return None

        def _norm_play(x: Any) -> dict[str, Any] | None:
            try:
                if not isinstance(x, dict):
                    return None
                outp: dict[str, Any] = {}
                for k in ("market", "side"):
                    if k in x and x.get(k) is not None:
                        outp[k] = str(x.get(k)).strip().lower()
                if "book" in x and x.get("book") is not None:
                    outp["book"] = _canonical_bookmaker_key(x.get("book")) or None
                for k in ("line", "price"):
                    if k in x:
                        outp[k] = _safe_float(x.get(k))
                for k in ("edge", "ev", "ev_pct"):
                    if k in x:
                        outp[k] = _safe_float(x.get(k))
                # Preserve any other fields as-is (jsonable primitives)
                for k, v in x.items():
                    if k in outp:
                        continue
                    if isinstance(v, (str, int, float, bool)) or v is None:
                        outp[k] = v
                if not outp.get("market") or not outp.get("side"):
                    return None
                return outp
            except Exception:
                return None

        def _normalize_plays_all(plays: list[Any]) -> list[dict[str, Any]]:
            """Normalize all plays and drop exact duplicates.

            We intentionally keep multiple books/lines per (market, side) so downstream
            sim-vs-line scoring can select the best available edge.
            """
            try:
                outp: list[dict[str, Any]] = []
                seen: set[tuple[str, str, float | None, str | None, float | None]] = set()
                for raw in plays or []:
                    p2 = _norm_play(raw)
                    if not p2:
                        continue
                    key = (
                        str(p2.get("market") or ""),
                        str(p2.get("side") or ""),
                        _safe_float(p2.get("line")),
                        (str(p2.get("book") or "").strip().lower() or None),
                        _safe_float(p2.get("price")),
                    )
                    if key in seen:
                        continue
                    seen.add(key)
                    outp.append(p2)
                return outp
            except Exception:
                return []

        for _, r in df.iterrows():
            try:
                team = str(r.get("team") or "").strip().upper()
                player = str(r.get("player") or "").strip()
                if not team or not player:
                    continue

                plays = _parse_lit(r.get("plays"))
                if plays is None:
                    plays = _parse_lit(r.get("_plays_list"))
                if not isinstance(plays, list):
                    plays = []
                plays = _normalize_plays_all(plays)

                top_play = _parse_lit(r.get("top_play"))
                if isinstance(top_play, dict):
                    top_play = _norm_play(top_play)
                else:
                    top_play = None
                if top_play is None and plays:
                    top_play = plays[0]

                reasons = _parse_lit(r.get("top_play_reasons"))
                if not isinstance(reasons, list):
                    reasons = []

                row = {
                    "player": player,
                    "team": team,
                    "plays": plays,
                    "top_play": top_play,
                    "top_play_reasons": reasons,
                    "top_play_explain": (None if pd.isna(r.get("top_play_explain")) else r.get("top_play_explain")) if "top_play_explain" in df.columns else None,
                    "top_play_baseline": _safe_float(r.get("top_play_baseline")) if "top_play_baseline" in df.columns else None,
                    "top_play_consensus": _safe_float(r.get("top_play_consensus")),
                    "top_play_line_adv": _safe_float(r.get("top_play_line_adv")),
                }
                out.setdefault(team, []).append(row)
            except Exception:
                continue

        # Stable sort: best EV% first when available, else keep file order.
        for t in list(out.keys()):
            try:
                out[t].sort(
                    key=lambda rr: _safe_float(((rr.get("top_play") or {}) if isinstance(rr.get("top_play"), dict) else {}).get("ev_pct"))
                    or float("-inf"),
                    reverse=True,
                )
            except Exception:
                pass

            # De-dupe to one row per player (keep best/top sorted row)
            try:
                seen_players: set[str] = set()
                uniq: list[dict[str, Any]] = []
                for rr in out.get(t) or []:
                    nm = str(rr.get("player") or "").strip().upper()
                    if not nm or nm in seen_players:
                        continue
                    seen_players.add(nm)
                    uniq.append(rr)
                out[t] = uniq
            except Exception:
                pass

        if not out:
            edges_df = _read_csv_if_exists(edges_path)
            return _load_from_edges_fallback(edges_df)

        return out
    except Exception:
        try:
            edges_df = _read_csv_if_exists(edges_path)
            return _load_from_edges_fallback(edges_df)
        except Exception:
            return out


def _load_props_predictions_name_lookup(date_str: str) -> dict[tuple[str, str], dict[str, Any]]:
    out: dict[tuple[str, str], dict[str, Any]] = {}
    p = DATA_PROCESSED_DIR / f"props_predictions_{date_str}.csv"
    if not p.exists():
        try:
            _maybe_fetch_remote_processed(p.name)
        except Exception:
            pass
    try:
        df = _read_csv_if_exists(p)
        if df is None or not isinstance(df, pd.DataFrame) or df.empty:
            return out
        name_col = "player_name" if "player_name" in df.columns else ("player" if "player" in df.columns else None)
        team_col = "team" if "team" in df.columns else None
        if not name_col or not team_col:
            return out
        for _, row in df.iterrows():
            team_tri = str(row.get(team_col) or "").strip().upper()
            player_name = str(row.get(name_col) or "").strip()
            player_key = _norm_player_name(player_name)
            if not team_tri or not player_key:
                continue
            out[(team_tri, player_key)] = row.to_dict()
        return out
    except Exception:
        return out


def _load_props_recommendations_top_by_game_snapshot(date_str: str) -> dict[str, Any] | None:
    p = DATA_PROCESSED_DIR / f"props_recommendations_top_by_game_{date_str}.json"
    if not p.exists():
        try:
            _maybe_fetch_remote_processed(p.name)
        except Exception:
            pass
    try:
        if not p.exists():
            return None
        with p.open("r", encoding="utf-8") as f:
            payload = json.load(f)
        return payload if isinstance(payload, dict) else None
    except Exception:
        return None


def _pick_top_players(players: list[dict[str, Any]], stat_key: str, n: int = 6) -> list[dict[str, Any]]:
    def key_fn(pr: dict[str, Any]):
        return _safe_float(pr.get(stat_key)) or float("-inf")

    arr = [p for p in (players or []) if isinstance(p, dict)]
    arr.sort(key=key_fn, reverse=True)
    return arr[: max(0, int(n))]


def _best_bets_local_now_naive() -> datetime:
    try:
        tz_name = (os.environ.get("APP_TZ") or "America/New_York").strip()
        try:
            from zoneinfo import ZoneInfo

            return datetime.now(ZoneInfo(tz_name)).replace(tzinfo=None, microsecond=0)
        except Exception:
            tz_offsets = {
                "America/New_York": -5,
                "US/Eastern": -5,
                "America/Chicago": -6,
                "US/Central": -6,
                "America/Denver": -7,
                "US/Mountain": -7,
                "America/Los_Angeles": -8,
                "US/Pacific": -8,
            }
            off = tz_offsets.get(tz_name)
            if off is None:
                try:
                    off = int((os.environ.get("APP_TZ_OFFSET_HOURS") or "-5").strip())
                except Exception:
                    off = -5
            return (datetime.utcnow() + timedelta(hours=int(off))).replace(microsecond=0)
    except Exception:
        return datetime.now().replace(microsecond=0)


def _best_bets_local_start_dt(value: Any) -> datetime | None:
    try:
        if value in (None, ""):
            return None
        ts = pd.to_datetime(value, errors="coerce", utc=True)
        if pd.isna(ts):
            ts = pd.to_datetime(value, errors="coerce")
            if pd.isna(ts):
                return None
            if getattr(ts, "tzinfo", None) is None:
                return ts.to_pydatetime().replace(microsecond=0)
        tz_name = (os.environ.get("APP_TZ") or "America/New_York").strip()
        try:
            from zoneinfo import ZoneInfo

            ts = ts.tz_convert(ZoneInfo(tz_name))
        except Exception:
            pass
        return ts.to_pydatetime().replace(tzinfo=None, microsecond=0)
    except Exception:
        return None


def _best_bets_local_start_label(value: Any) -> str | None:
    dt_local = _best_bets_local_start_dt(value)
    if dt_local is None:
        return None
    try:
        return dt_local.strftime("%Y-%m-%d %H:%M")
    except Exception:
        return None


def _best_bets_sentence(text: Any) -> str:
    s = str(text or "").strip()
    if not s:
        return ""
    if s.endswith((".", "!", "?")):
        return s
    return f"{s}."


def _best_bets_unique_strings(items: list[Any]) -> list[str]:
    out: list[str] = []
    seen: set[str] = set()
    for raw in items or []:
        s = _best_bets_sentence(raw)
        if not s:
            continue
        key = s.strip().lower()
        if key in seen:
            continue
        seen.add(key)
        out.append(s)
    return out


def _best_bets_unique_names(items: list[Any]) -> list[str]:
    out: list[str] = []
    seen: set[str] = set()
    for raw in items or []:
        s = str(raw or "").strip()
        if not s:
            continue
        key = s.lower()
        if key in seen:
            continue
        seen.add(key)
        out.append(s)
    return out


def _best_bets_clamp01(value: Any) -> float:
    v = _safe_float(value)
    if v is None:
        return 0.0
    return float(max(0.0, min(1.0, v)))


def _best_bets_prob_from_ev(ev: Any, price: Any) -> float | None:
    evf = _safe_float(ev)
    dec = _american_to_decimal(price)
    if evf is None or dec is None or dec <= 0:
        return None
    try:
        return float(max(0.01, min(0.99, (float(evf) + 1.0) / float(dec))))
    except Exception:
        return None


def _best_bets_profit_to_american(profit_units: float | None) -> int | None:
    try:
        if profit_units is None:
            return None
        pu = float(profit_units)
        if not np.isfinite(pu) or pu <= 0.0:
            return None
        if pu >= 1.0:
            return int(round(pu * 100.0))
        return -int(round(100.0 / pu))
    except Exception:
        return None


def _best_bets_combo_profit_units(combo: tuple[dict[str, Any], ...]) -> float | None:
    total_dec = 1.0
    for leg in combo:
        dec = _american_to_decimal(leg.get("price"))
        if dec is None:
            return None
        total_dec *= float(dec)
    return float(total_dec - 1.0)


def _best_bets_priority_sort_key(row: dict[str, Any]) -> tuple[float, float, float, float]:
    return (
        float(row.get("recommendation_priority_score") or 0.0),
        float(row.get("score") or 0.0),
        float(row.get("p_win") or 0.0),
        float(row.get("ev_pct") if row.get("ev_pct") is not None else (float(row.get("ev") or 0.0) * 100.0)),
    )


def _best_bets_build_parlays(
    ranked_candidates: list[dict[str, Any]],
    *,
    parlay_size: int,
    max_parlays: int,
) -> list[dict[str, Any]]:
    parlays: list[dict[str, Any]] = []
    if parlay_size < 2:
        return parlays

    for combo in combinations(ranked_candidates, parlay_size):
        game_keys = [str(leg.get("game_key") or "") for leg in combo]
        if any(not key for key in game_keys):
            continue
        if len(game_keys) != len(set(game_keys)):
            continue
        player_keys = [str(leg.get("player_key") or "") for leg in combo if leg.get("player_key")]
        if player_keys and len(player_keys) != len(set(player_keys)):
            continue

        combined_p = 1.0
        avg_score = 0.0
        avg_priority = 0.0
        min_leg_score = 100.0
        min_priority = 100.0
        valid = True
        for leg in combo:
            p_win = _safe_float(leg.get("p_win"))
            score = _safe_float(leg.get("score"))
            priority = _safe_float(leg.get("recommendation_priority_score"))
            if p_win is None or score is None or priority is None:
                valid = False
                break
            combined_p *= float(max(0.0, min(1.0, p_win)))
            avg_score += float(score)
            avg_priority += float(priority)
            min_leg_score = min(min_leg_score, float(score))
            min_priority = min(min_priority, float(priority))
        if not valid:
            continue

        profit_units = _best_bets_combo_profit_units(combo)
        if profit_units is None:
            continue

        avg_score /= float(parlay_size)
        avg_priority /= float(parlay_size)
        expected_units = combined_p * float(profit_units) - (1.0 - combined_p)
        parlays.append(
            {
                "legs": [dict(leg) for leg in combo],
                "combined_p_win": round(combined_p, 4),
                "avg_leg_score": round(avg_score, 1),
                "min_leg_score": round(min_leg_score, 1),
                "avg_recommendation_priority": round(avg_priority, 1),
                "min_recommendation_priority": round(min_priority, 1),
                "profit_units_per_1_risk": round(float(profit_units), 3),
                "expected_units_per_1_risk": round(float(expected_units), 3),
                "approx_american_odds": _best_bets_profit_to_american(float(profit_units)),
            }
        )

    parlays.sort(
        key=lambda row: (
            -float(row.get("avg_recommendation_priority") or 0.0),
            -float(row.get("min_recommendation_priority") or 0.0),
            -float(row.get("combined_p_win") or 0.0),
            -float(row.get("expected_units_per_1_risk") or 0.0),
            -float(row.get("min_leg_score") or 0.0),
            -float(row.get("avg_leg_score") or 0.0),
        )
    )
    return parlays[: max(1, int(max_parlays))]


def _best_bets_load_injury_snapshot(date_str: str) -> dict[str, dict[str, Any]]:
    counts: dict[str, int] = {}
    impact: dict[str, float] = {}
    key_outs: dict[str, list[str]] = {}
    path = DATA_PROCESSED_DIR / f"injuries_counts_{date_str}.json"
    if not path.exists():
        try:
            _maybe_fetch_remote_processed(path.name)
        except Exception:
            pass
    if not path.exists():
        return {"counts": counts, "impact": impact, "key_outs": key_outs}
    try:
        obj = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        obj = {}

    try:
        for team, raw_count in ((obj or {}).get("team_counts") or {}).items():
            tri = (_get_tricode(team) or str(team or "").strip().upper())
            try:
                counts[tri] = int(float(raw_count))
            except Exception:
                continue
    except Exception:
        counts = {}

    try:
        for team, raw_impact in ((obj or {}).get("team_impact") or {}).items():
            tri = (_get_tricode(team) or str(team or "").strip().upper())
            imp = _safe_float(raw_impact)
            if tri and imp is not None:
                impact[tri] = float(imp)
    except Exception:
        impact = {}

    try:
        for team, names in ((obj or {}).get("team_key_outs") or {}).items():
            tri = (_get_tricode(team) or str(team or "").strip().upper())
            if not tri or not isinstance(names, list):
                continue
            key_outs[tri] = _best_bets_unique_names([str(name or "").strip() for name in names])[:3]
    except Exception:
        key_outs = {}

    try:
        players = (obj or {}).get("players") or []
        for row in players:
            if not isinstance(row, dict):
                continue
            team = (_get_tricode(row.get("team")) or str(row.get("team") or "").strip().upper())
            status = str(row.get("status") or row.get("injury_status") or "").strip().upper()
            player = str(row.get("player") or row.get("player_name") or "").strip()
            if not team or not player or status not in {"OUT", "DOUBTFUL", "SUSPENDED", "INACTIVE", "REST"}:
                continue
            key_outs.setdefault(team, []).append(player)
        for team, names in list(key_outs.items()):
            key_outs[team] = _best_bets_unique_names(names)[:3]
            if team not in counts:
                counts[team] = len(key_outs[team])
    except Exception:
        pass

    return {"counts": counts, "impact": impact, "key_outs": key_outs}


def _best_bets_pick_first_numeric(mapping: Any, *names: str) -> float | None:
    if mapping is None:
        return None
    for name in names:
        try:
            value = mapping.get(name)  # type: ignore[attr-defined]
        except Exception:
            value = None
        number = _safe_float(value)
        if number is not None:
            return float(number)
    return None


@lru_cache(maxsize=16)
def _load_best_bets_props_team_scoring_context(date_str: str) -> dict[str, dict[str, Any]]:
    path = DATA_PROCESSED_DIR / f"props_predictions_{date_str}.csv"
    if not path.exists():
        try:
            _maybe_fetch_remote_processed(path.name)
        except Exception:
            pass
    df = _read_csv_if_exists(path)
    out: dict[str, dict[str, Any]] = {}
    if not isinstance(df, pd.DataFrame) or df is None or df.empty:
        return out

    for _, raw in df.iterrows():
        team_key = (_get_tricode(raw.get("team")) or str(raw.get("team") or "").strip().upper())
        if not team_key:
            continue
        entry = out.setdefault(
            team_key,
            {"points_sum": 0.0, "minutes_sum": 0.0, "players": 0, "players_with_points": 0},
        )
        entry["players"] = int(entry.get("players") or 0) + 1

        pts_mean = _best_bets_pick_first_numeric(raw, "pts_mean", "pred_pts", "points_mean", "pred_points")
        if pts_mean is not None and float(pts_mean) >= 0.0:
            entry["points_sum"] = float(entry.get("points_sum") or 0.0) + float(pts_mean)
            entry["players_with_points"] = int(entry.get("players_with_points") or 0) + 1

        min_mean = _best_bets_pick_first_numeric(raw, "min_mean", "pred_min", "minutes_mean", "pred_minutes")
        if min_mean is not None and float(min_mean) > 0.0:
            entry["minutes_sum"] = float(entry.get("minutes_sum") or 0.0) + float(min_mean)

    for team_key, entry in out.items():
        regulation_team_minutes = max(1.0, float(getattr(LEAGUE, "regulation_team_minutes", 240.0)))
        minutes_sum = max(0.0, min(regulation_team_minutes, float(entry.get("minutes_sum") or 0.0)))
        coverage = _best_bets_clamp01(minutes_sum / regulation_team_minutes) if minutes_sum > 0.0 else 0.0
        points_sum = max(0.0, float(entry.get("points_sum") or 0.0))
        players_with_points = int(entry.get("players_with_points") or 0)

        prop_team_total = None
        if points_sum > 0.0:
            if minutes_sum >= (regulation_team_minutes / 2.0):
                prop_team_total = float(points_sum / max(0.55, coverage))
            else:
                per_min = float(points_sum / max(1.0, minutes_sum)) if minutes_sum > 0.0 else 0.0
                prop_team_total = float(points_sum + (per_min * max(0.0, regulation_team_minutes - minutes_sum) * 0.55))
            prop_team_total = float(max(70.0, min(140.0, prop_team_total)))

        blend_weight = max(0.0, min(0.60, (coverage - 0.45) / 0.55)) if coverage > 0.45 else 0.0
        if players_with_points < 7:
            blend_weight *= 0.6

        entry["minutes_sum"] = minutes_sum
        entry["minutes_coverage"] = round(float(coverage), 4)
        entry["team_total_points"] = prop_team_total
        entry["blend_weight"] = round(float(max(0.0, min(0.60, blend_weight))), 4)
        entry["team"] = team_key

    return out


def _best_bets_adjust_matchup_total(
    *,
    raw_total: float | None,
    raw_margin: float | None,
    market_total: float | None,
    home_prop_ctx: dict[str, Any] | None,
    away_prop_ctx: dict[str, Any] | None,
    home_off: float | None,
    away_off: float | None,
    home_def: float | None,
    away_def: float | None,
    league_off: float | None,
    league_def: float | None,
    home_recent_offense: float | None,
    away_recent_offense: float | None,
    home_recent_allowed: float | None,
    away_recent_allowed: float | None,
    league_recent_offense: float | None,
    league_recent_allowed: float | None,
    game_pace: float | None,
    league_pace: float | None,
) -> dict[str, float | None]:
    home_base = None
    away_base = None
    if raw_total is not None and raw_margin is not None:
        try:
            home_base = 0.5 * (float(raw_total) + float(raw_margin))
            away_base = 0.5 * (float(raw_total) - float(raw_margin))
        except Exception:
            home_base = None
            away_base = None

    home_prop_total = _safe_float((home_prop_ctx or {}).get("team_total_points")) if isinstance(home_prop_ctx, dict) else None
    away_prop_total = _safe_float((away_prop_ctx or {}).get("team_total_points")) if isinstance(away_prop_ctx, dict) else None
    home_prop_weight = _safe_float((home_prop_ctx or {}).get("blend_weight")) if isinstance(home_prop_ctx, dict) else None
    away_prop_weight = _safe_float((away_prop_ctx or {}).get("blend_weight")) if isinstance(away_prop_ctx, dict) else None
    home_prop_weight = 0.0 if home_prop_weight is None else float(max(0.0, min(0.60, home_prop_weight)))
    away_prop_weight = 0.0 if away_prop_weight is None else float(max(0.0, min(0.60, away_prop_weight)))

    home_prop_blend = home_base
    if home_prop_total is not None:
        if home_base is not None:
            home_prop_blend = float((1.0 - home_prop_weight) * float(home_base) + home_prop_weight * float(home_prop_total))
        else:
            home_prop_blend = float(home_prop_total)

    away_prop_blend = away_base
    if away_prop_total is not None:
        if away_base is not None:
            away_prop_blend = float((1.0 - away_prop_weight) * float(away_base) + away_prop_weight * float(away_prop_total))
        else:
            away_prop_blend = float(away_prop_total)

    prop_blended_total = raw_total
    if home_prop_blend is not None and away_prop_blend is not None:
        prop_blended_total = float(home_prop_blend + away_prop_blend)

    prop_blended_margin = None
    if home_prop_blend is not None and away_prop_blend is not None:
        prop_blended_margin = float(home_prop_blend - away_prop_blend)

    matchup_adjustment = 0.0
    pace_gap = None
    if game_pace is not None and league_pace is not None:
        pace_gap = float(game_pace) - float(league_pace)
        matchup_adjustment += 0.28 * float(pace_gap)
    if home_off is not None and away_off is not None and league_off is not None:
        matchup_adjustment += 0.10 * ((float(home_off) - float(league_off)) + (float(away_off) - float(league_off)))
    if home_def is not None and away_def is not None and league_def is not None:
        matchup_adjustment += 0.10 * ((float(home_def) - float(league_def)) + (float(away_def) - float(league_def)))
    if home_recent_offense is not None and away_recent_offense is not None and league_recent_offense is not None:
        matchup_adjustment += 0.06 * ((float(home_recent_offense) - float(league_recent_offense)) + (float(away_recent_offense) - float(league_recent_offense)))
    if home_recent_allowed is not None and away_recent_allowed is not None and league_recent_allowed is not None:
        matchup_adjustment += 0.06 * ((float(home_recent_allowed) - float(league_recent_allowed)) + (float(away_recent_allowed) - float(league_recent_allowed)))
    matchup_adjustment = float(max(-8.0, min(8.0, matchup_adjustment)))

    matchup_margin_adjustment = 0.0
    if home_off is not None and away_off is not None:
        matchup_margin_adjustment += 0.12 * (float(home_off) - float(away_off))
    if home_def is not None and away_def is not None:
        matchup_margin_adjustment += 0.10 * (float(away_def) - float(home_def))
    if home_recent_offense is not None and away_recent_offense is not None:
        matchup_margin_adjustment += 0.07 * (float(home_recent_offense) - float(away_recent_offense))
    if home_recent_allowed is not None and away_recent_allowed is not None:
        matchup_margin_adjustment += 0.07 * (float(away_recent_allowed) - float(home_recent_allowed))
    matchup_margin_adjustment = float(max(-6.0, min(6.0, matchup_margin_adjustment)))

    adjusted_margin = prop_blended_margin if prop_blended_margin is not None else raw_margin
    if adjusted_margin is not None:
        adjusted_margin = float(adjusted_margin) + float(matchup_margin_adjustment)
        if raw_margin is not None:
            adjusted_margin = float(max(float(raw_margin) - 7.0, min(float(raw_margin) + 7.0, float(adjusted_margin))))

    adjusted_total = prop_blended_total
    if adjusted_total is not None:
        adjusted_total = float(adjusted_total) + float(matchup_adjustment)
        if market_total is not None:
            adjusted_total = float((0.90 * float(adjusted_total)) + (0.10 * float(market_total)))
        if raw_total is not None:
            adjusted_total = float(max(float(raw_total) - 12.0, min(float(raw_total) + 12.0, float(adjusted_total))))

    home_adjusted_total = home_prop_blend
    away_adjusted_total = away_prop_blend
    if adjusted_total is not None and adjusted_margin is not None:
        home_adjusted_total = float(0.5 * (float(adjusted_total) + float(adjusted_margin)))
        away_adjusted_total = float(0.5 * (float(adjusted_total) - float(adjusted_margin)))

    return {
        "raw_margin": raw_margin,
        "raw_total": raw_total,
        "home_base_total": home_base,
        "away_base_total": away_base,
        "home_prop_total": home_prop_total,
        "away_prop_total": away_prop_total,
        "home_prop_blend": home_prop_blend,
        "away_prop_blend": away_prop_blend,
        "home_adjusted_total": home_adjusted_total,
        "away_adjusted_total": away_adjusted_total,
        "prop_blended_margin": prop_blended_margin,
        "prop_blended_total": prop_blended_total,
        "matchup_margin_adjustment": matchup_margin_adjustment,
        "adjusted_margin": adjusted_margin,
        "matchup_adjustment": matchup_adjustment,
        "adjusted_total": adjusted_total,
        "pace_gap": pace_gap,
        "home_prop_weight": home_prop_weight,
        "away_prop_weight": away_prop_weight,
    }


def _best_bets_margin_to_home_win_prob(
    margin: float | None,
    raw_home_win_prob: float | None = None,
) -> float | None:
    if margin is None and raw_home_win_prob is None:
        return None

    spread_prob = None
    if margin is not None:
        try:
            spread_prob = 1.0 / (1.0 + math.exp(-float(margin) / 6.0))
        except Exception:
            spread_prob = None

    out = spread_prob
    if raw_home_win_prob is not None and spread_prob is not None:
        out = (0.75 * float(raw_home_win_prob)) + (0.25 * float(spread_prob))
    elif raw_home_win_prob is not None:
        out = float(raw_home_win_prob)

    if out is None:
        return None
    return float(max(0.03, min(0.97, float(out))))


def _load_best_bets_game_context(date_str: str) -> dict[str, Any]:
    path = DATA_PROCESSED_DIR / f"predictions_{date_str}.csv"
    if not path.exists():
        try:
            _maybe_fetch_remote_processed(path.name)
        except Exception:
            pass
    df = _read_csv_if_exists(path)
    by_pair: dict[tuple[str, str], dict[str, Any]] = {}
    by_team: dict[str, dict[str, Any]] = {}
    total_vals: list[float] = []
    if not isinstance(df, pd.DataFrame) or df is None or df.empty:
        return {"by_pair": by_pair, "by_team": by_team, "slate_total_median": None}

    recent_offense_avgs, _recent_offense_ranks = _compute_team_offense_stats(date_str)
    allowed_avgs, _allowed_ranks = _compute_team_allowed_stats(date_str)
    team_advanced = _load_team_advanced_stats_frame(date_str)
    props_team_scoring = _load_best_bets_props_team_scoring_context(date_str)

    advanced_by_team: dict[str, dict[str, float | None]] = {}
    league_advanced: dict[str, float | None] = {"pace": None, "off_rtg": None, "def_rtg": None}
    if isinstance(team_advanced, pd.DataFrame) and not team_advanced.empty:
        for _, adv_row in team_advanced.iterrows():
            team_key = str(adv_row.get("team") or "").strip().upper()
            if not team_key:
                continue
            advanced_by_team[team_key] = {
                "pace": _safe_float(adv_row.get("pace")),
                "off_rtg": _safe_float(adv_row.get("off_rtg")),
                "def_rtg": _safe_float(adv_row.get("def_rtg")),
            }
        for col in ("pace", "off_rtg", "def_rtg"):
            if col not in team_advanced.columns:
                continue
            series = pd.to_numeric(team_advanced[col], errors="coerce").replace([np.inf, -np.inf], np.nan).dropna()
            if not series.empty:
                league_advanced[col] = float(series.mean())

    recent_allowed_pts: dict[str, float] = {}
    for team_key, stats in (allowed_avgs or {}).items():
        pts_allowed = _safe_float((stats or {}).get("pts"))
        if pts_allowed is None:
            continue
        recent_allowed_pts[str(team_key or "").strip().upper()] = float(pts_allowed)

    league_recent_offense = None
    recent_offense_vals = [float(v) for v in (recent_offense_avgs or {}).values() if v is not None and np.isfinite(float(v))]
    if recent_offense_vals:
        league_recent_offense = float(np.mean(recent_offense_vals))

    league_recent_allowed = None
    recent_allowed_vals = [float(v) for v in recent_allowed_pts.values() if v is not None and np.isfinite(float(v))]
    if recent_allowed_vals:
        league_recent_allowed = float(np.mean(recent_allowed_vals))

    for _, r in df.iterrows():
        home = str(r.get("home_team") or r.get("home") or "").strip()
        away = str(r.get("visitor_team") or r.get("away_team") or r.get("away") or "").strip()
        if not home or not away:
            continue
        home_tri = (_get_tricode(home) or home.strip().upper())
        away_tri = (_get_tricode(away) or away.strip().upper())
        home_adv = _best_bets_team_lookup(advanced_by_team, home_tri, home) or {}
        away_adv = _best_bets_team_lookup(advanced_by_team, away_tri, away) or {}

        home_pace = _safe_float((home_adv or {}).get("pace"))
        away_pace = _safe_float((away_adv or {}).get("pace"))
        game_pace = None
        try:
            if home_pace is not None and away_pace is not None:
                game_pace = float(0.5 * (float(home_pace) + float(away_pace)))
        except Exception:
            game_pace = None

        raw_margin = _safe_float(r.get("spread_margin") if r.get("spread_margin") is not None else r.get("pred_margin"))
        raw_total = _safe_float(r.get("totals") if r.get("totals") is not None else r.get("pred_total"))
        market_total = _safe_float(r.get("total"))
        home_recent_offense = _safe_float(_best_bets_team_lookup(recent_offense_avgs, home_tri, home))
        away_recent_offense = _safe_float(_best_bets_team_lookup(recent_offense_avgs, away_tri, away))
        home_recent_allowed = _safe_float(_best_bets_team_lookup(recent_allowed_pts, home_tri, home))
        away_recent_allowed = _safe_float(_best_bets_team_lookup(recent_allowed_pts, away_tri, away))
        total_parts = _best_bets_adjust_matchup_total(
            raw_total=raw_total,
            raw_margin=raw_margin,
            market_total=market_total,
            home_prop_ctx=props_team_scoring.get(home_tri),
            away_prop_ctx=props_team_scoring.get(away_tri),
            home_off=_safe_float((home_adv or {}).get("off_rtg")),
            away_off=_safe_float((away_adv or {}).get("off_rtg")),
            home_def=_safe_float((home_adv or {}).get("def_rtg")),
            away_def=_safe_float((away_adv or {}).get("def_rtg")),
            league_off=_safe_float(league_advanced.get("off_rtg")),
            league_def=_safe_float(league_advanced.get("def_rtg")),
            home_recent_offense=home_recent_offense,
            away_recent_offense=away_recent_offense,
            home_recent_allowed=home_recent_allowed,
            away_recent_allowed=away_recent_allowed,
            league_recent_offense=league_recent_offense,
            league_recent_allowed=league_recent_allowed,
            game_pace=game_pace,
            league_pace=_safe_float(league_advanced.get("pace")),
        )
        adjusted_total = _safe_float(total_parts.get("adjusted_total"))
        adjusted_margin = _safe_float(total_parts.get("adjusted_margin"))
        raw_home_win_prob = _safe_float(
            r.get("home_win_prob_cal")
            if r.get("home_win_prob_cal") is not None
            else (r.get("home_win_prob") if r.get("home_win_prob") is not None else r.get("home_win_prob_iso"))
        )
        adjusted_home_win_prob = _best_bets_margin_to_home_win_prob(adjusted_margin, raw_home_win_prob)
        if adjusted_total is not None:
            total_vals.append(float(adjusted_total))
        elif raw_total is not None:
            total_vals.append(float(raw_total))
        ctx = {
            "home_team": home,
            "away_team": away,
            "home_tri": home_tri,
            "away_tri": away_tri,
            "pred_margin": adjusted_margin if adjusted_margin is not None else raw_margin,
            "pred_margin_raw": raw_margin,
            "pred_margin_adjusted": adjusted_margin,
            "pred_margin_prop_blend": _safe_float(total_parts.get("prop_blended_margin")),
            "pred_margin_matchup_adjustment": _safe_float(total_parts.get("matchup_margin_adjustment")),
            "pred_total": adjusted_total if adjusted_total is not None else raw_total,
            "pred_total_raw": raw_total,
            "pred_total_adjusted": adjusted_total,
            "pred_total_prop_blend": _safe_float(total_parts.get("prop_blended_total")),
            "pred_total_matchup_adjustment": _safe_float(total_parts.get("matchup_adjustment")),
            "pred_total_pace_gap": _safe_float(total_parts.get("pace_gap")),
            "home_pred_points": _safe_float(total_parts.get("home_adjusted_total")) if _safe_float(total_parts.get("home_adjusted_total")) is not None else (_safe_float(total_parts.get("home_prop_blend")) if _safe_float(total_parts.get("home_prop_blend")) is not None else _safe_float(total_parts.get("home_base_total"))),
            "away_pred_points": _safe_float(total_parts.get("away_adjusted_total")) if _safe_float(total_parts.get("away_adjusted_total")) is not None else (_safe_float(total_parts.get("away_prop_blend")) if _safe_float(total_parts.get("away_prop_blend")) is not None else _safe_float(total_parts.get("away_base_total"))),
            "home_win_prob": adjusted_home_win_prob if adjusted_home_win_prob is not None else raw_home_win_prob,
            "home_win_prob_raw": raw_home_win_prob,
            "home_win_prob_adjusted": adjusted_home_win_prob,
            "commence_time": r.get("commence_time") if r.get("commence_time") not in (None, "") else r.get("start_time"),
            "home_ml": _safe_float(r.get("home_ml")),
            "away_ml": _safe_float(r.get("away_ml")),
            "home_spread": _safe_float(r.get("home_spread")),
            "away_spread": _safe_float(r.get("away_spread")),
            "market_total": market_total,
            "league_pace": _safe_float(league_advanced.get("pace")),
            "league_off_rtg": _safe_float(league_advanced.get("off_rtg")),
            "league_def_rtg": _safe_float(league_advanced.get("def_rtg")),
            "home_pace": home_pace,
            "away_pace": away_pace,
            "game_pace": game_pace,
            "home_off_rtg": _safe_float((home_adv or {}).get("off_rtg")),
            "home_def_rtg": _safe_float((home_adv or {}).get("def_rtg")),
            "away_off_rtg": _safe_float((away_adv or {}).get("off_rtg")),
            "away_def_rtg": _safe_float((away_adv or {}).get("def_rtg")),
            "home_recent_offense": home_recent_offense,
            "away_recent_offense": away_recent_offense,
            "home_recent_allowed_pts": home_recent_allowed,
            "away_recent_allowed_pts": away_recent_allowed,
            "league_recent_offense": league_recent_offense,
            "league_recent_allowed_pts": league_recent_allowed,
            "home_prop_points_sum": _safe_float((props_team_scoring.get(home_tri) or {}).get("points_sum")),
            "away_prop_points_sum": _safe_float((props_team_scoring.get(away_tri) or {}).get("points_sum")),
            "home_prop_minutes_coverage": _safe_float((props_team_scoring.get(home_tri) or {}).get("minutes_coverage")),
            "away_prop_minutes_coverage": _safe_float((props_team_scoring.get(away_tri) or {}).get("minutes_coverage")),
            "home_prop_blend_weight": _safe_float((props_team_scoring.get(home_tri) or {}).get("blend_weight")),
            "away_prop_blend_weight": _safe_float((props_team_scoring.get(away_tri) or {}).get("blend_weight")),
        }
        for key in {
            (home.upper(), away.upper()),
            (home_tri.upper(), away_tri.upper()),
        }:
            by_pair[key] = ctx
        for key in {home.upper(), away.upper(), home_tri.upper(), away_tri.upper()}:
            by_team[key] = ctx

    slate_total_median = None
    if total_vals:
        try:
            slate_total_median = float(np.median(total_vals))
        except Exception:
            slate_total_median = None
    return {"by_pair": by_pair, "by_team": by_team, "slate_total_median": slate_total_median}


def _load_best_bets_props_prediction_lookup(date_str: str) -> dict[tuple[str, str], dict[str, Any]]:
    path = DATA_PROCESSED_DIR / f"props_predictions_{date_str}.csv"
    if not path.exists():
        try:
            _maybe_fetch_remote_processed(path.name)
        except Exception:
            pass
    df = _read_csv_if_exists(path)
    out: dict[tuple[str, str], dict[str, Any]] = {}
    if not isinstance(df, pd.DataFrame) or df is None or df.empty:
        return out

    for _, r in df.iterrows():
        player = str(r.get("player_name") or r.get("player") or "").strip()
        team = (_get_tricode(r.get("team")) or str(r.get("team") or "").strip().upper())
        if not player or not team:
            continue
        row = r.to_dict()
        row["team_tricode"] = team
        row["player_key"] = _norm_player_name(player)
        out[(row["player_key"], team)] = row
    return out


def _best_bets_prop_reason_label(market: str) -> str:
    return {
        "pts": "points",
        "reb": "rebounds",
        "ast": "assists",
        "threes": "threes",
        "pra": "PRA",
        "pr": "points + rebounds",
        "pa": "points + assists",
        "ra": "rebounds + assists",
        "stl": "steals",
        "blk": "blocks",
        "tov": "turnovers",
    }.get(str(market or "").strip().lower(), str(market or "").strip().lower())


def _best_bets_prop_home_flag(value: Any) -> bool | None:
    if isinstance(value, (bool, np.bool_)):
        return bool(value)
    numeric = _safe_float(value)
    if numeric is not None:
        return bool(float(numeric) > 0.0)
    text = str(value or "").strip().lower()
    if text in {"1", "true", "yes", "home", "h"}:
        return True
    if text in {"0", "false", "no", "away", "road", "a"}:
        return False
    return None


@lru_cache(maxsize=1)
def _load_best_bets_player_logs_frame() -> pd.DataFrame:
    path = DATA_PROCESSED_DIR / "player_logs.csv"
    if not path.exists():
        return pd.DataFrame()

    wanted = {
        "PLAYER_NAME",
        "TEAM_ABBREVIATION",
        "GAME_DATE",
        "MATCHUP",
        "MIN",
        "PTS",
        "REB",
        "AST",
        "FG3M",
        "STL",
        "BLK",
        "TOV",
    }
    try:
        df = pd.read_csv(path, usecols=lambda c: str(c).strip().upper() in wanted)
    except Exception:
        return pd.DataFrame()
    if df is None or df.empty:
        return pd.DataFrame()

    cols = {str(c).strip().upper(): c for c in df.columns}
    rename_map: dict[str, str] = {}
    for source, target in (
        ("PLAYER_NAME", "player_name"),
        ("TEAM_ABBREVIATION", "team_abbr"),
        ("GAME_DATE", "game_date"),
        ("MATCHUP", "matchup"),
        ("MIN", "min"),
        ("PTS", "pts"),
        ("REB", "reb"),
        ("AST", "ast"),
        ("FG3M", "threes"),
        ("STL", "stl"),
        ("BLK", "blk"),
        ("TOV", "tov"),
    ):
        actual = cols.get(source)
        if actual:
            rename_map[actual] = target
    try:
        df = df.rename(columns=rename_map).copy()
    except Exception:
        return pd.DataFrame()
    if "player_name" not in df.columns or "team_abbr" not in df.columns:
        return pd.DataFrame()

    df["player_name"] = df["player_name"].astype(str).str.strip()
    df["team_abbr"] = df["team_abbr"].astype(str).str.strip().str.upper()
    df["player_key"] = df["player_name"].map(_norm_player_name)
    df["game_date"] = pd.to_datetime(df.get("game_date"), errors="coerce")

    def _matchup_context(matchup: Any) -> tuple[str | None, bool | None]:
        text = str(matchup or "").strip().upper()
        if " VS. " in text:
            parts = text.split(" VS. ", 1)
            return (parts[1].strip() or None, True)
        if " @ " in text:
            parts = text.split(" @ ", 1)
            return (parts[1].strip() or None, False)
        return (None, None)

    opp_values: list[str | None] = []
    home_values: list[bool | None] = []
    for raw in df.get("matchup", pd.Series([None] * len(df))).tolist():
        opp_tri, is_home = _matchup_context(raw)
        opp_values.append(opp_tri)
        home_values.append(is_home)
    df["opp_tri"] = opp_values
    df["is_home"] = home_values

    for col in ("min", "pts", "reb", "ast", "threes", "stl", "blk", "tov"):
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors="coerce")
        else:
            df[col] = np.nan

    try:
        df = df.sort_values(["player_key", "game_date"], ascending=[True, False]).reset_index(drop=True)
    except Exception:
        pass
    return df


def _best_bets_player_log_stat_series(frame: pd.DataFrame, market: str) -> pd.Series:
    market_key = str(market or "").strip().lower()
    if frame is None or frame.empty:
        return pd.Series(dtype=float)
    if market_key in {"pts", "reb", "ast", "threes", "stl", "blk", "tov"}:
        return pd.to_numeric(frame.get(market_key), errors="coerce")
    if market_key == "pra":
        return (
            pd.to_numeric(frame.get("pts"), errors="coerce")
            + pd.to_numeric(frame.get("reb"), errors="coerce")
            + pd.to_numeric(frame.get("ast"), errors="coerce")
        )
    if market_key == "pr":
        return pd.to_numeric(frame.get("pts"), errors="coerce") + pd.to_numeric(frame.get("reb"), errors="coerce")
    if market_key == "pa":
        return pd.to_numeric(frame.get("pts"), errors="coerce") + pd.to_numeric(frame.get("ast"), errors="coerce")
    if market_key == "ra":
        return pd.to_numeric(frame.get("reb"), errors="coerce") + pd.to_numeric(frame.get("ast"), errors="coerce")
    return pd.Series(dtype=float)


def _best_bets_prop_history_context(
    *,
    date_str: str,
    player_name: Any,
    team_tri: Any,
    opponent: Any,
    market: str,
    home_flag: bool | None,
    line_value: Any = None,
) -> dict[str, Any]:
    df = _load_best_bets_player_logs_frame()
    if df is None or df.empty:
        return {}

    player_key = _norm_player_name(player_name)
    team_key = str(team_tri or "").strip().upper()
    opponent_key = str(opponent or "").strip().upper()
    if not player_key:
        return {}

    all_hist = df[df["player_key"] == player_key].copy()
    if all_hist.empty:
        return {}
    cutoff = pd.to_datetime(date_str, errors="coerce")
    if pd.notna(cutoff):
        all_hist = all_hist[all_hist["game_date"] < cutoff].copy()
    if all_hist.empty:
        return {}

    all_hist = all_hist.sort_values("game_date", ascending=False).copy()
    all_stat_series = _best_bets_player_log_stat_series(all_hist, market)
    all_minutes_series = pd.to_numeric(all_hist.get("min"), errors="coerce") if "min" in all_hist.columns else pd.Series(index=all_hist.index, dtype=float)
    all_played_mask = all_stat_series.notna()
    if not all_minutes_series.empty:
        all_played_mask = all_played_mask & (all_minutes_series.isna() | (all_minutes_series > 0))
    all_hist = all_hist.loc[all_played_mask].copy()
    if all_hist.empty:
        return {}
    all_hist["_stat_value"] = pd.to_numeric(all_stat_series.loc[all_hist.index], errors="coerce")
    all_hist = all_hist[all_hist["_stat_value"].notna()].copy()
    if all_hist.empty:
        return {}

    hist = all_hist.copy()
    if team_key:
        team_hist = hist[hist["team_abbr"] == team_key].copy()
        if not team_hist.empty:
            hist = team_hist
    if hist.empty:
        return {}

    hist = hist.sort_values("game_date", ascending=False).copy()

    recent10 = hist.head(10).copy()
    recent5 = hist.head(5).copy()
    opp_hist = hist[hist["opp_tri"] == opponent_key].copy() if opponent_key else pd.DataFrame()
    career_opp_hist = all_hist[all_hist["opp_tri"] == opponent_key].copy() if opponent_key else pd.DataFrame()
    venue_hist = hist[hist["is_home"] == bool(home_flag)].copy() if home_flag is not None else pd.DataFrame()

    def _avg(frame: pd.DataFrame) -> float | None:
        if frame is None or frame.empty:
            return None
        series = pd.to_numeric(frame.get("_stat_value"), errors="coerce").dropna()
        if series.empty:
            return None
        try:
            return float(series.mean())
        except Exception:
            return None

    def _mode(frame: pd.DataFrame) -> int | None:
        if frame is None or frame.empty:
            return None
        series = pd.to_numeric(frame.get("_stat_value"), errors="coerce").dropna()
        if series.empty:
            return None
        try:
            rounded = series.round().astype(int)
            modes = rounded.mode(dropna=True)
            if modes.empty:
                return None
            return int(modes.iloc[0])
        except Exception:
            return None

    def _hit(frame: pd.DataFrame, line: Any) -> dict[str, Any]:
        line_num = _safe_float(line)
        if frame is None or frame.empty or line_num is None:
            return {"count": None, "games": 0, "rate": None, "threshold": None}
        threshold = int(math.floor(float(line_num)) + 1)
        series = pd.to_numeric(frame.get("_stat_value"), errors="coerce").dropna()
        if series.empty:
            return {"count": None, "games": 0, "rate": None, "threshold": threshold}
        try:
            hits = int((series >= threshold).sum())
            games = int(len(series.index))
            rate = float(hits) / float(games) if games > 0 else None
            return {"count": hits, "games": games, "rate": rate, "threshold": threshold}
        except Exception:
            return {"count": None, "games": 0, "rate": None, "threshold": threshold}

    return {
        "opponent_avg": _avg(opp_hist),
        "opponent_games": int(len(opp_hist.index)) if not opp_hist.empty else 0,
        "opponent_hit": _hit(opp_hist, line_value),
        "career_opponent_avg": _avg(career_opp_hist),
        "career_opponent_games": int(len(career_opp_hist.index)) if not career_opp_hist.empty else 0,
        "career_opponent_hit": _hit(career_opp_hist, line_value),
        "venue_avg": _avg(venue_hist),
        "venue_games": int(len(venue_hist.index)) if not venue_hist.empty else 0,
        "venue_hit": _hit(venue_hist, line_value),
        "last5_avg": _avg(recent5),
        "last5_games": int(len(recent5.index)) if not recent5.empty else 0,
        "last10_avg": _avg(recent10),
        "last10_games": int(len(recent10.index)) if not recent10.empty else 0,
        "season_avg": _avg(hist),
        "season_mode": _mode(hist),
        "season_games": int(len(hist.index)) if not hist.empty else 0,
        "season_hit": _hit(hist, line_value),
        "last10_hit": _hit(recent10, line_value),
        "last5_hit": _hit(recent5, line_value),
    }


def _prop_ladder_benchmark_total(value: Any) -> int | None:
    num = _safe_float(value)
    if num is None:
        return None
    try:
        return max(0, int(math.floor(float(num) + 0.5)))
    except Exception:
        return None


def _prop_ladder_history_benchmarks(history_ctx: dict[str, Any] | None) -> list[dict[str, Any]]:
    if not isinstance(history_ctx, dict):
        return []
    candidates = [
        ("last5_avg", "L5 avg", history_ctx.get("last5_avg"), "recent"),
        ("last10_avg", "L10 avg", history_ctx.get("last10_avg"), "recent"),
        ("season_avg", "Season avg", history_ctx.get("season_avg"), "season"),
        ("season_mode", "Season mode", history_ctx.get("season_mode"), "season"),
    ]
    opponent_avg = _safe_float(history_ctx.get("opponent_avg"))
    opponent_games = int(history_ctx.get("opponent_games") or 0)
    if opponent_avg is not None and opponent_games > 0:
        candidates.append(("opponent_avg", f"Vs opp avg ({opponent_games})", opponent_avg, "opponent"))

    out: list[dict[str, Any]] = []
    seen_totals: set[tuple[str, int]] = set()
    for key, label, raw_value, tone in candidates:
        value_num = _safe_float(raw_value)
        total = _prop_ladder_benchmark_total(raw_value)
        if value_num is None or total is None:
            continue
        dedupe_key = (key, total)
        if dedupe_key in seen_totals:
            continue
        seen_totals.add(dedupe_key)
        out.append(
            {
                "key": key,
                "label": label,
                "value": float(value_num),
                "total": int(total),
                "tone": tone,
            }
        )
    return out


def _attach_prop_ladder_history_markers(
    ladder_rows: object,
    history_ctx: dict[str, Any] | None,
) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    benchmarks = _prop_ladder_history_benchmarks(history_ctx)
    if not isinstance(ladder_rows, list):
        return ([], benchmarks)

    out: list[dict[str, Any]] = []
    for ladder_row in ladder_rows:
        if not isinstance(ladder_row, dict):
            continue
        row_copy = dict(ladder_row)
        total_num = _coerce_prop_ladder_float(ladder_row.get("total"))
        total_int = _prop_ladder_benchmark_total(total_num)
        markers = []
        if total_int is not None:
            markers = [
                {
                    "key": benchmark.get("key"),
                    "label": benchmark.get("label"),
                    "tone": benchmark.get("tone"),
                    "value": benchmark.get("value"),
                }
                for benchmark in benchmarks
                if int(benchmark.get("total") or -1) == total_int
            ]
        row_copy["markers"] = markers
        out.append(row_copy)
    return (out, benchmarks)


@lru_cache(maxsize=16)
def _load_best_bets_smart_sim_player_lookup(date_str: str) -> dict[tuple[str, str], dict[str, Any]]:
    out: dict[tuple[str, str], dict[str, Any]] = {}
    for fp in _load_smart_sim_files_for_authoritative_slate(date_str):
        try:
            obj = json.loads(fp.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(obj, dict):
            continue
        players = obj.get("players") if isinstance(obj.get("players"), dict) else {}
        home_tri = _canonical_team_tri(obj.get("home"))
        away_tri = _canonical_team_tri(obj.get("away"))
        for side, team_key in (("home", home_tri), ("away", away_tri)):
            if not team_key:
                continue
            arr = players.get(side) if isinstance(players, dict) else []
            if not isinstance(arr, list):
                continue
            for raw in arr:
                if not isinstance(raw, dict):
                    continue
                player_name = str(raw.get("player_name") or "").strip()
                player_key = _norm_player_name(player_name)
                if not player_key:
                    continue
                out[(team_key, player_key)] = {
                    "player_name": player_name,
                    "team": team_key,
                    "min_mean": _safe_float(raw.get("min_mean")),
                    "pts_mean": _safe_float(raw.get("pts_mean")),
                    "pra_mean": _safe_float(raw.get("pra_mean")),
                    "scenarios": raw.get("scenarios") if isinstance(raw.get("scenarios"), dict) else {},
                }
    return out


def _best_bets_prop_scenario_quantile(scenarios: dict[str, Any] | None, scenario_key: str, market: str, quantile: str = "p50") -> float | None:
    if not isinstance(scenarios, dict):
        return None
    scenario = scenarios.get(scenario_key) if isinstance(scenarios.get(scenario_key), dict) else None
    if not isinstance(scenario, dict):
        return None

    def _q(stat_key: str) -> float | None:
        bucket = scenario.get(f"{stat_key}_q") if isinstance(scenario.get(f"{stat_key}_q"), dict) else None
        if not isinstance(bucket, dict):
            return None
        return _safe_float(bucket.get(quantile))

    market_key = str(market or "").strip().lower()
    if market_key in {"pts", "reb", "ast", "threes", "pra"}:
        return _q(market_key)
    if market_key == "pr":
        parts = [_q("pts"), _q("reb")]
    elif market_key == "pa":
        parts = [_q("pts"), _q("ast")]
    elif market_key == "ra":
        parts = [_q("reb"), _q("ast")]
    else:
        return None
    vals = [float(v) for v in parts if v is not None]
    return float(sum(vals)) if vals else None


def _best_bets_prop_sim_context(date_str: str, player_name: Any, team_tri: Any, market: str) -> dict[str, Any]:
    team_key = str(team_tri or "").strip().upper()
    player_key = _norm_player_name(player_name)
    if not team_key or not player_key:
        return {}
    entry = _load_best_bets_smart_sim_player_lookup(date_str).get((team_key, player_key))
    if not isinstance(entry, dict):
        return {}

    scenarios = entry.get("scenarios") if isinstance(entry.get("scenarios"), dict) else {}
    close_p50 = _best_bets_prop_scenario_quantile(scenarios, "close", market)
    medium_p50 = _best_bets_prop_scenario_quantile(scenarios, "medium", market)
    blowout_p50 = _best_bets_prop_scenario_quantile(scenarios, "blowout", market)
    close_n = _safe_float(((scenarios.get("close") or {}) if isinstance(scenarios.get("close"), dict) else {}).get("n"))
    blowout_n = _safe_float(((scenarios.get("blowout") or {}) if isinstance(scenarios.get("blowout"), dict) else {}).get("n"))
    close_gap = None
    if close_p50 is not None and blowout_p50 is not None:
        close_gap = float(close_p50) - float(blowout_p50)

    min_mean = _safe_float(entry.get("min_mean"))
    pts_mean = _safe_float(entry.get("pts_mean"))
    pra_mean = _safe_float(entry.get("pra_mean"))
    is_star = False
    try:
        is_star = bool(
            (min_mean is not None and float(min_mean) >= 32.0)
            or (pts_mean is not None and float(pts_mean) >= 20.0)
            or (pra_mean is not None and float(pra_mean) >= 30.0)
        )
    except Exception:
        is_star = False

    return {
        "close_p50": close_p50,
        "medium_p50": medium_p50,
        "blowout_p50": blowout_p50,
        "close_gap": close_gap,
        "close_n": int(close_n) if close_n is not None else 0,
        "blowout_n": int(blowout_n) if blowout_n is not None else 0,
        "min_mean": min_mean,
        "pts_mean": pts_mean,
        "pra_mean": pra_mean,
        "is_star": is_star,
    }


def _best_bets_settle_prop_pick(*, actual: Any, line: Any, side: Any) -> str | None:
    actual_val = _safe_float(actual)
    line_val = _safe_float(line)
    side_key = str(side or "").strip().upper()
    if actual_val is None or line_val is None or side_key not in {"OVER", "UNDER"}:
        return None
    if abs(float(actual_val) - float(line_val)) < 1e-9:
        return "PUSH"
    if side_key == "OVER":
        return "WIN" if float(actual_val) > float(line_val) else "LOSS"
    return "WIN" if float(actual_val) < float(line_val) else "LOSS"


@lru_cache(maxsize=16)
def _load_recon_props_frame(date_str: str) -> tuple[pd.DataFrame, str | None]:
    recon_path = DATA_PROCESSED_DIR / f"recon_props_{date_str}.csv"
    try:
        if recon_path.exists():
            df = pd.read_csv(recon_path)
            if isinstance(df, pd.DataFrame) and not df.empty:
                return df, recon_path.name
    except Exception:
        pass

    daily_actuals_path = DATA_PROCESSED_DIR / f"props_actuals_{date_str}.csv"
    try:
        if daily_actuals_path.exists():
            df = pd.read_csv(daily_actuals_path)
            if isinstance(df, pd.DataFrame) and not df.empty:
                return df, daily_actuals_path.name
    except Exception:
        pass

    parquet_path = DATA_PROCESSED_DIR / "props_actuals.parquet"
    try:
        if parquet_path.exists():
            df = pd.read_parquet(parquet_path)
            if isinstance(df, pd.DataFrame) and not df.empty and "date" in df.columns:
                tmp = df.copy()
                tmp["date"] = pd.to_datetime(tmp["date"], errors="coerce").dt.date
                target_date = pd.to_datetime(date_str, errors="coerce")
                if not pd.isna(target_date):
                    tmp = tmp[tmp["date"] == target_date.date()].copy()
                if not tmp.empty:
                    return tmp, parquet_path.name
    except Exception:
        pass

    return pd.DataFrame(), None


@lru_cache(maxsize=16)
def _load_recon_props_lookup(date_str: str) -> tuple[dict[int, dict[str, Any]], dict[tuple[str, str], dict[str, Any]]]:
    df, _ = _load_recon_props_frame(date_str)
    if df is None or df.empty:
        return {}, {}

    by_id: dict[int, dict[str, Any]] = {}
    by_key: dict[tuple[str, str], dict[str, Any]] = {}
    for _, r in df.iterrows():
        row = r.to_dict()
        pts = _safe_float(row.get("pts"))
        reb = _safe_float(row.get("reb"))
        ast = _safe_float(row.get("ast"))
        record = {
            "date": row.get("date"),
            "player_id": _safe_int(row.get("player_id")),
            "player_name": str(row.get("player_name") or "").strip(),
            "team_abbr": str(row.get("team_abbr") or "").strip().upper(),
            "pts": pts,
            "reb": reb,
            "ast": ast,
            "threes": _safe_float(row.get("threes")),
            "stl": _safe_float(row.get("stl")),
            "blk": _safe_float(row.get("blk")),
            "tov": _safe_float(row.get("tov")),
            "pr": _safe_float(row.get("pr")),
            "pa": _safe_float(row.get("pa")),
            "ra": _safe_float(row.get("ra")),
            "pra": _safe_float(row.get("pra")),
        }
        if record["pr"] is None and pts is not None and reb is not None:
            record["pr"] = float(pts + reb)
        if record["pa"] is None and pts is not None and ast is not None:
            record["pa"] = float(pts + ast)
        if record["ra"] is None and reb is not None and ast is not None:
            record["ra"] = float(reb + ast)
        if record["pra"] is None:
            combo_parts = [pts, reb, ast]
            if all(part is not None for part in combo_parts):
                record["pra"] = float(sum(combo_parts))
        pid = record.get("player_id")
        if pid:
            by_id[int(pid)] = record
        team_key = str(record.get("team_abbr") or "").strip().upper()
        player_key = _norm_player_name(record.get("player_name"))
        if team_key and player_key:
            by_key[(team_key, player_key)] = record
    return by_id, by_key


@lru_cache(maxsize=32)
def _load_finals_lookup(date_str: str) -> dict[tuple[str, str], dict[str, Any]]:
    path = DATA_PROCESSED_DIR / f"finals_{date_str}.csv"
    if not path.exists():
        try:
            _maybe_fetch_remote_processed(path.name)
        except Exception:
            pass
    try:
        if not path.exists():
            return {}
        df = pd.read_csv(path)
    except Exception:
        return {}
    if not isinstance(df, pd.DataFrame) or df.empty:
        return {}

    out: dict[tuple[str, str], dict[str, Any]] = {}
    for _, raw_row in df.iterrows():
        try:
            row = raw_row.to_dict()
            home_tri = str(_get_tricode(_espn_to_tri(row.get("home_tri"))) or "").strip().upper()
            away_tri = str(_get_tricode(_espn_to_tri(row.get("away_tri"))) or "").strip().upper()
            home_pts = _safe_float(row.get("home_pts"))
            away_pts = _safe_float(row.get("visitor_pts"))
            if not home_tri or not away_tri:
                continue
            if home_pts is None or away_pts is None:
                continue
            out[(home_tri, away_tri)] = {
                "home_pts": home_pts,
                "visitor_pts": away_pts,
            }
        except Exception:
            continue
    return out


def _best_bets_prop_market_label(market: str) -> str:
    return {
        "pts": "PTS",
        "reb": "REB",
        "ast": "AST",
        "threes": "3PM",
        "pra": "PRA",
        "pr": "PR",
        "pa": "PA",
        "ra": "RA",
        "stl": "STL",
        "blk": "BLK",
        "tov": "TOV",
    }.get(str(market or "").strip().lower(), str(market or "").strip().upper())


def _best_bets_prop_stat_value(row: dict[str, Any] | None, market: str, prefix: str) -> float | None:
    if not isinstance(row, dict):
        return None

    def _v(suffix: str) -> float | None:
        return _safe_float(row.get(f"{prefix}_{suffix}"))

    market_key = str(market or "").strip().lower()
    if market_key == "pts":
        return _v("pts")
    if market_key == "reb":
        return _v("reb")
    if market_key == "ast":
        return _v("ast")
    if market_key == "threes":
        return _v("threes")
    if market_key == "stl":
        return _v("stl")
    if market_key == "blk":
        return _v("blk")
    if market_key == "tov":
        return _v("tov")
    if market_key == "pra":
        direct = _v("pra")
        if direct is not None:
            return direct
        parts = [_v("pts"), _v("reb"), _v("ast")]
    elif market_key == "pr":
        direct = _v("pr")
        if direct is not None:
            return direct
        parts = [_v("pts"), _v("reb")]
    elif market_key == "pa":
        direct = _v("pa")
        if direct is not None:
            return direct
        parts = [_v("pts"), _v("ast")]
    elif market_key == "ra":
        direct = _v("ra")
        if direct is not None:
            return direct
        parts = [_v("reb"), _v("ast")]
    else:
        return None
    vals = [float(v) for v in parts if v is not None]
    return float(sum(vals)) if vals else None


def _best_bets_prop_sd_value(row: dict[str, Any] | None, market: str) -> float | None:
    if not isinstance(row, dict):
        return None

    def _sd(suffix: str) -> float | None:
        return _safe_float(row.get(f"sd_{suffix}"))

    market_key = str(market or "").strip().lower()
    if market_key in {"pts", "reb", "ast", "threes", "stl", "blk", "tov"}:
        return _sd(market_key)
    if market_key == "pra":
        direct = _sd("pra")
        if direct is not None:
            return direct
        parts = [_sd("pts"), _sd("reb"), _sd("ast")]
    elif market_key == "pr":
        parts = [_sd("pts"), _sd("reb")]
    elif market_key == "pa":
        parts = [_sd("pts"), _sd("ast")]
    elif market_key == "ra":
        parts = [_sd("reb"), _sd("ast")]
    else:
        return None
    vals = [float(v) for v in parts if v is not None]
    if not vals:
        return None
    try:
        return float(math.sqrt(sum(v * v for v in vals)))
    except Exception:
        return None


def _best_bets_prop_win_prob(mu: float | None, sd: float | None, line: float | None, side: str) -> float | None:
    if mu is None or line is None:
        return None
    side_key = str(side or "").strip().lower()
    if side_key not in {"over", "under", "o", "u"}:
        return None
    if sd is None or sd <= 0 or not np.isfinite(sd):
        if side_key in {"over", "o"}:
            if mu > line:
                return 0.95
            if mu < line:
                return 0.05
            return 0.5
        if mu < line:
            return 0.95
        if mu > line:
            return 0.05
        return 0.5

    def _cdf(z: float) -> float:
        return 0.5 * (1.0 + math.erf(float(z) / math.sqrt(2.0)))

    try:
        if abs(float(line) - round(float(line))) <= 1e-6:
            z_over = (float(line) + 0.5 - float(mu)) / float(sd)
            z_under = (float(line) - 0.5 - float(mu)) / float(sd)
            p_over = 1.0 - _cdf(z_over)
            p_under = _cdf(z_under)
        else:
            z = (float(line) - float(mu)) / float(sd)
            p_over = 1.0 - _cdf(z)
            p_under = 1.0 - p_over
        prob = p_over if side_key in {"over", "o"} else p_under
        return float(max(0.01, min(0.99, prob)))
    except Exception:
        return None


def _decorate_game_best_bet_candidate(
    row: dict[str, Any],
    *,
    date_str: str,
    ctx: dict[str, Any] | None,
    injury_snapshot: dict[str, dict[str, Any]],
    slate_total_median: float | None,
) -> dict[str, Any] | None:
    home = str(row.get("home") or "").strip()
    away = str(row.get("away") or "").strip()
    side = str(row.get("side") or "").strip()
    market = str(row.get("market") or "").strip().upper()
    if not home or not away or not side or market not in {"ATS", "ML", "TOTAL", "OU"}:
        return None

    market = "TOTAL" if market == "OU" else market
    rec_code = "OU" if market == "TOTAL" else market
    home_tri = (_get_tricode(home) or home.strip().upper())
    away_tri = (_get_tricode(away) or away.strip().upper())
    pick_home = side.strip().lower() == home.strip().lower() or side.strip().lower() == "home"
    pick_away = side.strip().lower() == away.strip().lower() or side.strip().lower() == "away"
    if market in {"ATS", "ML"} and not (pick_home or pick_away):
        return None

    price = _safe_float(row.get("price"))
    ev = _safe_float(row.get("ev"))
    implied_prob = _safe_float(row.get("implied_prob")) or _american_to_implied_prob(price)
    pred_margin = _safe_float(row.get("pred_margin"))
    pred_total = _safe_float(row.get("pred_total"))
    market_home_margin = _safe_float(row.get("market_home_margin"))
    raw_line = _safe_float(row.get("line"))
    start_raw = row.get("date")
    if isinstance(ctx, dict):
        if market == "TOTAL":
            pred_total = _safe_float(ctx.get("pred_total_adjusted")) or _safe_float(ctx.get("pred_total")) or pred_total
        elif market == "ATS":
            pred_margin = _safe_float(ctx.get("pred_margin_adjusted")) or _safe_float(ctx.get("pred_margin")) or pred_margin
        else:
            pred_margin = pred_margin if pred_margin is not None else _safe_float(ctx.get("pred_margin"))
            pred_total = pred_total if pred_total is not None else _safe_float(ctx.get("pred_total"))
        start_raw = ctx.get("commence_time") if ctx.get("commence_time") not in (None, "") else start_raw

    pick_line = raw_line
    spread_edge = None
    total_edge = None
    p_win = _best_bets_prob_from_ev(ev, price)
    if market == "ATS":
        if market_home_margin is not None and pred_margin is not None:
            spread_edge = (float(pred_margin) - float(market_home_margin)) if pick_home else (float(market_home_margin) - float(pred_margin))
            pick_line = (-float(market_home_margin)) if pick_home else float(market_home_margin)
        if p_win is None and spread_edge is not None:
            p_win = float(max(0.05, min(0.95, 0.5 + (float(spread_edge) / 12.0))))
    elif market == "TOTAL":
        if pred_total is not None and raw_line is not None:
            is_over = side.strip().lower().startswith("o")
            total_edge = (float(pred_total) - float(raw_line)) if is_over else (float(raw_line) - float(pred_total))
        if p_win is None and total_edge is not None:
            p_win = float(max(0.05, min(0.95, 0.5 + (float(total_edge) / 18.0))))
    elif market == "ML":
        if isinstance(ctx, dict):
            home_prob = _safe_float(ctx.get("home_win_prob_adjusted")) or _safe_float(ctx.get("home_win_prob"))
            if home_prob is not None:
                p_win = float(home_prob if pick_home else (1.0 - home_prob))

    own_tri = home_tri if pick_home else away_tri
    opp_tri = away_tri if pick_home else home_tri
    own_name = home if pick_home else away
    opp_name = away if pick_home else home
    own_outs = int((injury_snapshot.get("counts") or {}).get(own_tri, 0) or 0)
    opp_outs = int((injury_snapshot.get("counts") or {}).get(opp_tri, 0) or 0)
    own_key_outs = list((injury_snapshot.get("key_outs") or {}).get(own_tri, []) or [])
    opp_key_outs = list((injury_snapshot.get("key_outs") or {}).get(opp_tri, []) or [])
    combined_outs = own_outs + opp_outs

    game_pace_ctx = _safe_float((ctx or {}).get("game_pace")) if isinstance(ctx, dict) else None
    league_pace_ctx = _safe_float((ctx or {}).get("league_pace")) if isinstance(ctx, dict) else None
    pace_gap_ctx = None
    if game_pace_ctx is not None and league_pace_ctx is not None:
        try:
            pace_gap_ctx = float(game_pace_ctx) - float(league_pace_ctx)
        except Exception:
            pace_gap_ctx = None
    prop_total_raw = _safe_float((ctx or {}).get("pred_total_prop_blend")) if isinstance(ctx, dict) else None
    matchup_total_adj = _safe_float((ctx or {}).get("pred_total_matchup_adjustment")) if isinstance(ctx, dict) else None
    home_pred_points = _safe_float((ctx or {}).get("home_pred_points")) if isinstance(ctx, dict) else None
    away_pred_points = _safe_float((ctx or {}).get("away_pred_points")) if isinstance(ctx, dict) else None
    prop_margin_raw = _safe_float((ctx or {}).get("pred_margin_prop_blend")) if isinstance(ctx, dict) else None
    matchup_margin_adj = _safe_float((ctx or {}).get("pred_margin_matchup_adjustment")) if isinstance(ctx, dict) else None
    home_prop_blend_weight = _safe_float((ctx or {}).get("home_prop_blend_weight")) if isinstance(ctx, dict) else None
    away_prop_blend_weight = _safe_float((ctx or {}).get("away_prop_blend_weight")) if isinstance(ctx, dict) else None
    home_prop_minutes_coverage = _safe_float((ctx or {}).get("home_prop_minutes_coverage")) if isinstance(ctx, dict) else None
    away_prop_minutes_coverage = _safe_float((ctx or {}).get("away_prop_minutes_coverage")) if isinstance(ctx, dict) else None

    game_shape = {
        "pace_gap": round(float(pace_gap_ctx), 3) if pace_gap_ctx is not None else None,
        "home_pred_points": round(float(home_pred_points), 3) if home_pred_points is not None else None,
        "away_pred_points": round(float(away_pred_points), 3) if away_pred_points is not None else None,
        "pred_total_prop_blend": round(float(prop_total_raw), 3) if prop_total_raw is not None else None,
        "pred_total_matchup_adjustment": round(float(matchup_total_adj), 3) if matchup_total_adj is not None else None,
        "pred_margin_prop_blend": round(float(prop_margin_raw), 3) if prop_margin_raw is not None else None,
        "pred_margin_matchup_adjustment": round(float(matchup_margin_adj), 3) if matchup_margin_adj is not None else None,
        "home_prop_blend_weight": round(float(home_prop_blend_weight), 3) if home_prop_blend_weight is not None else None,
        "away_prop_blend_weight": round(float(away_prop_blend_weight), 3) if away_prop_blend_weight is not None else None,
        "home_prop_minutes_coverage": round(float(home_prop_minutes_coverage), 3) if home_prop_minutes_coverage is not None else None,
        "away_prop_minutes_coverage": round(float(away_prop_minutes_coverage), 3) if away_prop_minutes_coverage is not None else None,
        "combined_outs": int(combined_outs),
    }

    basketball_reasons: list[str] = []
    basketball_points = 0.0

    def _add_basketball_reason(text: str | None, points: float) -> None:
        nonlocal basketball_points
        if not text:
            return
        basketball_reasons.append(str(text).strip())
        basketball_points += float(points)

    if market in {"ATS", "ML"}:
        league_off = _safe_float((ctx or {}).get("league_off_rtg")) if isinstance(ctx, dict) else None
        league_def = _safe_float((ctx or {}).get("league_def_rtg")) if isinstance(ctx, dict) else None
        own_off = _safe_float((ctx or {}).get("home_off_rtg" if pick_home else "away_off_rtg")) if isinstance(ctx, dict) else None
        own_def = _safe_float((ctx or {}).get("home_def_rtg" if pick_home else "away_def_rtg")) if isinstance(ctx, dict) else None
        opp_off = _safe_float((ctx or {}).get("away_off_rtg" if pick_home else "home_off_rtg")) if isinstance(ctx, dict) else None
        opp_def = _safe_float((ctx or {}).get("away_def_rtg" if pick_home else "home_def_rtg")) if isinstance(ctx, dict) else None
        own_recent_offense = _safe_float((ctx or {}).get("home_recent_offense" if pick_home else "away_recent_offense")) if isinstance(ctx, dict) else None
        opp_recent_offense = _safe_float((ctx or {}).get("away_recent_offense" if pick_home else "home_recent_offense")) if isinstance(ctx, dict) else None
        own_recent_allowed = _safe_float((ctx or {}).get("home_recent_allowed_pts" if pick_home else "away_recent_allowed_pts")) if isinstance(ctx, dict) else None
        opp_recent_allowed = _safe_float((ctx or {}).get("away_recent_allowed_pts" if pick_home else "home_recent_allowed_pts")) if isinstance(ctx, dict) else None
        league_recent_offense = _safe_float((ctx or {}).get("league_recent_offense")) if isinstance(ctx, dict) else None
        league_recent_allowed = _safe_float((ctx or {}).get("league_recent_allowed_pts")) if isinstance(ctx, dict) else None
        league_pace = _safe_float((ctx or {}).get("league_pace")) if isinstance(ctx, dict) else None
        game_pace = _safe_float((ctx or {}).get("game_pace")) if isinstance(ctx, dict) else None

        attack_edge = 0.0
        defense_softness = 0.0
        if (own_off is not None) and (league_off is not None):
            attack_edge = max(0.0, float(own_off) - float(league_off))
        if (opp_def is not None) and (league_def is not None):
            defense_softness = max(0.0, float(opp_def) - float(league_def))
        if attack_edge >= 1.5 and defense_softness >= 1.0:
            _add_basketball_reason(
                f"{own_name} has graded {attack_edge:.1f} points per 100 above league-average offense, and {opp_name}'s defense has been {defense_softness:.1f} points softer than average",
                0.28 + min(0.12, (float(attack_edge) + float(defense_softness)) / 24.0),
            )

        defense_edge = 0.0
        opponent_off_gap = 0.0
        if (own_def is not None) and (league_def is not None):
            defense_edge = max(0.0, float(league_def) - float(own_def))
        if (opp_off is not None) and (league_off is not None):
            opponent_off_gap = max(0.0, float(league_off) - float(opp_off))
        if defense_edge >= 1.0 and opponent_off_gap >= 1.0:
            _add_basketball_reason(
                f"{own_name} can control possessions with a defense {defense_edge:.1f} points per 100 better than league average against a {opp_name} offense {opponent_off_gap:.1f} below average",
                0.24 + min(0.10, (float(defense_edge) + float(opponent_off_gap)) / 24.0),
            )

        recent_attack_edge = None
        recent_softness = None
        if own_recent_offense is not None and league_recent_offense is not None:
            recent_attack_edge = float(own_recent_offense) - float(league_recent_offense)
        if opp_recent_allowed is not None and league_recent_allowed is not None:
            recent_softness = float(opp_recent_allowed) - float(league_recent_allowed)
        if (
            own_recent_offense is not None
            and opp_recent_allowed is not None
            and (
                (recent_attack_edge is not None and recent_attack_edge >= 1.5)
                or (recent_softness is not None and recent_softness >= 1.5)
                or (float(own_recent_offense) - float(opp_recent_allowed) >= 2.0)
            )
        ):
            _add_basketball_reason(
                f"{own_name} has scored {float(own_recent_offense):.1f} points per game over the last 21 days, and {opp_name} has allowed {float(opp_recent_allowed):.1f} over that same stretch",
                0.22 + min(0.08, max(float(recent_attack_edge or 0.0), 0.0) / 10.0 + max(float(recent_softness or 0.0), 0.0) / 10.0),
            )

        recent_defense_edge = None
        recent_opponent_lull = None
        if own_recent_allowed is not None and league_recent_allowed is not None:
            recent_defense_edge = float(league_recent_allowed) - float(own_recent_allowed)
        if opp_recent_offense is not None and league_recent_offense is not None:
            recent_opponent_lull = float(league_recent_offense) - float(opp_recent_offense)
        if (
            own_recent_allowed is not None
            and opp_recent_offense is not None
            and (
                (recent_defense_edge is not None and recent_defense_edge >= 1.5)
                or (recent_opponent_lull is not None and recent_opponent_lull >= 1.5)
                or (float(opp_recent_offense) - float(own_recent_allowed) <= 2.0)
            )
        ):
            _add_basketball_reason(
                f"{own_name} has held opponents to {float(own_recent_allowed):.1f} points per game lately while {opp_name} has scored {float(opp_recent_offense):.1f}",
                0.20 + min(0.08, max(float(recent_defense_edge or 0.0), 0.0) / 10.0 + max(float(recent_opponent_lull or 0.0), 0.0) / 10.0),
            )

        if market == "ATS" and pick_line is not None and game_pace is not None and league_pace is not None:
            pace_gap = float(game_pace) - float(league_pace)
            if float(pick_line) > 0.0 and pace_gap <= -1.5:
                _add_basketball_reason(
                    f"The matchup projects {abs(float(pace_gap)):.1f} possessions slower than league average, which helps an underdog cover in fewer-possession game states",
                    0.12,
                )
            elif float(pick_line) < 0.0 and pace_gap >= 1.5:
                _add_basketball_reason(
                    f"The matchup projects {float(pace_gap):.1f} possessions faster than league average, which gives the stronger side more trips to create separation",
                    0.12,
                )

        outs_diff = opp_outs - own_outs
        if outs_diff >= 1:
            _add_basketball_reason(
                f"{opp_name} is more depleted tonight with {outs_diff} extra rotation outs on the wrong side of this matchup",
                min(0.20, 0.10 + (0.05 * float(outs_diff))),
            )
        if opp_key_outs:
            _add_basketball_reason(f"Key absences for {opp_name} include {', '.join(opp_key_outs[:2])}", 0.08)
        if own_outs == 0 and opp_outs >= 1:
            _add_basketball_reason(f"{side} comes in with the cleaner rotation health profile", 0.08)
    else:
        is_over = side.strip().lower().startswith("o")
        if pred_total is not None and slate_total_median is not None:
            if is_over and float(pred_total) >= float(slate_total_median) + 2.5:
                basketball_reasons.append("The game environment projects faster and more open than a typical slate total")
                basketball_points += 0.26
            elif (not is_over) and float(pred_total) <= float(slate_total_median) - 2.5:
                basketball_reasons.append("The game environment projects slower and more controlled than a typical slate total")
                basketball_points += 0.26
        if pred_total is not None and raw_line is not None and home_pred_points is not None and away_pred_points is not None:
            if is_over and home_pred_points >= 109.0 and away_pred_points >= 104.0:
                basketball_reasons.append(
                    f"Both teams still project into scoring range at {float(home_pred_points):.1f} and {float(away_pred_points):.1f}, which keeps the over live without needing one-sided shotmaking"
                )
                basketball_points += 0.20
            elif (not is_over) and (home_pred_points <= 108.0 or away_pred_points <= 102.0):
                basketball_reasons.append(
                    f"The shape leans under because one side is held down to {min(float(home_pred_points), float(away_pred_points)):.1f} projected points"
                )
                basketball_points += 0.18
        if pace_gap_ctx is not None:
            if is_over and float(pace_gap_ctx) >= 1.25:
                basketball_reasons.append(
                    f"Pace is running {float(pace_gap_ctx):+.1f} possessions versus league average, which supports more scoring events than the market baseline"
                )
                basketball_points += min(0.18, max(0.0, float(pace_gap_ctx)) / 8.0)
            elif (not is_over) and float(pace_gap_ctx) <= -1.25:
                basketball_reasons.append(
                    f"Pace is running {float(pace_gap_ctx):+.1f} possessions versus league average, which points to a shorter possession count and less total volume"
                )
                basketball_points += min(0.18, abs(float(pace_gap_ctx)) / 8.0)
        if prop_total_raw is not None and pred_total is not None:
            prop_lift = float(prop_total_raw) - float(pred_total)
            if is_over and prop_lift >= 5.0:
                basketball_reasons.append(
                    f"Player scoring priors are adding {prop_lift:.1f} points to the game shape, a sign that individual usage is stronger than the raw team total"
                )
                basketball_points += min(0.18, float(prop_lift) / 30.0)
            elif (not is_over) and prop_lift <= -5.0:
                basketball_reasons.append(
                    f"Player scoring priors trim {abs(prop_lift):.1f} points off the total outlook, which reinforces the lower-possession scoring case"
                )
                basketball_points += min(0.18, abs(float(prop_lift)) / 30.0)
        if matchup_total_adj is not None and abs(float(matchup_total_adj)) >= 1.5:
            if is_over and float(matchup_total_adj) > 0:
                basketball_reasons.append(
                    f"Matchup context adds {float(matchup_total_adj):+.1f} points on top of the base total, so the over is being lifted by more than generic pace alone"
                )
                basketball_points += min(0.14, abs(float(matchup_total_adj)) / 14.0)
            elif (not is_over) and float(matchup_total_adj) < 0:
                basketball_reasons.append(
                    f"Matchup context pulls {float(matchup_total_adj):+.1f} points off the base total, which aligns with the under rather than a pure market fade"
                )
                basketball_points += min(0.14, abs(float(matchup_total_adj)) / 14.0)
        if (
            home_prop_minutes_coverage is not None
            and away_prop_minutes_coverage is not None
            and min(float(home_prop_minutes_coverage), float(away_prop_minutes_coverage)) >= 0.85
            and home_prop_blend_weight is not None
            and away_prop_blend_weight is not None
            and max(float(home_prop_blend_weight), float(away_prop_blend_weight)) >= 0.5
        ):
            basketball_reasons.append("The total is being informed by near-full player minute coverage rather than a thin top-of-rotation estimate")
            basketball_points += 0.10
        if combined_outs >= 3 and not is_over:
            basketball_reasons.append("Missing rotation pieces thin out scoring depth on both sides of the matchup")
            basketball_points += 0.18
        elif combined_outs >= 3 and is_over:
            basketball_reasons.append("Shorthanded rotations can create unstable defensive possessions and bench-heavy minutes")
            basketball_points += 0.12

    if market in {"ATS", "ML"} and pred_margin is not None and prop_margin_raw is not None:
        margin_support = float(prop_margin_raw) - float(pred_margin)
        if pick_home and margin_support >= 2.0:
            _add_basketball_reason(
                f"Player usage and scoring priors still tilt {home} by {margin_support:.1f} points beyond the team-level spread view",
                min(0.14, float(margin_support) / 16.0),
            )
        elif pick_away and margin_support <= -2.0:
            _add_basketball_reason(
                f"Player usage and scoring priors still tilt {away} by {abs(float(margin_support)):.1f} points beyond the team-level spread view",
                min(0.14, abs(float(margin_support)) / 16.0),
            )
    if market in {"ATS", "ML"} and matchup_margin_adj is not None and abs(float(matchup_margin_adj)) >= 1.25:
        toward_home = float(matchup_margin_adj) > 0.0
        if (pick_home and toward_home) or (pick_away and not toward_home):
            target_team = home if toward_home else away
            _add_basketball_reason(
                f"Matchup context shifts the spread shape {float(matchup_margin_adj):+.1f} points toward {target_team}",
                min(0.12, abs(float(matchup_margin_adj)) / 14.0),
            )

    sim_reasons: list[str] = []
    sim_points = 0.0
    prob_edge = None
    if p_win is not None and implied_prob is not None:
        prob_edge = float(p_win) - float(implied_prob)
    if market == "ATS" and spread_edge is not None:
        sim_reasons.append(f"The model makes {side} {float(spread_edge):+.1f} points better than this spread")
        sim_points += min(0.65, abs(float(spread_edge)) / 8.0)
        if isinstance(ctx, dict):
            raw_ctx_margin = _safe_float(ctx.get("pred_margin_raw"))
            adjusted_ctx_margin = _safe_float(ctx.get("pred_margin_adjusted"))
            if raw_ctx_margin is not None and adjusted_ctx_margin is not None and abs(float(adjusted_ctx_margin) - float(raw_ctx_margin)) >= 0.75:
                toward_side = home if float(adjusted_ctx_margin) > float(raw_ctx_margin) else away
                sim_reasons.append(
                    f"Prop scoring and opponent matchup context shift the spread projection {abs(float(adjusted_ctx_margin) - float(raw_ctx_margin)):.1f} points toward {toward_side} versus the raw game model"
                )
                sim_points += min(0.14, abs(float(adjusted_ctx_margin) - float(raw_ctx_margin)) / 8.0)
    elif market == "TOTAL" and total_edge is not None and raw_line is not None and pred_total is not None:
        sim_reasons.append(f"The model total lands at {float(pred_total):.1f} against {float(raw_line):.1f}")
        sim_points += min(0.65, abs(float(total_edge)) / 10.0)
        if isinstance(ctx, dict):
            raw_ctx_total = _safe_float(ctx.get("pred_total_raw"))
            adjusted_ctx_total = _safe_float(ctx.get("pred_total_adjusted"))
            if raw_ctx_total is not None and adjusted_ctx_total is not None and abs(float(adjusted_ctx_total) - float(raw_ctx_total)) >= 1.0:
                direction = "higher" if float(adjusted_ctx_total) > float(raw_ctx_total) else "lower"
                sim_reasons.append(
                    f"Prop scoring and opponent matchup context push the projection {abs(float(adjusted_ctx_total) - float(raw_ctx_total)):.1f} points {direction} than the raw game model"
                )
                sim_points += min(0.18, abs(float(adjusted_ctx_total) - float(raw_ctx_total)) / 12.0)
    elif market == "ML" and p_win is not None and implied_prob is not None:
        sim_reasons.append(f"Win probability grades at {float(p_win) * 100.0:.1f}% against {float(implied_prob) * 100.0:.1f}% implied")
        sim_points += min(0.65, max(0.0, float(p_win) - float(implied_prob)) / 0.12)
        if isinstance(ctx, dict):
            raw_home_prob = _safe_float(ctx.get("home_win_prob_raw"))
            adjusted_home_prob = _safe_float(ctx.get("home_win_prob_adjusted"))
            if raw_home_prob is not None and adjusted_home_prob is not None and abs(float(adjusted_home_prob) - float(raw_home_prob)) >= 0.02:
                direction = home if float(adjusted_home_prob) > float(raw_home_prob) else away
                sim_reasons.append(
                    f"Prop scoring and opponent matchup context move win probability {abs(float(adjusted_home_prob) - float(raw_home_prob)) * 100.0:.1f} points toward {direction} versus the raw game model"
                )
                sim_points += min(0.12, abs(float(adjusted_home_prob) - float(raw_home_prob)) / 0.10)

    if p_win is not None and market != "ML":
        sim_reasons.append(f"The simulated cover rate is {float(p_win) * 100.0:.1f}%")
        sim_points += min(0.30, max(0.0, float(p_win) - 0.5) / 0.2)

    value_reasons: list[str] = []
    value_points = 0.0
    if ev is not None:
        value_reasons.append(f"Projected value is {float(ev) * 100.0:+.1f}% per unit risked")
        value_points += min(0.65, max(0.0, float(ev)) / 0.25)
    if price is not None and abs(float(price)) <= 130:
        value_reasons.append(f"The price is still playable at {float(price):+.0f}")
        value_points += 0.15
    if prob_edge is not None and prob_edge > 0:
        value_reasons.append(f"Model probability clears the market by {float(prob_edge) * 100.0:.1f} points")
        value_points += min(0.20, float(prob_edge) / 0.10)

    basketball_reasons = _best_bets_unique_strings(basketball_reasons)
    sim_reasons = _best_bets_unique_strings(sim_reasons)
    value_reasons = _best_bets_unique_strings(value_reasons)

    basketball_score = round(_best_bets_clamp01(basketball_points) * 100.0, 1)
    sim_support_score = round(_best_bets_clamp01(sim_points) * 100.0, 1)
    value_support_score = round(_best_bets_clamp01(value_points) * 100.0, 1)
    explicit_score = _safe_float(row.get("score"))
    score = explicit_score
    if score is None:
        score = round((0.70 * sim_support_score) + (0.30 * value_support_score), 1)
    priority = round((0.50 * basketball_score) + (0.30 * sim_support_score) + (0.20 * value_support_score), 1)

    if market == "ATS":
        if pick_line is not None:
            display_pick = f"{side} {float(pick_line):+.1f}"
        else:
            display_pick = side
    elif market == "TOTAL":
        display_pick = f"{side.title()} {float(raw_line):.1f}" if raw_line is not None else side.title()
    else:
        display_pick = f"{side} ML"

    matchup = f"{away} @ {home}"
    start_dt_local = _best_bets_local_start_dt(start_raw)
    return {
        "game_key": f"{date_str}:{away_tri}@{home_tri}",
        "game_id": row.get("game_id") or f"{date_str}:{away_tri}@{home_tri}",
        "date": date_str,
        "market": market,
        "rec_code": rec_code,
        "selection": side,
        "display_pick": display_pick,
        "matchup": matchup,
        "home_team": home,
        "away_team": away,
        "home_tricode": home_tri,
        "away_tricode": away_tri,
        "line": pick_line if market == "ATS" else raw_line,
        "price": price,
        "p_win": round(float(p_win), 4) if p_win is not None else None,
        "implied_prob": round(float(implied_prob), 4) if implied_prob is not None else None,
        "prob_edge": round(float(prob_edge), 4) if prob_edge is not None else None,
        "ev": ev,
        "ev_pct": round(float(ev) * 100.0, 2) if ev is not None else None,
        "edge": _safe_float(row.get("edge")),
        "score": score,
        "basketball_priority_score": basketball_score,
        "sim_support_score": sim_support_score,
        "value_support_score": value_support_score,
        "recommendation_priority_score": priority,
        "basketball_summary": " ".join(basketball_reasons[:2]) if basketball_reasons else None,
        "basketball_reasons": basketball_reasons,
        "sim_reasons": sim_reasons,
        "value_reasons": value_reasons,
        "model_reasons": list(sim_reasons) + list(value_reasons),
        "reasons": list(basketball_reasons) + list(sim_reasons) + list(value_reasons),
        "game_shape": game_shape,
        "pred_margin": pred_margin,
        "pred_total": pred_total,
        "why_explain": row.get("why_explain"),
        "score_explain": row.get("score_explain"),
        "score_components": row.get("score_components"),
        "start_time_local": _best_bets_local_start_label(start_raw),
        "start_dt_local": start_dt_local,
        "source": "recommendations",
    }


def _decorate_prop_best_bet_candidate(
    item: dict[str, Any],
    *,
    date_str: str,
    pred_row: dict[str, Any] | None,
    matchup_ctx: dict[str, Any] | None,
    injury_snapshot: dict[str, dict[str, Any]],
    slate_total_median: float | None,
) -> dict[str, Any] | None:
    player = str(item.get("player") or "").strip()
    team_tri = (_get_tricode(item.get("team")) or str(item.get("team") or "").strip().upper())
    top_play = item.get("top_play") if isinstance(item.get("top_play"), dict) else None
    if not player or not team_tri or not isinstance(top_play, dict):
        return None

    market = str(top_play.get("market") or "").strip().lower()
    side = str(top_play.get("side") or "").strip().upper()
    if not market or not side:
        return None

    line = _safe_float(top_play.get("line"))
    price = _safe_float(top_play.get("price"))
    ev = _safe_float(top_play.get("ev"))
    ev_pct = _safe_float(top_play.get("ev_pct"))
    if ev_pct is None and ev is not None:
        ev_pct = float(ev) * 100.0
    consensus = _safe_float(item.get("top_play_consensus"))
    line_adv = _safe_float(item.get("top_play_line_adv"))
    baseline = _safe_float(item.get("top_play_baseline"))
    if baseline is None:
        baseline = _best_bets_prop_stat_value(pred_row, market, "pred")
    sd = _best_bets_prop_sd_value(pred_row, market)
    roll5 = _best_bets_prop_stat_value(pred_row, market, "roll5")
    roll3 = _best_bets_prop_stat_value(pred_row, market, "roll3")
    roll10 = _best_bets_prop_stat_value(pred_row, market, "roll10")
    lag1 = _best_bets_prop_stat_value(pred_row, market, "lag1")
    pred_min = _safe_float((pred_row or {}).get("pred_min"))
    roll5_min = _safe_float((pred_row or {}).get("roll5_min"))
    roll10_min = _safe_float((pred_row or {}).get("roll10_min"))
    home_flag = _best_bets_prop_home_flag((pred_row or {}).get("home"))
    b2b = False
    try:
        b2b = bool(float((pred_row or {}).get("b2b") or 0.0) > 0.0)
    except Exception:
        b2b = False

    p_win = (
        _safe_float(top_play.get("model_prob"))
        or _safe_float(top_play.get("prob_calib"))
        or _safe_float(top_play.get("probability"))
        or _safe_float(top_play.get("p_win"))
        or _safe_float(top_play.get("prob"))
    )
    if p_win is None:
        p_win = _best_bets_prop_win_prob(baseline, sd, line, side)
    if p_win is None:
        p_win = _best_bets_prob_from_ev(ev, price)
    implied_prob = _american_to_implied_prob(price)
    prob_edge = None
    if p_win is not None and implied_prob is not None:
        prob_edge = float(p_win) - float(implied_prob)

    is_over = side.startswith("O")
    gap = None
    if baseline is not None and line is not None:
        gap = (float(baseline) - float(line)) if is_over else (float(line) - float(baseline))
    z_gap = None
    if gap is not None and sd is not None and sd > 0:
        z_gap = float(gap) / float(sd)

    matchup = None
    start_raw = None
    pred_total = None
    opponent = str((pred_row or {}).get("opponent") or "").strip().upper() or None
    if isinstance(matchup_ctx, dict):
        matchup = f"{matchup_ctx.get('away_team')} @ {matchup_ctx.get('home_team')}"
        start_raw = matchup_ctx.get("commence_time")
        pred_total = _safe_float(matchup_ctx.get("pred_total"))
        if matchup_ctx.get("home_tri") == team_tri:
            opponent = str(matchup_ctx.get("away_tri") or opponent or "")
        elif matchup_ctx.get("away_tri") == team_tri:
            opponent = str(matchup_ctx.get("home_tri") or opponent or "")
    if not matchup and opponent:
        matchup = f"{opponent} @ {team_tri}"

    history_ctx = _best_bets_prop_history_context(
        date_str=date_str,
        player_name=player,
        team_tri=team_tri,
        opponent=opponent,
        market=market,
        home_flag=home_flag,
    )
    sim_ctx = _best_bets_prop_sim_context(date_str, player, team_tri, market)

    basketball_reasons: list[str] = []
    basketball_points = 0.0
    usage_markets = {"pts", "ast", "threes", "pra", "pr", "pa", "ra"}
    scoring_markets = {"pts", "ast", "threes", "pra", "pr", "pa", "ra"}
    rebound_markets = {"reb", "ra", "pr", "pra"}
    minutes_base = pred_min if pred_min is not None else roll5_min
    team_outs = int((injury_snapshot.get("counts") or {}).get(team_tri, 0) or 0)
    market_label = _best_bets_prop_reason_label(market)

    if roll5 is not None and line is not None:
        if is_over and float(roll5) >= float(line) + 0.5:
            basketball_reasons.append(f"Recent form is already clearing this number with a last-five average of {float(roll5):.1f}")
            basketball_points += 0.30
        elif (not is_over) and float(roll5) <= float(line) - 0.5:
            basketball_reasons.append(f"Recent form has stayed below this line with a last-five average of {float(roll5):.1f}")
            basketball_points += 0.30
    if roll10 is not None and line is not None:
        if is_over and float(roll10) >= float(line) + 0.5:
            basketball_reasons.append(f"The last-10 sample is still above this number at {float(roll10):.1f}, so the over is not just riding a short heater")
            basketball_points += 0.18
        elif (not is_over) and float(roll10) <= float(line) - 0.5:
            basketball_reasons.append(f"The last-10 sample is holding under this line at {float(roll10):.1f}, which supports the lower-volume case")
            basketball_points += 0.18
    elif roll3 is not None and line is not None:
        if is_over and float(roll3) >= float(line) + 0.5:
            basketball_reasons.append(f"The short-term trend is up with a last-three average of {float(roll3):.1f}")
            basketball_points += 0.18
        elif (not is_over) and float(roll3) <= float(line) - 0.5:
            basketball_reasons.append(f"The short-term trend sits under this number at {float(roll3):.1f} over the last three")
            basketball_points += 0.18
    if lag1 is not None and line is not None:
        if is_over and float(lag1) >= float(line):
            basketball_reasons.append(f"The last game landed at {float(lag1):.1f}, which is already above this line")
            basketball_points += 0.08
        elif (not is_over) and float(lag1) <= float(line):
            basketball_reasons.append(f"The last game landed at {float(lag1):.1f}, which stayed under this line")
            basketball_points += 0.08
    if minutes_base is not None:
        if is_over and float(minutes_base) >= 30.0:
            basketball_reasons.append(f"The minute load looks stable around {float(minutes_base):.1f}")
            basketball_points += 0.16
        elif (not is_over) and float(minutes_base) <= 26.0:
            basketball_reasons.append(f"Projected minutes sit in a softer band around {float(minutes_base):.1f}")
            basketball_points += 0.16
    if pred_min is not None and roll10_min is not None:
        minute_gap = float(pred_min) - float(roll10_min)
        if is_over and minute_gap >= 1.5:
            basketball_reasons.append(f"Projected minutes ({float(pred_min):.1f}) sit above his last-10 workload ({float(roll10_min):.1f}), which strengthens the volume path")
            basketball_points += 0.12
        elif (not is_over) and minute_gap <= -1.5:
            basketball_reasons.append(f"Projected minutes ({float(pred_min):.1f}) are lighter than his last-10 workload ({float(roll10_min):.1f}), which leans under")
            basketball_points += 0.12

    opponent_avg = _safe_float(history_ctx.get("opponent_avg"))
    opponent_games = int(history_ctx.get("opponent_games") or 0)
    if opponent_avg is not None and opponent_games >= 2 and line is not None:
        if is_over and float(opponent_avg) >= float(line) + 0.5:
            basketball_reasons.append(f"He has averaged {float(opponent_avg):.1f} {market_label} in {opponent_games} recent games against {opponent or 'this opponent'}")
            basketball_points += min(0.18, 0.08 + (0.02 * float(min(opponent_games, 5))))
        elif (not is_over) and float(opponent_avg) <= float(line) - 0.5:
            basketball_reasons.append(f"He has stayed at {float(opponent_avg):.1f} {market_label} across {opponent_games} recent looks against {opponent or 'this opponent'}")
            basketball_points += min(0.18, 0.08 + (0.02 * float(min(opponent_games, 5))))

    venue_avg = _safe_float(history_ctx.get("venue_avg"))
    venue_games = int(history_ctx.get("venue_games") or 0)
    venue_label = None
    if home_flag is True:
        venue_label = "at home"
    elif home_flag is False:
        venue_label = "on the road"
    if venue_label and venue_avg is not None and venue_games >= 5 and line is not None:
        if is_over and float(venue_avg) >= float(line) + 0.5:
            basketball_reasons.append(f"{venue_label.capitalize()}, he is averaging {float(venue_avg):.1f} {market_label} over his last {venue_games} games in that split")
            basketball_points += 0.14
        elif (not is_over) and float(venue_avg) <= float(line) - 0.5:
            basketball_reasons.append(f"{venue_label.capitalize()}, he is averaging only {float(venue_avg):.1f} {market_label} over his last {venue_games} games in that split")
            basketball_points += 0.14

    close_p50 = _safe_float(sim_ctx.get("close_p50"))
    blowout_p50 = _safe_float(sim_ctx.get("blowout_p50"))
    close_gap = _safe_float(sim_ctx.get("close_gap"))
    close_n = int(sim_ctx.get("close_n") or 0)
    blowout_n = int(sim_ctx.get("blowout_n") or 0)
    is_star = bool(sim_ctx.get("is_star"))
    scenario_gap_threshold = 0.75 if is_star else 1.0
    scenario_ready = bool(
        market in usage_markets
        and close_p50 is not None
        and blowout_p50 is not None
        and close_gap is not None
        and blowout_n >= 25
        and ((close_n >= 10) if is_star else (close_n >= 20))
    )
    if scenario_ready:
        if is_over and float(close_gap) >= float(scenario_gap_threshold):
            basketball_reasons.append(f"SmartSim keeps his {market_label} median at {float(close_p50):.1f} in close games versus {float(blowout_p50):.1f} in blowouts, so the over benefits if his closing workload stays live")
            basketball_points += 0.18
        elif (not is_over) and float(close_gap) >= float(scenario_gap_threshold) and line is not None and float(blowout_p50) <= float(line) - 0.5:
            basketball_reasons.append(f"The blowout branch trims his {market_label} median to {float(blowout_p50):.1f}, which is the cleaner path for this under")
            basketball_points += 0.16
        if is_star and float(close_gap) >= float(scenario_gap_threshold):
            if is_over:
                basketball_reasons.append(f"{player} carries a star-level closing role, so tight fourth-quarter scripts keep the ball and late-possession usage in his hands")
                basketball_points += 0.12
            elif line is not None and float(blowout_p50) <= float(line) - 0.5:
                basketball_reasons.append(f"Because {player}'s highest-usage minutes come in competitive finishes, this under improves if the game leans toward the blowout branch")
                basketball_points += 0.10
    if team_outs >= 2 and market in usage_markets and is_over:
        basketball_reasons.append(f"A thinner {team_tri} rotation can concentrate touches toward {player}")
        basketball_points += 0.18
    elif team_outs == 0 and market in usage_markets and (not is_over):
        basketball_reasons.append(f"A healthy {team_tri} rotation keeps touches spread out across the lineup")
        basketball_points += 0.10
    if b2b and (not is_over):
        basketball_reasons.append("The back-to-back spot adds efficiency and minute downside")
        basketball_points += 0.14
    elif (not b2b) and is_over and minutes_base is not None and float(minutes_base) >= 28.0:
        basketball_reasons.append("This is a cleaner rest spot without a back-to-back tax")
        basketball_points += 0.10
    if pred_total is not None and slate_total_median is not None:
        if market in scoring_markets:
            if is_over and float(pred_total) >= float(slate_total_median) + 3.0:
                basketball_reasons.append("The game environment projects faster and higher scoring than the slate median")
                basketball_points += 0.16
            elif (not is_over) and float(pred_total) <= float(slate_total_median) - 3.0:
                basketball_reasons.append("The game environment projects slower and lower scoring than the slate median")
                basketball_points += 0.16
        elif market in rebound_markets:
            if is_over and float(pred_total) >= float(slate_total_median) + 2.0:
                basketball_reasons.append("Projected shot volume should create extra rebound chances")
                basketball_points += 0.14
            elif (not is_over) and float(pred_total) <= float(slate_total_median) - 2.0:
                basketball_reasons.append("A softer scoring environment trims the rebound volume case")
                basketball_points += 0.14

    sim_reasons: list[str] = []
    sim_points = 0.0
    if baseline is not None and line is not None:
        sim_reasons.append(f"The model baseline sits at {float(baseline):.1f} against a {float(line):.1f} line")
        sim_points += min(0.45, max(0.0, float(gap or 0.0)) / 3.0)
    if z_gap is not None:
        sim_reasons.append(f"That leaves roughly {float(z_gap):+.2f} standard deviations of cushion")
        sim_points += min(0.30, abs(float(z_gap)) / 1.5)
    if p_win is not None:
        sim_reasons.append(f"Win probability grades at {float(p_win) * 100.0:.1f}%")
        sim_points += min(0.30, max(0.0, float(p_win) - 0.5) / 0.2)
    if close_p50 is not None and blowout_p50 is not None and close_gap is not None and abs(float(close_gap)) >= 1.0:
        sim_reasons.append(f"Scenario split shows a {float(close_p50):.1f} close-game median versus {float(blowout_p50):.1f} in blowouts")
        sim_points += min(0.18, abs(float(close_gap)) / 6.0)

    value_reasons: list[str] = []
    value_points = 0.0
    if ev_pct is not None:
        value_reasons.append(f"Projected value is {float(ev_pct):+.1f}% per unit risked")
        value_points += min(0.60, max(0.0, float(ev_pct)) / 25.0)
    if consensus is not None and consensus >= 0.5:
        value_reasons.append("Multiple books are aligned on this side")
        value_points += min(0.20, float(consensus) * 0.20)
    if line_adv is not None and line_adv >= 0.5:
        value_reasons.append("The current book is still hanging the best available line")
        value_points += min(0.15, float(line_adv) * 0.15)
    if price is not None and abs(float(price)) <= 125:
        value_reasons.append(f"The price stays workable at {float(price):+.0f}")
        value_points += 0.10
    if prob_edge is not None and prob_edge > 0:
        value_reasons.append(f"Model probability clears the market by {float(prob_edge) * 100.0:.1f} points")
        value_points += min(0.15, float(prob_edge) / 0.10)

    basketball_reasons = _best_bets_unique_strings(basketball_reasons)
    sim_reasons = _best_bets_unique_strings(sim_reasons)
    value_reasons = _best_bets_unique_strings(value_reasons)

    basketball_score = round(_best_bets_clamp01(basketball_points) * 100.0, 1)
    sim_support_score = round(_best_bets_clamp01(sim_points) * 100.0, 1)
    value_support_score = round(_best_bets_clamp01(value_points) * 100.0, 1)
    explicit_score = _safe_float(item.get("score"))
    score = explicit_score
    if score is None:
        score = round((0.65 * sim_support_score) + (0.35 * value_support_score), 1)
    priority = round((0.45 * basketball_score) + (0.35 * sim_support_score) + (0.20 * value_support_score), 1)

    game_key = None
    if isinstance(matchup_ctx, dict):
        game_key = f"{date_str}:{matchup_ctx.get('away_tri')}@{matchup_ctx.get('home_tri')}"
    elif opponent:
        game_key = f"{date_str}:{opponent}@{team_tri}"
    if not game_key:
        game_key = f"{date_str}:{team_tri}:{player}"

    return {
        "game_key": game_key,
        "player_key": f"{_norm_player_name(player)}@{team_tri}",
        "date": date_str,
        "market": market,
        "rec_code": _best_bets_prop_market_label(market),
        "selection": side,
        "display_pick": f"{player} {side.title()} {float(line):.1f} {_best_bets_prop_market_label(market)}" if line is not None else f"{player} {side.title()} {_best_bets_prop_market_label(market)}",
        "matchup": matchup or team_tri,
        "player": player,
        "team": team_tri,
        "opponent": opponent,
        "line": line,
        "price": price,
        "p_win": round(float(p_win), 4) if p_win is not None else None,
        "implied_prob": round(float(implied_prob), 4) if implied_prob is not None else None,
        "prob_edge": round(float(prob_edge), 4) if prob_edge is not None else None,
        "ev": ev,
        "ev_pct": round(float(ev_pct), 2) if ev_pct is not None else None,
        "edge": _safe_float(top_play.get("edge")),
        "score": score,
        "basketball_priority_score": basketball_score,
        "sim_support_score": sim_support_score,
        "value_support_score": value_support_score,
        "recommendation_priority_score": priority,
        "basketball_summary": " ".join(basketball_reasons[:2]) if basketball_reasons else None,
        "basketball_reasons": basketball_reasons,
        "sim_reasons": sim_reasons,
        "value_reasons": value_reasons,
        "model_reasons": list(sim_reasons) + list(value_reasons),
        "reasons": list(basketball_reasons) + list(sim_reasons) + list(value_reasons),
        "model_baseline": baseline,
        "model_sd": sd,
        "top_play": dict(top_play),
        "top_play_reasons": list(item.get("top_play_reasons") or []),
        "top_play_consensus": consensus,
        "top_play_line_adv": line_adv,
        "top_play_explain": item.get("top_play_explain"),
        "start_time_local": _best_bets_local_start_label(start_raw),
        "start_dt_local": _best_bets_local_start_dt(start_raw),
        "source": "props_recommendations",
    }


def _recommendation_reason_bucket_payload(source: dict[str, Any] | None) -> dict[str, Any]:
    if not isinstance(source, dict):
        return {
            "basketball_summary": None,
            "basketball_reasons": [],
            "sim_reasons": [],
            "value_reasons": [],
            "model_reasons": [],
            "market_reasons": [],
            "reasons": [],
        }

    def _strings(values: Any) -> list[str]:
        if not isinstance(values, list):
            return []
        out: list[str] = []
        for raw in values:
            text = str(raw or "").strip()
            if text:
                out.append(text)
        return _best_bets_unique_strings(out)

    basketball_reasons = _strings(source.get("basketball_reasons"))
    sim_reasons = _strings(source.get("sim_reasons"))
    value_reasons = _strings(source.get("value_reasons"))
    explicit_model_reasons = _strings(source.get("model_reasons"))
    explicit_market_reasons = _strings(source.get("market_reasons"))

    if sim_reasons:
        model_reasons = list(sim_reasons)
    else:
        model_reasons = list(explicit_model_reasons)
        if explicit_market_reasons:
            market_keys = {reason.lower() for reason in explicit_market_reasons}
            model_reasons = [reason for reason in model_reasons if reason.lower() not in market_keys]
        elif value_reasons:
            value_keys = {reason.lower() for reason in value_reasons}
            model_reasons = [reason for reason in model_reasons if reason.lower() not in value_keys]
        model_reasons = _best_bets_unique_strings(model_reasons)

    market_reasons = explicit_market_reasons or list(value_reasons)
    market_reasons = _best_bets_unique_strings(market_reasons)
    value_reasons = value_reasons or list(market_reasons)
    reasons = _best_bets_unique_strings(list(basketball_reasons) + list(model_reasons) + list(market_reasons))

    basketball_summary = str(source.get("basketball_summary") or "").strip() or None
    if basketball_summary is None and basketball_reasons:
        basketball_summary = "; ".join(basketball_reasons[:2])

    return {
        "basketball_summary": basketball_summary,
        "basketball_reasons": basketball_reasons,
        "sim_reasons": sim_reasons,
        "value_reasons": value_reasons,
        "model_reasons": model_reasons,
        "market_reasons": market_reasons,
        "reasons": reasons,
    }


def _extend_recommendation_reason_payload(
    source: dict[str, Any] | None,
    *,
    basketball_reasons: Any = None,
    model_reasons: Any = None,
    market_reasons: Any = None,
) -> dict[str, Any]:
    payload = _recommendation_reason_bucket_payload(source)

    def _strings(values: Any) -> list[str]:
        if values is None:
            return []
        if isinstance(values, str):
            text = values.strip()
            return [text] if text else []
        if not isinstance(values, (list, tuple, set)):
            return []
        out: list[str] = []
        for raw in values:
            text = str(raw or "").strip()
            if text:
                out.append(text)
        return _best_bets_unique_strings(out)

    extra_basketball = _strings(basketball_reasons)
    extra_model = _strings(model_reasons)
    extra_market = _strings(market_reasons)

    payload["basketball_reasons"] = _best_bets_unique_strings(
        list(payload.get("basketball_reasons") or []) + extra_basketball
    )
    payload["sim_reasons"] = _best_bets_unique_strings(
        list(payload.get("sim_reasons") or []) + extra_model
    )
    payload["model_reasons"] = _best_bets_unique_strings(
        list(payload.get("model_reasons") or []) + extra_model
    )
    payload["value_reasons"] = _best_bets_unique_strings(
        list(payload.get("value_reasons") or []) + extra_market
    )
    payload["market_reasons"] = _best_bets_unique_strings(
        list(payload.get("market_reasons") or []) + extra_market
    )
    payload["reasons"] = _best_bets_unique_strings(
        list(payload.get("basketball_reasons") or [])
        + list(payload.get("model_reasons") or [])
        + list(payload.get("market_reasons") or [])
    )

    if isinstance(source, dict):
        for key in (
            "market",
            "side",
            "line",
            "price",
            "home",
            "away",
            "market_home_margin",
            "basketball_priority_score",
            "sim_support_score",
            "value_support_score",
            "recommendation_priority_score",
            "pred_margin",
            "pred_total",
            "model_baseline",
            "model_sd",
            "p_win",
            "implied_prob",
            "prob_edge",
            "ev",
            "ev_pct",
            "edge",
            "display_pick",
            "selection",
            "matchup",
            "game_shape",
            "top_play_explain",
            "start_time_local",
            "start_dt_local",
        ):
            value = source.get(key)
            if value is not None:
                payload[key] = value

    if not payload.get("basketball_summary") and payload.get("basketball_reasons"):
        payload["basketball_summary"] = "; ".join((payload.get("basketball_reasons") or [])[:2])

    return payload


