def _cards_policy_number(row: dict[str, Any] | None, *keys: str) -> float | None:
    if not isinstance(row, dict):
        return None
    for key in keys:
        value = row.get(key)
        if value is None and isinstance(row.get("best"), dict):
            value = row["best"].get(key)
        if value is None and isinstance(row.get("top_play"), dict):
            value = row["top_play"].get(key)
        num = _safe_float(value)
        if num is not None:
            return num
    return None


def _cards_locked_policy_components(row: dict[str, Any]) -> dict[str, float | None]:
    trend = _cards_policy_number(row, "basketball_priority_score")
    sim = _cards_policy_number(row, "sim_support_score", "score")
    value = _cards_policy_number(row, "value_support_score")
    priority = _cards_policy_number(row, "recommendation_priority_score", "score_adj", "score")
    p_win = _cards_policy_number(row, "p_win", "model_prob", "probability", "prob_calib")
    implied_prob = _cards_policy_number(row, "implied_prob")
    prob_edge = _cards_policy_number(row, "prob_edge")
    if prob_edge is None and p_win is not None and implied_prob is not None:
        prob_edge = float(p_win) - float(implied_prob)
    ev_pct = _cards_policy_number(row, "ev_pct")
    if ev_pct is None:
        ev = _cards_policy_number(row, "ev")
        if ev is not None:
            ev_pct = float(ev) * 100.0
    consensus = _cards_policy_number(row, "top_play_consensus")
    line_adv = _cards_policy_number(row, "top_play_line_adv")

    if trend is None and priority is not None and sim is not None and value is not None:
        trend = max(0.0, min(100.0, (float(priority) - (0.35 * float(sim)) - (0.20 * float(value))) / 0.45))
    if sim is None and priority is not None:
        sim = float(priority)
    if value is None:
        value = max(0.0, min(100.0, float(ev_pct or 0.0)))

    score = None
    if trend is not None or sim is not None or value is not None:
        score = round(
            (0.45 * float(trend or 0.0))
            + (0.35 * float(sim or 0.0))
            + (0.20 * float(value or 0.0)),
            3,
        )
        if consensus is not None:
            score += min(4.0, 4.0 * float(max(0.0, min(1.0, consensus))))
        if line_adv is not None:
            score += min(3.0, 3.0 * float(max(0.0, min(1.0, line_adv))))
        if prob_edge is not None and prob_edge > 0:
            score += min(6.0, float(prob_edge) * 100.0 * 0.18)
        score = round(max(0.0, min(100.0, float(score))), 3)

    return {
        "trend": trend,
        "sim": sim,
        "value": value,
        "priority": priority,
        "p_win": p_win,
        "prob_edge": prob_edge,
        "ev_pct": ev_pct,
        "consensus": consensus,
        "line_adv": line_adv,
        "score": score,
    }


def _cards_locked_policy_sort_key(row: dict[str, Any]) -> tuple[float, float, float, float, float, float]:
    comp = _cards_locked_policy_components(row)
    return (
        float(comp.get("score") or 0.0),
        float(comp.get("trend") or 0.0),
        float(comp.get("sim") or 0.0),
        float(comp.get("prob_edge") or 0.0),
        float(comp.get("ev_pct") or 0.0),
        float(comp.get("priority") or 0.0),
    )


def _cards_locked_policy_has_rich_inputs(row: dict[str, Any]) -> bool:
    trend = _cards_policy_number(row, "basketball_priority_score")
    sim = _cards_policy_number(row, "sim_support_score")
    value = _cards_policy_number(row, "value_support_score")
    p_win = _cards_policy_number(row, "p_win", "model_prob", "probability", "prob_calib")
    prob_edge = _cards_policy_number(row, "prob_edge")
    signal_count = sum(
        value is not None
        for value in (trend, sim, value, p_win, prob_edge)
    )
    return bool((trend is not None and sim is not None) or signal_count >= 3)


def _cards_locked_policy_has_support_signal(row: dict[str, Any], comp: dict[str, float | None] | None = None) -> bool:
    comp = comp if isinstance(comp, dict) else _cards_locked_policy_components(row)
    consensus = comp.get("consensus")
    line_adv = comp.get("line_adv")
    prob_edge = comp.get("prob_edge")
    return bool(
        (consensus is not None and float(consensus) > 0.0)
        or (line_adv is not None and float(line_adv) > 0.0)
        or (prob_edge is not None and float(prob_edge) > 0.0)
    )


def _cards_locked_policy_qualifies(row: dict[str, Any], *, market_type: str, tier: str) -> bool:
    policy = _NBA_CARDS_LOCKED_POLICY
    comp = _cards_locked_policy_components(row)
    score = float(comp.get("score") or 0.0)
    trend = float(comp.get("trend") or 0.0)
    sim = float(comp.get("sim") or 0.0)
    p_win = comp.get("p_win")
    prob_edge = comp.get("prob_edge")
    market_key = str(row.get("market") or "").strip().upper()
    price = _cards_policy_number(row, "price", "odds")

    if market_type == "prop":
        if tier == "official":
            if not _cards_locked_policy_has_rich_inputs(row):
                return False
            if not _cards_locked_policy_has_support_signal(row, comp):
                return False
            if score < float(policy.get("prop_generic_official_min_score") or 0.0):
                return False
            if trend < float(policy.get("prop_generic_official_min_trend") or 0.0):
                return False
            if sim < float(policy.get("prop_generic_official_min_sim") or 0.0):
                return False
            if p_win is None or float(p_win) < float(policy.get("prop_generic_official_min_win_prob") or 0.0):
                return False
            if prob_edge is None or float(prob_edge) < float(policy.get("prop_generic_official_min_prob_edge") or 0.0):
                return False
            return True
        if not _cards_locked_policy_has_rich_inputs(row):
            if not _cards_locked_policy_has_support_signal(row, comp):
                return False
            return score >= float(policy["prop_lite_min_playable"])
        return score >= float(policy["prop_min_playable"])

    if tier == "official":
        if market_key == "ML" and price is not None and float(price) < float(policy["game_market_ml_min_price"]):
            return False
        if score < float(policy["game_market_min_official"]):
            return False
        if trend < float(policy["game_market_min_trend"]):
            return False
        if sim < float(policy["game_market_min_sim"]):
            return False
        if prob_edge is not None and float(prob_edge) < float(policy["game_market_min_prob_edge"]):
            return False
        return True
    return score >= float(policy["game_market_min_playable"])


def _cards_locked_policy_annotate(row: dict[str, Any]) -> dict[str, Any]:
    comp = _cards_locked_policy_components(row)
    out = dict(row)
    out["locked_policy_score"] = comp.get("score")
    out["locked_policy_trend_score"] = comp.get("trend")
    out["locked_policy_sim_score"] = comp.get("sim")
    out["locked_policy_value_score"] = comp.get("value")
    return out


def _cards_prop_canonical_candidate(row: dict[str, Any]) -> Any | None:
    if not isinstance(row, dict) or _build_canonical_prop_candidate is None:
        return None
    try:
        return _build_canonical_prop_candidate(
            row,
            team=str(row.get("team") or "").strip().upper() or None,
            opponent=str(row.get("opponent") or "").strip().upper() or None,
            team_side=str(row.get("team_side") or "").strip().lower() or None,
        )
    except Exception:
        return None


def _cards_prop_sleeve_key(row: dict[str, Any]) -> str | None:
    candidate = _cards_prop_canonical_candidate(row)
    if candidate is None:
        return None
    sleeve_key = str(getattr(candidate, "sleeve_key", "") or "").strip().lower()
    return sleeve_key or None


def _cards_prop_sleeve_policy(row: dict[str, Any]) -> dict[str, Any] | None:
    sleeve_key = _cards_prop_sleeve_key(row)
    if not sleeve_key:
        return None
    policy = _NBA_CARDS_PROP_SLEEVE_POLICY.get(sleeve_key)
    if not isinstance(policy, dict):
        return None
    return dict(policy, sleeve_key=sleeve_key)


def _cards_prop_has_complete_canonical_inputs(row: dict[str, Any]) -> bool:
    candidate = _cards_prop_canonical_candidate(row)
    if candidate is None:
        return False
    return bool(
        getattr(candidate, "sim_mean", None) is not None
        and getattr(candidate, "sim_sd", None) is not None
        and getattr(candidate, "model_prob", None) is not None
        and getattr(candidate, "line", None) is not None
        and getattr(candidate, "price", None) is not None
    )


def _cards_prop_row_player_key(row: dict[str, Any]) -> tuple[str, str] | None:
    if not isinstance(row, dict):
        return None
    team_key = str(row.get("team") or "").strip().upper()
    player_key = _norm_player_name(str(row.get("player") or row.get("player_name") or ""))
    if not team_key or not player_key:
        return None
    return team_key, player_key


def _cards_prop_playable_via_sleeve_policy(row: dict[str, Any]) -> bool:
    sleeve_policy = _cards_prop_sleeve_policy(row)
    if not _cards_prop_has_complete_canonical_inputs(row):
        return False

    if not isinstance(sleeve_policy, dict):
        return _cards_locked_policy_qualifies(row, market_type="prop", tier="playable")

    team_side_required = str(sleeve_policy.get("team_side") or "").strip().lower()
    if team_side_required:
        row_team_side = str(row.get("team_side") or "").strip().lower()
        if row_team_side != team_side_required:
            return False

    comp = _cards_locked_policy_components(row)
    score = float(comp.get("score") or 0.0)
    trend = float(comp.get("trend") or 0.0)
    sim = float(comp.get("sim") or 0.0)
    p_win = comp.get("p_win")
    prob_edge = comp.get("prob_edge")

    if score < float(sleeve_policy.get("min_score") or 0.0):
        return False
    if trend < float(sleeve_policy.get("min_trend") or 0.0):
        return False
    if sim < float(sleeve_policy.get("min_sim") or 0.0):
        return False
    if p_win is None or float(p_win) < float(sleeve_policy.get("min_win_prob") or 0.0):
        return False
    if prob_edge is None or float(prob_edge) < float(sleeve_policy.get("min_prob_edge") or 0.0):
        return False
    return True


def _cards_prop_official_via_sleeve_policy(row: dict[str, Any]) -> bool:
    sleeve_policy = _cards_prop_sleeve_policy(row)
    if not _cards_prop_has_complete_canonical_inputs(row):
        return False
    if not _cards_locked_policy_has_rich_inputs(row):
        return False

    team_side_required = str((sleeve_policy or {}).get("team_side") or "").strip().lower()
    if team_side_required:
        row_team_side = str(row.get("team_side") or "").strip().lower()
        if row_team_side != team_side_required:
            return False

    if not isinstance(sleeve_policy, dict) or not bool(sleeve_policy.get("official")):
        return _cards_locked_policy_qualifies(row, market_type="prop", tier="official")

    policy = _NBA_CARDS_LOCKED_POLICY
    comp = _cards_locked_policy_components(row)
    score = float(comp.get("score") or 0.0)
    trend = float(comp.get("trend") or 0.0)
    sim = float(comp.get("sim") or 0.0)
    p_win = comp.get("p_win")
    prob_edge = comp.get("prob_edge")

    min_score = float(sleeve_policy.get("official_min_score") or policy.get("prop_min_official") or 0.0)
    min_trend = float(sleeve_policy.get("official_min_trend") or policy.get("prop_min_trend") or 0.0)
    min_sim = float(sleeve_policy.get("official_min_sim") or policy.get("prop_min_sim") or 0.0)
    min_prob_edge = float(sleeve_policy.get("official_min_prob_edge") or policy.get("prop_min_prob_edge") or 0.0)
    min_win_prob = float(sleeve_policy.get("official_min_win_prob") or policy.get("prop_min_win_prob") or 0.0)

    if score < min_score:
        return False
    if trend < min_trend:
        return False
    if sim < min_sim:
        return False
    if p_win is None or float(p_win) < min_win_prob:
        return False
    if prob_edge is None or float(prob_edge) < min_prob_edge:
        return False
    return True


def _cards_select_prop_buckets(rows: list[dict[str, Any]]) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    ranked = [_cards_locked_policy_annotate(row) for row in rows if isinstance(row, dict)]
    ranked.sort(key=_cards_locked_policy_sort_key, reverse=True)

    policy = _NBA_CARDS_LOCKED_POLICY
    official_cap_total = int(policy.get("prop_official_cap_per_game") or 0)
    playable_cap_total = int(policy.get("prop_cap_per_game") or 0)
    official: list[dict[str, Any]] = []
    playable: list[dict[str, Any]] = []
    official_by_sleeve: dict[str, int] = {}
    official_players: set[tuple[str, str]] = set()
    playable_by_sleeve: dict[str, int] = {}
    playable_players: set[tuple[str, str]] = set()
    for row in ranked:
        sleeve_policy = _cards_prop_sleeve_policy(row)
        sleeve_key = str((sleeve_policy or {}).get("sleeve_key") or "").strip().lower()
        player_key = _cards_prop_row_player_key(row)

        if _cards_prop_official_via_sleeve_policy(row):
            if official_cap_total <= 0 or len(official) < official_cap_total:
                if player_key is not None and player_key in official_players:
                    continue
                if sleeve_key:
                    official_cap = int((sleeve_policy or {}).get("official_max_per_game") or policy.get("prop_official_cap_per_game") or 0)
                    if official_cap > 0 and int(official_by_sleeve.get(sleeve_key, 0)) >= official_cap:
                        continue
                selected = dict(row, card_bucket="official")
                if sleeve_key:
                    selected["playable_sleeve"] = sleeve_key
                    official_by_sleeve[sleeve_key] = int(official_by_sleeve.get(sleeve_key, 0) + 1)
                if player_key is not None:
                    official_players.add(player_key)
                official.append(selected)
                continue

        if not _cards_prop_playable_via_sleeve_policy(row):
            continue
        if playable_cap_total > 0 and len(playable) >= playable_cap_total:
            continue
        if player_key is not None and player_key in official_players:
            continue
        if player_key is not None and player_key in playable_players:
            continue
        if sleeve_key:
            max_per_game = int((sleeve_policy or {}).get("max_per_game") or 0)
            if max_per_game > 0 and int(playable_by_sleeve.get(sleeve_key, 0)) >= max_per_game:
                continue

        selected = dict(row, card_bucket="playable")
        if sleeve_key:
            selected["playable_sleeve"] = sleeve_key
            playable_by_sleeve[sleeve_key] = int(playable_by_sleeve.get(sleeve_key, 0) + 1)
        if player_key is not None:
            playable_players.add(player_key)
        playable.append(selected)

    if not official and not playable:
        for row in ranked:
            comp = _cards_locked_policy_components(row)
            has_positive_signal = bool(
                _cards_locked_policy_has_support_signal(row, comp)
                or float(comp.get("ev_pct") or 0.0) > 0.0
                or float(comp.get("priority") or 0.0) > 0.0
            )
            if not has_positive_signal:
                continue
            official.append(dict(row, card_bucket="official"))
            break

    for idx, row in enumerate(official, start=1):
        row["card_rank"] = idx
    for idx, row in enumerate(playable, start=1):
        row["card_rank"] = idx
    return official, playable


def _pregame_card_market_family(candidate: dict[str, Any]) -> str:
    market = str(candidate.get("market") or "").strip().upper()
    kind = str(candidate.get("kind") or "").strip().lower()
    if kind == "prop":
        return f"prop:{market.lower()}"
    return f"game:{market}"


def _pregame_card_base_score(row: dict[str, Any]) -> float:
    comp = _cards_locked_policy_components(row)
    score = max(0.0, min(1.0, float(comp.get("score") or 0.0) / 100.0))
    ev_pct = _cards_policy_number(row, "ev_pct")
    if ev_pct is None:
        ev = _cards_policy_number(row, "ev")
        if ev is not None:
            ev_pct = float(ev) * 100.0
    ev_norm = max(0.0, min(1.0, float(ev_pct or 0.0) / 12.0))
    prob_edge = comp.get("prob_edge")
    if prob_edge is None:
        prob_edge = _safe_float(row.get("edge"))
    prob_norm = max(0.0, min(1.0, float(prob_edge or 0.0) / 0.08))
    bucket = str(row.get("card_bucket") or "").strip().lower()
    bonus = float(_NBA_PREGAME_PORTFOLIO_POLICY.get("official_bonus") or 0.0) if bucket == "official" else 0.0
    return round((0.65 * score) + (0.20 * ev_norm) + (0.15 * prob_norm) + bonus, 6)


def _pregame_card_team_key(game: dict[str, Any], row: dict[str, Any], kind: str) -> str | None:
    home_tri = str(game.get("home_tri") or "").strip().upper()
    away_tri = str(game.get("away_tri") or "").strip().upper()
    if kind == "prop":
        team_key = str(row.get("team") or row.get("team_tri") or "").strip().upper()
        return team_key or None
    selection = str(row.get("selection") or row.get("side") or "").strip().lower()
    if selection in {"home", home_tri.lower()}:
        return home_tri or None
    if selection in {"away", away_tri.lower()}:
        return away_tri or None
    return None


def _pregame_card_candidate_identity(game: dict[str, Any], row: dict[str, Any], kind: str) -> tuple[Any, ...]:
    home_tri = str(game.get("home_tri") or "").strip().upper()
    away_tri = str(game.get("away_tri") or "").strip().upper()
    if kind == "prop":
        best = row.get("best") if isinstance(row.get("best"), dict) else {}
        market = str(best.get("market") or row.get("market") or "").strip().lower()
        side = str(best.get("side") or row.get("selection") or row.get("side") or "").strip().upper()
        line = _safe_float(best.get("line") if best.get("line") is not None else row.get("line"))
        team_key = str(row.get("team") or row.get("team_tri") or "").strip().upper()
        player_key = _norm_player_name(str(row.get("player") or row.get("player_name") or ""))
        return ("prop", home_tri, away_tri, team_key, player_key, market, side, float(line) if line is not None else None)
    market = str(row.get("market") or "").strip().upper()
    selection = str(row.get("selection") or row.get("side") or "").strip().lower()
    line = _safe_float(row.get("line"))
    return ("game", home_tri, away_tri, market, selection, float(line) if line is not None else None)


def _pregame_card_pair_penalty(left: dict[str, Any], right: dict[str, Any]) -> float:
    penalty = 0.0
    if left.get("matchup_key") == right.get("matchup_key"):
        penalty += 0.08
    if left.get("team_key") and left.get("team_key") == right.get("team_key"):
        penalty += 0.08
    if left.get("market_family") == right.get("market_family"):
        penalty += 0.10
    if left.get("kind") == "prop" and right.get("kind") == "prop":
        if left.get("prop_market") and left.get("prop_market") == right.get("prop_market"):
            penalty += 0.08
        if left.get("player_key") and left.get("player_key") == right.get("player_key"):
            penalty += 0.25
    if left.get("kind") != right.get("kind") and left.get("matchup_key") == right.get("matchup_key"):
        penalty += 0.04
    return min(0.35, max(0.0, penalty))


def _pregame_card_allocate_stakes(selected: list[dict[str, Any]], *, bankroll: float, reserve_pct: float, min_stake: float, max_stake: float) -> list[float]:
    if not selected:
        return []
    available = max(0.0, float(bankroll) * (1.0 - float(reserve_pct)))
    if available <= 0:
        return [0.0 for _ in selected]
    weights = [max(0.1, float(item.get("selected_score") or item.get("base_score") or 0.1)) for item in selected]
    total_weight = sum(weights)
    if total_weight <= 0:
        weights = [1.0 for _ in selected]
        total_weight = float(len(selected))
    stakes = [available * (weight / total_weight) for weight in weights]
    stakes = [min(float(max_stake), max(float(min_stake), float(stake))) for stake in stakes]
    total_stake = sum(stakes)
    if total_stake > available and total_stake > 0:
        scale = available / total_stake
        stakes = [round(stake * scale, 2) for stake in stakes]
    else:
        stakes = [round(stake, 2) for stake in stakes]
    return stakes


def _pregame_portfolio_unit_size(policy: dict[str, Any] | None) -> float:
    if isinstance(policy, dict):
        unit_size = _safe_float(policy.get("unit_size"))
        if unit_size is not None and unit_size > 0:
            return float(unit_size)
    return _BETTING_UNIT_SIZE


def _pregame_portfolio_units(amount: float | None, unit_size: float | None) -> float | None:
    amt = _safe_float(amount)
    unit = _safe_float(unit_size)
    if amt is None or unit is None or unit <= 0:
        return None
    return round(float(amt) / float(unit), 3)


def _apply_pregame_card_portfolio(games: list[dict[str, Any]]) -> dict[str, Any]:
    policy = _NBA_PREGAME_PORTFOLIO_POLICY
    if not bool(policy.get("enabled")):
        return {"enabled": False, "selected": 0, "candidates": 0}

    candidates: list[dict[str, Any]] = []
    for game in games:
        if not isinstance(game, dict) or bool(game.get("plays_locked")):
            continue
        home_tri = str(game.get("home_tri") or "").strip().upper()
        away_tri = str(game.get("away_tri") or "").strip().upper()
        matchup_key = f"{away_tri}@{home_tri}" if home_tri and away_tri else None
        for row in (game.get("game_market_recommendations") or []):
            if not isinstance(row, dict):
                continue
            bucket = str(row.get("card_bucket") or "official").strip().lower() or "official"
            if bucket not in {"official", "playable"}:
                continue
            market = str(row.get("market") or "").strip().upper()
            candidates.append(
                {
                    "kind": "game",
                    "row": row,
                    "game": game,
                    "matchup_key": matchup_key,
                    "team_key": _pregame_card_team_key(game, row, "game"),
                    "market_family": f"game:{market}",
                    "prop_market": None,
                    "player_key": None,
                    "identity": _pregame_card_candidate_identity(game, row, "game"),
                    "base_score": _pregame_card_base_score(row),
                }
            )
        prop_map = game.get("prop_recommendations") if isinstance(game.get("prop_recommendations"), dict) else {}
        for side_key in ("away", "home"):
            for row in (prop_map.get(side_key) or []):
                if not isinstance(row, dict):
                    continue
                bucket = str(row.get("card_bucket") or "").strip().lower()
                if bucket not in {"official", "playable"}:
                    continue
                best = row.get("best") if isinstance(row.get("best"), dict) else {}
                prop_market = str(best.get("market") or row.get("market") or "").strip().lower() or None
                candidates.append(
                    {
                        "kind": "prop",
                        "row": row,
                        "game": game,
                        "matchup_key": matchup_key,
                        "team_key": _pregame_card_team_key(game, row, "prop"),
                        "market_family": f"prop:{prop_market or 'unknown'}",
                        "prop_market": prop_market,
                        "player_key": _cards_prop_row_player_key(row),
                        "identity": _pregame_card_candidate_identity(game, row, "prop"),
                        "base_score": _pregame_card_base_score(row),
                    }
                )

    if not candidates:
        unit_size = _pregame_portfolio_unit_size(policy)
        bankroll = float(policy.get("bankroll") or 0.0)
        return {
            "enabled": True,
            "bankroll": bankroll,
            "bankroll_units": _pregame_portfolio_units(bankroll, unit_size),
            "unit_size": unit_size,
            "selected": 0,
            "candidates": 0,
        }

    for candidate in candidates:
        row = candidate["row"]
        row["portfolio_selected"] = False
        row["portfolio_rank"] = None
        row["portfolio_score"] = round(float(candidate.get("base_score") or 0.0), 6)
        row["stake_amount"] = None
        row["stake_units"] = None
        row["stake_pct"] = None

    ranked = sorted(candidates, key=lambda item: float(item.get("base_score") or 0.0), reverse=True)
    bankroll = float(policy.get("bankroll") or 0.0)
    unit_size = _pregame_portfolio_unit_size(policy)
    reserve_pct = float(policy.get("reserve_pct") or 0.0)
    min_stake = float(policy.get("min_stake") or 0.0)
    max_stake = float(policy.get("max_stake") or 0.0)
    max_total = int(policy.get("max_official_plays") or 0)
    if min_stake > 0 and bankroll > 0:
        affordable_cap = int(max(1, math.floor((bankroll * max(0.0, 1.0 - reserve_pct)) / min_stake)))
        if max_total > 0:
            max_total = min(max_total, affordable_cap)
        else:
            max_total = affordable_cap

    selected: list[dict[str, Any]] = []
    matchup_counts: dict[str, int] = {}
    team_counts: dict[str, int] = {}
    market_family_counts: dict[str, int] = {}
    prop_market_counts: dict[str, int] = {}
    kind_counts: dict[str, int] = {}
    seen_identity: set[tuple[Any, ...]] = set()
    min_selected_score = float(policy.get("min_selected_score") or 0.0)
    min_game_selected_score = float(policy.get("min_game_selected_score") or min_selected_score)
    corr_scale = float(policy.get("corr_penalty_scale") or 0.0)

    def _try_select(candidate: dict[str, Any], *, require_game_floor: bool = False) -> bool:
        nonlocal selected
        if max_total > 0 and len(selected) >= max_total:
            return False
        identity = candidate.get("identity")
        if identity in seen_identity:
            return False
        matchup_key = str(candidate.get("matchup_key") or "").strip()
        team_key = str(candidate.get("team_key") or "").strip().upper()
        market_family = str(candidate.get("market_family") or "").strip()
        prop_market = str(candidate.get("prop_market") or "").strip().lower()
        kind = str(candidate.get("kind") or "").strip().lower()
        if matchup_key and int(matchup_counts.get(matchup_key, 0)) >= int(policy.get("max_per_matchup") or 0):
            return False
        if team_key and int(team_counts.get(team_key, 0)) >= int(policy.get("max_per_team") or 0):
            return False
        if market_family and int(market_family_counts.get(market_family, 0)) >= int(policy.get("max_per_market_family") or 0):
            return False
        if prop_market and int(prop_market_counts.get(prop_market, 0)) >= int(policy.get("max_per_prop_market") or 0):
            return False
        if kind == "prop" and int(kind_counts.get("prop", 0)) >= int(policy.get("max_prop_plays") or 0):
            return False
        pair_penalty = corr_scale * sum(_pregame_card_pair_penalty(candidate, existing) for existing in selected)
        selected_score = round(max(0.0, float(candidate.get("base_score") or 0.0) - float(pair_penalty)), 6)
        threshold = min_game_selected_score if require_game_floor else min_selected_score
        if selected and selected_score < threshold:
            return False
        candidate["selected_score"] = selected_score
        selected.append(candidate)
        seen_identity.add(identity)
        if matchup_key:
            matchup_counts[matchup_key] = int(matchup_counts.get(matchup_key, 0) + 1)
        if team_key:
            team_counts[team_key] = int(team_counts.get(team_key, 0) + 1)
        if market_family:
            market_family_counts[market_family] = int(market_family_counts.get(market_family, 0) + 1)
        if prop_market:
            prop_market_counts[prop_market] = int(prop_market_counts.get(prop_market, 0) + 1)
        if kind:
            kind_counts[kind] = int(kind_counts.get(kind, 0) + 1)
        return True

    required_games = int(policy.get("min_game_plays") or 0)
    if required_games > 0:
        for candidate in ranked:
            if len(selected) >= required_games:
                break
            if str(candidate.get("kind") or "") != "game":
                continue
            _try_select(candidate, require_game_floor=True)

    for candidate in ranked:
        if max_total > 0 and len(selected) >= max_total:
            break
        _try_select(candidate)

    if not selected and ranked:
        fallback = dict(ranked[0])
        fallback["selected_score"] = float(fallback.get("base_score") or 0.0)
        selected = [fallback]

    stakes = _pregame_card_allocate_stakes(
        selected,
        bankroll=bankroll,
        reserve_pct=reserve_pct,
        min_stake=min_stake,
        max_stake=max_stake,
    )
    selected_identity = {candidate.get("identity") for candidate in selected}
    selected_rank_lookup: dict[tuple[Any, ...], tuple[int, float, float]] = {}
    for idx, candidate in enumerate(selected, start=1):
        stake_amount = float(stakes[idx - 1]) if idx - 1 < len(stakes) else 0.0
        stake_units = _pregame_portfolio_units(stake_amount, unit_size)
        stake_pct = round((stake_amount / bankroll), 4) if bankroll > 0 else None
        selected_rank_lookup[candidate.get("identity")] = (idx, float(candidate.get("selected_score") or candidate.get("base_score") or 0.0), stake_amount)
        row = candidate["row"]
        row["card_bucket"] = "official"
        row["card_rank"] = idx
        row["portfolio_selected"] = True
        row["portfolio_rank"] = idx
        row["portfolio_score"] = round(float(candidate.get("selected_score") or candidate.get("base_score") or 0.0), 6)
        row["stake_amount"] = round(stake_amount, 2)
        row["stake_units"] = stake_units
        row["stake_pct"] = stake_pct

    playable_rank = 0
    for candidate in ranked:
        row = candidate["row"]
        if candidate.get("identity") in selected_identity:
            continue
        playable_rank += 1
        row["card_bucket"] = "playable"
        row["card_rank"] = playable_rank
        row["portfolio_selected"] = False
        row["portfolio_rank"] = None
        row["portfolio_score"] = round(float(candidate.get("base_score") or 0.0), 6)
        row["stake_amount"] = None
        row["stake_units"] = None
        row["stake_pct"] = None

    selected_stake_total = round(sum(float(item[2]) for item in selected_rank_lookup.values()), 2)
    return {
        "enabled": True,
        "bankroll": bankroll,
        "bankroll_units": _pregame_portfolio_units(bankroll, unit_size),
        "unit_size": unit_size,
        "reserve_pct": reserve_pct,
        "min_stake": min_stake,
        "min_stake_units": _pregame_portfolio_units(min_stake, unit_size),
        "max_stake": max_stake,
        "max_stake_units": _pregame_portfolio_units(max_stake, unit_size),
        "candidates": len(candidates),
        "selected": len(selected),
        "selected_stake_total": selected_stake_total,
        "selected_stake_units_total": _pregame_portfolio_units(selected_stake_total, unit_size),
    }


def _cards_prop_recommendations_need_bucket_refresh(
    prop_recommendations: dict[str, list[dict[str, Any]]] | None,
    *,
    snapshot_picks: list[dict[str, Any]] | None,
) -> bool:
    total_rows = 0
    official_rows = 0
    playable_rows = 0
    for side_key in ("home", "away"):
        rows = prop_recommendations.get(side_key) if isinstance(prop_recommendations, dict) else []
        if not isinstance(rows, list):
            continue
        for row in rows:
            if not isinstance(row, dict):
                continue
            total_rows += 1
            bucket = str(row.get("card_bucket") or "").strip().lower()
            if bucket not in {"official", "playable", "discard"}:
                return total_rows > 0
            if bucket == "official":
                official_rows += 1
            elif bucket == "playable":
                playable_rows += 1

    if total_rows <= 0:
        return False

    snapshot_count = sum(1 for pick in (snapshot_picks or []) if _prop_snapshot_identity(pick) is not None)
    if snapshot_count > 0 and total_rows > snapshot_count and playable_rows <= 0 and official_rows >= snapshot_count:
        return True
    return False


def _merge_recommendation_reason_fields(
    target: dict[str, Any],
    source: dict[str, Any] | None,
    *,
    top_play_key: str | None = None,
) -> dict[str, Any]:
    if not isinstance(target, dict):
        return target

    payload = _recommendation_reason_bucket_payload(source)
    for key, value in payload.items():
        if isinstance(value, list):
            target[key] = list(value)
        elif value is not None:
            target[key] = value

    if top_play_key:
        target[top_play_key] = list(payload.get("reasons") or [])

    if isinstance(source, dict):
        for key in (
            "market",
            "side",
            "line",
            "price",
            "home_team",
            "away_team",
            "home_tricode",
            "away_tricode",
            "market_home_margin",
            "basketball_priority_score",
            "sim_support_score",
            "value_support_score",
            "recommendation_priority_score",
            "pred_margin",
            "pred_total",
            "model_baseline",
            "model_sd",
            "p_win",
            "implied_prob",
            "prob_edge",
            "ev",
            "ev_pct",
            "edge",
            "display_pick",
            "selection",
            "matchup",
            "game_shape",
            "top_play_explain",
            "start_time_local",
            "start_dt_local",
        ):
            value = source.get(key)
            if value is not None:
                target[key] = value
    return target


def _prop_source_support_fields(
    source_row: dict[str, Any] | None,
    *,
    market: str,
    side: str,
    line: float | None,
) -> dict[str, Any]:
    plays: list[dict[str, Any]] = []
    if isinstance(source_row, dict):
        raw_plays = source_row.get("plays")
        if isinstance(raw_plays, list):
            plays = [raw for raw in raw_plays if isinstance(raw, dict)]
        elif isinstance(source_row.get("top_play"), dict):
            plays = [source_row.get("top_play")]

    market_key = str(market or "").strip().lower()
    side_key = str(side or "").strip().upper()
    matching: list[dict[str, Any]] = []
    for raw in plays:
        mk = str(raw.get("market") or "").strip().lower()
        sd = str(raw.get("side") or "").strip().upper()
        if mk == market_key and sd == side_key:
            matching.append(raw)

    books = {
        _canonical_bookmaker_key(raw.get("book"))
        for raw in matching
        if _canonical_bookmaker_key(raw.get("book"))
    }
    books_count = int(len(books))
    consensus = 0.0
    if books_count > 0:
        consensus = max(0.0, min(1.0, (float(books_count) - 1.0) / 4.0))

    line_adv = 0.0
    if line is not None:
        try:
            lines = [_safe_float(raw.get("line")) for raw in matching]
            clean_lines = [float(value) for value in lines if value is not None]
            if clean_lines:
                if side_key == "OVER" and float(line) <= min(clean_lines) + 1e-6:
                    line_adv = 1.0
                elif side_key == "UNDER" and float(line) >= max(clean_lines) - 1e-6:
                    line_adv = 1.0
        except Exception:
            line_adv = 0.0

    return {
        "top_play_consensus": consensus,
        "top_play_line_adv": line_adv,
        "top_play_books_count": books_count,
    }


def _best_bets_ctx_for_matchup(
    game_context: dict[str, Any] | None,
    *,
    home: Any,
    away: Any,
) -> dict[str, Any] | None:
    if not isinstance(game_context, dict):
        return None
    by_pair = game_context.get("by_pair") if isinstance(game_context.get("by_pair"), dict) else {}
    by_team = game_context.get("by_team") if isinstance(game_context.get("by_team"), dict) else {}

    home_name = str(home or "").strip()
    away_name = str(away or "").strip()
    home_tri = (_get_tricode(home_name) or home_name.upper()) if home_name else ""
    away_tri = (_get_tricode(away_name) or away_name.upper()) if away_name else ""

    for key in (
        (home_name.upper(), away_name.upper()),
        (home_tri.upper(), away_tri.upper()),
    ):
        if key in by_pair and isinstance(by_pair.get(key), dict):
            return by_pair.get(key)

    for key in (home_name.upper(), away_name.upper(), home_tri.upper(), away_tri.upper()):
        if key in by_team and isinstance(by_team.get(key), dict):
            return by_team.get(key)
    return None


def _live_pregame_prior_for_matchup(
    game_context: dict[str, Any] | None,
    *,
    home: Any,
    away: Any,
) -> dict[str, Any] | None:
    ctx = _best_bets_ctx_for_matchup(game_context, home=home, away=away)
    if not isinstance(ctx, dict):
        return None

    out: dict[str, Any] = {}
    for key in (
        "home_team",
        "away_team",
        "home_tri",
        "away_tri",
        "pred_total",
        "pred_total_raw",
        "pred_total_adjusted",
        "pred_total_prop_blend",
        "pred_total_matchup_adjustment",
        "pred_margin",
        "pred_margin_raw",
        "pred_margin_adjusted",
        "pred_margin_prop_blend",
        "pred_margin_matchup_adjustment",
        "home_win_prob",
        "home_win_prob_raw",
        "home_win_prob_adjusted",
        "home_pred_points",
        "away_pred_points",
        "market_total",
        "commence_time",
        "game_pace",
        "league_pace",
        "home_off_rtg",
        "away_off_rtg",
        "home_def_rtg",
        "away_def_rtg",
        "home_recent_offense",
        "away_recent_offense",
        "home_recent_allowed_pts",
        "away_recent_allowed_pts",
        "home_prop_minutes_coverage",
        "away_prop_minutes_coverage",
        "home_prop_blend_weight",
        "away_prop_blend_weight",
    ):
        value = ctx.get(key)
        if value is not None:
            out[key] = value
    return out or None


def _live_team_pregame_prior_for_matchup(
    game_context: dict[str, Any] | None,
    *,
    home: Any,
    away: Any,
    team: Any,
) -> dict[str, Any] | None:
    prior = _live_pregame_prior_for_matchup(game_context, home=home, away=away)
    if not isinstance(prior, dict):
        return None

    team_key = (_get_tricode(str(team or "")) or str(team or "").strip().upper()) if team is not None else ""
    home_key = (_get_tricode(str(prior.get("home_tri") or prior.get("home_team") or home or "")) or str(prior.get("home_tri") or prior.get("home_team") or home or "").strip().upper())
    away_key = (_get_tricode(str(prior.get("away_tri") or prior.get("away_team") or away or "")) or str(prior.get("away_tri") or prior.get("away_team") or away or "").strip().upper())
    if not team_key or team_key not in {home_key, away_key}:
        return None

    raw_total = _safe_float(prior.get("pred_total_raw"))
    adjusted_total = _safe_float(prior.get("pred_total_adjusted"))
    if adjusted_total is None:
        adjusted_total = _safe_float(prior.get("pred_total"))
    raw_margin = _safe_float(prior.get("pred_margin_raw"))
    adjusted_margin = _safe_float(prior.get("pred_margin_adjusted"))
    if adjusted_margin is None:
        adjusted_margin = _safe_float(prior.get("pred_margin"))

    raw_home_total = None
    raw_away_total = None
    if raw_total is not None and raw_margin is not None:
        try:
            raw_home_total = 0.5 * (float(raw_total) + float(raw_margin))
            raw_away_total = 0.5 * (float(raw_total) - float(raw_margin))
        except Exception:
            raw_home_total = None
            raw_away_total = None

    if team_key == home_key:
        team_side = "home"
        team_points_adjusted = _safe_float(prior.get("home_pred_points"))
        team_points_raw = raw_home_total
        team_margin_raw = raw_margin
        team_margin_adjusted = adjusted_margin
    else:
        team_side = "away"
        team_points_adjusted = _safe_float(prior.get("away_pred_points"))
        team_points_raw = raw_away_total
        team_margin_raw = None if raw_margin is None else -float(raw_margin)
        team_margin_adjusted = None if adjusted_margin is None else -float(adjusted_margin)

    game_total_ratio = None
    if adjusted_total is not None and raw_total is not None and float(raw_total) > 1e-6:
        try:
            game_total_ratio = float(max(0.88, min(1.12, float(adjusted_total) / float(raw_total))))
        except Exception:
            game_total_ratio = None

    team_total_ratio = None
    if team_points_adjusted is not None and team_points_raw is not None and float(team_points_raw) > 1e-6:
        try:
            team_total_ratio = float(max(0.85, min(1.18, float(team_points_adjusted) / float(team_points_raw))))
        except Exception:
            team_total_ratio = None

    return {
        "team_side": team_side,
        "game_total_raw": raw_total,
        "game_total_adjusted": adjusted_total,
        "game_total_ratio": game_total_ratio,
        "team_pred_points_raw": team_points_raw,
        "team_pred_points_adjusted": team_points_adjusted,
        "team_total_ratio": team_total_ratio,
        "team_margin_raw": team_margin_raw,
        "team_margin_adjusted": team_margin_adjusted,
    }


def _live_player_prop_pregame_multiplier(team_prior: dict[str, Any] | None, stat_key: Any) -> float | None:
    if not isinstance(team_prior, dict):
        return None
    stat = _live_stat_key(stat_key)
    team_ratio = _safe_float(team_prior.get("team_total_ratio"))
    game_ratio = _safe_float(team_prior.get("game_total_ratio"))
    if team_ratio is None and game_ratio is None:
        return None

    base = None
    if stat == "pts":
        base = team_ratio
    elif stat == "ast" and team_ratio is not None:
        base = 1.0 + 0.75 * (float(team_ratio) - 1.0)
    elif stat == "threes" and team_ratio is not None:
        base = 1.0 + 1.05 * (float(team_ratio) - 1.0)
    elif stat == "pra" and team_ratio is not None:
        base = 1.0 + 0.90 * (float(team_ratio) - 1.0)
    elif stat == "reb" and game_ratio is not None:
        base = 1.0 + 0.35 * (float(game_ratio) - 1.0)
    elif stat == "tov" and team_ratio is not None:
        base = 1.0 + 0.40 * (float(team_ratio) - 1.0)
    elif stat in {"stl", "blk"} and game_ratio is not None:
        base = 1.0 + 0.25 * (float(game_ratio) - 1.0)
    if base is None:
        return None
    try:
        return float(max(0.85, min(1.18, float(base))))
    except Exception:
        return None


def _decorate_game_recommendation_payload(
    row: dict[str, Any] | None,
    *,
    date_str: str,
    game_context: dict[str, Any] | None,
    injury_snapshot: dict[str, dict[str, Any]],
    slate_total_median: float | None,
) -> dict[str, Any] | None:
    if not isinstance(row, dict):
        return None
    ctx = _best_bets_ctx_for_matchup(game_context, home=row.get("home"), away=row.get("away"))
    decorated = _decorate_game_best_bet_candidate(
        dict(row),
        date_str=date_str,
        ctx=ctx,
        injury_snapshot=injury_snapshot,
        slate_total_median=slate_total_median,
    )
    if not isinstance(decorated, dict):
        return None
    payload: dict[str, Any] = {}
    return _merge_recommendation_reason_fields(payload, decorated)


def _cards_game_selection_key(side: Any, home_tri: str, away_tri: str, home_name: str, away_name: str) -> str:
    raw = str(side or "").strip()
    if not raw:
        return ""
    raw_key = raw.lower()
    home_keys = {"home", str(home_tri or "").lower(), str(home_name or "").lower()}
    away_keys = {"away", str(away_tri or "").lower(), str(away_name or "").lower()}
    if raw_key in home_keys:
        return "home"
    if raw_key in away_keys:
        return "away"
    if raw_key in {"over", "under"}:
        return raw_key
    return raw_key


def _attach_recon_to_game_market_recommendation(
    row: dict[str, Any],
    *,
    home_tri: str,
    away_tri: str,
    home_name: str,
    away_name: str,
    odds_row: dict[str, Any] | None,
    actual_row: dict[str, Any] | None,
) -> None:
    if not isinstance(row, dict) or not isinstance(actual_row, dict):
        return

    home_pts = _safe_float(actual_row.get("home_pts"))
    away_pts = _safe_float(actual_row.get("visitor_pts"))
    if home_pts is None or away_pts is None:
        return

    market = str(row.get("market") or "").strip().upper()
    selection = _cards_game_selection_key(
        row.get("side") if row.get("side") is not None else row.get("selection"),
        home_tri,
        away_tri,
        home_name,
        away_name,
    )
    final_margin = float(home_pts) - float(away_pts)
    final_total = float(home_pts) + float(away_pts)
    price = _safe_float(row.get("price"))
    if price is None:
        price = _safe_float(row.get("odds"))

    result = None
    actual_value = None
    if market == "ML" and selection in {"home", "away"}:
        actual_value = final_margin
        if price is None and isinstance(odds_row, dict):
            price = _safe_float(odds_row.get("home_ml" if selection == "home" else "away_ml"))
        home_won = final_margin > 0.0
        result = "win" if ((selection == "home") == home_won) else "loss"
    elif market in {"ATS", "SPREAD", "SPREADS"} and selection in {"home", "away"}:
        actual_value = final_margin
        if price is None:
            price = -110.0
        home_spread = None
        if isinstance(odds_row, dict):
            home_spread = _safe_float(odds_row.get("home_spread"))
        if home_spread is None:
            market_home_margin = _safe_float(row.get("market_home_margin"))
            if market_home_margin is not None:
                home_spread = -float(market_home_margin)
        if home_spread is None:
            return
        if selection == "home":
            diff = float(final_margin) + float(home_spread)
        else:
            diff = -float(final_margin) - float(home_spread)
        if abs(diff) < 1e-9:
            result = "push"
        else:
            result = "win" if diff > 0.0 else "loss"
    elif market in {"TOTAL", "OU"} and selection in {"over", "under"}:
        actual_value = final_total
        if price is None:
            price = -110.0
        total_line = _safe_float(row.get("line"))
        if total_line is None and isinstance(odds_row, dict):
            total_line = _safe_float(odds_row.get("total"))
        if total_line is None:
            return
        diff = float(final_total) - float(total_line) if selection == "over" else float(total_line) - float(final_total)
        if abs(diff) < 1e-9:
            result = "push"
        else:
            result = "win" if diff > 0.0 else "loss"

    if result not in {"win", "loss", "push"}:
        return

    row["home_pts"] = float(home_pts)
    row["away_pts"] = float(away_pts)
    row["final_margin"] = float(final_margin)
    row["final_total"] = float(final_total)
    if price is not None:
        row["price"] = float(price)
    row["actual"] = actual_value
    row["result"] = result
    profit_u = _ll_profit_units(float(price), result) if price is not None else None
    if profit_u is not None:
        row["profit_u"] = float(profit_u)


def _decorate_prop_recommendation_payload(
    *,
    player_name: Any,
    team_tri: Any,
    top_play: dict[str, Any] | None,
    date_str: str,
    prop_prediction_lookup: dict[tuple[str, str], dict[str, Any]] | None,
    game_context: dict[str, Any] | None,
    injury_snapshot: dict[str, dict[str, Any]],
    slate_total_median: float | None,
    support_fields: dict[str, Any] | None = None,
) -> dict[str, Any] | None:
    player = str(player_name or "").strip()
    team_key = (_get_tricode(team_tri) or str(team_tri or "").strip().upper())
    if not player or not team_key or not isinstance(top_play, dict):
        return None

    pred_row = None
    if isinstance(prop_prediction_lookup, dict):
        pred_row = prop_prediction_lookup.get((_norm_player_name(player), team_key))

    matchup_ctx = None
    if isinstance(game_context, dict):
        by_team = game_context.get("by_team") if isinstance(game_context.get("by_team"), dict) else {}
        matchup_ctx = by_team.get(team_key) or by_team.get(str(team_tri or "").strip().upper())

    item = {
        "player": player,
        "team": team_key,
        "top_play": dict(top_play),
    }
    if isinstance(support_fields, dict):
        for key, value in support_fields.items():
            if value is not None:
                item[key] = value

    decorated = _decorate_prop_best_bet_candidate(
        item,
        date_str=date_str,
        pred_row=pred_row,
        matchup_ctx=matchup_ctx,
        injury_snapshot=injury_snapshot,
        slate_total_median=slate_total_median,
    )
    if not isinstance(decorated, dict):
        return None
    payload: dict[str, Any] = {}
    return _merge_recommendation_reason_fields(payload, decorated, top_play_key="top_play_reasons")


def _load_cards_game_recommendations_index(date_str: str) -> dict[tuple[str, str], list[dict[str, Any]]]:
    path = DATA_PROCESSED_DIR / f"recommendations_{date_str}.csv"
    if not path.exists():
        try:
            _maybe_fetch_remote_processed(path.name)
        except Exception:
            pass
    try:
        if not path.exists():
            return {}
        df = pd.read_csv(path)
    except Exception:
        return {}
    if not isinstance(df, pd.DataFrame) or df.empty:
        return {}

    out: dict[tuple[str, str], list[dict[str, Any]]] = {}
    for _, raw_row in df.iterrows():
        try:
            row = raw_row.to_dict()
            home_tri = _get_tricode(row.get("home")) or str(row.get("home") or "").strip().upper()
            away_tri = _get_tricode(row.get("away")) or str(row.get("away") or "").strip().upper()
            if not home_tri or not away_tri:
                continue
            out.setdefault((home_tri, away_tri), []).append(row)
        except Exception:
            continue
    return out


def _load_cards_prop_snapshot_index(date_str: str) -> dict[tuple[str, str], list[dict[str, Any]]]:
    payload = _load_props_recommendations_top_by_game_snapshot(date_str) or {}
    top_by_game = payload.get("top_by_game") if isinstance(payload.get("top_by_game"), list) else []
    out: dict[tuple[str, str], list[dict[str, Any]]] = {}
    for game in top_by_game:
        if not isinstance(game, dict):
            continue
        home_tri = str(game.get("home_tricode") or "").strip().upper()
        away_tri = str(game.get("away_tricode") or "").strip().upper()
        if not home_tri or not away_tri:
            continue
        picks = [pick for pick in (game.get("picks") or []) if isinstance(pick, dict)]
        if picks:
            out[(home_tri, away_tri)] = picks
    return out


def _load_cards_prop_recommendations_snapshot(date_str: str) -> dict[str, Any] | None:
    path = DATA_PROCESSED_DIR / f"cards_props_snapshot_{date_str}.json"
    if not path.exists():
        try:
            _maybe_fetch_remote_processed(path.name)
        except Exception:
            pass
    try:
        if not path.exists():
            return None
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return None


def _load_cards_prop_recommendations_index(date_str: str) -> dict[tuple[str, str], dict[str, list[dict[str, Any]]]]:
    payload = _load_cards_prop_recommendations_snapshot(date_str) or {}
    games = payload.get("games") if isinstance(payload.get("games"), list) else []
    out: dict[tuple[str, str], dict[str, list[dict[str, Any]]]] = {}
    for game in games:
        if not isinstance(game, dict):
            continue
        home_tri = str(game.get("home_tri") or "").strip().upper()
        away_tri = str(game.get("away_tri") or "").strip().upper()
        if not home_tri or not away_tri:
            continue
        prop_recommendations = game.get("prop_recommendations") if isinstance(game.get("prop_recommendations"), dict) else {}
        home_rows = [row for row in (prop_recommendations.get("home") or []) if isinstance(row, dict)]
        away_rows = [row for row in (prop_recommendations.get("away") or []) if isinstance(row, dict)]
        if home_rows or away_rows:
            out[(home_tri, away_tri)] = {
                "home": home_rows,
                "away": away_rows,
            }
    return out


def _load_cards_sim_detail_snapshot(date_str: str) -> dict[str, Any] | None:
    fname = f"cards_sim_detail_{date_str}.json"
    candidates = _processed_path_candidates(fname, prefer_repo=True)
    path = candidates[0] if candidates else (DATA_PROCESSED_DIR / fname)
    if not any(candidate.exists() for candidate in candidates):
        try:
            _maybe_fetch_remote_processed(fname)
        except Exception:
            pass
    try:
        for candidate in _processed_path_candidates(fname, prefer_repo=True):
            if candidate.exists():
                return json.loads(candidate.read_text(encoding="utf-8"))
        return None
    except Exception:
        return None


def _load_cards_sim_detail_scenario_fallback_index(date_str: str) -> dict[tuple[str, str], dict[str, Any]]:
    path = DATA_PROCESSED_DIR / f"smartsim_player_scenarios_{date_str}.csv"
    minutes_path = DATA_PROCESSED_DIR / f"pregame_expected_minutes_{date_str}.csv"
    try:
        df = _read_csv_if_exists(path)
    except Exception:
        df = None
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return {}

    working = df.copy()
    try:
        if "date" in working.columns:
            working = working.loc[working["date"].astype(str).str.strip() == str(date_str)]
    except Exception:
        pass
    try:
        if "split_type" in working.columns:
            working = working.loc[working["split_type"].astype(str).str.strip().str.lower() == "scenario"]
    except Exception:
        pass
    if working.empty:
        return {}

    minutes_lookup: dict[tuple[str, str], float] = {}
    try:
        minutes_df = _read_csv_if_exists(minutes_path)
        if isinstance(minutes_df, pd.DataFrame) and not minutes_df.empty:
            for _, raw in minutes_df.iterrows():
                team_tri = str(_get_tricode(raw.get("team_tri")) or raw.get("team_tri") or "").strip().upper()
                player_name = str(raw.get("player_name") or "").strip()
                exp_min = _safe_float(raw.get("exp_min_mean"))
                if not team_tri or not player_name or exp_min is None:
                    continue
                minutes_lookup[(team_tri, _norm_player_name(player_name))] = float(exp_min)
    except Exception:
        minutes_lookup = {}

    def _weighted_stat(frame: pd.DataFrame, column: str) -> float | None:
        if column not in frame.columns:
            return None
        total_weight = 0.0
        weighted_sum = 0.0
        for _, raw in frame.iterrows():
            value = _safe_float(raw.get(column))
            if value is None:
                continue
            weight = _safe_float(raw.get("n"))
            weight = float(weight) if weight is not None and weight > 0 else 1.0
            weighted_sum += float(value) * weight
            total_weight += weight
        if total_weight <= 0:
            return None
        return float(weighted_sum / total_weight)

    index: dict[tuple[str, str], dict[str, Any]] = {}
    group_cols = ["home", "away", "side", "team", "player_id", "player_name"]
    available_group_cols = [column for column in group_cols if column in working.columns]
    if len(available_group_cols) < 6:
        return {}

    for group_key, frame in working.groupby(available_group_cols, dropna=False):
        key_map = dict(zip(available_group_cols, group_key if isinstance(group_key, tuple) else (group_key,)))
        home_tri = str(_get_tricode(key_map.get("home")) or key_map.get("home") or "").strip().upper()
        away_tri = str(_get_tricode(key_map.get("away")) or key_map.get("away") or "").strip().upper()
        side_key = str(key_map.get("side") or "").strip().lower()
        team_tri = str(_get_tricode(key_map.get("team")) or key_map.get("team") or "").strip().upper()
        player_name = str(key_map.get("player_name") or "").strip()
        if not home_tri or not away_tri or side_key not in {"home", "away"} or not team_tri or not player_name:
            continue

        pts_mean = _weighted_stat(frame, "pts_p50")
        reb_mean = _weighted_stat(frame, "reb_p50")
        ast_mean = _weighted_stat(frame, "ast_p50")
        threes_mean = _weighted_stat(frame, "threes_p50")
        pra_mean = _weighted_stat(frame, "pra_p50")
        if pra_mean is None:
            components = [value for value in (pts_mean, reb_mean, ast_mean) if value is not None]
            if components:
                pra_mean = float(sum(components))
        min_mean = minutes_lookup.get((team_tri, _norm_player_name(player_name)))

        player_row = {
            "player_id": _safe_int(key_map.get("player_id")),
            "player_name": player_name,
            "team": team_tri,
            "min_mean": min_mean,
            "pts_mean": pts_mean,
            "reb_mean": reb_mean,
            "ast_mean": ast_mean,
            "threes_mean": threes_mean,
            "pra_mean": pra_mean,
        }

        matchup_key = (home_tri, away_tri)
        entry = index.setdefault(
            matchup_key,
            {
                "players": {"home": [], "away": []},
                "missing_prop_players": {"home": [], "away": []},
                "injuries": {"home": [], "away": []},
                "players_summary": {},
            },
        )
        entry["players"][side_key].append(player_row)

    for detail in index.values():
        for side_key in ("home", "away"):
            rows = detail["players"].get(side_key) or []
            filtered_rows: list[dict[str, Any]] = []
            ranked_rows: list[tuple[float, float, dict[str, Any]]] = []
            for row in rows:
                min_mean = _safe_float(row.get("min_mean"))
                if min_mean is None:
                    continue
                pra_mean = _safe_float(row.get("pra_mean")) or 0.0
                ranked_rows.append((float(min_mean), float(pra_mean), row))
            ranked_rows.sort(key=lambda item: (-item[0], -item[1], str(item[2].get("player_name") or "").strip().upper()))
            for idx, (min_mean, _pra_mean, row) in enumerate(ranked_rows):
                if min_mean < 4.0 and idx >= 10:
                    continue
                filtered_rows.append(row)
            detail["players"][side_key] = filtered_rows
        detail["players_summary"] = {
            "home": int(len(detail["players"].get("home") or [])),
            "away": int(len(detail["players"].get("away") or [])),
            "missing_home": 0,
            "missing_away": 0,
            "injured_home": 0,
            "injured_away": 0,
        }
    return index


def _load_cards_sim_detail_index(date_str: str) -> dict[tuple[str, str], dict[str, Any]]:
    payload = _load_cards_sim_detail_snapshot(date_str) or {}
    games = payload.get("games") if isinstance(payload.get("games"), list) else []
    out: dict[tuple[str, str], dict[str, Any]] = {}

    def _normalize_player_rows(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
        ranked_rows: list[tuple[float, float, dict[str, Any]]] = []
        for row in rows:
            min_mean = _safe_float(row.get("min_mean"))
            if min_mean is None:
                continue
            pra_mean = _safe_float(row.get("pra_mean")) or 0.0
            ranked_rows.append((float(min_mean), float(pra_mean), row))
        ranked_rows.sort(key=lambda item: (-item[0], -item[1], str(item[2].get("player_name") or "").strip().upper()))

        filtered_rows: list[dict[str, Any]] = []
        for idx, (min_mean, _pra_mean, row) in enumerate(ranked_rows):
            if min_mean < 4.0 and idx >= 10:
                continue
            filtered_rows.append(dict(row))
        return filtered_rows

    for game in games:
        if not isinstance(game, dict):
            continue
        home_tri = str(game.get("home_tri") or "").strip().upper()
        away_tri = str(game.get("away_tri") or "").strip().upper()
        if not home_tri or not away_tri:
            continue
        sim = game.get("sim") if isinstance(game.get("sim"), dict) else {}
        players = sim.get("players") if isinstance(sim.get("players"), dict) else {"home": [], "away": []}
        missing_prop_players = sim.get("missing_prop_players") if isinstance(sim.get("missing_prop_players"), dict) else {"home": [], "away": []}
        injuries = sim.get("injuries") if isinstance(sim.get("injuries"), dict) else {"home": [], "away": []}
        summary = sim.get("players_summary") if isinstance(sim.get("players_summary"), dict) else {}
        home_rows = _normalize_player_rows([row for row in (players.get("home") or []) if isinstance(row, dict)])
        away_rows = _normalize_player_rows([row for row in (players.get("away") or []) if isinstance(row, dict)])
        out[(home_tri, away_tri)] = {
            "players": {
                "home": home_rows,
                "away": away_rows,
            },
            "missing_prop_players": {
                "home": [row for row in (missing_prop_players.get("home") or []) if isinstance(row, dict)],
                "away": [row for row in (missing_prop_players.get("away") or []) if isinstance(row, dict)],
            },
            "injuries": {
                "home": [row for row in (injuries.get("home") or []) if isinstance(row, dict)],
                "away": [row for row in (injuries.get("away") or []) if isinstance(row, dict)],
            },
            "players_summary": {
                **dict(summary),
                "home": int(len(home_rows)),
                "away": int(len(away_rows)),
            },
        }
    fallback_index = _load_cards_sim_detail_scenario_fallback_index(date_str)
    for matchup_key, detail in fallback_index.items():
        existing = out.get(matchup_key)
        existing_rows = 0
        if isinstance(existing, dict):
            players = existing.get("players") if isinstance(existing.get("players"), dict) else {}
            existing_rows = int(len(players.get("home") or [])) + int(len(players.get("away") or []))
        fallback_players = detail.get("players") if isinstance(detail.get("players"), dict) else {}
        fallback_rows = int(len(fallback_players.get("home") or [])) + int(len(fallback_players.get("away") or []))
        if fallback_rows > existing_rows:
            out[matchup_key] = detail
    return out


def _cards_recommendation_sort_key(row: dict[str, Any]) -> tuple[float, float, float, float]:
    if not isinstance(row, dict):
        return (0.0, 0.0, 0.0, 0.0)
    return _best_bets_priority_sort_key(row)


def _cards_market_label(value: Any) -> str:
    market = str(value or "").strip().upper()
    if market == "ATS":
        return "Spread"
    if market in {"TOTAL", "OU"}:
        return "Total"
    if market == "ML":
        return "Moneyline"
    return market.title() if market else "Market"


def _build_cards_game_market_recommendations(
    *,
    date_str: str,
    home_name: str,
    away_name: str,
    home_tri: str,
    away_tri: str,
    bet: dict[str, Any],
    game_context: dict[str, Any] | None,
    injury_snapshot: dict[str, dict[str, Any]],
    slate_total_median: float | None,
    raw_rows: list[dict[str, Any]] | None,
    allow_pregame_updates: bool = True,
) -> list[dict[str, Any]]:
    candidates: list[dict[str, Any]] = []
    source_rows = [row for row in (raw_rows or []) if isinstance(row, dict)]
    pair_ctx = _best_bets_ctx_for_matchup(game_context, home=home_name, away=away_name)

    if source_rows and allow_pregame_updates:
        total_line = _safe_float(bet.get("total"))
        adjusted_total = _safe_float((pair_ctx or {}).get("pred_total_adjusted")) if isinstance(pair_ctx, dict) else None
        if adjusted_total is not None and total_line is not None:
            total_side = "over" if float(adjusted_total) >= float(total_line) else "under"
            total_ev = bet.get("over_ev") if total_side == "over" else bet.get("under_ev")
            source_rows = [
                row
                for row in source_rows
                if str(row.get("market") or "").strip().upper() not in {"TOTAL", "OU"}
            ]
            source_rows.append(
                {
                    "home": home_name,
                    "away": away_name,
                    "market": "TOTAL",
                    "side": total_side,
                    "line": total_line,
                    "price": -110,
                    "ev": total_ev,
                    "edge": float(adjusted_total) - float(total_line),
                    "pred_total": adjusted_total,
                    "date": date_str,
                    "source": "prop_adjusted_context",
                }
            )

    if not source_rows:
        if not allow_pregame_updates:
            return []
        home_spread = _safe_float(bet.get("home_spread"))
        total_line = _safe_float(bet.get("total"))
        fallback_rows = [
            {
                "home": home_name,
                "away": away_name,
                "market": "ML",
                "side": "home" if (_safe_float(bet.get("home_ml_ev")) or float("-inf")) >= (_safe_float(bet.get("away_ml_ev")) or float("-inf")) else "away",
                "price": bet.get("home_ml") if (_safe_float(bet.get("home_ml_ev")) or float("-inf")) >= (_safe_float(bet.get("away_ml_ev")) or float("-inf")) else bet.get("away_ml"),
                "ev": bet.get("home_ml_ev") if (_safe_float(bet.get("home_ml_ev")) or float("-inf")) >= (_safe_float(bet.get("away_ml_ev")) or float("-inf")) else bet.get("away_ml_ev"),
                "date": date_str,
            },
            {
                "home": home_name,
                "away": away_name,
                "market": "ATS",
                "side": "home" if (_safe_float(bet.get("home_spread_ev")) or float("-inf")) >= (_safe_float(bet.get("away_spread_ev")) or float("-inf")) else "away",
                "line": abs(float(home_spread)) if home_spread is not None else None,
                "price": -110,
                "ev": bet.get("home_spread_ev") if (_safe_float(bet.get("home_spread_ev")) or float("-inf")) >= (_safe_float(bet.get("away_spread_ev")) or float("-inf")) else bet.get("away_spread_ev"),
                "market_home_margin": (-float(home_spread)) if home_spread is not None else None,
                "pred_margin": _safe_float((game_context.get("by_pair") or {}).get((home_tri, away_tri), {}).get("pred_margin")) if isinstance(game_context, dict) else None,
                "date": date_str,
            },
            {
                "home": home_name,
                "away": away_name,
                "market": "TOTAL",
                "side": "over" if (_safe_float(bet.get("over_ev")) or float("-inf")) >= (_safe_float(bet.get("under_ev")) or float("-inf")) else "under",
                "line": total_line,
                "price": -110,
                "ev": bet.get("over_ev") if (_safe_float(bet.get("over_ev")) or float("-inf")) >= (_safe_float(bet.get("under_ev")) or float("-inf")) else bet.get("under_ev"),
                "pred_total": _safe_float((game_context.get("by_pair") or {}).get((home_tri, away_tri), {}).get("pred_total")) if isinstance(game_context, dict) else None,
                "date": date_str,
            },
        ]
        source_rows = [row for row in fallback_rows if _safe_float(row.get("ev")) is not None]

    for row in source_rows:
        decorated = _decorate_game_recommendation_payload(
            row,
            date_str=date_str,
            game_context=game_context,
            injury_snapshot=injury_snapshot,
            slate_total_median=slate_total_median,
        )
        if not isinstance(decorated, dict):
            continue
        entry = dict(decorated)
        entry["market"] = row.get("market") or entry.get("market")
        entry["market_label"] = _cards_market_label(entry.get("market") or row.get("market") or entry.get("rec_code"))
        candidates.append(entry)

    if not candidates:
        return []

    by_market: dict[str, list[dict[str, Any]]] = {}
    for row in candidates:
        market_key = str(row.get("market") or "").strip().upper()
        by_market.setdefault(market_key, []).append(row)

    official: list[dict[str, Any]] = []
    playable: list[dict[str, Any]] = []
    for rows in by_market.values():
        ranked = sorted((_cards_locked_policy_annotate(row) for row in rows), key=_cards_locked_policy_sort_key, reverse=True)
        selected = next((row for row in ranked if _cards_locked_policy_qualifies(row, market_type="game", tier="official")), None)
        if selected is not None:
            official.append(dict(selected, card_bucket="official"))
        fallback = next(
            (
                row
                for row in ranked
                if _cards_locked_policy_qualifies(row, market_type="game", tier="playable")
                and _pregame_card_candidate_identity({"home_tri": home_tri, "away_tri": away_tri}, row, "game")
                != (_pregame_card_candidate_identity({"home_tri": home_tri, "away_tri": away_tri}, selected, "game") if isinstance(selected, dict) else None)
            ),
            None,
        )
        if fallback is not None:
            playable.append(dict(fallback, card_bucket="playable"))

    ordered_official = sorted(official, key=_cards_locked_policy_sort_key, reverse=True)
    for idx, row in enumerate(ordered_official, start=1):
        row["card_rank"] = idx
    ordered_playable = sorted(playable, key=_cards_locked_policy_sort_key, reverse=True)
    for idx, row in enumerate(ordered_playable, start=1):
        row["card_rank"] = idx
    return ordered_official + ordered_playable


def _prop_recommendation_identity(row: dict[str, Any]) -> tuple[str, str, str, str, float | None] | None:
    if not isinstance(row, dict):
        return None
    best = row.get("best") if isinstance(row.get("best"), dict) else {}
    team_key = str(row.get("team") or "").strip().upper()
    player_key = _norm_player_name(str(row.get("player") or ""))
    market = str(best.get("market") or "").strip().lower()
    side = str(best.get("side") or "").strip().upper()
    line = _safe_float(best.get("line"))
    if not team_key or not player_key or not market or not side:
        return None
    return (team_key, player_key, market, side, float(line) if line is not None else None)


def _prop_snapshot_identity(pick: dict[str, Any]) -> tuple[str, str, str, str, float | None] | None:
    if not isinstance(pick, dict):
        return None
    top_play = pick.get("top_play") if isinstance(pick.get("top_play"), dict) else {}
    team_key = str(pick.get("team_tricode") or pick.get("team") or "").strip().upper()
    player_key = _norm_player_name(str(pick.get("player") or ""))
    market = str(top_play.get("market") or "").strip().lower()
    side = str(top_play.get("side") or "").strip().upper()
    line = _safe_float(top_play.get("line"))
    if not team_key or not player_key or not market or not side:
        return None
    return (team_key, player_key, market, side, float(line) if line is not None else None)


def _apply_cards_prop_recommendation_buckets(
    prop_recommendations: dict[str, list[dict[str, Any]]],
    *,
    snapshot_picks: list[dict[str, Any]] | None,
) -> None:
    ranked_rows: list[dict[str, Any]] = []
    for side_key in ("home", "away"):
        rows = prop_recommendations.get(side_key) if isinstance(prop_recommendations, dict) else []
        for row in (rows or []):
            if isinstance(row, dict):
                ranked_rows.append(row)

    ranked_rows.sort(key=_cards_recommendation_sort_key, reverse=True)
    snapshot_meta: dict[tuple[str, str, str, str, float | None], dict[str, Any]] = {}
    for pick in (snapshot_picks or []):
        ident = _prop_snapshot_identity(pick)
        if ident is not None:
            snapshot_meta[ident] = pick

    if snapshot_meta:
        for row in ranked_rows:
            ident = _prop_recommendation_identity(row)
            match = snapshot_meta.get(ident) if ident is not None else None
            if match is not None:
                if match.get("tier") is not None and row.get("tier") is None:
                    row["tier"] = match.get("tier")
                if match.get("score_adj") is not None and row.get("recommendation_priority_score") is None:
                    row["recommendation_priority_score"] = match.get("score_adj")

    official_rows, playable_rows = _cards_select_prop_buckets(ranked_rows)
    official_keys = {
        _prop_recommendation_identity(row)
        for row in official_rows
        if _prop_recommendation_identity(row) is not None
    }
    playable_keys = {
        _prop_recommendation_identity(row)
        for row in playable_rows
        if _prop_recommendation_identity(row) is not None
    }
    official_count = 0
    playable_count = 0
    for row in ranked_rows:
        ident = _prop_recommendation_identity(row)
        if ident is not None and ident in official_keys:
            row.update({k: v for k, v in next((r for r in official_rows if _prop_recommendation_identity(r) == ident), {}).items() if k.startswith("locked_policy_") or k == "playable_sleeve"})
            row["card_bucket"] = "official"
            official_count += 1
            row["card_rank"] = official_count
        elif ident is not None and ident in playable_keys:
            row.update({k: v for k, v in next((r for r in playable_rows if _prop_recommendation_identity(r) == ident), {}).items() if k.startswith("locked_policy_") or k == "playable_sleeve"})
            row["card_bucket"] = "playable"
            playable_count += 1
            row["card_rank"] = playable_count
        else:
            row.update(_cards_locked_policy_annotate(row))
            row["card_bucket"] = "discard"
            row["card_rank"] = None


def _build_cards_prop_recommendations_from_source(
    props_recs_by_team: dict[str, list[dict[str, Any]]],
    *,
    home_tri: str,
    away_tri: str,
    date_str: str | None = None,
) -> dict[str, list[dict[str, Any]]]:
    out: dict[str, list[dict[str, Any]]] = {"home": [], "away": []}
    pred_lookup = _load_best_bets_props_prediction_lookup(date_str) if date_str else {}

    def _source_play_identity(play: dict[str, Any] | None) -> tuple[str, str, float | None] | None:
        if not isinstance(play, dict):
            return None
        market = str(play.get("market") or "").strip().lower()
        side = str(play.get("side") or "").strip().upper()
        line = _safe_float(play.get("line"))
        if not market or not side:
            return None
        return market, side, line

    def _source_play_same_market_side(
        left: tuple[str, str, float | None] | None,
        right: tuple[str, str, float | None] | None,
    ) -> bool:
        if left is None or right is None:
            return False
        return left[0] == right[0] and left[1] == right[1]

    def _source_play_sort_key(play: dict[str, Any]) -> tuple[float, float, float, float]:
        ev_pct = _safe_float(play.get("ev_pct"))
        if ev_pct is None:
            ev = _safe_float(play.get("ev"))
            if ev is not None:
                ev_pct = float(ev) * 100.0
        edge = _safe_float(play.get("edge"))
        price = _safe_float(play.get("price"))
        line = _safe_float(play.get("line"))
        side = str(play.get("side") or "").strip().upper()
        line_value = float(line or 0.0)
        if side == "UNDER":
            line_value = -line_value
        return (
            float(ev_pct if ev_pct is not None else float("-inf")),
            float(edge if edge is not None else float("-inf")),
            float(price if price is not None else float("-inf")),
            line_value,
        )

    for side_key, team_tri in (("home", home_tri), ("away", away_tri)):
        rows: list[dict[str, Any]] = []
        for source_row in (props_recs_by_team.get(team_tri) or []):
            if not isinstance(source_row, dict):
                continue
            best = source_row.get("top_play") if isinstance(source_row.get("top_play"), dict) else None
            if not isinstance(best, dict):
                continue

            player_name = str(source_row.get("player") or best.get("player") or best.get("player_name") or "").strip()
            if not player_name:
                continue

            top_play_reasons = [
                str(item).strip()
                for item in (source_row.get("top_play_reasons") or [])
                if str(item).strip()
            ] if isinstance(source_row.get("top_play_reasons"), list) else []

            picks = [dict(pick) for pick in (source_row.get("plays") or []) if isinstance(pick, dict)]
            for pick in picks:
                pick.setdefault("player", player_name)
                pick.setdefault("player_name", player_name)
                pick.setdefault("team", team_tri)

            play_groups: dict[tuple[str, str], dict[str, Any]] = {}
            for pick in picks:
                market = str(pick.get("market") or "").strip().lower()
                selection = str(pick.get("side") or "").strip().upper()
                if not market or not selection:
                    continue
                key = (market, selection)
                current = play_groups.get(key)
                if current is None or _source_play_sort_key(pick) > _source_play_sort_key(current):
                    play_groups[key] = pick

            if not play_groups:
                best_key = _source_play_identity(best)
                if best_key is not None:
                    play_groups[(best_key[0], best_key[1])] = dict(best)

            player_pred = pred_lookup.get((_norm_player_name(player_name), team_tri)) if isinstance(pred_lookup, dict) else None

            best_identity = _source_play_identity(best)
            for grouped_play in play_groups.values():
                best_row = dict(grouped_play)
                best_row.setdefault("player", player_name)
                best_row.setdefault("player_name", player_name)
                best_row.setdefault("team", team_tri)

                play_identity = _source_play_identity(best_row)
                play_reasons = list(top_play_reasons) if _source_play_same_market_side(play_identity, best_identity) else []
                if play_reasons and not isinstance(best_row.get("reasons"), list):
                    best_row["reasons"] = list(play_reasons)

                matching_picks = [
                    dict(pick)
                    for pick in picks
                    if _source_play_same_market_side(_source_play_identity(pick), play_identity)
                ]
                if not matching_picks:
                    matching_picks = [dict(best_row)]

                top_play_baseline = _safe_float(best_row.get("model_baseline"))
                if top_play_baseline is None and _source_play_same_market_side(play_identity, best_identity):
                    top_play_baseline = _safe_float(source_row.get("top_play_baseline"))

                ev_pct = _safe_float(best_row.get("ev_pct"))
                if ev_pct is None:
                    ev = _safe_float(best_row.get("ev"))
                    if ev is not None:
                        ev_pct = float(ev) * 100.0

                recommendation_priority_score = ev_pct
                if recommendation_priority_score is None:
                    recommendation_priority_score = _safe_float(best_row.get("edge"))
                if recommendation_priority_score is None and play_identity is not None and play_identity == best_identity:
                    recommendation_priority_score = _safe_float(source_row.get("recommendation_priority_score"))

                rows.append(
                    _flatten_prop_recommendation_row(
                        {
                            "player": player_name,
                            "team": team_tri,
                            "best": best_row,
                            "picks": matching_picks,
                            "top_play_reasons": play_reasons,
                            "why_explain": str(source_row.get("top_play_explain") or "").strip() or None if play_reasons else None,
                            "top_play_baseline": top_play_baseline,
                            "top_play_consensus": _safe_float(source_row.get("top_play_consensus")) if play_identity is not None and play_identity == best_identity else None,
                            "top_play_line_adv": _safe_float(source_row.get("top_play_line_adv")) if play_identity is not None and play_identity == best_identity else None,
                            "recommendation_priority_score": recommendation_priority_score,
                            "source": "props_recommendations",
                        },
                        team_tri=team_tri,
                        home_tri=home_tri,
                        away_tri=away_tri,
                        date_str=date_str,
                        player_sim=(player_pred if isinstance(player_pred, dict) else None),
                    )
                )

        rows.sort(key=_cards_recommendation_sort_key, reverse=True)
        out[side_key] = rows

    return out


def _prop_recommendation_player_sim_stats(player_row: dict[str, Any] | None, market: Any) -> tuple[float | None, float | None]:
    if not isinstance(player_row, dict):
        return None, None

    def _first_numeric(*keys: str) -> float | None:
        for key in keys:
            value = _safe_float(player_row.get(key))
            if value is not None:
                return value
        return None

    market_key = str(market or "").strip().lower()
    if market_key in {"points"}:
        market_key = "pts"
    elif market_key in {"rebounds"}:
        market_key = "reb"
    elif market_key in {"assists"}:
        market_key = "ast"
    elif market_key in {"3pm", "3ptm", "fg3m"}:
        market_key = "threes"
    elif market_key in {"steals", "steal"}:
        market_key = "stl"
    elif market_key in {"blocks", "block"}:
        market_key = "blk"
    elif market_key in {"turnovers", "turnover", "to"}:
        market_key = "tov"

    direct_fields = {
        "pts": (("pts_mean", "pred_pts", "mean_pts", "points_mean", "pred_points"), ("pts_sd", "sd_pts", "points_sd")),
        "reb": (("reb_mean", "pred_reb", "mean_reb"), ("reb_sd", "sd_reb")),
        "ast": (("ast_mean", "pred_ast", "mean_ast"), ("ast_sd", "sd_ast")),
        "threes": (("threes_mean", "pred_threes", "mean_threes"), ("threes_sd", "sd_threes")),
        "stl": (("stl_mean", "pred_stl", "mean_stl"), ("stl_sd", "sd_stl")),
        "blk": (("blk_mean", "pred_blk", "mean_blk"), ("blk_sd", "sd_blk")),
        "tov": (("tov_mean", "pred_tov", "mean_tov"), ("tov_sd", "sd_tov")),
        "pra": (("pra_mean", "pred_pra", "mean_pra"), ("pra_sd", "sd_pra")),
    }
    if market_key in direct_fields:
        mean_keys, sd_keys = direct_fields[market_key]
        return _first_numeric(*mean_keys), _first_numeric(*sd_keys)

    pts_mu = _first_numeric("pts_mean", "pred_pts", "mean_pts", "points_mean", "pred_points")
    pts_sd = _first_numeric("pts_sd", "sd_pts", "points_sd")
    reb_mu = _first_numeric("reb_mean", "pred_reb", "mean_reb")
    reb_sd = _first_numeric("reb_sd", "sd_reb")
    ast_mu = _first_numeric("ast_mean", "pred_ast", "mean_ast")
    ast_sd = _first_numeric("ast_sd", "sd_ast")

    def _sum(mu1: float | None, sd1: float | None, mu2: float | None, sd2: float | None) -> tuple[float | None, float | None]:
        if mu1 is None or mu2 is None:
            return None, None
        left_sd = 0.0 if sd1 is None else float(sd1)
        right_sd = 0.0 if sd2 is None else float(sd2)
        return float(mu1 + mu2), float(math.sqrt(max(0.0, left_sd * left_sd + right_sd * right_sd)))

    if market_key == "pa":
        direct_mu = _first_numeric("pa_mean", "pred_pa", "mean_pa")
        direct_sd = _first_numeric("pa_sd", "sd_pa")
        if direct_mu is not None and direct_sd is not None:
            return direct_mu, direct_sd
        combo_mu, combo_sd = _sum(pts_mu, pts_sd, ast_mu, ast_sd)
        return (direct_mu if direct_mu is not None else combo_mu), combo_sd
    if market_key == "pr":
        direct_mu = _first_numeric("pr_mean", "pred_pr", "mean_pr")
        direct_sd = _first_numeric("pr_sd", "sd_pr")
        if direct_mu is not None and direct_sd is not None:
            return direct_mu, direct_sd
        combo_mu, combo_sd = _sum(pts_mu, pts_sd, reb_mu, reb_sd)
        return (direct_mu if direct_mu is not None else combo_mu), combo_sd
    if market_key == "ra":
        direct_mu = _first_numeric("ra_mean", "pred_ra", "mean_ra")
        direct_sd = _first_numeric("ra_sd", "sd_ra")
        if direct_mu is not None and direct_sd is not None:
            return direct_mu, direct_sd
        combo_mu, combo_sd = _sum(reb_mu, reb_sd, ast_mu, ast_sd)
        return (direct_mu if direct_mu is not None else combo_mu), combo_sd
    return None, None


def _flatten_prop_recommendation_row(
    row: dict[str, Any],
    *,
    team_tri: str | None = None,
    home_tri: str | None = None,
    away_tri: str | None = None,
    date_str: str | None = None,
    player_sim: dict[str, Any] | None = None,
) -> dict[str, Any]:
    if not isinstance(row, dict):
        return row

    team_key = str(team_tri or row.get("team") or "").strip().upper() or None
    home_key = str(home_tri or "").strip().upper()
    away_key = str(away_tri or "").strip().upper()
    if team_key == home_key and away_key:
        opponent = away_key
        team_side = "home"
    elif team_key == away_key and home_key:
        opponent = home_key
        team_side = "away"
    else:
        opponent = str(row.get("opponent") or "").strip().upper() or None
        team_side = str(row.get("team_side") or "").strip().lower() or None

    effective = _season_betting_card_effective_prop_row(row)
    candidate = None
    if _build_canonical_prop_candidate is not None:
        try:
            game_key = str(row.get("game_key") or "").strip() or None
            if game_key is None and date_str and home_key and away_key:
                game_key = f"{date_str}:{away_key}@{home_key}"
            candidate = _build_canonical_prop_candidate(
                row,
                date=date_str,
                game_key=game_key,
                team=team_key,
                opponent=opponent,
                team_side=team_side,
            )
        except Exception:
            candidate = None

    market = str((getattr(candidate, "market", None) if candidate is not None else None) or effective.get("market") or row.get("market") or "").strip().lower() or None
    side = str((getattr(candidate, "side", None) if candidate is not None else None) or effective.get("side") or row.get("side") or row.get("selection") or "").strip().upper() or None
    line = _safe_float((getattr(candidate, "line", None) if candidate is not None else None))
    if line is None:
        line = _safe_float(effective.get("line"))
    price = _safe_float((getattr(candidate, "price", None) if candidate is not None else None))
    if price is None:
        price = _safe_float(effective.get("price"))
    implied_prob = _safe_float((getattr(candidate, "implied_prob", None) if candidate is not None else None))
    if implied_prob is None:
        implied_prob = _safe_float(effective.get("implied_prob"))
    model_prob = _safe_float((getattr(candidate, "model_prob", None) if candidate is not None else None))
    if model_prob is None:
        model_prob = (
            _safe_float(effective.get("model_prob"))
            or _safe_float(effective.get("probability"))
            or _safe_float(effective.get("prob_calib"))
            or _safe_float(effective.get("p_win"))
        )
    push_prob = _safe_float((getattr(candidate, "push_prob", None) if candidate is not None else None))
    if push_prob is None:
        push_prob = _safe_float(effective.get("p_push"))
    ev_pct = _safe_float((getattr(candidate, "ev_pct", None) if candidate is not None else None))
    if ev_pct is None:
        ev_pct = _safe_float(effective.get("ev_pct"))
    ev = _safe_float(effective.get("ev"))
    if ev is None and ev_pct is not None:
        ev = float(ev_pct) / 100.0
    if model_prob is None and ev is not None and price is not None:
        model_prob = _best_bets_prob_from_ev(ev, price)

    sim_mu = _safe_float((getattr(candidate, "sim_mean", None) if candidate is not None else None))
    if sim_mu is None:
        sim_mu = (
            _safe_float(effective.get("sim_mu"))
            or _safe_float(effective.get("model_baseline"))
            or _safe_float(row.get("top_play_baseline"))
        )
    sim_sd = _safe_float((getattr(candidate, "sim_sd", None) if candidate is not None else None))
    if sim_sd is None:
        sim_sd = _safe_float(effective.get("sim_sd"))
    if player_sim is not None and market:
        player_mu, player_sd = _prop_recommendation_player_sim_stats(player_sim, market)
        if sim_mu is None:
            sim_mu = player_mu
        if sim_sd is None:
            sim_sd = player_sd

    minutes = _safe_float((getattr(candidate, "minutes", None) if candidate is not None else None))
    if minutes is None:
        minutes = (
            _safe_float(effective.get("expected_minutes"))
            or _safe_float(effective.get("minutes_proj"))
            or _safe_float(effective.get("min_mean"))
            or _safe_float(effective.get("pred_min"))
            or _safe_float(effective.get("roll5_min"))
        )
    if minutes is None and player_sim is not None:
        minutes = (
            _safe_float(player_sim.get("min_mean"))
            or _safe_float(player_sim.get("pred_min"))
            or _safe_float(player_sim.get("roll5_min"))
        )

    game_key = str(row.get("game_key") or "").strip() or None
    if game_key is None and date_str and home_key and away_key:
        game_key = f"{date_str}:{away_key}@{home_key}"

    if team_key:
        row["team"] = team_key
    if opponent:
        row["opponent"] = opponent
    if team_side:
        row["team_side"] = team_side
    if date_str and not row.get("date"):
        row["date"] = date_str
    if game_key and not row.get("game_key"):
        row["game_key"] = game_key
    if market:
        row["market"] = market
    if side:
        row["side"] = side
        row.setdefault("selection", side)
    if line is not None:
        row["line"] = line
    if price is not None:
        row["price"] = price
    if implied_prob is not None:
        row["implied_prob"] = implied_prob
    if push_prob is not None:
        row["p_push"] = push_prob
    if ev is not None:
        row["ev"] = ev
    if ev_pct is not None:
        row["ev_pct"] = ev_pct
    if sim_mu is not None:
        row["sim_mu"] = sim_mu
        row.setdefault("model_baseline", sim_mu)
    if sim_sd is not None:
        row["sim_sd"] = sim_sd
    if minutes is not None:
        row["expected_minutes"] = minutes
        row.setdefault("minutes_proj", minutes)
        row.setdefault("min_mean", minutes)
    if model_prob is not None:
        row["model_prob"] = model_prob
        row.setdefault("prob_calib", model_prob)
        row.setdefault("probability", model_prob)
        row.setdefault("prob", model_prob)
        row.setdefault("win_prob", model_prob)
        row.setdefault("p_win", model_prob)

    best = row.get("best") if isinstance(row.get("best"), dict) else None
    if isinstance(best, dict):
        for key in ("market", "side", "line", "price", "implied_prob", "p_push", "ev", "ev_pct", "sim_mu", "sim_sd"):
            if row.get(key) is not None and best.get(key) is None:
                best[key] = row.get(key)
        if minutes is not None:
            best.setdefault("expected_minutes", minutes)
            best.setdefault("minutes_proj", minutes)
            best.setdefault("min_mean", minutes)
        if model_prob is not None:
            best.setdefault("model_prob", model_prob)
            best.setdefault("prob_calib", model_prob)
            best.setdefault("probability", model_prob)
            best.setdefault("p_win", model_prob)
        if opponent and not best.get("opponent"):
            best["opponent"] = opponent
        if team_key and not best.get("team"):
            best["team"] = team_key
    return row


def _cards_started_matchups_index(date_str: str, now_local: datetime | None = None) -> dict[tuple[str, str], dict[str, Any]]:
    now_local = now_local if isinstance(now_local, datetime) else _best_bets_local_now_naive()
    try:
        if str(date_str or "") != now_local.date().isoformat():
            return {}
    except Exception:
        return {}

    try:
        _source, games = _live_build_scoreboard_games(date_str)
    except Exception:
        return {}

    out: dict[tuple[str, str], dict[str, Any]] = {}
    for game in (games or []):
        if not isinstance(game, dict):
            continue
        home_tri = _canonical_team_tri(game.get("home"))
        away_tri = _canonical_team_tri(game.get("away"))
        if not home_tri or not away_tri:
            continue
        out[(home_tri, away_tri)] = {
            "game_id": str(game.get("game_id") or "").strip() or None,
            "in_progress": bool(game.get("in_progress")),
            "final": bool(game.get("final")),
            "status": str(game.get("status") or "").strip() or None,
            "period": _safe_int(game.get("period")),
            "clock": str(game.get("clock") or "").strip() or None,
            "home_pts": _safe_int(game.get("home_pts")),
            "away_pts": _safe_int(game.get("away_pts")),
            "periods": [dict(row) for row in (game.get("periods") or []) if isinstance(row, dict)],
        }
    return out


def _cards_matchup_has_started(
    date_str: str,
    *,
    home_tri: str,
    away_tri: str,
    commence_time: Any,
    started_matchups: dict[tuple[str, str], dict[str, Any]] | None,
    now_local: datetime | None = None,
) -> bool:
    now_local = now_local if isinstance(now_local, datetime) else _best_bets_local_now_naive()
    try:
        requested_date = datetime.strptime(str(date_str or ""), "%Y-%m-%d").date()
        local_date = now_local.date()
        if requested_date < local_date:
            return True
        if requested_date > local_date:
            return False
    except Exception:
        pass

    status = (started_matchups or {}).get((str(home_tri or "").upper(), str(away_tri or "").upper()))
    if isinstance(status, dict):
        if bool(status.get("in_progress")) or bool(status.get("final")):
            return True
        return False

    start_dt_local = _best_bets_local_start_dt(commence_time)
    if isinstance(start_dt_local, datetime):
        return start_dt_local <= now_local
    return False


def _build_games_best_bets_and_parlays(
    date_str: str,
    *,
    best_bets: int,
    candidate_pool: int,
    parlay_size: int,
    max_parlays: int,
    future_only: bool,
    include_markets: tuple[str, ...],
    min_score: float,
) -> dict[str, Any]:
    path = DATA_PROCESSED_DIR / f"recommendations_{date_str}.csv"
    if not path.exists():
        try:
            _maybe_fetch_remote_processed(path.name)
        except Exception:
            pass
    df = _read_csv_if_exists(path)
    allowed = {"TOTAL" if str(m).strip().upper() in {"OU", "TOTAL"} else str(m).strip().upper() for m in include_markets if str(m).strip()}
    if not allowed:
        allowed = {"ATS", "ML", "TOTAL"}

    if not isinstance(df, pd.DataFrame) or df is None or df.empty:
        return {
            "status": "error",
            "date": date_str,
            "message": f"no game recommendations artifact available for {date_str}",
            "source_summary": [{"market": m, "status": "empty", "count": 0} for m in sorted(allowed)],
            "candidate_count": 0,
            "best_bet": None,
            "best_bets": [],
            "parlays": [],
            "generated_utc": datetime.utcnow().replace(microsecond=0).isoformat() + "Z",
            "as_of_local": _best_bets_local_now_naive().isoformat(timespec="seconds"),
            "params": {
                "best_bets": int(best_bets),
                "candidate_pool": int(candidate_pool),
                "parlay_size": int(parlay_size),
                "max_parlays": int(max_parlays),
                "future_only": bool(future_only),
                "include_markets": sorted(allowed),
                "min_score": float(min_score),
            },
        }

    ctx = _load_best_bets_game_context(date_str)
    injury_snapshot = _best_bets_load_injury_snapshot(date_str)
    now_local = _best_bets_local_now_naive()
    raw_counts: dict[str, int] = {"ATS": 0, "ML": 0, "OU": 0}
    candidates: list[dict[str, Any]] = []

    for _, r in df.iterrows():
        row = r.to_dict()
        market = str(row.get("market") or "").strip().upper()
        market_key = "TOTAL" if market == "OU" else market
        if market_key not in allowed:
            continue
        home = str(row.get("home") or "").strip()
        away = str(row.get("away") or "").strip()
        pair_ctx = None
        if home and away:
            pair_ctx = (ctx.get("by_pair") or {}).get((home.upper(), away.upper()))
            if pair_ctx is None:
                home_tri = (_get_tricode(home) or home.upper())
                away_tri = (_get_tricode(away) or away.upper())
                pair_ctx = (ctx.get("by_pair") or {}).get((home_tri.upper(), away_tri.upper()))
        cand = _decorate_game_best_bet_candidate(
            row,
            date_str=date_str,
            ctx=pair_ctx,
            injury_snapshot=injury_snapshot,
            slate_total_median=_safe_float(ctx.get("slate_total_median")),
        )
        if not isinstance(cand, dict):
            continue
        if future_only and isinstance(cand.get("start_dt_local"), datetime) and cand.get("start_dt_local") < now_local:
            continue
        if float(cand.get("score") or 0.0) < float(min_score):
            continue
        raw_counts[str(cand.get("rec_code") or "").upper()] = raw_counts.get(str(cand.get("rec_code") or "").upper(), 0) + 1
        candidates.append(cand)

    if not candidates:
        message = "No future picks remain after filtering games that have already started." if future_only else f"no qualifying game recommendations available for {date_str}"
        return {
            "status": "error",
            "date": date_str,
            "message": message,
            "source_summary": [
                {"market": m, "status": ("empty" if raw_counts.get(m, 0) <= 0 else "ok"), "count": int(raw_counts.get(m, 0) or 0)}
                for m in ["ATS", "ML", "OU"]
                if ({"TOTAL" if m == "OU" else m} & allowed)
            ],
            "candidate_count": 0,
            "best_bet": None,
            "best_bets": [],
            "parlays": [],
            "generated_utc": datetime.utcnow().replace(microsecond=0).isoformat() + "Z",
            "as_of_local": now_local.isoformat(timespec="seconds"),
            "params": {
                "best_bets": int(best_bets),
                "candidate_pool": int(candidate_pool),
                "parlay_size": int(parlay_size),
                "max_parlays": int(max_parlays),
                "future_only": bool(future_only),
                "include_markets": sorted(allowed),
                "min_score": float(min_score),
            },
        }

    ranked_unique: list[dict[str, Any]] = []
    seen_games: set[str] = set()
    for row in sorted(candidates, key=_best_bets_priority_sort_key, reverse=True):
        game_key = str(row.get("game_key") or "")
        if not game_key or game_key in seen_games:
            continue
        seen_games.add(game_key)
        ranked_unique.append(row)

    best_bets_rows = ranked_unique[: max(1, int(best_bets))]
    parlay_pool = ranked_unique[: max(int(parlay_size), int(candidate_pool))]
    parlays = _best_bets_build_parlays(
        parlay_pool,
        parlay_size=max(2, int(parlay_size)),
        max_parlays=max(1, int(max_parlays)),
    )
    return {
        "status": "ok",
        "date": date_str,
        "generated_utc": datetime.utcnow().replace(microsecond=0).isoformat() + "Z",
        "as_of_local": now_local.isoformat(timespec="seconds"),
        "params": {
            "best_bets": int(best_bets),
            "candidate_pool": int(candidate_pool),
            "parlay_size": int(parlay_size),
            "max_parlays": int(max_parlays),
            "future_only": bool(future_only),
            "include_markets": sorted(allowed),
            "min_score": float(min_score),
        },
        "message": None,
        "source_summary": [
            {"market": m, "status": ("ok" if raw_counts.get(m, 0) > 0 else "empty"), "count": int(raw_counts.get(m, 0) or 0)}
            for m in ["ATS", "ML", "OU"]
            if (("TOTAL" if m == "OU" else m) in allowed)
        ],
        "candidate_count": len(ranked_unique),
        "best_bet": (best_bets_rows[0] if best_bets_rows else None),
        "best_bets": best_bets_rows,
        "parlays": parlays,
    }


def _build_props_best_bets_and_parlays(
    date_str: str,
    *,
    best_bets: int,
    candidate_pool: int,
    parlay_size: int,
    max_parlays: int,
    future_only: bool,
    include_markets: tuple[str, ...],
    min_score: float,
) -> dict[str, Any]:
    props_by_team = _load_props_recommendations_by_team(date_str)
    allowed = {str(m).strip().lower() for m in include_markets if str(m).strip()}
    pred_lookup = _load_best_bets_props_prediction_lookup(date_str)
    game_ctx = _load_best_bets_game_context(date_str)
    injury_snapshot = _best_bets_load_injury_snapshot(date_str)
    now_local = _best_bets_local_now_naive()
    raw_counts: dict[str, int] = {}
    candidates: list[dict[str, Any]] = []

    for team, items in props_by_team.items():
        team_tri = (_get_tricode(team) or str(team).strip().upper())
        matchup_ctx = (game_ctx.get("by_team") or {}).get(team_tri) or (game_ctx.get("by_team") or {}).get(str(team).strip().upper())
        for item in items or []:
            top_play = item.get("top_play") if isinstance(item.get("top_play"), dict) else None
            if not isinstance(top_play, dict):
                continue
            market = str(top_play.get("market") or "").strip().lower()
            if allowed and market not in allowed:
                continue
            player_key = (_norm_player_name(item.get("player")) if item.get("player") else "")
            pred_row = pred_lookup.get((player_key, team_tri))
            cand = _decorate_prop_best_bet_candidate(
                item,
                date_str=date_str,
                pred_row=pred_row,
                matchup_ctx=matchup_ctx,
                injury_snapshot=injury_snapshot,
                slate_total_median=_safe_float(game_ctx.get("slate_total_median")),
            )
            if not isinstance(cand, dict):
                continue
            if future_only and isinstance(cand.get("start_dt_local"), datetime) and cand.get("start_dt_local") < now_local:
                continue
            if float(cand.get("score") or 0.0) < float(min_score):
                continue
            rec_code = str(cand.get("rec_code") or market).upper()
            raw_counts[rec_code] = raw_counts.get(rec_code, 0) + 1
            candidates.append(cand)

    if not candidates:
        message = "No future props remain after filtering games that have already started." if future_only else f"no qualifying props recommendations available for {date_str}"
        return {
            "status": "error",
            "date": date_str,
            "message": message,
            "source_summary": [
                {"market": market, "status": "empty", "count": 0}
                for market in sorted(_best_bets_prop_market_label(m) for m in allowed) if allowed
            ],
            "candidate_count": 0,
            "best_bet": None,
            "best_bets": [],
            "parlays": [],
            "generated_utc": datetime.utcnow().replace(microsecond=0).isoformat() + "Z",
            "as_of_local": now_local.isoformat(timespec="seconds"),
            "params": {
                "best_bets": int(best_bets),
                "candidate_pool": int(candidate_pool),
                "parlay_size": int(parlay_size),
                "max_parlays": int(max_parlays),
                "future_only": bool(future_only),
                "include_markets": sorted(allowed),
                "min_score": float(min_score),
            },
        }

    ranked = sorted(candidates, key=_best_bets_priority_sort_key, reverse=True)
    best_bets_rows = ranked[: max(1, int(best_bets))]
    parlay_pool = ranked[: max(int(parlay_size), int(candidate_pool))]
    parlays = _best_bets_build_parlays(
        parlay_pool,
        parlay_size=max(2, int(parlay_size)),
        max_parlays=max(1, int(max_parlays)),
    )
    ordered_summary = []
    for code, count in sorted(raw_counts.items(), key=lambda item: (-item[1], item[0])):
        ordered_summary.append({"market": code, "status": "ok", "count": int(count)})

    return {
        "status": "ok",
        "date": date_str,
        "generated_utc": datetime.utcnow().replace(microsecond=0).isoformat() + "Z",
        "as_of_local": now_local.isoformat(timespec="seconds"),
        "params": {
            "best_bets": int(best_bets),
            "candidate_pool": int(candidate_pool),
            "parlay_size": int(parlay_size),
            "max_parlays": int(max_parlays),
            "future_only": bool(future_only),
            "include_markets": sorted(allowed),
            "min_score": float(min_score),
        },
        "message": None,
        "source_summary": ordered_summary,
        "candidate_count": len(ranked),
        "best_bet": (best_bets_rows[0] if best_bets_rows else None),
        "best_bets": best_bets_rows,
        "parlays": parlays,
    }


def _sim_vs_line_prop_recommendations(
    players_out: dict[str, list[dict[str, Any]]],
    props_recs_by_team: dict[str, list[dict[str, Any]]],
    home_tri: str,
    away_tri: str,
    topn_per_side: int = 6,
    allowed_markets: set[str] | None = None,
    allowed_books: set[str] | None = None,
    min_ev_pct: float | None = None,
    excluded_books: set[str] | None = None,
) -> dict[str, list[dict[str, Any]]]:
    """Return market-based prop recommendations computed from SmartSim vs betting lines.

    We use props_recommendations_YYYY-MM-DD.csv only as a *line/book/price source*.
    Probabilities/EV are recomputed from SmartSim player aggregates.
    """
    import math

    def _norm_cdf(x: float) -> float:
        return 0.5 * (1.0 + math.erf(x / math.sqrt(2.0)))

    def _american_to_decimal(a: float | None) -> float | None:
        try:
            if a is None:
                return None
            aa = float(a)
            if not math.isfinite(aa) or aa == 0:
                return None
            if aa > 0:
                return 1.0 + (aa / 100.0)
            return 1.0 + (100.0 / abs(aa))
        except Exception:
            return None

    def _ev_per_unit(p_win: float, price: float | None, p_push: float = 0.0) -> float | None:
        # EV per 1u stake with pushes: p_win*(dec-1) - p_lose, p_lose=1-p_win-p_push
        # => EV = p_win*dec + p_push - 1
        try:
            pv = float(max(0.0, min(1.0, float(p_win))))
            pp = float(max(0.0, min(1.0, float(p_push))))
            dec = _american_to_decimal(price)
            if dec is None:
                return None
            return float(pv * float(dec) + pp - 1.0)
        except Exception:
            return None

    def _p_over_under_push(mu: float, sd: float, line: float) -> tuple[float, float, float]:
        """Push-aware probabilities for integer-valued props (Normal approx + continuity correction)."""
        try:
            if sd <= 0 or not np.isfinite(sd) or not np.isfinite(mu) or not np.isfinite(line):
                if mu > line:
                    return 1.0, 0.0, 0.0
                if mu < line:
                    return 0.0, 1.0, 0.0
                return 0.0, 0.0, 1.0
            is_int_line = abs(float(line) - round(float(line))) <= 1e-6
            if is_int_line:
                # Over win if X >= L+1 => threshold L+0.5
                z_over = (float(line) + 0.5 - float(mu)) / float(sd)
                p_over = 1.0 - _norm_cdf(z_over)
                # Under win if X <= L-1 => threshold L-0.5
                z_under = (float(line) - 0.5 - float(mu)) / float(sd)
                p_under = _norm_cdf(z_under)
                p_push = 1.0 - float(p_over) - float(p_under)
            else:
                z = (float(line) - float(mu)) / float(sd)
                p_over = 1.0 - _norm_cdf(z)
                p_under = 1.0 - float(p_over)
                p_push = 0.0
            p_over = float(max(0.0, min(1.0, p_over)))
            p_under = float(max(0.0, min(1.0, p_under)))
            p_push = float(max(0.0, min(1.0, p_push)))
            return p_over, p_under, p_push
        except Exception:
            return 0.0, 0.0, 0.0

    def _p_win_for_side(mu: float, sd: float, line: float, side: str) -> tuple[float | None, float]:
        s = str(side or "").strip().lower()
        p_over, p_under, p_push = _p_over_under_push(mu, sd, line)
        if s in {"under", "u"}:
            return float(p_under), float(p_push)
        if s in {"over", "o"}:
            return float(p_over), float(p_push)
        return None, 0.0

    def _get_mu_sd(p: dict[str, Any], market: str) -> tuple[float | None, float | None]:
        m = str(market or "").strip().lower()
        # Base stats
        if m in {"pts", "points"}:
            return _safe_float(p.get("pts_mean")), _safe_float(p.get("pts_sd"))
        if m in {"reb", "rebounds"}:
            return _safe_float(p.get("reb_mean")), _safe_float(p.get("reb_sd"))
        if m in {"ast", "assists"}:
            return _safe_float(p.get("ast_mean")), _safe_float(p.get("ast_sd"))
        if m in {"threes", "3pm", "3ptm", "fg3m"}:
            return _safe_float(p.get("threes_mean")), _safe_float(p.get("threes_sd"))
        if m in {"stl", "steals", "steal"}:
            return _safe_float(p.get("stl_mean")), _safe_float(p.get("stl_sd"))
        if m in {"blk", "blocks", "block"}:
            return _safe_float(p.get("blk_mean")), _safe_float(p.get("blk_sd"))
        if m in {"tov", "turnovers", "turnover", "to"}:
            return _safe_float(p.get("tov_mean")), _safe_float(p.get("tov_sd"))
        if m in {"pra"}:
            return _safe_float(p.get("pra_mean")), _safe_float(p.get("pra_sd"))

        # Two-stat combos: approximate with independence for SD.
        pts_mu, pts_sd = _safe_float(p.get("pts_mean")), _safe_float(p.get("pts_sd"))
        reb_mu, reb_sd = _safe_float(p.get("reb_mean")), _safe_float(p.get("reb_sd"))
        ast_mu, ast_sd = _safe_float(p.get("ast_mean")), _safe_float(p.get("ast_sd"))

        def _sum(mu1: float | None, sd1: float | None, mu2: float | None, sd2: float | None) -> tuple[float | None, float | None]:
            if mu1 is None or mu2 is None:
                return None, None
            s1 = 0.0 if sd1 is None else float(sd1)
            s2 = 0.0 if sd2 is None else float(sd2)
            # Independence underestimates variance because real stats are correlated.
            sd = float(math.sqrt(max(0.0, s1 * s1 + s2 * s2)))
            return float(mu1 + mu2), float(sd)

        if m in {"pa"}:
            return _sum(pts_mu, pts_sd, ast_mu, ast_sd)
        if m in {"pr"}:
            return _sum(pts_mu, pts_sd, reb_mu, reb_sd)
        if m in {"ra"}:
            return _sum(reb_mu, reb_sd, ast_mu, ast_sd)

        return None, None

    def _apply_guardrails(mu: float | None, sd: float | None, market: str) -> tuple[float | None, float | None]:
        try:
            if mu is None or sd is None:
                return mu, sd
            mu2 = float(mu)
            sd2 = float(sd)
            if not np.isfinite(mu2) or not np.isfinite(sd2):
                return None, None
            # Floor SD to avoid pathological certainty.
            sd2 = max(sd2, 1.0)
            # Extra conservatism for combo markets where independence underestimates variance.
            m = str(market or "").strip().lower()
            if m in {"pa", "pr", "ra", "pra"}:
                sd2 = sd2 * 1.20
            return mu2, sd2
        except Exception:
            return mu, sd

    def _same_market_side_plays(row: dict[str, Any], market: str, side: str) -> list[dict[str, Any]]:
        out: list[dict[str, Any]] = []
        try:
            for raw in (row.get("plays") or []):
                if not isinstance(raw, dict):
                    continue
                mk = str(raw.get("market") or "").strip().lower()
                sd = str(raw.get("side") or "").strip().upper()
                if mk == str(market or "").strip().lower() and sd == str(side or "").strip().upper():
                    out.append(raw)
        except Exception:
            return []
        return out

    def _aligned_books_count(plays: list[dict[str, Any]]) -> int:
        try:
            books = {
                _canonical_bookmaker_key(p.get("book"))
                for p in (plays or [])
                if isinstance(p, dict) and _canonical_bookmaker_key(p.get("book"))
            }
            return int(len(books))
        except Exception:
            return 0

    def _best_line_available(side: str, plays: list[dict[str, Any]], line: float | None) -> bool:
        try:
            cur = _safe_float(line)
            if cur is None:
                return False
            lines = [_safe_float(p.get("line")) for p in (plays or []) if isinstance(p, dict)]
            lines = [float(v) for v in lines if v is not None]
            if not lines:
                return False
            sd = str(side or "").strip().upper()
            if sd == "OVER":
                return bool(float(cur) <= min(lines) + 1e-9)
            if sd == "UNDER":
                return bool(float(cur) >= max(lines) - 1e-9)
        except Exception:
            return False
        return False

    def _best_price_available(plays: list[dict[str, Any]], price: float | None) -> bool:
        try:
            cur = _safe_float(price)
            if cur is None:
                return False
            prices = [_safe_float(p.get("price")) for p in (plays or []) if isinstance(p, dict)]
            prices = [float(v) for v in prices if v is not None]
            return bool(prices and float(cur) >= max(prices) - 1e-9)
        except Exception:
            return False

    def _build_pregame_guidance(play: dict[str, Any], same_market_plays: list[dict[str, Any]]) -> dict[str, Any]:
        side = str(play.get("side") or "").strip().upper()
        line = _safe_float(play.get("line"))
        price = _safe_float(play.get("price"))
        open_line = _safe_float(play.get("open_line"))
        open_price = _safe_float(play.get("open_price"))
        line_move = _safe_float(play.get("line_move"))
        implied_move = _safe_float(play.get("implied_move"))
        sim_mu = _safe_float(play.get("sim_mu"))
        books_count = _aligned_books_count(same_market_plays)
        best_line = _best_line_available(side, same_market_plays, line)
        best_price = _best_price_available(same_market_plays, price)

        entry_state = "flat"
        try:
            if line is not None and open_line is not None and abs(float(line) - float(open_line)) >= 0.24:
                if side == "OVER":
                    entry_state = "better" if float(line) < float(open_line) else "worse"
                elif side == "UNDER":
                    entry_state = "better" if float(line) > float(open_line) else "worse"
            elif price is not None and open_price is not None and abs(float(price) - float(open_price)) >= 10.0:
                entry_state = "better" if float(price) > float(open_price) else "worse"
        except Exception:
            entry_state = "flat"

        move_signal = 0
        try:
            if line_move is not None and abs(float(line_move)) >= 0.24:
                if side == "OVER":
                    move_signal = 1 if float(line_move) > 0 else -1
                elif side == "UNDER":
                    move_signal = 1 if float(line_move) < 0 else -1
            elif implied_move is not None and abs(float(implied_move)) >= 0.015:
                if side == "OVER":
                    move_signal = 1 if float(implied_move) > 0 else -1
                elif side == "UNDER":
                    move_signal = 1 if float(implied_move) < 0 else -1
        except Exception:
            move_signal = 0
        market_view = "agree" if move_signal > 0 else ("disagree" if move_signal < 0 else "neutral")

        fast_move = False
        try:
            fast_move = bool(
                (line_move is not None and abs(float(line_move)) >= 1.0)
                or (implied_move is not None and abs(float(implied_move)) >= 0.05)
            )
        except Exception:
            fast_move = False

        play_to_line = None
        within_play_to = True
        edge_cushion = None
        try:
            if sim_mu is not None and line is not None and side in {"OVER", "UNDER"}:
                edge_cushion = (float(sim_mu) - float(line)) if side == "OVER" else (float(line) - float(sim_mu))
                haircut = 0.35
                if market_view == "disagree":
                    haircut += 0.15
                if entry_state == "worse":
                    haircut += 0.15
                if books_count <= 1:
                    haircut += 0.10
                if not best_line:
                    haircut += 0.10
                if fast_move:
                    haircut += 0.10
                if edge_cushion is not None and float(edge_cushion) > haircut:
                    target = (float(sim_mu) - haircut) if side == "OVER" else (float(sim_mu) + haircut)
                    if side == "OVER":
                        play_to_line = math.floor(target * 2.0) / 2.0
                        within_play_to = bool(float(line) <= float(play_to_line) + 1e-9)
                    else:
                        play_to_line = math.ceil(target * 2.0) / 2.0
                        within_play_to = bool(float(line) >= float(play_to_line) - 1e-9)
                else:
                    within_play_to = False
        except Exception:
            play_to_line = None
            within_play_to = True

        action = "Shop"
        if not within_play_to:
            action = "Pass"
        elif market_view == "agree":
            if entry_state in {"better", "flat"}:
                action = "Bet now" if (best_line or (best_price and books_count >= 2)) else "Shop"
            else:
                action = "Pass" if (fast_move and not best_line) else "Shop"
        elif market_view == "disagree":
            if entry_state == "better":
                action = "Wait"
            elif entry_state == "flat":
                action = "Wait"
            else:
                action = "Pass"
        else:
            if entry_state == "better":
                action = "Bet now" if best_line else "Shop"
            elif entry_state == "flat":
                action = "Bet now" if (best_line and (best_price or books_count >= 2)) else "Shop"
            else:
                action = "Shop" if (best_line and not fast_move) else "Pass"

        summary = "Little movement so far; use line shopping."
        if market_view == "agree" and entry_state == "worse":
            summary = f"Market agreed with the {side.lower()}, but this number is worse than the open."
        elif market_view == "agree":
            summary = f"Market agreed with the {side.lower()} and this entry is still playable."
        elif market_view == "disagree" and entry_state == "better":
            summary = f"This number improved from the open, but the market is leaning the other way."
        elif market_view == "disagree":
            summary = f"The market is moving against the {side.lower()} without giving a better entry."
        elif entry_state == "better":
            summary = "Entry improved from the open, but confirmation is limited."
        elif entry_state == "worse":
            summary = "Current entry is worse than the open, so price shopping matters."

        tags: list[str] = []
        if market_view == "agree":
            tags.append("Market agrees")
        elif market_view == "disagree":
            tags.append("Market disagrees")
        if entry_state == "better":
            tags.append("Better than open")
        elif entry_state == "worse":
            tags.append("Worse than open")
        if books_count >= 3:
            tags.append(f"{books_count} books aligned")
        elif books_count >= 2:
            tags.append(f"{books_count} books posted")
        if best_line:
            tags.append("Best line")
        elif best_price:
            tags.append("Best price")
        if fast_move:
            tags.append("Fast move")

        return {
            "action": action,
            "action_code": str(action).strip().lower().replace(" ", "_"),
            "market_view": market_view,
            "entry_state": entry_state,
            "books_count": books_count,
            "best_line": bool(best_line),
            "best_price": bool(best_price),
            "fast_move": bool(fast_move),
            "play_to_line": play_to_line,
            "within_play_to": bool(within_play_to),
            "edge_cushion": edge_cushion,
            "summary": summary,
            "tags": tags,
        }

    def _build_scored_play(
        source_play: dict[str, Any],
        row: dict[str, Any],
        market: str,
        side: str,
        line: float,
        price: float | None,
        mu: float,
        sd: float,
        pw: float,
        p_push: float,
        ev: float,
    ) -> dict[str, Any]:
        scored_play: dict[str, Any] = {
            "market": str(market).strip().lower(),
            "side": str(side).strip().upper(),
            "line": float(line),
            "book": _canonical_bookmaker_key(source_play.get("book")) or None,
            "price": _safe_float(price) if price is not None else None,
            "sim_mu": float(mu),
            "sim_sd": float(sd),
            "p_win": float(pw),
            "p_push": float(p_push),
            "ev": float(ev),
            "ev_pct": float(ev) * 100.0,
        }
        for key in ("snapshot_ts", "open_snapshot_ts"):
            if key in source_play:
                scored_play[key] = source_play.get(key)
        for key in ("open_line", "open_price", "open_implied_prob", "line_move", "implied_move", "edge"):
            if key in source_play:
                scored_play[key] = _safe_float(source_play.get(key))
        same_market_plays = _same_market_side_plays(row, market, side)
        scored_play["guidance"] = _build_pregame_guidance(scored_play, same_market_plays)
        return scored_play

    # Build team-scoped lookups from normalized name -> player sim row.
    # This prevents any accidental cross-team name matching.
    lookup_by_team: dict[str, dict[str, dict[str, Any]]] = {
        str(home_tri or "").strip().upper(): {},
        str(away_tri or "").strip().upper(): {},
    }
    for side, tri in (("home", str(home_tri or "").strip().upper()), ("away", str(away_tri or "").strip().upper())):
        if not tri:
            continue
        for p in players_out.get(side) or []:
            if not isinstance(p, dict):
                continue
            nm = _norm_player_name_for_keys(p.get("player_name"))
            if nm:
                lookup_by_team.setdefault(tri, {})[nm] = p

    def _build_for_team(team_tri: str) -> list[dict[str, Any]]:
        rows = props_recs_by_team.get(str(team_tri or "").strip().upper()) or []
        scored: list[dict[str, Any]] = []
        team_key = str(team_tri or "").strip().upper()
        team_lookup = lookup_by_team.get(team_key) or {}
        for rr in rows:
            try:
                player_name = str(rr.get("player") or "").strip()
                if not player_name:
                    continue
                p = team_lookup.get(_norm_player_name_for_keys(player_name))
                if not isinstance(p, dict):
                    continue

                # Guardrail: ignore extremely low-minute players (unstable distribution).
                try:
                    min_mean = _safe_float(p.get("min_mean"))
                    if min_mean is not None and min_mean < 8.0:
                        continue
                except Exception:
                    pass

                scored_plays: list[dict[str, Any]] = []

                for play in (rr.get("plays") or []):
                    if not isinstance(play, dict):
                        continue
                    market = play.get("market")
                    side = play.get("side")
                    line = _safe_float(play.get("line"))
                    price = play.get("price")
                    if market is None or side is None or line is None:
                        continue

                    # Restrict markets by default; bookmaker filters are opt-in.
                    try:
                        mk = str(market).strip().lower()
                    except Exception:
                        mk = ""
                    if allowed_markets and mk not in allowed_markets:
                        continue
                    bk = _canonical_bookmaker_key(play.get("book"))
                    if allowed_books and bk and (bk not in allowed_books):
                        continue
                    if excluded_books and bk and (bk in excluded_books):
                        continue

                    mu, sd = _get_mu_sd(p, str(market))
                    mu, sd = _apply_guardrails(mu, sd, str(market))
                    if mu is None or sd is None:
                        continue
                    pw, p_push = _p_win_for_side(float(mu), float(sd), float(line), str(side))
                    if pw is None:
                        continue
                    # Cap extremes to avoid infinite-looking EV from SD underestimation.
                    pw = float(max(0.02, min(0.98, float(pw))))
                    ev = _ev_per_unit(float(pw), _safe_float(price) if price is not None else -110.0, p_push=float(p_push))
                    if ev is None:
                        continue
                    if min_ev_pct is not None:
                        try:
                            if float(ev) * 100.0 < float(min_ev_pct):
                                continue
                        except Exception:
                            pass
                    scored_plays.append(
                        _build_scored_play(
                            play,
                            rr,
                            str(market),
                            str(side),
                            float(line),
                            _safe_float(price) if price is not None else None,
                            float(mu),
                            float(sd),
                            float(pw),
                            float(p_push),
                            float(ev),
                        )
                    )

                # If plays were missing/unusable, fall back to top_play
                if not scored_plays:
                    # Fall back to top_play if plays were missing
                    tp = rr.get("top_play")
                    if isinstance(tp, dict):
                        market = tp.get("market")
                        side = tp.get("side")
                        line = _safe_float(tp.get("line"))
                        price = tp.get("price")
                        if market is not None and side is not None and line is not None:
                            # Apply the same market defaults and optional book filters to the fallback path.
                            try:
                                mk = str(market).strip().lower()
                            except Exception:
                                mk = ""
                            if allowed_markets and mk not in allowed_markets:
                                market = None
                            bk = _canonical_bookmaker_key(tp.get("book"))
                            if allowed_books and bk and (bk not in allowed_books):
                                market = None
                            if excluded_books and bk and (bk in excluded_books):
                                market = None

                        if market is not None and side is not None and line is not None:
                            mu, sd = _get_mu_sd(p, str(market))
                            mu, sd = _apply_guardrails(mu, sd, str(market))
                            if mu is not None and sd is not None:
                                pw, p_push = _p_win_for_side(float(mu), float(sd), float(line), str(side))
                                if pw is not None:
                                    pw = float(max(0.02, min(0.98, float(pw))))
                                ev = _ev_per_unit(float(pw), _safe_float(price) if price is not None else -110.0, p_push=float(p_push)) if pw is not None else None
                                if pw is not None and ev is not None:
                                    if min_ev_pct is not None:
                                        try:
                                            if float(ev) * 100.0 < float(min_ev_pct):
                                                continue
                                        except Exception:
                                            pass
                                    scored_plays.append(
                                        _build_scored_play(
                                            tp,
                                            rr,
                                            str(market),
                                            str(side),
                                            float(line),
                                            _safe_float(price) if price is not None else None,
                                            float(mu),
                                            float(sd),
                                            float(pw),
                                            float(p_push),
                                            float(ev),
                                        )
                                    )

                if not scored_plays:
                    continue

                # De-dupe: recommend each prop once (best line only).
                # Keyed by (market, side) so multiple books/alt-lines collapse.
                try:
                    best_by_key: dict[tuple[str, str], dict[str, Any]] = {}
                    for sp in scored_plays:
                        if not isinstance(sp, dict):
                            continue
                        mk = str(sp.get("market") or "").strip().lower()
                        sd = str(sp.get("side") or "").strip().upper()
                        if not mk or not sd:
                            continue
                        k = (mk, sd)
                        cur = best_by_key.get(k)
                        cur_ev = _safe_float(cur.get("ev")) if isinstance(cur, dict) else None
                        sp_ev = _safe_float(sp.get("ev"))
                        if cur is None or (sp_ev is not None and (cur_ev is None or float(sp_ev) > float(cur_ev))):
                            best_by_key[k] = sp
                    scored_plays = list(best_by_key.values()) or scored_plays
                except Exception:
                    pass

                # Rank plays for this player and keep top few (UI can show multiple).
                scored_plays.sort(key=lambda z: _safe_float(z.get("ev")) or float("-inf"), reverse=True)
                top_k = 3
                picks = scored_plays[: max(1, int(top_k))]
                best_play = picks[0] if picks else None
                if not isinstance(best_play, dict):
                    continue

                sim_player_id = _safe_int(p.get("player_id")) if isinstance(p, dict) else None
                source_player_id = _safe_int(rr.get("player_id")) if isinstance(rr, dict) else None
                resolved_player_id = None
                try:
                    resolved_player_id = _resolve_player_id(player_name, team_tri)
                except Exception:
                    resolved_player_id = None
                if resolved_player_id is None:
                    resolved_player_id = sim_player_id if sim_player_id is not None else source_player_id

                photo = _best_player_headshot_url(
                    photo=((rr.get("photo") or rr.get("player_photo")) if isinstance(rr, dict) else None),
                    nba_player_id=resolved_player_id,
                    source_player_id=(source_player_id if source_player_id is not None else sim_player_id),
                )

                scored.append(
                    _flatten_prop_recommendation_row(
                        {
                            "player": player_name,
                            "player_id": resolved_player_id,
                            "photo": photo,
                            "player_photo": photo,
                            "team": str(team_tri or "").strip().upper(),
                            "best": best_play,
                            "picks": picks,
                            "source": "runtime_smartsim",
                        },
                        team_tri=team_tri,
                        home_tri=home_tri,
                        away_tri=away_tri,
                        player_sim=p,
                    )
                )
            except Exception:
                continue

        scored.sort(key=lambda x: _safe_float(((x.get("best") or {}) if isinstance(x.get("best"), dict) else {}).get("ev")) or float("-inf"), reverse=True)
        return scored[: max(0, int(topn_per_side))]

    return {
        "home": _build_for_team(home_tri),
        "away": _build_for_team(away_tri),
    }


def _player_prop_targets(players: list[dict[str, Any]], side: str) -> list[dict[str, Any]]:
    """Projection-based prop targets from aggregated sims (no market lines required)."""
    out: list[dict[str, Any]] = []
    if not players:
        return out

    def add(stat: str, key: str, topn: int = 3):
        for pr in _pick_top_players(players, key, n=topn):
            out.append(
                {
                    "side": side,
                    "player_id": pr.get("player_id"),
                    "player_name": pr.get("player_name"),
                    "stat": stat,
                    "mean": _safe_float(pr.get(key)),
                    "sd": _safe_float(pr.get(key.replace("_mean", "_sd"))) if isinstance(key, str) else None,
                    "q": pr.get(key.replace("_mean", "_q")) if isinstance(key, str) else None,
                }
            )

    add("PTS", "pts_mean")
    add("REB", "reb_mean")
    add("AST", "ast_mean")
    add("PRA", "pra_mean")
    add("3PM", "threes_mean")

    # De-dupe same player+stat
    seen = set()
    uniq: list[dict[str, Any]] = []
    for r in out:
        k = (str(r.get("player_id")), str(r.get("stat")))
        if k in seen:
            continue
        seen.add(k)
        uniq.append(r)
    return uniq


def _matchup_writeup(game: dict[str, Any]) -> str:
    try:
        home = str(game.get("home_name") or game.get("home_tri") or "Home")
        away = str(game.get("away_name") or game.get("away_tri") or "Away")
        odds = game.get("odds") or {}
        sim = game.get("sim") or {}
        score = sim.get("score") or {}

        p_home = _safe_float(score.get("p_home_win"))
        home_mean = _safe_float(score.get("home_mean"))
        away_mean = _safe_float(score.get("away_mean"))
        total_mean = _safe_float(score.get("total_mean"))

        market_total = _safe_float((sim.get("market") or {}).get("market_total"))
        market_spread = _safe_float((sim.get("market") or {}).get("market_home_spread"))
        if market_total is None:
            market_total = _safe_float(odds.get("total"))
        if market_spread is None:
            market_spread = _safe_float(odds.get("home_spread"))

        # Key players
        home_players = (sim.get("players") or {}).get("home") or []
        away_players = (sim.get("players") or {}).get("away") or []
        hp = _pick_top_players(home_players, "pts_mean", n=2)
        ap = _pick_top_players(away_players, "pts_mean", n=2)

        def _names(arr):
            return ", ".join([str(p.get("player_name")) for p in arr if p.get("player_name")])

        lines = []
        if market_spread is not None or market_total is not None:
            lines.append(
                f"The market opens this matchup at {home} {market_spread:+g} with a total of {market_total:g}."
            )
        if home_mean is not None and away_mean is not None:
            lines.append(
                f"Across aggregated SmartSim runs, the projected final is {home} {home_mean:.1f}, {away} {away_mean:.1f} (total {total_mean:.1f})."
            )
        if p_home is not None:
            lines.append(f"That translates to roughly a {p_home*100:.1f}% win probability for {home}.")
        if hp or ap:
            lines.append(
                f"On the player side, {home}’s scoring is led by {_names(hp) or 'its top options'}, while {away} leans on {_names(ap) or 'its primary scorers'}."
            )

        # Quarter tilt if available
        periods = sim.get("periods") or {}
        q1 = periods.get("q1") if isinstance(periods, dict) else None
        if isinstance(q1, dict) and _safe_float(q1.get("margin_mean")) is not None:
            m1 = float(q1.get("margin_mean"))
            if abs(m1) >= 2.0:
                leader = home if m1 > 0 else away
                lines.append(f"Early script: SmartSim shows {leader} with a meaningful Q1 edge (mean margin {m1:+.1f}).")

        return " ".join(lines).strip()
    except Exception:
        return ""


@app.route("/api/cards")
def api_cards():
    """Return enriched game cards for a date, built from saved SmartSim aggregates.

    Query params:
      - date: YYYY-MM-DD (required)
      - include_players: 1/true/yes to include heavy per-player sim rows
            - include_sim_ladders: 1/true/yes to include heavy interval ladders
      - home / away: optional matchup filter when requesting one game
    """
    d = _parse_date_param(request)
    if not d:
        return jsonify({"error": "missing date"}), 400

    def _is_truthy_arg(value: Any) -> bool:
        return str(value or "").strip().lower() in {"1", "true", "yes", "on"}

    def _normalize_team_arg(value: Any) -> str:
        raw = str(value or "").strip()
        if not raw:
            return ""
        try:
            return str(_get_tricode(raw) or raw).strip().upper()
        except Exception:
            return raw.strip().upper()

    requested_date = d
    include_players = _is_truthy_arg(request.args.get("include_players", request.args.get("includePlayers")))
    include_sim_ladders = _is_truthy_arg(request.args.get("include_sim_ladders", request.args.get("includeSimLadders")))
    requested_home_tri = _normalize_team_arg(request.args.get("home"))
    requested_away_tri = _normalize_team_arg(request.args.get("away"))
    props_source = str(request.args.get("props_source", request.args.get("propsSource", "auto")) or "auto").strip().lower()
    if props_source not in {"auto", "snapshot", "runtime", "source"}:
        props_source = "auto"
    smart_sim_files = _load_smart_sim_files_for_authoritative_slate(d)
    if not smart_sim_files:
        next_date, next_files = _find_next_available_smart_sim_date(d, max_ahead=_app_lookahead_days())
        if next_date and next_files:
            d = next_date
            smart_sim_files = next_files

    odds_map = _load_game_odds_map(d)
    prediction_rows_map = _load_predictions_rows_map(d)
    props_map = _load_props_predictions_map(d)
    min_priors = _compute_player_minutes_priors(d, days_back=21)
    props_edges_line_idx = _live_load_props_edges_index(d)
    props_recs_by_team = _load_props_recommendations_by_team(d)
    injury_ctx_map = _load_injury_context_map(d)
    roster_map = _roster_players_for_date(d)
    best_bets_game_context = _load_best_bets_game_context(d)
    best_bets_prop_prediction_lookup = _load_best_bets_props_prediction_lookup(d)
    best_bets_injury_snapshot = _best_bets_load_injury_snapshot(d)
    best_bets_slate_total_median = _safe_float(
        best_bets_game_context.get("slate_total_median")
        if isinstance(best_bets_game_context, dict)
        else None
    )
    cards_game_recommendations_index = _load_cards_game_recommendations_index(d)
    cards_prop_snapshot_index = _load_cards_prop_snapshot_index(d)
    cards_prop_recommendations_index = _load_cards_prop_recommendations_index(d)
    cards_sim_detail_index = _load_cards_sim_detail_index(d) if include_players else {}
    finals_lookup = _load_finals_lookup(d)
    now_local = _best_bets_local_now_naive()
    started_matchups = _cards_started_matchups_index(d, now_local)

    props_recs_source_lookup: dict[tuple[str, str], dict[str, Any]] = {}
    try:
        for team_tri, rows in (props_recs_by_team or {}).items():
            team_key = str(team_tri or "").strip().upper()
            if not team_key:
                continue
            for row in (rows or []):
                if not isinstance(row, dict):
                    continue
                player_key = _norm_player_name(str(row.get("player") or ""))
                if player_key:
                    props_recs_source_lookup[(team_key, player_key)] = row
    except Exception:
        props_recs_source_lookup = {}

    # Optional recon maps (historical dates). These are also fetched by the frontend
    # in results-mode, but we load them here so the API can attach useful summaries
    # like boxscore reconciliation without requiring extra requests.
    recon_games_map: dict[tuple[str, str], dict[str, Any]] = {}
    recon_quarters_map: dict[tuple[str, str], dict[str, Any]] = {}
    recon_props_by_id: dict[int, dict[str, Any]] = {}
    recon_props_by_key: dict[tuple[str, str], dict[str, Any]] = {}
    try:
        rg = DATA_PROCESSED_DIR / f"recon_games_{d}.csv"
        if rg.exists():
            df = pd.read_csv(rg)
            for _, row in df.iterrows():
                h = str(row.get("home_tri") or "").strip().upper()
                a = str(row.get("away_tri") or "").strip().upper()
                if h and a:
                    recon_games_map[(h, a)] = row.to_dict()
    except Exception:
        recon_games_map = {}
    try:
        rq = DATA_PROCESSED_DIR / f"recon_quarters_{d}.csv"
        if rq.exists():
            df = pd.read_csv(rq)
            for _, row in df.iterrows():
                h = str(row.get("home_tri") or "").strip().upper()
                a = str(row.get("away_tri") or "").strip().upper()
                if h and a:
                    recon_quarters_map[(h, a)] = row.to_dict()
    except Exception:
        recon_quarters_map = {}
    try:
        recon_props_by_id, recon_props_by_key = _load_recon_props_lookup(d)
    except Exception:
        recon_props_by_id, recon_props_by_key = {}, {}

    def _boxscore_prop_market_key(market: Any) -> str | None:
        try:
            mk = str(market or "").strip().lower()
        except Exception:
            return None
        return {
            "pts": "pts",
            "points": "pts",
            "player_points": "pts",
            "player_points_alternate": "pts",
            "reb": "reb",
            "rebounds": "reb",
            "player_rebounds": "reb",
            "player_rebounds_alternate": "reb",
            "ast": "ast",
            "assists": "ast",
            "player_assists": "ast",
            "player_assists_alternate": "ast",
            "threes": "threes",
            "3pm": "threes",
            "3ptm": "threes",
            "fg3m": "threes",
            "player_threes": "threes",
            "stl": "stl",
            "steal": "stl",
            "steals": "stl",
            "player_steals": "stl",
            "blk": "blk",
            "block": "blk",
            "blocks": "blk",
            "player_blocks": "blk",
            "tov": "tov",
            "to": "tov",
            "turnover": "tov",
            "turnovers": "tov",
            "player_turnovers": "tov",
            "pra": "pra",
            "player_points_rebounds_assists": "pra",
            "player_points_rebounds_assists_alternate": "pra",
            "pa": "pa",
            "player_points_assists": "pa",
            "pr": "pr",
            "player_points_rebounds": "pr",
            "ra": "ra",
            "player_rebounds_assists": "ra",
        }.get(mk)

    def _canonical_boxscore_prop_side(side: Any) -> str | None:
        try:
            s = str(side or "").strip().lower()
        except Exception:
            return None
        if s in {"over", "o"}:
            return "OVER"
        if s in {"under", "u"}:
            return "UNDER"
        return None

    def _boxscore_prop_option_sort_key(option: dict[str, Any]) -> tuple[int, float]:
        side = _canonical_boxscore_prop_side(option.get("side"))
        line = _safe_float(option.get("line"))
        line_key = float(line) if line is not None else float("inf")
        if side == "OVER":
            return (0, line_key)
        if side == "UNDER":
            return (1, -line_key)
        return (2, line_key)

    def _lookup_recon_prop_actuals(team_tri: Any, player_name: Any, player_id: Any) -> dict[str, Any] | None:
        try:
            pid = int(float(player_id))
        except Exception:
            pid = None
        if pid is not None and pid in recon_props_by_id:
            return dict(recon_props_by_id.get(pid) or {})
        team_key = str(team_tri or "").strip().upper()
        player_key = _norm_player_name(player_name)
        if team_key and player_key:
            row = recon_props_by_key.get((team_key, player_key))
            if isinstance(row, dict):
                return dict(row)
        return None

    def _apply_recon_to_prop_option(option: dict[str, Any], actual_row: dict[str, Any]) -> None:
        if not isinstance(option, dict) or not isinstance(actual_row, dict):
            return
        market_key = _boxscore_prop_market_key(option.get("market")) or _boxscore_prop_market_key(option.get("stat"))
        if market_key is None:
            market_key = str(option.get("market") or "").strip().lower() or None
        actual_val = _safe_float(actual_row.get(str(market_key or "").lower())) if market_key else None
        if actual_val is None:
            return
        option["actual"] = float(actual_val)
        result = _best_bets_settle_prop_pick(actual=actual_val, line=option.get("line"), side=option.get("side"))
        if result:
            option["result"] = result

    def _attach_recon_to_player_prop_row(row: dict[str, Any], team_tri: Any) -> None:
        if not isinstance(row, dict):
            return
        actual_row = _lookup_recon_prop_actuals(team_tri, row.get("player_name"), row.get("player_id"))
        if not isinstance(actual_row, dict):
            return
        actual_props = {
            key: actual_row.get(key)
            for key in ("pts", "reb", "ast", "threes", "stl", "blk", "tov", "pr", "pa", "ra", "pra")
            if actual_row.get(key) is not None
        }
        if actual_props:
            row["actual_props"] = actual_props
        options_map = row.get("prop_line_options") if isinstance(row.get("prop_line_options"), dict) else {}
        for options in options_map.values():
            if not isinstance(options, list):
                continue
            for option in options:
                _apply_recon_to_prop_option(option, actual_row)

    def _attach_recon_to_prop_recommendation(row: dict[str, Any], team_tri: Any) -> None:
        if not isinstance(row, dict):
            return
        best = row.get("best") if isinstance(row.get("best"), dict) else None
        actual_row = _lookup_recon_prop_actuals(team_tri, row.get("player"), best.get("player_id") if isinstance(best, dict) else None)
        if not isinstance(actual_row, dict):
            audit_row = _lookup_playable_prop_unresolved_audit(
                d,
                team_tri,
                row.get("player"),
                best.get("player_id") if isinstance(best, dict) else None,
                best.get("market") if isinstance(best, dict) else row.get("market"),
                best.get("side") if isinstance(best, dict) else row.get("side"),
                best.get("line") if isinstance(best, dict) else row.get("line"),
            )
            if isinstance(audit_row, dict) and audit_row:
                row["unresolved_audit"] = dict(audit_row)
                row["unresolved_reason"] = str(audit_row.get("unresolved_reason") or "").strip().lower() or None
                row["audit_classification"] = str(audit_row.get("audit_classification") or "").strip().lower() or None
                row["coverage_subtype"] = str(audit_row.get("coverage_subtype") or "").strip().lower() or None
                if isinstance(best, dict):
                    best["unresolved_audit"] = dict(audit_row)
                    best["unresolved_reason"] = row.get("unresolved_reason")
                    best["audit_classification"] = row.get("audit_classification")
                    best["coverage_subtype"] = row.get("coverage_subtype")
            return
        actual_props = {
            key: actual_row.get(key)
            for key in ("pts", "reb", "ast", "threes", "stl", "blk", "tov", "pr", "pa", "ra", "pra")
            if actual_row.get(key) is not None
        }
        if actual_props:
            row["actual_props"] = actual_props
        if isinstance(best, dict):
            market_key = _boxscore_prop_market_key(best.get("market")) or str(best.get("market") or "").strip().lower()
            actual_val = _safe_float(actual_row.get(market_key))
            if actual_val is not None:
                row["actual"] = float(actual_val)
                best["actual"] = float(actual_val)
            result = _best_bets_settle_prop_pick(actual=actual_val, line=best.get("line"), side=best.get("side"))
            if result:
                row["result"] = result
                best["result"] = result
        picks = row.get("picks") if isinstance(row.get("picks"), list) else []
        for pick in picks:
            if not isinstance(pick, dict):
                continue
            market_key = _boxscore_prop_market_key(pick.get("market")) or str(pick.get("market") or "").strip().lower()
            actual_val = _safe_float(actual_row.get(market_key))
            if actual_val is not None:
                pick["actual"] = float(actual_val)
            result = _best_bets_settle_prop_pick(actual=actual_val, line=pick.get("line"), side=pick.get("side"))
            if result:
                pick["result"] = result

    def _resolve_boxscore_prop_teams_from_snapshot(player_name: Any, home_team: Any, away_team: Any) -> list[str]:
        player_key = _norm_player_name_for_keys(player_name)
        home_tri_key = str(_get_tricode(str(home_team or "")) or "").strip().upper()
        away_tri_key = str(_get_tricode(str(away_team or "")) or "").strip().upper()
        fallback_teams: list[str] = []
        for tri in (home_tri_key, away_tri_key):
            if tri and tri not in fallback_teams:
                fallback_teams.append(tri)

        if not player_key:
            return fallback_teams

        home_roster = roster_map.get(home_tri_key) or set()
        away_roster = roster_map.get(away_tri_key) or set()

        if home_tri_key and player_key in home_roster and player_key not in away_roster:
            return [home_tri_key]
        if away_tri_key and player_key in away_roster and player_key not in home_roster:
            return [away_tri_key]
        matched_teams: list[str] = []
        if home_tri_key and player_key in home_roster:
            matched_teams.append(home_tri_key)
        if away_tri_key and player_key in away_roster and away_tri_key not in matched_teams:
            matched_teams.append(away_tri_key)
        if matched_teams:
            return matched_teams

        # Raw snapshots can arrive before roster coverage catches up for same-day moves.
        # Fall back to the game participants so cards still surface the board by player name.
        return fallback_teams

    def _choose_boxscore_prop_line(lines: list[float], target: Any) -> float | None:
        clean: list[float] = []
        for vv in (lines or []):
            try:
                if isinstance(vv, dict):
                    fv = float(vv.get("line"))
                else:
                    fv = float(vv)
                if np.isfinite(fv):
                    clean.append(fv)
            except Exception:
                continue
        if not clean:
            return None

        target_v = _safe_float(target)
        if target_v is not None:
            try:
                return float(min(clean, key=lambda fv: (abs(float(fv) - float(target_v)), abs(float(fv)))))
            except Exception:
                pass
        try:
            return float(np.median(np.asarray(clean, dtype=float)))
        except Exception:
            return float(clean[0])

    def _slim_cards_sim_context(context_obj: Any) -> dict[str, Any] | None:
        if not isinstance(context_obj, dict):
            return None
        keep_keys = (
            "away_pace",
            "home_pace",
            "game_pace",
            "league_pace",
            "away_b2b",
            "home_b2b",
            "away_injuries_out",
            "home_injuries_out",
            "roster_mode",
            "pbp_used",
            "fallback_reason",
            "pregame_prior",
        )
        slim = {key: context_obj.get(key) for key in keep_keys if key in context_obj}
        return slim or None

    def _remember_boxscore_prop_line(
        out: dict[str, dict[str, dict[str, Any]]],
        team_tri: Any,
        player_name: Any,
        market: Any,
        line_val: Any,
        side: Any = None,
        price: Any = None,
        book: Any = None,
        book_title: Any = None,
        source: Any = None,
        edge: Any = None,
        ev: Any = None,
        ev_pct: Any = None,
        snapshot_ts: Any = None,
        last_update: Any = None,
        open_line: Any = None,
        open_price: Any = None,
        line_move: Any = None,
        implied_move: Any = None,
    ) -> None:
        team_key = str(team_tri or "").strip().upper()
        player_label = str(player_name or "").strip()
        player_key = _norm_player_name_for_keys(player_label)
        market_key = _boxscore_prop_market_key(market)
        line_num = _safe_float(line_val)
        if not team_key or not player_key or not market_key or line_num is None:
            return
        team_map = out.setdefault(team_key, {})
        entry = team_map.setdefault(player_key, {"player_name": player_label, "markets": {}})
        if player_label and not str(entry.get("player_name") or "").strip():
            entry["player_name"] = player_label
        markets = entry.setdefault("markets", {})
        if isinstance(markets, dict):
            option = {
                "line": float(line_num),
                "side": _canonical_boxscore_prop_side(side),
                "price": _safe_float(price),
                "book": _canonical_bookmaker_key(book) or None,
                "book_title": (str(book_title).strip() if str(book_title or "").strip() else None),
                "source": (str(source).strip().lower() if str(source or "").strip() else None),
                "edge": _safe_float(edge),
                "ev": _safe_float(ev),
                "ev_pct": _safe_float(ev_pct),
                "snapshot_ts": (str(snapshot_ts).strip() if str(snapshot_ts or "").strip() else None),
                "last_update": (str(last_update).strip() if str(last_update or "").strip() else None),
                "open_line": _safe_float(open_line),
                "open_price": _safe_float(open_price),
                "line_move": _safe_float(line_move),
                "implied_move": _safe_float(implied_move),
            }
            if option.get("ev_pct") is None and option.get("ev") is not None:
                try:
                    option["ev_pct"] = float(option.get("ev")) * 100.0
                except Exception:
                    pass
            markets.setdefault(market_key, []).append(option)

    def _aggregate_boxscore_prop_options(options: list[dict[str, Any]]) -> list[dict[str, Any]]:
        grouped: dict[tuple[str | None, float], dict[str, Any]] = {}
        for raw in (options or []):
            if not isinstance(raw, dict):
                continue
            line_val = _safe_float(raw.get("line"))
            if line_val is None:
                continue
            side = _canonical_boxscore_prop_side(raw.get("side"))
            key = (side, float(line_val))
            group = grouped.get(key)
            if group is None:
                group = {
                    "side": side,
                    "line": float(line_val),
                    "books": [],
                    "book_count": 0,
                    "best_price": None,
                    "edge": None,
                    "ev": None,
                    "ev_pct": None,
                    "sources": [],
                }
                grouped[key] = group

            source = str(raw.get("source") or "").strip().lower()
            if source and source not in group["sources"]:
                group["sources"].append(source)

            price_val = _safe_float(raw.get("price"))
            best_price = _safe_float(group.get("best_price"))
            if price_val is not None and (best_price is None or float(price_val) > float(best_price)):
                group["best_price"] = float(price_val)

            for metric_key in ("edge", "ev", "ev_pct"):
                raw_metric = _safe_float(raw.get(metric_key))
                cur_metric = _safe_float(group.get(metric_key))
                if raw_metric is None:
                    continue
                if cur_metric is None or abs(float(raw_metric)) > abs(float(cur_metric)):
                    group[metric_key] = float(raw_metric)

            book_key = _canonical_bookmaker_key(raw.get("book")) or None
            if book_key:
                matched_book = None
                for book_row in group["books"]:
                    if str(book_row.get("book") or "") == book_key:
                        matched_book = book_row
                        break
                if matched_book is None:
                    matched_book = {
                        "book": book_key,
                        "book_title": (str(raw.get("book_title")).strip() if str(raw.get("book_title") or "").strip() else None),
                        "price": price_val,
                        "snapshot_ts": (str(raw.get("snapshot_ts")).strip() if str(raw.get("snapshot_ts") or "").strip() else None),
                        "last_update": (str(raw.get("last_update")).strip() if str(raw.get("last_update") or "").strip() else None),
                        "open_line": _safe_float(raw.get("open_line")),
                        "open_price": _safe_float(raw.get("open_price")),
                        "line_move": _safe_float(raw.get("line_move")),
                        "implied_move": _safe_float(raw.get("implied_move")),
                    }
                    group["books"].append(matched_book)
                else:
                    cur_price = _safe_float(matched_book.get("price"))
                    if price_val is not None and (cur_price is None or float(price_val) > float(cur_price)):
                        matched_book["price"] = float(price_val)
                    for meta_key in ("book_title", "snapshot_ts", "last_update"):
                        if not matched_book.get(meta_key):
                            meta_val = str(raw.get(meta_key) or "").strip()
                            if meta_val:
                                matched_book[meta_key] = meta_val
                    for meta_key in ("open_line", "open_price", "line_move", "implied_move"):
                        if _safe_float(matched_book.get(meta_key)) is None:
                            meta_val = _safe_float(raw.get(meta_key))
                            if meta_val is not None:
                                matched_book[meta_key] = float(meta_val)

        out_options: list[dict[str, Any]] = []
        for group in grouped.values():
            books = group.get("books") if isinstance(group.get("books"), list) else []
            books.sort(
                key=lambda book_row: (
                    -(_safe_float(book_row.get("price")) if _safe_float(book_row.get("price")) is not None else float("-inf")),
                    str(book_row.get("book_title") or book_row.get("book") or ""),
                )
            )
            group["book_count"] = len(books)
            out_options.append(group)

        out_options.sort(key=_boxscore_prop_option_sort_key)
        return out_options

    def _build_boxscore_player_prop_payload(
        team_tri: Any,
        player_name: Any,
        mean_targets: dict[str, Any] | None = None,
    ) -> tuple[dict[str, float], dict[str, list[dict[str, Any]]]]:
        player_key = _norm_player_name_for_keys(player_name)
        team_key = str(team_tri or "").strip().upper()
        player_entry = (team_boxscore_prop_sources.get(team_key) or {}).get(player_key) or {}
        player_markets = player_entry.get("markets") if isinstance(player_entry.get("markets"), dict) else {}

        prop_lines: dict[str, float] = {}
        prop_line_options: dict[str, list[dict[str, Any]]] = {}
        target_map = mean_targets if isinstance(mean_targets, dict) else {}

        for market_key, mean_key in (
            ("pts", "pts_mean"),
            ("reb", "reb_mean"),
            ("ast", "ast_mean"),
            ("threes", "threes_mean"),
            ("stl", "stl_mean"),
            ("blk", "blk_mean"),
            ("tov", "tov_mean"),
            ("pra", "pra_mean"),
        ):
            raw_options = list((player_markets or {}).get(market_key) or [])
            grouped_options = _aggregate_boxscore_prop_options(raw_options)
            if grouped_options:
                prop_line_options[market_key] = grouped_options

            line_val = _safe_float(props_edges_line_idx.get((team_key, player_key, market_key))) if player_key else None
            if line_val is None:
                line_val = _choose_boxscore_prop_line(raw_options, target_map.get(mean_key))
            if line_val is not None:
                prop_lines[market_key] = float(line_val)

        return prop_lines, prop_line_options

    def _build_boxscore_prop_recommendation_index(prop_recs: dict[str, list[dict[str, Any]]]) -> dict[tuple[str, str, str, str, float], list[dict[str, Any]]]:
        out: dict[tuple[str, str, str, str, float], list[dict[str, Any]]] = {}
        for rows in (prop_recs or {}).values():
            for row in (rows or []):
                if not isinstance(row, dict):
                    continue
                team_key = str(row.get("team") or "").strip().upper()
                player_key = _norm_player_name_for_keys(row.get("player"))
                if not team_key or not player_key:
                    continue
                picks: list[dict[str, Any]] = []
                effective_pick = _season_betting_card_effective_prop_row(row)
                if isinstance(effective_pick, dict) and effective_pick:
                    picks = [effective_pick]
                elif isinstance(row.get("best"), dict):
                    picks = [row.get("best")]
                elif isinstance(row.get("top_play"), dict):
                    picks = [row.get("top_play")]
                elif isinstance(row.get("picks"), list):
                    picks = [pick for pick in row.get("picks") if isinstance(pick, dict)]
                for rank, pick in enumerate(picks, start=1):
                    if not isinstance(pick, dict):
                        continue
                    market_key = _boxscore_prop_market_key(pick.get("market"))
                    side_key = _canonical_boxscore_prop_side(pick.get("side"))
                    line_val = _safe_float(pick.get("line"))
                    if not team_key or not player_key or not market_key or not side_key or line_val is None:
                        continue
                    guidance = pick.get("guidance") if isinstance(pick.get("guidance"), dict) else {}
                    out.setdefault((team_key, player_key, market_key, side_key, float(line_val)), []).append(
                        {
                            "rank": int(rank),
                            "primary": bool(rank == 1),
                            "book": _canonical_bookmaker_key(pick.get("book")) or None,
                            "price": _safe_float(pick.get("price")),
                            "ev_pct": _safe_float(pick.get("ev_pct")),
                            "action": (str(guidance.get("action") or "").strip() if str(guidance.get("action") or "").strip() else None),
                            "action_code": (str(guidance.get("action_code") or "").strip() if str(guidance.get("action_code") or "").strip() else None),
                            "play_to_line": _safe_float(guidance.get("play_to_line")),
                            "summary": (str(guidance.get("summary") or "").strip() if str(guidance.get("summary") or "").strip() else None),
                        }
                    )
        return out

    def _apply_boxscore_prop_recommendation_markers(
        rows: list[dict[str, Any]],
        team_tri: str,
        rec_index: dict[tuple[str, str, str, str, float], list[dict[str, Any]]],
    ) -> None:
        team_key = str(team_tri or "").strip().upper()
        if not team_key:
            return
        for row in (rows or []):
            if not isinstance(row, dict):
                continue
            player_key = _norm_player_name_for_keys(row.get("player_name"))
            if not player_key:
                continue
            line_options = row.get("prop_line_options") if isinstance(row.get("prop_line_options"), dict) else {}
            if not line_options:
                continue
            for market_key, options in line_options.items():
                if not isinstance(options, list):
                    continue
                for option in options:
                    if not isinstance(option, dict):
                        continue
                    side_key = _canonical_boxscore_prop_side(option.get("side"))
                    line_val = _safe_float(option.get("line"))
                    if not side_key or line_val is None:
                        continue
                    matches = rec_index.get((team_key, player_key, str(market_key), side_key, float(line_val))) or []
                    if not matches:
                        continue
                    matches.sort(
                        key=lambda rr: (
                            0 if rr.get("primary") else 1,
                            int(rr.get("rank") or 9999),
                            -(_safe_float(rr.get("ev_pct")) if _safe_float(rr.get("ev_pct")) is not None else float("-inf")),
                        )
                    )
                    best_match = matches[0]
                    option["recommended"] = True
                    option["recommended_primary"] = any(bool(rr.get("primary")) for rr in matches)
                    option["recommendation_rank"] = min(int(rr.get("rank") or 9999) for rr in matches)
                    rec_evs = [_safe_float(rr.get("ev_pct")) for rr in matches if _safe_float(rr.get("ev_pct")) is not None]
                    if rec_evs:
                        option["recommendation_ev_pct"] = max(float(v) for v in rec_evs)
                    for meta_key in ("book", "price", "action", "action_code", "play_to_line", "summary"):
                        meta_val = best_match.get(meta_key)
                        if meta_val is not None:
                            option[f"recommendation_{meta_key}"] = meta_val
                options.sort(
                    key=lambda opt: (
                        0 if opt.get("recommended_primary") else (1 if opt.get("recommended") else 2),
                        *_boxscore_prop_option_sort_key(opt),
                    )
                )

    def _build_boxscore_prop_line_sources(date_str: str) -> dict[str, dict[str, dict[str, Any]]]:
        out: dict[str, dict[str, dict[str, Any]]] = {}
        try:
            raw_p = None
            try:
                raw_p = _live_find_processed_csv("oddsapi_player_props", date_str)
            except Exception:
                raw_p = None
            if raw_p is None:
                try:
                    raw_candidate = DATA_RAW_DIR / f"odds_nba_player_props_{date_str}.csv"
                    if raw_candidate.exists() and raw_candidate.stat().st_size > 0:
                        raw_p = raw_candidate
                except Exception:
                    raw_p = None
            if raw_p is None:
                try:
                    from nba_betting.config import paths as _paths  # type: ignore

                    raw_candidate = _paths.data_raw / f"odds_nba_player_props_{date_str}.csv"
                    if raw_candidate.exists() and raw_candidate.stat().st_size > 0:
                        raw_p = raw_candidate
                except Exception:
                    raw_p = None
            if raw_p:
                df = pd.read_csv(raw_p)
                if df is not None and not df.empty:
                    cols = {str(c).strip().lower(): str(c) for c in df.columns}
                    market_col = cols.get("market")
                    name_col = cols.get("player_name")
                    line_col = cols.get("point")
                    side_col = cols.get("outcome_name")
                    price_col = cols.get("price")
                    book_col = cols.get("bookmaker")
                    book_title_col = cols.get("bookmaker_title")
                    home_col = cols.get("home_team")
                    away_col = cols.get("away_team")
                    snapshot_col = cols.get("snapshot_ts")
                    last_update_col = cols.get("last_update")
                    if market_col and name_col and line_col and side_col and home_col and away_col:
                        for _, row in df.iterrows():
                            for team_tri in _resolve_boxscore_prop_teams_from_snapshot(
                                row.get(name_col),
                                row.get(home_col),
                                row.get(away_col),
                            ):
                                _remember_boxscore_prop_line(
                                    out,
                                    team_tri,
                                    row.get(name_col),
                                    row.get(market_col),
                                    row.get(line_col),
                                    side=row.get(side_col),
                                    price=row.get(price_col) if price_col else None,
                                    book=row.get(book_col) if book_col else None,
                                    book_title=row.get(book_title_col) if book_title_col else None,
                                    source="snapshot",
                                    snapshot_ts=row.get(snapshot_col) if snapshot_col else None,
                                    last_update=row.get(last_update_col) if last_update_col else None,
                                )
        except Exception:
            pass

        try:
            edges_p = _live_find_processed_csv("props_edges", date_str)
            if edges_p:
                df = pd.read_csv(edges_p)
                if df is not None and not df.empty:
                    cols = {str(c).strip().lower(): str(c) for c in df.columns}
                    tcol = cols.get("team")
                    ncol = cols.get("player_name")
                    scol = cols.get("stat")
                    lcol = cols.get("line")
                    side_col = cols.get("side")
                    price_col = cols.get("price")
                    edge_col = cols.get("edge")
                    ev_col = cols.get("ev")
                    book_col = cols.get("bookmaker")
                    book_title_col = cols.get("bookmaker_title")
                    snapshot_col = cols.get("snapshot_ts")
                    open_line_col = cols.get("open_line")
                    open_price_col = cols.get("open_price")
                    line_move_col = cols.get("line_move")
                    implied_move_col = cols.get("implied_move")
                    if tcol and ncol and scol and lcol:
                        for _, row in df.iterrows():
                            _remember_boxscore_prop_line(
                                out,
                                row.get(tcol),
                                row.get(ncol),
                                row.get(scol),
                                row.get(lcol),
                                side=row.get(side_col) if side_col else None,
                                price=row.get(price_col) if price_col else None,
                                book=row.get(book_col) if book_col else None,
                                book_title=row.get(book_title_col) if book_title_col else None,
                                source="edges",
                                edge=row.get(edge_col) if edge_col else None,
                                ev=row.get(ev_col) if ev_col else None,
                                snapshot_ts=row.get(snapshot_col) if snapshot_col else None,
                                open_line=row.get(open_line_col) if open_line_col else None,
                                open_price=row.get(open_price_col) if open_price_col else None,
                                line_move=row.get(line_move_col) if line_move_col else None,
                                implied_move=row.get(implied_move_col) if implied_move_col else None,
                            )
        except Exception:
            pass

        try:
            for team_tri, rows in (props_recs_by_team or {}).items():
                for rr in (rows or []):
                    player_name = rr.get("player")
                    for play in (rr.get("plays") or []):
                        if not isinstance(play, dict):
                            continue
                        _remember_boxscore_prop_line(
                            out,
                            team_tri,
                            player_name,
                            play.get("market"),
                            play.get("line"),
                            side=play.get("side"),
                            price=play.get("price"),
                            book=play.get("book"),
                            source="recommendations",
                            edge=play.get("edge"),
                            ev=play.get("ev"),
                            ev_pct=play.get("ev_pct"),
                        )
        except Exception:
            pass
        return out

    def _player_known_unavailable(team_tri: str, player_name: Any) -> bool:
        try:
            team_key = str(team_tri or "").strip().upper()
            name_key = _norm_player_name(str(player_name or ""))
            ctx = injury_ctx_map.get((team_key, name_key)) if team_key and name_key else None
            if isinstance(ctx, dict):
                st = str(ctx.get("injury_status") or "").strip().upper()
                return (st == "OUT") or (ctx.get("playing_today") is False)
        except Exception:
            pass
        return False

    def _canon_nba_game_id(game_id: Any) -> str:
        try:
            raw = str(game_id or "").strip()
        except Exception:
            return ""
        digits = "".join([c for c in raw if c.isdigit()])
        if len(digits) == 8:
            return "00" + digits
        if len(digits) == 9:
            return "0" + digits
        return digits

    def _boxscore_reconcile_points(game_id: Any, home_tri: str, away_tri: str) -> Optional[dict[str, Any]]:
        gid = _canon_nba_game_id(game_id)
        if not gid:
            return None
        p = DATA_PROCESSED_DIR / "boxscores" / f"boxscore_{gid}.csv"
        if not p.exists():
            return {"ok": False, "game_id": gid, "reason": "missing_boxscore"}
        try:
            df = pd.read_csv(p)
        except Exception as e:
            return {"ok": False, "game_id": gid, "reason": f"read_error: {e}"}

        if "teamTricode" not in df.columns or "points" not in df.columns:
            return {"ok": False, "game_id": gid, "reason": "missing_columns"}

        try:
            df["teamTricode"] = df["teamTricode"].astype(str).str.strip().str.upper()
        except Exception:
            pass
        try:
            pts = pd.to_numeric(df["points"], errors="coerce")
        except Exception:
            pts = df["points"]

        sums = {}
        rows = {}
        try:
            for tri, grp in df.groupby("teamTricode"):
                rows[str(tri)] = int(len(grp))
                try:
                    sums[str(tri)] = float(pd.to_numeric(grp["points"], errors="coerce").fillna(0.0).sum())
                except Exception:
                    sums[str(tri)] = float(0.0)
        except Exception:
            # Last-resort simple aggregation
            try:
                for tri in set(df["teamTricode"].tolist()):
                    mask = df["teamTricode"] == tri
                    rows[str(tri)] = int(mask.sum())
                    sums[str(tri)] = float(pd.to_numeric(df.loc[mask, "points"], errors="coerce").fillna(0.0).sum())
            except Exception:
                return {"ok": False, "game_id": gid, "reason": "aggregate_error"}

        h = str(home_tri or "").strip().upper()
        a = str(away_tri or "").strip().upper()
        home_pts_players = sums.get(h)
        away_pts_players = sums.get(a)

        # Attach best-available actual team points from recon_games (if present).
        actual = recon_games_map.get((h, a)) or {}
        home_pts_actual = _safe_float(actual.get("home_pts"))
        away_pts_actual = _safe_float(actual.get("visitor_pts"))

        def _diff(x: Optional[float], y: Optional[float]) -> Optional[float]:
            if x is None or y is None:
                return None
            return float(x) - float(y)

        diff_home = _diff(home_pts_players, home_pts_actual)
        diff_away = _diff(away_pts_players, away_pts_actual)
        # Treat within 0.5 as OK (float CSVs sometimes represent ints).
        ok = True
        if diff_home is not None and abs(diff_home) > 0.5:
            ok = False
        if diff_away is not None and abs(diff_away) > 0.5:
            ok = False

        return {
            "ok": ok,
            "game_id": gid,
            "home_tri": h,
            "away_tri": a,
            "home_pts_players": home_pts_players,
            "away_pts_players": away_pts_players,
            "home_rows": rows.get(h),
            "away_rows": rows.get(a),
            "home_pts_actual": home_pts_actual,
            "away_pts_actual": away_pts_actual,
            "diff_home": diff_home,
            "diff_away": diff_away,
        }

    all_team_boxscore_prop_sources = _build_boxscore_prop_line_sources(d) if include_players else {}

    smart_sim_files_by_matchup: dict[tuple[str, str], Path] = {}
    for fp in smart_sim_files:
        matchup = _smart_sim_matchup_from_path(d, fp)
        if matchup is not None and matchup not in smart_sim_files_by_matchup:
            smart_sim_files_by_matchup[matchup] = fp

    slate_matchups = set(smart_sim_files_by_matchup.keys()) | set(odds_map.keys()) | set(prediction_rows_map.keys())

    def _matchup_sort_key(matchup: tuple[str, str]) -> tuple[str, str, str]:
        odds_row = odds_map.get(matchup) or {}
        pred_row = prediction_rows_map.get(matchup) or {}
        commence_time = odds_row.get("commence_time") or pred_row.get("commence_time") or ""
        return (str(commence_time or ""), matchup[0], matchup[1])

    games: list[dict[str, Any]] = []
    for home_tri, away_tri in sorted(slate_matchups, key=_matchup_sort_key):
        if requested_home_tri and home_tri != requested_home_tri:
            continue
        if requested_away_tri and away_tri != requested_away_tri:
            continue
        fp = smart_sim_files_by_matchup.get((home_tri, away_tri))
        if fp is not None:
            try:
                obj = json.loads(fp.read_text(encoding="utf-8"))
            except Exception:
                continue
            if not isinstance(obj, dict):
                continue
        else:
            obj = _build_fallback_smart_sim_object(
                d,
                home_tri,
                away_tri,
                prediction_rows_map.get((home_tri, away_tri)),
                odds_map.get((home_tri, away_tri)),
            )
            if not isinstance(obj, dict):
                continue
            fp = DATA_PROCESSED_DIR / f"smart_sim_{d}_{home_tri}_{away_tri}.json"

        sim_error = obj.get("error")

        home_tri = _canonical_team_tri(obj.get("home") or home_tri)
        away_tri = _canonical_team_tri(obj.get("away") or away_tri)
        if not home_tri or not away_tri:
            continue

        sim_detail_snapshot = cards_sim_detail_index.get((home_tri, away_tri)) if isinstance(cards_sim_detail_index, dict) else None

        odds = dict(odds_map.get((home_tri, away_tri)) or {})
        home_name = str(odds.get("home_team") or home_tri)
        away_name = str(odds.get("visitor_team") or away_tri)
        game_started = _cards_matchup_has_started(
            d,
            home_tri=home_tri,
            away_tri=away_tri,
            commence_time=odds.get("commence_time") or (prediction_rows_map.get((home_tri, away_tri)) or {}).get("commence_time"),
            started_matchups=started_matchups,
            now_local=now_local,
        )

        matchup_live = (started_matchups or {}).get((home_tri, away_tri)) if isinstance(started_matchups, dict) else None
        try:
            if isinstance(matchup_live, dict) and bool(matchup_live.get("in_progress")):
                live_odds = _live_oddsapi_period_totals_for_game(d, home_tri, away_tri)
                game_lines = live_odds.get("game_lines") if isinstance(live_odds, dict) else None
                if isinstance(game_lines, dict) and game_lines:
                    for key in ("total", "home_spread", "away_spread", "home_ml", "away_ml"):
                        value = _safe_float(game_lines.get(key))
                        if value is not None:
                            odds[key] = value
                    if live_odds.get("source"):
                        odds["source"] = live_odds.get("source")
                    odds["updated_at"] = datetime.utcnow().isoformat(timespec="seconds") + "Z"
        except Exception:
            pass

        # Attach injury/status context onto sim player rows via props_predictions
        players = obj.get("players") if isinstance(obj.get("players"), dict) else {"home": [], "away": []}
        players_out: dict[str, list[dict[str, Any]]] = {"home": [], "away": []}

        def _is_blank(v: Any) -> bool:
            if v is None:
                return True
            # Preserve boolean False as meaningful (e.g. playing_today=False)
            if isinstance(v, (bool, np.bool_)):
                return False
            # Pandas often uses NaN floats for missing strings
            try:
                if isinstance(v, float) and np.isnan(v):
                    return True
            except Exception:
                pass
            try:
                if pd.isna(v):
                    return True
            except Exception:
                pass
            try:
                if isinstance(v, str):
                    s = v.strip()
                    if s == "":
                        return True
                    if s.lower() in {"nan", "none", "null", "na", "n/a"}:
                        return True
            except Exception:
                pass
            return False

        def _is_present(v: Any) -> bool:
            return not _is_blank(v)

        def _exclude_from_sim_output(player_row: dict[str, Any]) -> bool:
            try:
                st = str(player_row.get("injury_status") or "").strip().upper()
            except Exception:
                st = ""
            return (st == "OUT") or (player_row.get("playing_today") is False)

        team_boxscore_prop_sources = {
            home_tri: all_team_boxscore_prop_sources.get(home_tri) or {},
            away_tri: all_team_boxscore_prop_sources.get(away_tri) or {},
        } if include_players else {home_tri: {}, away_tri: {}}

        for side in ("home", "away"):
            arr = players.get(side) if isinstance(players, dict) else []
            out_arr: list[dict[str, Any]] = []
            for pr in (arr or []):
                if not isinstance(pr, dict):
                    continue
                pr2 = dict(pr)

                # Add minutes estimate (from recent boxscore priors) when available.
                try:
                    if "min_mean" not in pr2 and pr2.get("player_name"):
                        tri = home_tri if side == "home" else away_tri
                        nm_key = _norm_player_name_for_keys(pr2.get("player_name"))
                        m = min_priors.get((tri, nm_key))
                        if m is not None:
                            pr2["min_mean"] = float(m)
                except Exception:
                    pass

                try:
                    pid = int(float(pr2.get("player_id")))
                except Exception:
                    pid = None
                if pid is not None and pid in props_map:
                    ctx = props_map.get(pid) or {}
                    for k in ("injury_status", "playing_today", "team_on_slate", "opponent", "home"):
                        if k in ctx and (_is_blank(pr2.get(k))):
                            vv = ctx.get(k)
                            if _is_present(vv):
                                pr2[k] = vv

                # If props_predictions doesn't carry injury fields (often blank),
                # fall back to the raw injuries feed for display context.
                try:
                    if _is_blank(pr2.get("injury_status")) and pr2.get("player_name"):
                        tri = home_tri if side == "home" else away_tri
                        nk = _norm_player_name(pr2.get("player_name"))
                        ctx2 = injury_ctx_map.get((tri, nk))
                        if isinstance(ctx2, dict) and ctx2:
                            for k in ("injury_status", "playing_today", "injury", "injury_date"):
                                if k in ctx2 and _is_blank(pr2.get(k)):
                                    vv = ctx2.get(k)
                                    if _is_present(vv):
                                        pr2[k] = vv
                except Exception:
                    pass

                # Clean up placeholder values so we don't surface strings like "NAN".
                # (UI should only badge OUT, but keeping the API tidy helps debugging.)
                try:
                    for k in ("injury_status", "injury", "injury_date"):
                        if _is_blank(pr2.get(k)):
                            pr2.pop(k, None)
                    if _is_blank(pr2.get("playing_today")):
                        pr2.pop("playing_today", None)
                except Exception:
                    pass

                # Final cleanup: strip placeholder strings like "NAN" so the UI doesn't
                # render fake statuses when no real context is available.
                try:
                    for k in ("injury_status", "injury", "injury_date"):
                        if _is_blank(pr2.get(k)):
                            pr2.pop(k, None)
                except Exception:
                    pass

                if include_players:
                    try:
                        tri = home_tri if side == "home" else away_tri
                        tri_key = str(tri or "").strip().upper()
                        prop_lines, prop_line_options = _build_boxscore_player_prop_payload(tri_key, pr2.get("player_name"), pr2)
                        if prop_lines:
                            pr2["prop_lines"] = prop_lines
                        if prop_line_options:
                            pr2["prop_line_options"] = prop_line_options
                    except Exception:
                        pass

                if _exclude_from_sim_output(pr2):
                    continue
                out_arr.append(pr2)

            ranked_rows: list[tuple[float, float, dict[str, Any]]] = []
            for row in out_arr:
                min_mean = _safe_float(row.get("min_mean"))
                if min_mean is None:
                    continue
                pra_mean = _safe_float(row.get("pra_mean")) or 0.0
                ranked_rows.append((float(min_mean), float(pra_mean), row))
            ranked_rows.sort(key=lambda item: (-item[0], -item[1], str(item[2].get("player_name") or "").strip().upper()))

            trimmed_rows: list[dict[str, Any]] = []
            for idx, (min_mean, _pra_mean, row) in enumerate(ranked_rows):
                if min_mean < 4.0 and idx >= 10:
                    continue
                trimmed_rows.append(row)
            players_out[side] = trimmed_rows

        def _missing_prop_players_for_team(team_tri: str, raw_players: Any) -> list[dict[str, Any]]:
            team_key = str(team_tri or "").strip().upper()
            source_map = team_boxscore_prop_sources.get(team_key) or {}
            if not source_map:
                return []

            sim_player_keys: set[str] = set()
            for row in (raw_players or []):
                if not isinstance(row, dict):
                    continue
                nk = _norm_player_name_for_keys(row.get("player_name"))
                if nk:
                    sim_player_keys.add(nk)

            out_rows: list[dict[str, Any]] = []
            for player_key, entry in source_map.items():
                if player_key in sim_player_keys or not isinstance(entry, dict):
                    continue
                player_name = str(entry.get("player_name") or "").strip()
                if not player_name or _player_known_unavailable(team_key, player_name):
                    continue
                prop_lines, prop_line_options = _build_boxscore_player_prop_payload(team_key, player_name, None)
                if prop_lines:
                    row_out = {"player_name": player_name, "prop_lines": prop_lines}
                    if prop_line_options:
                        row_out["prop_line_options"] = prop_line_options
                    out_rows.append(row_out)

            out_rows.sort(key=lambda row: str(row.get("player_name") or "").strip().upper())
            return out_rows

        missing_prop_players = {
            "home": _missing_prop_players_for_team(home_tri, players.get("home") if isinstance(players, dict) else []),
            "away": _missing_prop_players_for_team(away_tri, players.get("away") if isinstance(players, dict) else []),
        } if include_players else {"home": [], "away": []}

        try:
            for side_key, team_tri in (("home", home_tri), ("away", away_tri)):
                for player_row in players_out.get(side_key) or []:
                    _attach_recon_to_player_prop_row(player_row, team_tri)
                for player_row in missing_prop_players.get(side_key) or []:
                    _attach_recon_to_player_prop_row(player_row, team_tri)
        except Exception:
            pass

        def _injury_list_for_team(team_tri: str) -> list[dict[str, Any]]:
            tri = str(team_tri or "").strip().upper()
            if not tri:
                return []
            roster_keys = roster_map.get(tri) or set()
            out_rows: list[dict[str, Any]] = []
            try:
                items = injury_ctx_map.items() if isinstance(injury_ctx_map, dict) else []
            except Exception:
                items = []
            for (t, nk), ctx in items:
                if str(t or "").strip().upper() != tri:
                    continue
                if roster_keys and str(nk or "") not in roster_keys:
                    continue
                if not isinstance(ctx, dict):
                    continue
                st_raw = ctx.get("injury_status")
                st = str(st_raw or "").strip().upper()
                is_out = (st == "OUT") or (ctx.get("playing_today") is False)
                if not is_out:
                    continue
                out_rows.append(
                    {
                        "player_name": ctx.get("player_name"),
                        "injury_status": (st_raw if _is_present(st_raw) else ("OUT" if ctx.get("playing_today") is False else None)),
                        "playing_today": ctx.get("playing_today"),
                        "injury": ctx.get("injury"),
                        "injury_date": ctx.get("injury_date"),
                    }
                )
            out_rows.sort(key=lambda r: str(r.get("player_name") or "").strip().upper())
            return out_rows

        injuries_payload = {
            "home": _injury_list_for_team(home_tri),
            "away": _injury_list_for_team(away_tri),
        }

        snapshot_players_summary = None
        if include_players and isinstance(sim_detail_snapshot, dict):
            try:
                snapshot_players = sim_detail_snapshot.get("players") if isinstance(sim_detail_snapshot.get("players"), dict) else {}
                snapshot_missing = sim_detail_snapshot.get("missing_prop_players") if isinstance(sim_detail_snapshot.get("missing_prop_players"), dict) else {}
                snapshot_injuries = sim_detail_snapshot.get("injuries") if isinstance(sim_detail_snapshot.get("injuries"), dict) else {}
                snapshot_summary = sim_detail_snapshot.get("players_summary") if isinstance(sim_detail_snapshot.get("players_summary"), dict) else {}

                current_player_rows = int(len(players_out.get("home") or [])) + int(len(players_out.get("away") or []))
                snapshot_player_rows = int(len(snapshot_players.get("home") or [])) + int(len(snapshot_players.get("away") or []))

                if snapshot_player_rows > current_player_rows:
                    players_out = {
                        "home": [dict(row) for row in (snapshot_players.get("home") or []) if isinstance(row, dict)],
                        "away": [dict(row) for row in (snapshot_players.get("away") or []) if isinstance(row, dict)],
                    }
                    missing_prop_players = {
                        "home": [dict(row) for row in (snapshot_missing.get("home") or []) if isinstance(row, dict)],
                        "away": [dict(row) for row in (snapshot_missing.get("away") or []) if isinstance(row, dict)],
                    }
                    injuries_payload = {
                        "home": [dict(row) for row in (snapshot_injuries.get("home") or []) if isinstance(row, dict)],
                        "away": [dict(row) for row in (snapshot_injuries.get("away") or []) if isinstance(row, dict)],
                    }

                if isinstance(snapshot_summary, dict) and snapshot_summary:
                    snapshot_players_summary = dict(snapshot_summary)
            except Exception:
                snapshot_players_summary = None

        def _fallback_intervals_1m(total_mean: Optional[float]) -> dict[str, Any]:
            tm = 0.0 if total_mean is None else float(total_mean)
            regulation_game_minutes = max(1, int(round(float(getattr(LEAGUE, "regulation_team_minutes", 240.0)) / 5.0)))
            regulation_period_minutes = max(1, int(round(float(getattr(LEAGUE, "regulation_period_seconds", 12 * 60)) / 60.0)))
            # Build a simple regulation ladder. This is a last-resort visualization
            # fallback for historical pages; real SmartSim files should provide richer ladders.
            segs: list[dict[str, Any]] = []
            for i in range(regulation_game_minutes):
                end_min = i + 1
                q = (i // regulation_period_minutes) + 1
                rem = regulation_period_minutes - (i % regulation_period_minutes)
                lab = f"Q{q} {rem}-{rem-1}" if rem >= 1 else f"Q{q}"
                cum = tm * (end_min / regulation_game_minutes) if tm else 0.0
                segs.append(
                    {
                        "label": lab,
                        "quarter": q,
                        "mu": tm / regulation_game_minutes if tm else 0.0,
                        "q": {"p10": None, "p50": None, "p90": None},
                        "cum_mu": cum,
                        "cum_q": {"p10": None, "p50": cum, "p90": None},
                    }
                )
            return {
                "segment_seconds": 60,
                "ot_segment_seconds": 60,
                "segments": segs,
                "segments_per_quarter": regulation_period_minutes,
            }

        def _ensure_intervals(sim_obj: dict[str, Any]) -> tuple[Optional[dict[str, Any]], Optional[dict[str, Any]]]:
            itv = sim_obj.get("intervals") if isinstance(sim_obj.get("intervals"), dict) else None
            itv1 = sim_obj.get("intervals_1m") if isinstance(sim_obj.get("intervals_1m"), dict) else None

            score_obj = sim_obj.get("score") if isinstance(sim_obj.get("score"), dict) else {}
            total_mean = _safe_float((score_obj or {}).get("total_mean"))

            def _has_segs(x: Optional[dict[str, Any]]) -> bool:
                try:
                    return bool(x) and isinstance(x.get("segments"), list) and len(x.get("segments")) > 0
                except Exception:
                    return False

            if not _has_segs(itv1) and total_mean is not None:
                itv1 = _fallback_intervals_1m(total_mean)
            if not _has_segs(itv) and itv1 is not None:
                # If only the 1m ladder exists, let the UI fall back to it.
                itv = itv1
            return itv, itv1

        # Ensure interval ladders exist (historical UI should not go blank).
        _itv, _itv1 = _ensure_intervals(obj)

        # Live Lens polling requires a stable, canonical game_id to join cards -> scoreboard.
        # Some SmartSim JSON files omit "game_id"; fall back to the matchup id (AWAY@HOME).
        sim_game_id = obj.get("game_id")
        if not sim_game_id:
            sim_game_id = f"{away_tri}@{home_tri}"

        sim = {
            "file": fp.name,
            "game_id": sim_game_id,
            "n_sims": obj.get("n_sims"),
            "mode": obj.get("mode"),
            "market": obj.get("market"),
            "context": _slim_cards_sim_context(obj.get("context")),
            "score": obj.get("score"),
            "periods": obj.get("periods"),
            "players_loaded": bool(include_players),
            "players_summary": snapshot_players_summary or {
                "home": int(len(players_out.get("home") or [])),
                "away": int(len(players_out.get("away") or [])),
                "missing_home": int(len(missing_prop_players.get("home") or [])),
                "missing_away": int(len(missing_prop_players.get("away") or [])),
                "injured_home": int(len(injuries_payload.get("home") or [])),
                "injured_away": int(len(injuries_payload.get("away") or [])),
            },
            "error": sim_error,
        }
        if include_sim_ladders:
            sim["intervals"] = _itv
            sim["intervals_1m"] = _itv1
        if include_players:
            sim["players"] = players_out
            sim["missing_prop_players"] = missing_prop_players
            sim["injuries"] = injuries_payload

        # Betting leans (EV uses odds prices if present)
        score = sim.get("score") or {}
        bet = {
            "p_home_win": _safe_float(score.get("p_home_win")),
            "p_home_cover": _safe_float(score.get("p_home_cover")),
            "p_total_over": _safe_float(score.get("p_total_over")),
        }
        bet["p_away_win"] = (1.0 - bet["p_home_win"]) if bet.get("p_home_win") is not None else None
        bet["p_total_under"] = (1.0 - bet["p_total_over"]) if bet.get("p_total_over") is not None else None
        bet["p_away_cover"] = (1.0 - bet["p_home_cover"]) if bet.get("p_home_cover") is not None else None

        # Moneyline EV
        bet["home_ml"] = _safe_float(odds.get("home_ml"))
        bet["away_ml"] = _safe_float(odds.get("away_ml"))
        bet["home_ml_imp"] = _american_to_implied_prob(odds.get("home_ml"))
        bet["away_ml_imp"] = _american_to_implied_prob(odds.get("away_ml"))
        bet["home_ml_ev"] = _ev_from_prob_and_american(bet.get("p_home_win"), odds.get("home_ml"))
        bet["away_ml_ev"] = _ev_from_prob_and_american(bet.get("p_away_win"), odds.get("away_ml"))

        # Spread/total: use quoted price if present; else assume -110 baseline
        hs_price = odds.get("home_spread_price")
        as_price = odds.get("away_spread_price")
        to_price = odds.get("total_over_price")
        tu_price = odds.get("total_under_price")

        bet["home_spread"] = _safe_float(odds.get("home_spread"))
        bet["total"] = _safe_float(odds.get("total"))
        bet["home_spread_ev"] = _ev_from_prob_and_american(bet.get("p_home_cover"), hs_price if hs_price is not None else -110)
        bet["away_spread_ev"] = _ev_from_prob_and_american(bet.get("p_away_cover"), as_price if as_price is not None else -110)
        bet["over_ev"] = _ev_from_prob_and_american(bet.get("p_total_over"), to_price if to_price is not None else -110)
        bet["under_ev"] = _ev_from_prob_and_american(bet.get("p_total_under"), tu_price if tu_price is not None else -110)

        # Unified prop recommendations: betting lines vs SmartSim aggregates.
        # Cards homepage: ROI-optimized defaults for props shown on each game card.
        try:
            raw_mkts = (
                request.args.get("prop_markets")
                or request.args.get("propMarkets")
                or "pts,reb,ast,threes,stl,blk,tov,pra"
            )
            allowed_markets = {m.strip().lower() for m in str(raw_mkts).replace(";", ",").split(",") if m.strip()}
        except Exception:
            allowed_markets = {"pts", "reb", "ast", "threes", "stl", "blk", "tov", "pra"}
        if not allowed_markets:
            allowed_markets = {"pts", "reb", "ast", "threes", "stl", "blk", "tov", "pra"}
        try:
            min_ev_pct = _safe_float(request.args.get("props_min_ev", request.args.get("propsMinEV", "1.0")))
            min_ev_pct = 1.0 if min_ev_pct is None else float(min_ev_pct)
        except Exception:
            min_ev_pct = 1.0
        requested_books = request.args.get("bookmakers")
        if requested_books is None:
            requested_books = request.args.get("books")
        allowed_books = (
            _player_prop_bookmakers_set(requested_books, env_name="PLAYER_PROP_BOOKMAKERS")
            if requested_books is not None and str(requested_books).strip()
            else None
        )
        try:
            exc_raw = (request.args.get("excludeBooks") or request.args.get("exclude_books"))
            s = str(exc_raw or "").strip().lower()
            if not s or s in {"none", "off", "0", "false", "no"}:
                excluded_books = set()
            else:
                excluded_books = {_canonical_bookmaker_key(x) for x in s.split(",") if _canonical_bookmaker_key(x)}
        except Exception:
            excluded_books = set()
        if allowed_books and excluded_books:
            allowed_books = {bk for bk in allowed_books if bk not in excluded_books}

        def _enrich_cards_prop_recommendations(prop_rows_by_side: dict[str, list[dict[str, Any]]] | None) -> None:
            for side_key, team_tri in (("home", home_tri), ("away", away_tri)):
                rows = prop_rows_by_side.get(side_key) if isinstance(prop_rows_by_side, dict) else []
                if not isinstance(rows, list):
                    continue
                for row in rows:
                    try:
                        if not isinstance(row, dict):
                            continue
                        player_name = str(row.get("player") or "").strip()
                        player_pred = None
                        if player_name and isinstance(best_bets_prop_prediction_lookup, dict):
                            player_pred = best_bets_prop_prediction_lookup.get((_norm_player_name(player_name), str(team_tri or "").strip().upper()))
                        _flatten_prop_recommendation_row(
                            row,
                            team_tri=team_tri,
                            home_tri=home_tri,
                            away_tri=away_tri,
                            date_str=d,
                            player_sim=(player_pred if isinstance(player_pred, dict) else None),
                        )

                        best = row.get("best") if isinstance(row.get("best"), dict) else None
                        if not isinstance(best, dict):
                            effective_pick = _season_betting_card_effective_prop_row(row)
                            if isinstance(effective_pick, dict) and effective_pick:
                                row["best"] = dict(effective_pick)
                                best = row["best"]

                        if isinstance(best, dict):
                            player_name = str(row.get("player") or best.get("player") or best.get("player_name") or "").strip()
                            player_key = _norm_player_name(player_name)
                            source_row = props_recs_source_lookup.get((str(team_tri or "").strip().upper(), player_key))
                            support_fields = _prop_source_support_fields(
                                source_row,
                                market=str(best.get("market") or ""),
                                side=str(best.get("side") or ""),
                                line=_safe_float(best.get("line")),
                            )
                            reason_payload = _decorate_prop_recommendation_payload(
                                player_name=player_name,
                                team_tri=team_tri,
                                top_play=best,
                                date_str=d,
                                prop_prediction_lookup=best_bets_prop_prediction_lookup,
                                game_context=best_bets_game_context,
                                injury_snapshot=best_bets_injury_snapshot,
                                slate_total_median=best_bets_slate_total_median,
                                support_fields=support_fields,
                            )
                            if isinstance(reason_payload, dict):
                                row.update(reason_payload)
                                row["top_play_reasons"] = list(reason_payload.get("top_play_reasons") or reason_payload.get("reasons") or [])
                                best["reasons"] = list(reason_payload.get("reasons") or [])
                                for key in ("basketball_summary", "basketball_reasons", "model_reasons", "market_reasons"):
                                    value = reason_payload.get(key)
                                    if isinstance(value, list):
                                        best[key] = list(value)
                                    elif value is not None:
                                        best[key] = value

                        _attach_recon_to_prop_recommendation(row, team_tri)
                    except Exception:
                        continue

        prop_recommendations_snapshot = cards_prop_recommendations_index.get((home_tri, away_tri)) if props_source in {"auto", "snapshot"} else None
        use_source_prop_recommendations = (
            props_source == "source"
            or (game_started and props_source != "runtime" and not isinstance(prop_recommendations_snapshot, dict))
            or (props_source == "auto" and not game_started and not isinstance(prop_recommendations_snapshot, dict))
        )
        started_source_prop_fallback = None
        if use_source_prop_recommendations:
            prop_recommendations = _build_cards_prop_recommendations_from_source(
                props_recs_by_team,
                home_tri=home_tri,
                away_tri=away_tri,
                date_str=d,
            )
            built_home = len(prop_recommendations.get("home") or []) if isinstance(prop_recommendations, dict) else 0
            built_away = len(prop_recommendations.get("away") or []) if isinstance(prop_recommendations, dict) else 0
            if props_source != "source" and built_home <= 0 and built_away <= 0 and isinstance(prop_recommendations_snapshot, dict):
                prop_recommendations = {
                    "home": [dict(row) for row in (prop_recommendations_snapshot.get("home") or []) if isinstance(row, dict)],
                    "away": [dict(row) for row in (prop_recommendations_snapshot.get("away") or []) if isinstance(row, dict)],
                }
            elif props_source == "auto" and built_home <= 0 and built_away <= 0:
                prop_recommendations = _sim_vs_line_prop_recommendations(
                    players_out,
                    props_recs_by_team,
                    home_tri=home_tri,
                    away_tri=away_tri,
                    topn_per_side=6,
                    allowed_markets=allowed_markets,
                    allowed_books=allowed_books,
                    min_ev_pct=min_ev_pct,
                    excluded_books=excluded_books,
                )
        elif isinstance(prop_recommendations_snapshot, dict):
            prop_recommendations = {
                "home": [dict(row) for row in (prop_recommendations_snapshot.get("home") or []) if isinstance(row, dict)],
                "away": [dict(row) for row in (prop_recommendations_snapshot.get("away") or []) if isinstance(row, dict)],
            }
        else:
            prop_recommendations = _sim_vs_line_prop_recommendations(
                players_out,
                props_recs_by_team,
                home_tri=home_tri,
                away_tri=away_tri,
                topn_per_side=6,
                allowed_markets=allowed_markets,
                allowed_books=allowed_books,
                min_ev_pct=min_ev_pct,
                excluded_books=excluded_books,
            )

        try:
            _enrich_cards_prop_recommendations(prop_recommendations)
        except Exception:
            pass

        if game_started and use_source_prop_recommendations and isinstance(prop_recommendations, dict):
            started_source_prop_fallback = {
                "home": [dict(row) for row in (prop_recommendations.get("home") or []) if isinstance(row, dict)],
                "away": [dict(row) for row in (prop_recommendations.get("away") or []) if isinstance(row, dict)],
            }

        try:
            snapshot_picks = cards_prop_snapshot_index.get((home_tri, away_tri)) or []
            _apply_cards_prop_recommendation_buckets(
                prop_recommendations,
                snapshot_picks=snapshot_picks,
            )
            for side_key in ("home", "away"):
                rows = prop_recommendations.get(side_key) if isinstance(prop_recommendations, dict) else []
                if not isinstance(rows, list):
                    continue
                prop_recommendations[side_key] = [
                    row for row in rows
                    if isinstance(row, dict) and str(row.get("card_bucket") or "").strip().lower() in {"official", "playable"}
                ]
            if (
                game_started
                and use_source_prop_recommendations
                and isinstance(started_source_prop_fallback, dict)
                and not any(prop_recommendations.get(side_key) for side_key in ("home", "away"))
            ):
                playable_rank = 0
                prop_recommendations = {
                    "home": [dict(row) for row in (started_source_prop_fallback.get("home") or []) if isinstance(row, dict)],
                    "away": [dict(row) for row in (started_source_prop_fallback.get("away") or []) if isinstance(row, dict)],
                }
                for side_key in ("home", "away"):
                    rows = prop_recommendations.get(side_key) if isinstance(prop_recommendations, dict) else []
                    if not isinstance(rows, list):
                        continue
                    for row in rows:
                        if not isinstance(row, dict):
                            continue
                        playable_rank += 1
                        row["card_bucket"] = "playable"
                        row["card_rank"] = playable_rank
        except Exception:
            pass

        try:
            game_market_recommendations = _build_cards_game_market_recommendations(
                date_str=d,
                home_name=home_name,
                away_name=away_name,
                home_tri=home_tri,
                away_tri=away_tri,
                bet=bet,
                game_context=best_bets_game_context,
                injury_snapshot=best_bets_injury_snapshot,
                slate_total_median=best_bets_slate_total_median,
                raw_rows=cards_game_recommendations_index.get((home_tri, away_tri)) or [],
                allow_pregame_updates=not game_started,
            )
            actual_game_row = recon_games_map.get((home_tri, away_tri)) if isinstance(recon_games_map, dict) else None
            if not isinstance(actual_game_row, dict):
                actual_game_row = finals_lookup.get((home_tri, away_tri)) if isinstance(finals_lookup, dict) else None
            if isinstance(actual_game_row, dict):
                for rec_row in game_market_recommendations:
                    if not isinstance(rec_row, dict):
                        continue
                    _attach_recon_to_game_market_recommendation(
                        rec_row,
                        home_tri=home_tri,
                        away_tri=away_tri,
                        home_name=home_name,
                        away_name=away_name,
                        odds_row=odds if isinstance(odds, dict) else None,
                        actual_row=actual_game_row,
                    )
        except Exception:
            game_market_recommendations = []

        pregame_prior = _live_pregame_prior_for_matchup(
            best_bets_game_context,
            home=home_name or home_tri,
            away=away_name or away_tri,
        )

        try:
            rec_index = _build_boxscore_prop_recommendation_index(prop_recommendations)
            _apply_boxscore_prop_recommendation_markers(players_out.get("home") or [], home_tri, rec_index)
            _apply_boxscore_prop_recommendation_markers(players_out.get("away") or [], away_tri, rec_index)
            _apply_boxscore_prop_recommendation_markers(missing_prop_players.get("home") or [], home_tri, rec_index)
            _apply_boxscore_prop_recommendation_markers(missing_prop_players.get("away") or [], away_tri, rec_index)
        except Exception:
            pass

        try:
            missing_bits: list[str] = []
            for side_key, tri in (("away", away_tri), ("home", home_tri)):
                rows = missing_prop_players.get(side_key) if isinstance(missing_prop_players, dict) else []
                rows = rows if isinstance(rows, list) else []
                if not rows:
                    continue
                names = [str(row.get("player_name") or "").strip() for row in rows if str(row.get("player_name") or "").strip()]
                if not names:
                    continue
                preview = ", ".join(names[:5])
                suffix = "" if len(names) <= 5 else f", +{len(names) - 5} more"
                missing_bits.append(f"{tri}: {preview}{suffix}")
        except Exception:
            missing_bits = []

        live_status = None
        live_state = None
        if isinstance(matchup_live, dict):
            home_score = _safe_int(matchup_live.get("home_pts"))
            away_score = _safe_int(matchup_live.get("away_pts"))
            live_status = {
                "game_id": str(matchup_live.get("game_id") or "").strip() or None,
                "status": str(matchup_live.get("status") or "").strip() or None,
                "is_live": bool(matchup_live.get("in_progress")),
                "is_final": bool(matchup_live.get("final")),
                "in_progress": bool(matchup_live.get("in_progress")),
                "final": bool(matchup_live.get("final")),
                "period": _safe_int(matchup_live.get("period")),
                "clock": str(matchup_live.get("clock") or "").strip() or None,
                "home_score": home_score,
                "away_score": away_score,
                "score": {
                    "home": home_score,
                    "away": away_score,
                },
                "periods": [dict(row) for row in (matchup_live.get("periods") or []) if isinstance(row, dict)],
            }
            live_state = {
                "game_id": live_status.get("game_id"),
                "status": live_status.get("status"),
                "period": live_status.get("period"),
                "clock": live_status.get("clock"),
                "in_progress": bool(live_status.get("in_progress")),
                "final": bool(live_status.get("final")),
                "home_pts": home_score,
                "away_pts": away_score,
                "periods": [dict(row) for row in (live_status.get("periods") or []) if isinstance(row, dict)],
            }

        game = {
            "date": d,
            "home_tri": home_tri,
            "away_tri": away_tri,
            "home_name": home_name,
            "away_name": away_name,
            "home_logo": _wnba_logo_url(home_tri),
            "away_logo": _wnba_logo_url(away_tri),
            "odds": odds,
            "sim": sim,
            "betting": bet,
            "live_status": live_status,
            "live_state": live_state,
            "prop_recommendations": prop_recommendations,
            "game_market_recommendations": game_market_recommendations,
            "plays_locked": bool(game_started),
        }
        if isinstance(pregame_prior, dict):
            sim_context = sim.get("context") if isinstance(sim.get("context"), dict) else {}
            sim_context = dict(sim_context)
            sim_context["pregame_prior"] = pregame_prior
            sim["context"] = sim_context
        if missing_bits and not sim_error:
            game.setdefault("warnings", [])
            game["warnings"].append("Players with prop lines missing from SmartSim boxscore: " + " • ".join(missing_bits))

        # Boxscore reconciliation (player-sum vs actual final team points, when available).
        try:
            bs = _boxscore_reconcile_points(sim.get("game_id"), home_tri, away_tri)
            if bs:
                game["boxscore_recon"] = bs
                if bs.get("ok") is False and bs.get("reason") not in {"missing_boxscore"}:
                    game.setdefault("warnings", [])
                    game["warnings"].append(
                        f"Boxscore recon mismatch: {home_tri} pts(players)={bs.get('home_pts_players')} vs actual={bs.get('home_pts_actual')}; "
                        f"{away_tri} pts(players)={bs.get('away_pts_players')} vs actual={bs.get('away_pts_actual')}"
                    )
        except Exception:
            pass
        game["writeup"] = _matchup_writeup(game)

        try:
            sim_context = sim.get("context") if isinstance(sim.get("context"), dict) else {}
            if str(sim_context.get("fallback_reason") or "").strip().lower() == "missing_smart_sim":
                game.setdefault("warnings", [])
                game["warnings"].append("Using predictions fallback because SmartSim artifact is missing for this matchup.")
        except Exception:
            pass

        if sim_error:
            try:
                game.setdefault("warnings", [])
                game["warnings"].append(f"SmartSim error for {home_tri}-{away_tri}: {sim_error}")
            except Exception:
                pass

        # Debug/guardrail: surface large market-vs-sim disagreement
        try:
            market_spread = _safe_float((sim.get("market") or {}).get("market_home_spread"))
            sim_margin = _safe_float((sim.get("score") or {}).get("margin_mean"))
            if market_spread is not None and sim_margin is not None:
                # If home is +7, market expects margin about -7.
                market_margin = -float(market_spread)
                if abs(sim_margin - market_margin) >= 12.0:
                    game.setdefault("warnings", [])
                    game["warnings"].append(
                        f"Large market-vs-sim disagreement: market margin ~{market_margin:+.1f}, sim margin {sim_margin:+.1f}"
                    )
        except Exception:
            pass

        games.append(game)

    # Stable order by start time if odds has commence_time
    def _sort_key(g: dict[str, Any]):
        try:
            ct = (g.get("odds") or {}).get("commence_time")
            return str(ct or "")
        except Exception:
            return ""

    games.sort(key=_sort_key)

    try:
        pregame_portfolio = _apply_pregame_card_portfolio(games)
    except Exception:
        pregame_portfolio = {"enabled": False, "selected": 0, "candidates": 0}

    return jsonify(
        _to_jsonable(
            {
                "date": d,
                "requested_date": requested_date,
                "lookahead_applied": bool(d != requested_date),
                "players_included": bool(include_players),
                "pregame_portfolio": pregame_portfolio,
                "games": games,
            }
        )
    )


@app.route("/api/cards/sim-detail")
def api_cards_sim_detail():
    d = _parse_date_param(request)
    if not d:
        return jsonify({"error": "missing date"}), 400

    home_tri = str(_get_tricode(request.args.get("home")) or request.args.get("home") or "").strip().upper()
    away_tri = str(_get_tricode(request.args.get("away")) or request.args.get("away") or "").strip().upper()
    if not home_tri or not away_tri:
        return jsonify({"error": "missing home/away"}), 400

    detail_index = _load_cards_sim_detail_index(d)
    detail = detail_index.get((home_tri, away_tri)) if isinstance(detail_index, dict) else None
    if isinstance(detail, dict):
        return jsonify(
            _to_jsonable(
                {
                    "date": d,
                    "requested_date": d,
                    "players_included": True,
                    "games": [
                        {
                            "home_tri": home_tri,
                            "away_tri": away_tri,
                            "sim": {
                                "players_loaded": True,
                                "players_summary": dict(detail.get("players_summary") or {}),
                                "players": {
                                    "home": [dict(row) for row in (detail.get("players", {}).get("home") or []) if isinstance(row, dict)],
                                    "away": [dict(row) for row in (detail.get("players", {}).get("away") or []) if isinstance(row, dict)],
                                },
                                "missing_prop_players": {
                                    "home": [dict(row) for row in (detail.get("missing_prop_players", {}).get("home") or []) if isinstance(row, dict)],
                                    "away": [dict(row) for row in (detail.get("missing_prop_players", {}).get("away") or []) if isinstance(row, dict)],
                                },
                                "injuries": {
                                    "home": [dict(row) for row in (detail.get("injuries", {}).get("home") or []) if isinstance(row, dict)],
                                    "away": [dict(row) for row in (detail.get("injuries", {}).get("away") or []) if isinstance(row, dict)],
                                },
                            },
                        }
                    ],
                }
            )
        )

    with app.test_request_context(f"/api/cards?date={d}&home={home_tri}&away={away_tri}&include_players=1"):
        return api_cards()


@app.route("/api/cards/props-strip")
def api_cards_props_strip():
    d = _parse_date_param(request)
    if not d:
        return jsonify({"error": "missing date"}), 400

    try:
        limit = int(float(str(request.args.get("limit") or "12").strip()))
    except Exception:
        limit = 12
    try:
        per_game_limit = int(float(str(request.args.get("per_game_limit") or "2").strip()))
    except Exception:
        per_game_limit = 2
    limit = max(1, min(24, limit))
    per_game_limit = max(1, min(4, per_game_limit))

    def _select_props_strip_items(candidates: list[dict[str, Any]]) -> list[dict[str, Any]]:
        candidates.sort(
            key=lambda item: (
                float(item.get("ev_pct") or float("-inf")),
                float(item.get("edge") or float("-inf")),
                float(item.get("score_adj") or item.get("score") or float("-inf")),
            ),
            reverse=True,
        )

        selected_items: list[dict[str, Any]] = []
        by_game_counts: dict[str, int] = {}
        for item in candidates:
            game_key = str(item.get("game_key") or "")
            if game_key and by_game_counts.get(game_key, 0) >= per_game_limit:
                continue
            selected_items.append(item)
            if game_key:
                by_game_counts[game_key] = int(by_game_counts.get(game_key, 0) + 1)
            if len(selected_items) >= limit:
                break
        return selected_items

    def _build_snapshot_items() -> tuple[list[dict[str, Any]], int]:
        snapshot = _load_props_recommendations_top_by_game_snapshot(d) or {}
        top_by_game = snapshot.get("top_by_game") if isinstance(snapshot.get("top_by_game"), list) else []
        pred_lookup = _load_props_predictions_name_lookup(d)

        items: list[dict[str, Any]] = []
        for game in top_by_game:
            if not isinstance(game, dict):
                continue
            home_tri = str(game.get("home_tricode") or "").strip().upper()
            away_tri = str(game.get("away_tricode") or "").strip().upper()
            game_key = f"{away_tri}@{home_tri}" if home_tri and away_tri else ""
            picks = game.get("picks") if isinstance(game.get("picks"), list) else []
            for pick in picks:
                if not isinstance(pick, dict):
                    continue
                player_name = str(pick.get("player") or "").strip()
                team_tri = str(pick.get("team_tricode") or pick.get("team") or "").strip().upper()
                top_play = pick.get("top_play") if isinstance(pick.get("top_play"), dict) else {}
                if not player_name or not team_tri or not isinstance(top_play, dict):
                    continue
                player_pred = pred_lookup.get((team_tri, _norm_player_name(player_name))) or {}
                opponent_tri = away_tri if team_tri == home_tri else home_tri
                player_id = player_pred.get("player_id")
                photo = _best_player_headshot_url(nba_player_id=player_id, source_player_id=player_id)
                items.append(
                    {
                        "game_key": game_key,
                        "home_tri": home_tri,
                        "away_tri": away_tri,
                        "team_tri": team_tri,
                        "opponent_tri": opponent_tri,
                        "player": player_name,
                        "player_id": player_id,
                        "photo": photo,
                        "market": str(top_play.get("market") or "").strip().lower(),
                        "side": str(top_play.get("side") or "").strip().upper(),
                        "line": _safe_float(top_play.get("line")),
                        "price": _safe_float(top_play.get("price")),
                        "edge": _safe_float(top_play.get("edge")),
                        "ev": _safe_float(top_play.get("ev")),
                        "ev_pct": _safe_float(top_play.get("ev_pct")),
                        "prob_calib": _safe_float(top_play.get("prob_calib")),
                        "line_move": _safe_float(top_play.get("line_move")),
                        "open_line": _safe_float(top_play.get("open_line")),
                        "open_price": _safe_float(top_play.get("open_price")),
                        "book": _canonical_bookmaker_key(top_play.get("book")) or None,
                        "snapshot_ts": top_play.get("snapshot_ts"),
                        "score": _safe_float(pick.get("score")),
                        "score_adj": _safe_float(pick.get("score_adj")),
                        "tier": str(pick.get("tier") or "").strip() or None,
                        "opponent": str(pick.get("opponent") or "").strip() or None,
                    }
                )
        snapshot_rows = int(snapshot.get("rows") or 0) if isinstance(snapshot, dict) else 0
        return items, snapshot_rows

    def _response_json_value(resp: Any) -> tuple[dict[str, Any] | None, int | None]:
        response_obj = resp
        status_code = None
        if isinstance(resp, tuple):
            if resp:
                response_obj = resp[0]
            if len(resp) >= 2:
                try:
                    status_code = int(resp[1])
                except Exception:
                    status_code = None
        try:
            if hasattr(response_obj, "status_code"):
                status_code = int(getattr(response_obj, "status_code"))
        except Exception:
            pass
        payload_obj = None
        try:
            if hasattr(response_obj, "get_json"):
                payload_obj = response_obj.get_json(silent=True)
        except Exception:
            payload_obj = None
        if isinstance(payload_obj, dict):
            return payload_obj, status_code
        return None, status_code

    def _build_cards_fallback_items() -> list[dict[str, Any]]:
        try:
            with app.test_request_context(f"/api/props?date={d}&sortBy=ev_desc&onlyEV=1&minEV=0"):
                payload_obj, status_code = _response_json_value(api_props())
        except Exception:
            payload_obj, status_code = None, None
        if status_code and status_code >= 400:
            return []
        rows = payload_obj.get("rows") if isinstance(payload_obj, dict) and isinstance(payload_obj.get("rows"), list) else []
        if not rows and isinstance(payload_obj, dict) and isinstance(payload_obj.get("data"), list):
            rows = payload_obj.get("data")
        items: list[dict[str, Any]] = []
        seen_players: set[tuple[str, str]] = set()
        for row in rows:
            if not isinstance(row, dict):
                continue
            player_name = str(row.get("player") or row.get("player_name") or "").strip()
            team_tri = str(row.get("team_tricode") or row.get("team") or "").strip().upper()
            if not player_name or not team_tri:
                continue
            dedupe_key = (team_tri, _norm_player_name(player_name))
            if dedupe_key in seen_players:
                continue
            seen_players.add(dedupe_key)
            home_tri = str(_get_tricode(str(row.get("home_team") or "")) or row.get("home_team") or "").strip().upper()
            away_tri = str(_get_tricode(str(row.get("away_team") or "")) or row.get("away_team") or "").strip().upper()
            game_key = f"{away_tri}@{home_tri}" if home_tri and away_tri else ""
            side = str(row.get("side") or "").strip().upper()
            market = str(row.get("stat") or row.get("market") or "").strip().lower()
            if side not in {"OVER", "UNDER"} or not market:
                continue
            player_id = row.get("player_id")
            opponent_tri = away_tri if team_tri == home_tri else home_tri
            ev_val = _safe_float(row.get("ev"))
            photo = _best_player_headshot_url(
                nba_player_id=player_id,
                source_player_id=player_id,
            )
            items.append(
                {
                    "game_key": game_key,
                    "home_tri": home_tri,
                    "away_tri": away_tri,
                    "team_tri": team_tri,
                    "opponent_tri": opponent_tri,
                    "player": player_name,
                    "player_id": player_id,
                    "photo": photo,
                    "market": market,
                    "side": side,
                    "line": _safe_float(row.get("line")),
                    "price": _safe_float(row.get("price")),
                    "edge": _safe_float(row.get("edge")),
                    "ev": ev_val,
                    "ev_pct": (float(ev_val) * 100.0) if ev_val is not None else None,
                    "prob_calib": _safe_float(row.get("model_prob")),
                    "line_move": _safe_float(row.get("line_move")),
                    "open_line": _safe_float(row.get("open_line")),
                    "open_price": _safe_float(row.get("open_price")),
                    "book": _canonical_bookmaker_key(row.get("bookmaker") or row.get("book") or row.get("bookmaker_title")) or None,
                    "snapshot_ts": row.get("snapshot_ts"),
                    "score": ev_val,
                    "score_adj": ev_val,
                    "tier": None,
                    "opponent": str(opponent_tri or "").strip() or None,
                }
            )
        return items

    live_props_price_lookup_exact: dict[tuple[str, str, str, str, float], dict[str, Any]] | None = None
    live_props_price_lookup_loose: dict[tuple[str, str, str, str], dict[str, Any]] | None = None

    def _price_lookup_key(team_tri: Any, player_name: Any, market: Any, side: Any) -> tuple[str, str, str, str] | None:
        team_key = str(team_tri or "").strip().upper()
        player_key = _norm_player_name(player_name)
        market_key = str(market or "").strip().lower()
        side_key = str(side or "").strip().upper()
        if not team_key or not player_key or not market_key or side_key not in {"OVER", "UNDER"}:
            return None
        return (team_key, player_key, market_key, side_key)

    def _price_lookup_key_exact(team_tri: Any, player_name: Any, market: Any, side: Any, line: Any) -> tuple[str, str, str, str, float] | None:
        base_key = _price_lookup_key(team_tri, player_name, market, side)
        line_val = _safe_float(line)
        if base_key is None or line_val is None:
            return None
        return (*base_key, round(float(line_val), 4))

    def _register_live_prop_price(
        exact_lookup: dict[tuple[str, str, str, str, float], dict[str, Any]],
        loose_lookup: dict[tuple[str, str, str, str], dict[str, Any]],
        *,
        team_tri: Any,
        player_name: Any,
        market: Any,
        side: Any,
        line: Any,
        price: Any,
        book: Any,
    ) -> None:
        loose_key = _price_lookup_key(team_tri, player_name, market, side)
        if loose_key is None:
            return
        entry = {"price": _safe_float(price), "book": _canonical_bookmaker_key(book) or None}
        if entry["price"] is None and not entry["book"]:
            return
        exact_key = _price_lookup_key_exact(team_tri, player_name, market, side, line)
        if exact_key is not None:
            prev_exact = exact_lookup.get(exact_key) or {}
            exact_lookup[exact_key] = {
                "price": entry["price"] if entry["price"] is not None else prev_exact.get("price"),
                "book": entry["book"] or prev_exact.get("book"),
            }
        prev_loose = loose_lookup.get(loose_key) or {}
        loose_lookup[loose_key] = {
            "price": entry["price"] if entry["price"] is not None else prev_loose.get("price"),
            "book": entry["book"] or prev_loose.get("book"),
        }

    def _get_live_prop_price_lookups() -> tuple[dict[tuple[str, str, str, str, float], dict[str, Any]], dict[tuple[str, str, str, str], dict[str, Any]]]:
        nonlocal live_props_price_lookup_exact, live_props_price_lookup_loose
        if live_props_price_lookup_exact is not None and live_props_price_lookup_loose is not None:
            return live_props_price_lookup_exact, live_props_price_lookup_loose

        exact_lookup: dict[tuple[str, str, str, str, float], dict[str, Any]] = {}
        loose_lookup: dict[tuple[str, str, str, str], dict[str, Any]] = {}

        snapshot_items_all, _ = _build_snapshot_items()
        for item in snapshot_items_all:
            if not isinstance(item, dict):
                continue
            _register_live_prop_price(
                exact_lookup,
                loose_lookup,
                team_tri=item.get("team_tri"),
                player_name=item.get("player"),
                market=item.get("market"),
                side=item.get("side"),
                line=item.get("line"),
                price=item.get("price"),
                book=item.get("book"),
            )

        try:
            with app.test_request_context(f"/api/props?date={d}"):
                payload_obj, status_code = _response_json_value(api_props())
        except Exception:
            payload_obj, status_code = None, None
        if not status_code or status_code < 400:
            rows = payload_obj.get("rows") if isinstance(payload_obj, dict) and isinstance(payload_obj.get("rows"), list) else []
            if not rows and isinstance(payload_obj, dict) and isinstance(payload_obj.get("data"), list):
                rows = payload_obj.get("data")
            for row in rows:
                if not isinstance(row, dict):
                    continue
                _register_live_prop_price(
                    exact_lookup,
                    loose_lookup,
                    team_tri=row.get("team_tricode") or row.get("team"),
                    player_name=row.get("player") or row.get("player_name"),
                    market=row.get("market") or row.get("stat"),
                    side=row.get("side"),
                    line=row.get("line"),
                    price=row.get("price"),
                    book=row.get("bookmaker") or row.get("book") or row.get("bookmaker_title"),
                )

        live_props_price_lookup_exact = exact_lookup
        live_props_price_lookup_loose = loose_lookup
        return exact_lookup, loose_lookup

    def _lookup_live_prop_price(team_tri: Any, player_name: Any, market: Any, side: Any, line: Any) -> dict[str, Any]:
        exact_lookup, loose_lookup = _get_live_prop_price_lookups()
        exact_key = _price_lookup_key_exact(team_tri, player_name, market, side, line)
        if exact_key is not None:
            exact_entry = exact_lookup.get(exact_key)
            if isinstance(exact_entry, dict) and (exact_entry.get("price") is not None or exact_entry.get("book")):
                return exact_entry
        loose_key = _price_lookup_key(team_tri, player_name, market, side)
        if loose_key is not None:
            loose_entry = loose_lookup.get(loose_key)
            if isinstance(loose_entry, dict) and (loose_entry.get("price") is not None or loose_entry.get("book")):
                return loose_entry
        return {}

    def _build_live_fallback_payload() -> dict[str, Any] | None:
        try:
            with app.test_request_context(f"/api/live_player_lens?date={d}"):
                payload_obj, status_code = _response_json_value(api_live_player_lens())
        except Exception:
            payload_obj, status_code = None, None
        if status_code and status_code >= 400:
            return None
        games = payload_obj.get("games") if isinstance(payload_obj, dict) and isinstance(payload_obj.get("games"), list) else []
        items: list[dict[str, Any]] = []
        for game in games:
            if not isinstance(game, dict):
                continue
            status = game.get("status") if isinstance(game.get("status"), dict) else {}
            rows = game.get("rows") if isinstance(game.get("rows"), list) else []
            game_items = []
            for row in rows:
                if not isinstance(row, dict):
                    continue
                if not row.get("player") or not row.get("team_tri"):
                    continue
                line_source = str(row.get("line_source") or "").strip().lower()
                if not line_source or line_source == "model":
                    continue
                side = str(row.get("ev_side") or row.get("lean") or "").strip().upper()
                if side not in {"OVER", "UNDER"}:
                    continue
                ev_val = _safe_float(row.get("ev"))
                ev_pct = (float(ev_val) * 100.0) if ev_val is not None else None
                line_value = _safe_float(row.get("line_live") if row.get("line_live") is not None else row.get("line"))
                price = _safe_float(row.get("price_under")) if side == "UNDER" else _safe_float(row.get("price_over"))
                book = _canonical_bookmaker_key(row.get("book")) or None
                if price is None or not book:
                    fallback_price = _lookup_live_prop_price(
                        row.get("team_tri"),
                        row.get("player"),
                        row.get("stat"),
                        side,
                        line_value,
                    )
                    if price is None:
                        price = _safe_float(fallback_price.get("price"))
                    if not book:
                        book = _canonical_bookmaker_key(fallback_price.get("book")) or None
                period = _safe_int(status.get("period"))
                clock = str(status.get("clock") or "").strip()
                if bool(status.get("final")):
                    status_label = "Final"
                elif bool(status.get("in_progress")):
                    status_label = f"Q{period or '-'} {clock}".strip()
                else:
                    status_label = "Live"
                game_items.append(
                    {
                        "game_key": f"{str(game.get('away') or '').strip().upper()}@{str(game.get('home') or '').strip().upper()}",
                        "away_tri": str(game.get("away") or "").strip().upper(),
                        "home_tri": str(game.get("home") or "").strip().upper(),
                        "team_tri": str(row.get("team_tri") or "").strip().upper(),
                        "opponent_tri": str((game.get("away") if str(row.get("team_tri") or "").strip().upper() == str(game.get("home") or "").strip().upper() else game.get("home")) or "").strip().upper(),
                        "player": str(row.get("player") or "").strip(),
                        "player_id": row.get("player_id"),
                        "photo": _best_player_headshot_url(photo=row.get("player_photo"), nba_player_id=row.get("player_id"), source_player_id=row.get("player_id")),
                        "market": str(row.get("stat") or "").strip().lower(),
                        "side": side,
                        "line": line_value,
                        "price": price,
                        "book": book,
                        "edge": ev_val,
                        "ev": ev_val,
                        "ev_pct": ev_pct,
                        "probability": _safe_float(row.get("win_prob")),
                        "klass": str(row.get("klass") or "").strip().upper() or None,
                        "line_source": line_source,
                        "status_label": status_label,
                        "actual": _safe_float(row.get("actual")),
                        "pace_proj": _safe_float(row.get("pace_proj")),
                        "pace_vs_line": _safe_float(row.get("pace_vs_line")),
                        "sim_mu": _safe_float(row.get("sim_mu")),
                        "sim_mu_adjusted": _safe_float(row.get("sim_mu_adjusted")),
                        "sim_vs_line": _safe_float(row.get("sim_vs_line")),
                        "sim_vs_line_adjusted": _safe_float(row.get("sim_vs_line_adjusted")),
                        "score_adj": _safe_float(row.get("bettable_score") or row.get("strength") or ev_val),
                        "first_seen_at": row.get("first_seen_at"),
                        "last_seen_at": row.get("last_seen_at"),
                    }
                )
            game_items.sort(
                key=lambda item: (
                    float(item.get("score_adj") or float("-inf")),
                    float(item.get("ev") or float("-inf")),
                    float(item.get("probability") or float("-inf")),
                ),
                reverse=True,
            )
            items.extend(game_items[:per_game_limit])

        selected_items = _select_props_strip_items(items)
        if not selected_items:
            return None
        return {
            "ok": True,
            "mode": "live",
            "date": d,
            "title": "Live player props",
            "subtitle": "Best current live player-prop rows from the live lens.",
            "items": selected_items,
            "rows": len(selected_items),
            "source": "live_player_lens",
        }

    snapshot_items, snapshot_rows = _build_snapshot_items()
    selected = _select_props_strip_items(snapshot_items)
    payload = {
        "ok": True,
        "mode": "pregame",
        "date": d,
        "title": "Pregame prop movement",
        "subtitle": "Top same-day prop cards from the daily recommendations export.",
        "items": selected,
        "rows": len(selected),
        "source": "props_recommendations_top_by_game",
        "snapshot_rows": snapshot_rows,
    }

    if not selected:
        cards_items = _build_cards_fallback_items()
        selected = _select_props_strip_items(cards_items)
        if selected:
            payload = {
                "ok": True,
                "mode": "pregame",
                "date": d,
                "title": "Pregame prop movement",
                "subtitle": "Top same-day prop cards from the current slate payload.",
                "items": selected,
                "rows": len(selected),
                "source": "api_props_fallback",
                "snapshot_rows": snapshot_rows,
            }

    live_payload = _build_live_fallback_payload()
    if live_payload:
        return jsonify(_to_jsonable(live_payload))

    return jsonify(
        _to_jsonable(
            payload
        )
    )


def _recommendations_summary():
    """Aggregate reconciliation-adjusted YTD stats for recommendations.

    Query params:
      - since: YYYY-MM-DD (default: 2025-10-21 opening day)
    - until: YYYY-MM-DD (default: the current US local slate date)
      - spread_edge: float threshold used to generate ATS picks (for recompute if files missing)
      - total_edge: float threshold used to generate TOTAL picks (for recompute if files missing)

    Returns JSON with Overall/High/Medium/Low buckets containing:
      total, resolved, wins, losses, pushes, accuracy_pct, stake_total, profit_total, roi_pct
    """
    try:
        from datetime import datetime
        import json as _json
        since = (request.args.get("since") or "2025-10-21").strip()
        until = (request.args.get("until") or _default_us_slate_date_str()).strip()
        th_spread = float(request.args.get("spread_edge", 1.0))
        th_total = float(request.args.get("total_edge", 1.5))

        # Utilities
        def _parse_date(s: str) -> Optional[datetime]:
            try:
                return datetime.strptime(s, "%Y-%m-%d")
            except Exception:
                return None

        def _american_to_decimal(amer: Any) -> Optional[float]:
            try:
                a = float(amer)
            except Exception:
                return None
            if a > 0:
                return 1.0 + (a / 100.0)
            if a < 0:
                return 1.0 + (100.0 / abs(a))
            return None

        def _tier_for_row(market: str, ev: Any, edge: Any) -> str:
            try:
                if (market or "").upper() == "ML":
                    v = float(ev)
                    if v >= 0.04:
                        return "High"
                    if v >= 0.02:
                        return "Medium"
                    return "Low"
            except Exception:
                pass
            try:
                if (market or "").upper() in {"ATS", "TOTAL"}:
                    e = abs(float(edge))
                    if e >= 4.0:
                        return "High"
                    if e >= 2.0:
                        return "Medium"
                    return "Low"
            except Exception:
                pass
            return "Low"

        # Fast path: serve cached summary if available (only if it matches the requested window + schema)
        try:
            _cache_p = DATA_PROCESSED_DIR / "recommendations_summary.json"
            if _cache_p.exists():
                with open(_cache_p, "r", encoding="utf-8") as fh:
                    cached = _json.load(fh)
                # Optional: basic sanity keys
                if (
                    isinstance(cached, dict)
                    and str(cached.get("version") or "") == "summary-v4-best-edges"
                    and str(cached.get("since") or "").strip() == since
                    and str(cached.get("until") or "").strip() == until
                ):
                    return jsonify(cached)
        except Exception:
            pass

        # Collect dates by existing recommendation files within range
        proc = DATA_PROCESSED_DIR
        ds = _parse_date(since) or datetime.utcnow()
        de = _parse_date(until) or datetime.utcnow()
        if de < ds:
            ds, de = de, ds

        # Discover recommendation exports; support both recommendations_*.csv and picks_*.csv
        rec_files_map = {}
        if proc.exists():
            # Picks exports (tools/recommend_picks.py) — canonicalize to same schema later
            for p in sorted(proc.glob("picks_*.csv")):
                try:
                    dstr = p.stem.replace("picks_", "")
                    d = _parse_date(dstr)
                    if d and ds.date() <= d.date() <= de.date():
                        rec_files_map[dstr] = p
                except Exception:
                    continue
            # Recommendations exports — if present, prefer these over picks for the date
            for p in sorted(proc.glob("recommendations_*.csv")):
                try:
                    dstr = p.stem.replace("recommendations_", "")
                    d = _parse_date(dstr)
                    if d and ds.date() <= d.date() <= de.date():
                        rec_files_map[dstr] = p
                except Exception:
                    continue

            # Best-edges exports — if present, prefer these over recommendations/picks for the date
            for p in sorted(proc.glob("best_edges_games_*.csv")):
                try:
                    dstr = p.stem.replace("best_edges_games_", "")
                    d = _parse_date(dstr)
                    if d and ds.date() <= d.date() <= de.date():
                        rec_files_map[dstr] = p
                except Exception:
                    continue
        rec_files = sorted([(dstr, fp) for dstr, fp in rec_files_map.items()])

        # Stats template per bucket
        def _empty_stats():
            return {
                "total": 0,
                "resolved": 0,
                "wins": 0,
                "losses": 0,
                "pushes": 0,
                "stake_total": 0.0,
                "profit_total": 0.0,
                "accuracy_pct": None,
                "roi_pct": None,
            }

        buckets = {k: _empty_stats() for k in ["Overall", "High", "Medium", "Low"]}
        props_buckets = {k: _empty_stats() for k in ["Overall", "High", "Medium", "Low"]}
        props_dates: list[str] = []
        # PBP-derived markets (metrics + tiered accuracy buckets)
        first_basket_metrics: list[dict] = []
        early_threes_metrics: list[dict] = []
        first_basket_buckets = {k: _empty_stats() for k in ["Overall", "High", "Medium", "Low"]}
        early_threes_buckets = {k: _empty_stats() for k in ["Overall", "High", "Medium", "Low"]}

        # Local tier helper based on probability only (avoid cross-function deps)
        def _tier_from_prob(p):
            try:
                v = float(p)
                if v >= 0.75:
                    return "High"
                if v >= 0.5:
                    return "Medium"
                return "Low"
            except Exception:
                return "Low"

        for dstr, fp in rec_files:
            try:
                rec = pd.read_csv(fp)
            except Exception:
                continue
            # Final scores for this date
            gfin = None
            try:
                gpath = DATA_PROCESSED_DIR / f"recon_games_{dstr}.csv"
                if gpath.exists():
                    gfin = pd.read_csv(gpath)
            except Exception:
                gfin = None
            # Odds for spread/total/ML pricing
            godds = None
            try:
                op = _find_game_odds_for_date(dstr)
                if op is not None:
                    godds = pd.read_csv(op)
            except Exception:
                godds = None

            # Normalize joins
            def _norm(s):
                return (str(s or "").strip())

            # Unified accessors for different export schemas (recommendations_* vs picks_*)
            cols = {c.lower(): c for c in rec.columns}

            def _col(*names):
                for n in names:
                    c = cols.get(str(n).lower())
                    if c:
                        return c
                return None

            home_col = _col("home", "home_team")
            away_col = _col("away", "visitor_team")
            side_col = _col("side", "pick")
            market_col = _col("market")
            ev_col = _col("ev")
            edge_col = _col("edge")
            odds_col = _col("price", "odds")
            prob_col = _col("implied_prob", "prob_adj")

            # Evaluate each recommendation
            for _, r in rec.iterrows():
                try:
                    market = str((r.get(market_col) if market_col else "") or "").upper()
                    side = str((r.get(side_col) if side_col else "") or "").strip()
                    home = _norm(r.get(home_col) if home_col else r.get("home"))
                    away = _norm(r.get(away_col) if away_col else r.get("away"))
                    ev = r.get(ev_col) if ev_col else None
                    edge = r.get(edge_col) if edge_col else None
                    # If EV is missing (common in picks_*), try to compute from probability + odds
                    if (ev is None or pd.isna(ev)) and market == "ML":
                        try:
                            prob = r.get(prob_col) if prob_col else None
                            price = r.get(odds_col) if odds_col else None
                            prob = float(prob) if prob is not None and not pd.isna(prob) else None
                            dec = _american_to_decimal(price) if price is not None and not pd.isna(price) else None
                            if prob is not None and dec is not None:
                                # EV per unit stake
                                ev = (prob * (dec - 1.0)) - ((1.0 - prob) * 1.0)
                        except Exception:
                            ev = None
                    tier = _tier_for_row(market, ev, edge)
                    for key in ("Overall", tier):
                        buckets[key]["total"] += 1

                    # find final row
                    hp = ap = None
                    if isinstance(gfin, pd.DataFrame) and not gfin.empty:
                        try:
                            row = gfin[(gfin.get("home_team").astype(str) == home) & (gfin.get("visitor_team").astype(str) == away)]
                            if row.empty:
                                # try swapped
                                row = gfin[(gfin.get("home_team").astype(str) == away) & (gfin.get("visitor_team").astype(str) == home)]
                            if not row.empty:
                                hp = pd.to_numeric(row.iloc[0].get("home_pts"), errors="coerce")
                                ap = pd.to_numeric(row.iloc[0].get("visitor_pts"), errors="coerce")
                                if pd.isna(hp) or pd.isna(ap):
                                    hp = ap = None
                        except Exception:
                            hp = ap = None

                    resolved = False
                    is_win = False
                    is_push = False
                    stake = 1.0
                    profit = 0.0

                    if market == "ML":
                        if hp is None or ap is None:
                            # unresolved
                            pass
                        else:
                            resolved = True
                            home_won = (float(hp) > float(ap))
                            pick_home = (side == home)
                            # ML odds
                            dec = None
                            if isinstance(godds, pd.DataFrame) and not godds.empty:
                                try:
                                    o = godds[(godds.get("home_team").astype(str) == home) & (godds.get("visitor_team").astype(str) == away)]
                                    if not o.empty:
                                        if pick_home:
                                            dec = _american_to_decimal(o.iloc[0].get("home_ml"))
                                        else:
                                            dec = _american_to_decimal(o.iloc[0].get("away_ml"))
                                except Exception:
                                    dec = None
                            if dec is None:
                                # Fallback to even money
                                dec = 2.0
                            if pick_home == home_won:
                                is_win = True
                                profit = (float(dec) - 1.0) * stake
                            else:
                                profit = -stake

                    elif market in {"ATS", "TOTAL"}:
                        # Need odds lines and finals
                        if isinstance(godds, pd.DataFrame) and not godds.empty and (hp is not None and ap is not None):
                            try:
                                o = godds[(godds.get("home_team").astype(str) == home) & (godds.get("visitor_team").astype(str) == away)]
                                if not o.empty:
                                    dec = None
                                    # Default spread/total price if not available
                                    default_dec = 1.909090909  # -110
                                    if market == "ATS":
                                        hsp = pd.to_numeric(o.iloc[0].get("home_spread"), errors="coerce")
                                        line_home = hsp if pd.notna(hsp) else None
                                        margin = float(hp) - float(ap)
                                        if side == home and line_home is not None:
                                            diff = margin + float(line_home)
                                            is_push = abs(diff) < 1e-9
                                            is_win = diff > 0
                                            try:
                                                sp_price = o.iloc[0].get("home_spread_price")
                                                dec = _american_to_decimal(sp_price) or default_dec
                                            except Exception:
                                                dec = default_dec
                                        elif side == away and line_home is not None:
                                            diff = -margin - float(line_home)
                                            is_push = abs(diff) < 1e-9
                                            is_win = diff > 0
                                            try:
                                                sp_price = o.iloc[0].get("away_spread_price")
                                                dec = _american_to_decimal(sp_price) or default_dec
                                            except Exception:
                                                dec = default_dec
                                    elif market == "TOTAL":
                                        tot = pd.to_numeric(o.iloc[0].get("total"), errors="coerce")
                                        if pd.notna(tot):
                                            pts = float(hp) + float(ap)
                                            if str(side).lower().startswith("o"):
                                                diff = pts - float(tot)
                                                try:
                                                    t_price = o.iloc[0].get("total_over_price")
                                                    dec = _american_to_decimal(t_price) or default_dec
                                                except Exception:
                                                    dec = default_dec
                                            else:
                                                diff = float(tot) - pts
                                                try:
                                                    t_price = o.iloc[0].get("total_under_price")
                                                    dec = _american_to_decimal(t_price) or default_dec
                                                except Exception:
                                                    dec = default_dec
                                            is_push = abs(diff) < 1e-9
                                            is_win = diff > 0
                                    if dec is not None:
                                        resolved = True
                                        if is_push:
                                            profit = 0.0
                                        elif is_win:
                                            profit = (float(dec) - 1.0) * stake
                                        else:
                                            profit = -stake
                            except Exception:
                                pass

                    # Update buckets
                    if resolved:
                        for key in ("Overall", tier):
                            b = buckets[key]
                            b["resolved"] += 1
                            if is_push:
                                b["pushes"] += 1
                            elif is_win:
                                b["wins"] += 1
                            else:
                                b["losses"] += 1
                            b["stake_total"] += stake
                            b["profit_total"] += profit
                except Exception:
                    continue

            # Evaluate props recommendations for the same date using recon_props_*
            # Prefer authoritative props best-edges snapshots when present
            best_props_path = DATA_PROCESSED_DIR / f"best_edges_props_{dstr}.csv"
            props_path = best_props_path if best_props_path.exists() else (DATA_PROCESSED_DIR / f"props_recommendations_{dstr}.csv")
            recon_props_path = DATA_PROCESSED_DIR / f"recon_props_{dstr}.csv"
            if props_path.exists() and recon_props_path.exists():
                try:
                    props_df = pd.read_csv(props_path)
                    recon_df = pd.read_csv(recon_props_path)
                except Exception:
                    # Skip if files fail to load
                    props_df = None
                    recon_df = None
                if isinstance(props_df, pd.DataFrame) and isinstance(recon_df, pd.DataFrame):
                    props_dates.append(dstr)
                    # Build player -> stat totals mapping per team for resolution
                    def _norm_name(s) -> str:
                        return str(s or "").strip().lower()
                    def _tri_team(v) -> str:
                        try:
                            tri = _get_tricode(v)
                            return (tri.upper() if isinstance(tri, str) and tri else str(v).strip().upper())
                        except Exception:
                            return str(v).strip().upper()
                    recon_df = recon_df.copy()
                    recon_df["_pname"] = recon_df.get("player_name", "").astype(str).str.lower()
                    recon_df["_team"] = recon_df.get("team_abbr", "").astype(str).str.upper()
                    recon_index: dict[tuple[str,str], dict[str,float]] = {}
                    for _, rr in recon_df.iterrows():
                        key = (_norm_name(rr.get("player_name")), str(rr.get("team_abbr") or "").strip().upper())
                        recon_index[key] = {
                            "pts": float(pd.to_numeric(rr.get("pts"), errors="coerce") or 0.0),
                            "reb": float(pd.to_numeric(rr.get("reb"), errors="coerce") or 0.0),
                            "ast": float(pd.to_numeric(rr.get("ast"), errors="coerce") or 0.0),
                            "threes": float(pd.to_numeric(rr.get("threes"), errors="coerce") or 0.0),
                            "pra": float(pd.to_numeric(rr.get("pra"), errors="coerce") or 0.0),
                        }
                    # Helper: parse plays column and select a top regular-price play
                    import ast as _ast, json as _json
                    def _parse_obj(val):
                        if isinstance(val, (list, dict)):
                            return val
                        s = str(val or "")
                        if s.strip() in {"", "None", "nan"}:
                            return None
                        try:
                            return _json.loads(s)
                        except Exception:
                            try:
                                return _ast.literal_eval(s)
                            except Exception:
                                return None
                    def _is_regular_price(p) -> bool:
                        try:
                            v = float(p)
                            return (v >= -150.0) and (v <= 150.0)
                        except Exception:
                            return False
                    def _is_regular_market(m) -> bool:
                        mm = str(m or "").lower()
                        return mm not in {"dd","td"}
                    def _top_play_from_row(row: pd.Series):
                        try:
                            plays = _parse_obj(row.get("plays"))
                            if isinstance(plays, list) and plays:
                                # Prefer regular-price plays; fallback to all
                                regular = [p for p in plays if _is_regular_market(p.get("market")) and _is_regular_price(p.get("price"))]
                                cand = regular if regular else plays
                                # Sort by ev_pct desc, then ev desc
                                def _evp(p):
                                    try:
                                        v = p.get("ev_pct")
                                        if v is not None and not pd.isna(v):
                                            return float(v)
                                        ve = p.get("ev")
                                        return (float(ve)*100.0 if ve is not None and not pd.isna(ve) else -1e9)
                                    except Exception:
                                        return -1e9
                                cand.sort(key=lambda p: (_evp(p), abs(p.get("edge") or 0.0)), reverse=True)
                                tp = cand[0]
                                return {
                                    "market": tp.get("market"),
                                    "side": tp.get("side"),
                                    "line": tp.get("line"),
                                    "price": tp.get("price"),
                                    "ev": tp.get("ev"),
                                    "edge": tp.get("edge"),
                                }
                        except Exception:
                            return None
                        return None
                    # Evaluate props: if using snapshot, rows are already flattened picks; else use cards (plays)
                    using_best_props = bool(best_props_path.exists() and (props_path == best_props_path))
                    for _, pr in props_df.iterrows():
                        try:
                            if using_best_props:
                                tp = {
                                    "market": pr.get("market"),
                                    "side": pr.get("side"),
                                    "line": pr.get("line"),
                                    "price": pr.get("price"),
                                    "ev": pr.get("ev"),
                                    "edge": pr.get("edge"),
                                }
                                player = _norm_name(pr.get("player"))
                                team = _tri_team(pr.get("team"))
                            else:
                                tp = _top_play_from_row(pr)
                                if not isinstance(tp, dict) or not tp:
                                    continue
                                player = _norm_name(pr.get("player"))
                                team = _tri_team(pr.get("team"))

                            stats = recon_index.get((player, team))
                            tier_here = _tier_for_row("PROPS", tp.get("ev"), tp.get("edge"))
                            props_buckets["Overall"]["total"] += 1
                            props_buckets[tier_here]["total"] += 1

                            if not isinstance(stats, dict) or not stats:
                                # unresolved (e.g., player DNP or data missing)
                                continue

                            # Resolve against line
                            mkt = str(tp.get("market") or "").lower()
                            side = str(tp.get("side") or "").upper()
                            line = tp.get("line")
                            try:
                                ln = float(line) if line is not None and not pd.isna(line) else None
                            except Exception:
                                ln = None
                            actual = None
                            if mkt == "pts":
                                actual = stats.get("pts")
                            elif mkt == "reb":
                                actual = stats.get("reb")
                            elif mkt == "ast":
                                actual = stats.get("ast")
                            elif mkt == "threes":
                                actual = stats.get("threes")
                            elif mkt == "pra":
                                actual = stats.get("pra")
                            elif mkt == "pr":
                                actual = (stats.get("pts", 0.0) + stats.get("reb", 0.0))
                            elif mkt == "ra":
                                actual = (stats.get("reb", 0.0) + stats.get("ast", 0.0))
                            elif mkt == "pa":
                                actual = (stats.get("pts", 0.0) + stats.get("ast", 0.0))

                            if ln is None or actual is None:
                                continue

                            is_push = abs(float(actual) - float(ln)) < 1e-9
                            is_win = False
                            if not is_push:
                                if side == "OVER":
                                    is_win = (float(actual) > float(ln))
                                elif side == "UNDER":
                                    is_win = (float(actual) < float(ln))

                            stake = 1.0
                            dec = _american_to_decimal(tp.get("price"))
                            if dec is None:
                                dec = 1.909090909
                            if is_push:
                                profit = 0.0
                            elif is_win:
                                profit = (float(dec) - 1.0) * stake
                            else:
                                profit = -stake

                            for key in ("Overall", tier_here):
                                b = props_buckets[key]
                                b["resolved"] += 1
                                if is_push:
                                    b["pushes"] += 1
                                elif is_win:
                                    b["wins"] += 1
                                else:
                                    b["losses"] += 1
                                b["stake_total"] += stake
                                b["profit_total"] += profit
                        except Exception:
                            continue

            # PBP recon metrics (first basket, early threes)
            try:
                pbp_recon = DATA_PROCESSED_DIR / f"pbp_reconcile_{dstr}.csv"
                if pbp_recon.exists():
                    dfp = pd.read_csv(pbp_recon)
                    # Compute means per date for standard columns if present
                    m: dict[str, Any] = {"date": dstr}
                    for col in [
                        "tip_brier","tip_logloss","first_basket_hit_top1","first_basket_hit_top5","early_threes_error","early_threes_brier_ge1"
                    ]:
                        if col in dfp.columns:
                            s = pd.to_numeric(dfp[col], errors="coerce").dropna()
                            if len(s) > 0:
                                m[col] = float(s.mean())
                    if ("first_basket_hit_top1" in m) or ("first_basket_hit_top5" in m):
                        first_basket_metrics.append({
                            "date": dstr,
                            "top1_hit_pct": round(100.0 * float(m.get("first_basket_hit_top1", 0.0)), 1) if ("first_basket_hit_top1" in m) else None,
                            "top5_hit_pct": round(100.0 * float(m.get("first_basket_hit_top5", 0.0)), 1) if ("first_basket_hit_top5" in m) else None,
                        })
                    if ("early_threes_error" in m) or ("early_threes_brier_ge1" in m):
                        early_threes_metrics.append({
                            "date": dstr,
                            "mae": abs(float(m.get("early_threes_error", 0.0))) if ("early_threes_error" in m) else None,
                            "brier_ge1": float(m.get("early_threes_brier_ge1", 0.0)) if ("early_threes_brier_ge1" in m) else None,
                        })
                    # Tiered accuracy for First Basket using PBP recon top-1 directly
                    try:
                        cols = {c.lower(): c for c in dfp.columns}
                        prob_col = cols.get("first_basket_top1_prob")
                        hit_col = cols.get("first_basket_hit_top1")
                        name_pred_col = cols.get("first_basket_top1_name")
                        name_act_col = cols.get("first_basket_actual_name")
                        if prob_col and hit_col:
                            dfp2 = dfp[[prob_col, hit_col]].copy()
                            dfp2[prob_col] = pd.to_numeric(dfp2[prob_col], errors="coerce")
                            dfp2[hit_col] = dfp2[hit_col].apply(lambda v: str(v).strip().lower() in {"true","1","yes"})
                            valid = dfp2[prob_col].notna()
                            if bool(valid.any()):
                                # Prefer hit flag derived from name equality if both columns exist
                                try:
                                    if hit_col:
                                        hit_all = dfp[hit_col].apply(lambda v: str(v).strip().lower() in {"true","1","yes"})
                                    elif name_pred_col and name_act_col:
                                        hit_all = (
                                            dfp[name_pred_col].astype(str).str.strip()
                                            == dfp[name_act_col].astype(str).str.strip()
                                        )
                                    else:
                                        hit_all = pd.Series([False] * len(dfp))
                                except Exception:
                                    hit_all = dfp[hit_col].apply(lambda v: str(v).strip().lower() in {"true","1","yes"})
                                probs_all = pd.to_numeric(dfp[prob_col], errors="coerce")
                                # Masks by tier
                                m_valid = probs_all.notna()
                                m_high = m_valid & (probs_all >= 0.6)
                                m_med = m_valid & (probs_all >= 0.5) & (probs_all < 0.6)
                                m_low = m_valid & (probs_all < 0.5)
                                def _upd(mask, tier_name):
                                    try:
                                        total = int(mask.sum())
                                        wins = int((hit_all & mask).sum())
                                        losses = total - wins
                                        if total > 0:
                                            # Overall
                                            b_all = first_basket_buckets["Overall"]
                                            b_all["total"] += total
                                            b_all["resolved"] += total
                                            b_all["wins"] += wins
                                            b_all["losses"] += losses
                                            # Tier-specific
                                            b_t = first_basket_buckets[tier_name]
                                            b_t["total"] += total
                                            b_t["resolved"] += total
                                            b_t["wins"] += wins
                                            b_t["losses"] += losses
                                    except Exception:
                                        pass
                                _upd(m_high, "High")
                                _upd(m_med, "Medium")
                                _upd(m_low, "Low")
                            else:
                                # Fallback: update Overall from hit flags only
                                try:
                                    t_count = int(dfp2[hit_col].sum())
                                    f_count = int((~dfp2[hit_col]).sum())
                                    b = first_basket_buckets["Overall"]
                                    b["total"] += (t_count + f_count)
                                    b["resolved"] += (t_count + f_count)
                                    b["wins"] += t_count
                                    b["losses"] += f_count
                                except Exception:
                                    pass
                    except Exception:
                        pass
                    # Tiered accuracy for Early Threes (Yes/No on >=1 made in 0-3m)
                    try:
                        thr_p = DATA_PROCESSED_DIR / f"early_threes_{dstr}.csv"
                        if thr_p.exists():
                            th = pd.read_csv(thr_p)
                            if not th.empty:
                                # Normalize essential fields
                                th["game_id"] = th.get("game_id").astype(str)
                                th["prob_ge_1"] = pd.to_numeric(th.get("prob_ge_1"), errors="coerce")
                                # recon actuals mapping
                                cols = {c.lower(): c for c in dfp.columns}
                                gid_col = cols.get("game_id")
                                act_col = cols.get("early_threes_actual")
                                if gid_col and act_col:
                                    dfp[gid_col] = dfp[gid_col].astype(str)
                                    amap = pd.to_numeric(dfp.set_index(gid_col)[act_col], errors="coerce").fillna(0.0).to_dict()
                                    for _, rr in th.iterrows():
                                        try:
                                            gid = str(rr.get("game_id"))
                                            prob = float(rr.get("prob_ge_1") or 0.0)
                                            side_yes = (prob >= 0.6)
                                            # Score and tier
                                            # Tier purely from probability
                                            tier = _tier_from_prob(prob)
                                            for key in ("Overall", tier):
                                                b = early_threes_buckets[key]
                                                b["total"] += 1
                                                # Resolve only if actual known
                                                actual = amap.get(gid)
                                                if actual is not None:
                                                    b["resolved"] += 1
                                                    hit = (float(actual) >= 1.0)
                                                    if (side_yes and hit) or ((not side_yes) and (not hit)):
                                                        b["wins"] += 1
                                                    else:
                                                        b["losses"] += 1
                                        except Exception:
                                            continue
                    except Exception:
                        pass
            except Exception:
                # Skip pbp metrics on error
                pass

        # Finalize percentages
        for k, b in buckets.items():
            if b["resolved"] > 0:
                try:
                    b["accuracy_pct"] = round(100.0 * b["wins"] / max(1, b["resolved"]), 1)
                except Exception:
                    b["accuracy_pct"] = None
            else:
                b["accuracy_pct"] = None
            if b["stake_total"] > 0:
                try:
                    b["roi_pct"] = round(100.0 * b["profit_total"] / max(1e-9, b["stake_total"]), 1)
                except Exception:
                    b["roi_pct"] = None
            else:
                b["roi_pct"] = None
        for k, b in props_buckets.items():
            if b["resolved"] > 0:
                try:
                    b["accuracy_pct"] = round(100.0 * b["wins"] / max(1, b["resolved"]), 1)
                except Exception:
                    b["accuracy_pct"] = None
            else:
                b["accuracy_pct"] = None
            if b["stake_total"] > 0:
                try:
                    b["roi_pct"] = round(100.0 * b["profit_total"] / max(1e-9, b["stake_total"]), 1)
                except Exception:
                    b["roi_pct"] = None
            else:
                b["roi_pct"] = None
        for k, b in first_basket_buckets.items():
            if b["resolved"] > 0:
                try:
                    b["accuracy_pct"] = round(100.0 * b["wins"] / max(1, b["resolved"]), 1)
                except Exception:
                    b["accuracy_pct"] = None
            else:
                b["accuracy_pct"] = None
            # ROI not computed; leave stake/profit as 0
            b["roi_pct"] = None
        for k, b in early_threes_buckets.items():
            if b["resolved"] > 0:
                try:
                    b["accuracy_pct"] = round(100.0 * b["wins"] / max(1, b["resolved"]), 1)
                except Exception:
                    b["accuracy_pct"] = None
            else:
                b["accuracy_pct"] = None
            b["roi_pct"] = None

        _out = {
            "since": since,
            "until": until,
            "version": "summary-v4-best-edges",
            "buckets": buckets,
            "dates": [d for d, _ in rec_files],
            "props_buckets": props_buckets,
            "props_dates": props_dates,
            "first_basket_metrics": first_basket_metrics,
            "early_threes_metrics": early_threes_metrics,
            "first_basket_buckets": first_basket_buckets,
            "early_threes_buckets": early_threes_buckets,
        }
        try:
            _cache_p = DATA_PROCESSED_DIR / "recommendations_summary.json"
            _cache_p.parent.mkdir(parents=True, exist_ok=True)
            with open(_cache_p, "w", encoding="utf-8") as fh:
                _json.dump(_out, fh)
        except Exception:
            pass
        return jsonify(_out)
    except Exception as e:  # noqa: BLE001
        return jsonify({"error": str(e)}), 500


def _recommendations_recaps():
    """Return per-date recap summaries (games + props) with reconciliation.

    Query params:
    - days: window size (default 21)
      - since/until: YYYY-MM-DD overrides window
    - include_legacy: include non-snapshot dates (default 0)

        Response:
            {version, window:{since,until}, items:[{date,games,props}]}
        Notes:
            - Includes pick-level details under games.picks and props.picks.
    """
    try:
        from datetime import datetime, timedelta
        import ast as _ast
        import json as _json

        def _parse_date(s: str):
            try:
                return datetime.strptime(str(s), "%Y-%m-%d")
            except Exception:
                return None

        def _american_to_decimal(a):
            try:
                aa = float(a)
            except Exception:
                return None
            if aa == 0:
                return None
            if aa > 0:
                return 1.0 + (aa / 100.0)
            return 1.0 + (100.0 / abs(aa))

        def _parse_obj(val):
            if isinstance(val, (list, dict)):
                return val
            s = str(val or "")
            if s.strip() in {"", "None", "nan"}:
                return None
            try:
                return _json.loads(s)
            except Exception:
                try:
                    return _ast.literal_eval(s)
                except Exception:
                    return None

        def _tier_for_row(market: str, ev: Any, edge: Any) -> str:
            try:
                if (market or "").upper() == "ML":
                    v = float(ev)
                    if v >= 0.04:
                        return "High"
                    if v >= 0.02:
                        return "Medium"
                    return "Low"
            except Exception:
                pass
            try:
                if (market or "").upper() in {"ATS", "TOTAL"}:
                    e = abs(float(edge))
                    if e >= 4.0:
                        return "High"
                    if e >= 2.0:
                        return "Medium"
                    return "Low"
            except Exception:
                pass
            return "Low"

        def _clean_tier(val: Any) -> str:
            try:
                t = str(val or "").strip().title()
                if t in {"High", "Medium", "Low"}:
                    return t
            except Exception:
                pass
            return "Low"

        def _empty():
            return {
                "total": 0,
                "resolved": 0,
                "wins": 0,
                "losses": 0,
                "pushes": 0,
                "stake_total": 0.0,
                "profit_total": 0.0,
                "accuracy_pct": None,
                "roi_pct": None,
            }

        def _finalize(b: dict) -> dict:
            try:
                res = int(b.get("resolved") or 0)
                wins = int(b.get("wins") or 0)
                stake = float(b.get("stake_total") or 0.0)
                prof = float(b.get("profit_total") or 0.0)
                b["accuracy_pct"] = round(100.0 * wins / max(1, res), 1) if res > 0 else None
                b["roi_pct"] = round(100.0 * prof / max(1e-9, stake), 1) if stake > 0 else None
            except Exception:
                b["accuracy_pct"] = None
                b["roi_pct"] = None
            return b

        # Window selection
        now = datetime.utcnow()
        days = int(request.args.get("days") or 21)
        since_q = (request.args.get("since") or "").strip()
        until_q = (request.args.get("until") or "").strip()
        if since_q and until_q:
            ds = _parse_date(since_q) or (now - timedelta(days=days))
            de = _parse_date(until_q) or now
        else:
            de = now
            ds = now - timedelta(days=days)
        if de < ds:
            ds, de = de, ds

        proc = DATA_PROCESSED_DIR
        if not proc.exists():
            return jsonify({"version": "recaps-v1", "window": {"since": ds.date().isoformat(), "until": de.date().isoformat()}, "items": []})

        include_legacy = str(request.args.get("include_legacy") or "0").strip().lower() in {"1", "true", "yes"}
        include_picks = str(request.args.get("include_picks") or "1").strip().lower() in {"1", "true", "yes"}

        # Discover dates. Default: snapshots-only to avoid confusing legacy scoring / market shapes.
        rec_map: dict[str, Path] = {}

        # Authoritative best-edges snapshots
        for p in sorted(proc.glob("best_edges_games_*.csv")):
            try:
                dstr = p.stem.replace("best_edges_games_", "")
                d = _parse_date(dstr)
                if d and ds.date() <= d.date() <= de.date():
                    rec_map[dstr] = p
            except Exception:
                continue

        if include_legacy:
            # Legacy: recommendations_*.csv preferred; fallback picks_*.csv
            for p in sorted(proc.glob("recommendations_*.csv")):
                try:
                    dstr = p.stem.replace("recommendations_", "")
                    d = _parse_date(dstr)
                    if d and ds.date() <= d.date() <= de.date():
                        rec_map.setdefault(dstr, p)
                except Exception:
                    continue
            for p in sorted(proc.glob("picks_*.csv")):
                try:
                    dstr = p.stem.replace("picks_", "")
                    d = _parse_date(dstr)
                    if d and ds.date() <= d.date() <= de.date():
                        rec_map.setdefault(dstr, p)
                except Exception:
                    continue

        dates = sorted(rec_map.keys(), reverse=True)
        items: list[dict[str, Any]] = []

        for dstr in dates:
            fp = rec_map.get(dstr)
            if not fp:
                continue

            # ---------- Games ----------
            games_out: dict[str, Any] = {
                "available": False,
                "recon_available": False,
                "odds_available": False,
                "snapshot_used": False,
                "buckets": {},
                "picks": [],
            }
            try:
                games_out["snapshot_used"] = bool(fp.name.startswith("best_edges_games_"))
            except Exception:
                games_out["snapshot_used"] = False
            try:
                rec = pd.read_csv(fp)
                if isinstance(rec, pd.DataFrame) and (not rec.empty):
                    games_out["available"] = True
            except Exception:
                rec = None
            gfin = None
            try:
                gpath = proc / f"recon_games_{dstr}.csv"
                if gpath.exists():
                    gfin = pd.read_csv(gpath)
                    games_out["recon_available"] = True
            except Exception:
                gfin = None
            godds = None
            try:
                op = _find_game_odds_for_date(dstr)
                if op is not None:
                    godds = pd.read_csv(op)
                    games_out["odds_available"] = True
            except Exception:
                godds = None

            buckets = {k: _empty() for k in ["Overall", "High", "Medium", "Low"]}
            if isinstance(rec, pd.DataFrame) and not rec.empty:
                cols = {c.lower(): c for c in rec.columns}
                def _col(*names):
                    for n in names:
                        c = cols.get(str(n).lower())
                        if c:
                            return c
                    return None
                home_col = _col("home", "home_team")
                away_col = _col("away", "visitor_team")
                side_col = _col("side", "pick")
                market_col = _col("market")
                ev_col = _col("ev")
                edge_col = _col("edge")

                def _norm(s):
                    return str(s or "").strip()

                for _, r in rec.iterrows():
                    try:
                        market = str((r.get(market_col) if market_col else "") or "").upper()
                        home = _norm(r.get(home_col) if home_col else r.get("home"))
                        away = _norm(r.get(away_col) if away_col else r.get("away"))
                        side = _norm(r.get(side_col) if side_col else r.get("side"))
                        ev = r.get(ev_col) if ev_col else None
                        edge = r.get(edge_col) if edge_col else None
                        tier = _tier_for_row(market, ev, edge)
                        for key in ("Overall", tier):
                            buckets[key]["total"] += 1

                        # Resolve using recon + odds
                        hp = ap = None
                        if isinstance(gfin, pd.DataFrame) and not gfin.empty:
                            try:
                                row = gfin[(gfin.get("home_team").astype(str) == home) & (gfin.get("visitor_team").astype(str) == away)]
                                if row.empty:
                                    row = gfin[(gfin.get("home_team").astype(str) == away) & (gfin.get("visitor_team").astype(str) == home)]
                                if not row.empty:
                                    hp = pd.to_numeric(row.iloc[0].get("home_pts"), errors="coerce")
                                    ap = pd.to_numeric(row.iloc[0].get("visitor_pts"), errors="coerce")
                                    if pd.isna(hp) or pd.isna(ap):
                                        hp = ap = None
                            except Exception:
                                hp = ap = None

                        resolved = False
                        is_win = False
                        is_push = False
                        stake = 1.0
                        profit = 0.0
                        if market == "ML":
                            if hp is None or ap is None:
                                pass
                            else:
                                resolved = True
                                home_won = (float(hp) > float(ap))
                                pick_home = (side == home)
                                dec = None
                                if isinstance(godds, pd.DataFrame) and not godds.empty:
                                    try:
                                        o = godds[(godds.get("home_team").astype(str) == home) & (godds.get("visitor_team").astype(str) == away)]
                                        if not o.empty:
                                            dec = _american_to_decimal(o.iloc[0].get("home_ml")) if pick_home else _american_to_decimal(o.iloc[0].get("away_ml"))
                                    except Exception:
                                        dec = None
                                if dec is None:
                                    dec = 2.0
                                if pick_home == home_won:
                                    is_win = True
                                    profit = (float(dec) - 1.0) * stake
                                else:
                                    profit = -stake
                        elif market in {"ATS", "TOTAL"}:
                            if isinstance(godds, pd.DataFrame) and not godds.empty and (hp is not None and ap is not None):
                                try:
                                    o = godds[(godds.get("home_team").astype(str) == home) & (godds.get("visitor_team").astype(str) == away)]
                                    if not o.empty:
                                        default_dec = 1.909090909
                                        dec = None
                                        if market == "ATS":
                                            hsp = pd.to_numeric(o.iloc[0].get("home_spread"), errors="coerce")
                                            line_home = hsp if pd.notna(hsp) else None
                                            margin = float(hp) - float(ap)
                                            if side == home and line_home is not None:
                                                diff = margin + float(line_home)
                                                is_push = abs(diff) < 1e-9
                                                is_win = diff > 0
                                                dec = default_dec
                                            elif side == away and line_home is not None:
                                                diff = -margin - float(line_home)
                                                is_push = abs(diff) < 1e-9
                                                is_win = diff > 0
                                                dec = default_dec
                                        else:
                                            tot = pd.to_numeric(o.iloc[0].get("total"), errors="coerce")
                                            if pd.notna(tot):
                                                pts = float(hp) + float(ap)
                                                diff = (pts - float(tot)) if str(side).lower().startswith("o") else (float(tot) - pts)
                                                is_push = abs(diff) < 1e-9
                                                is_win = diff > 0
                                                dec = default_dec
                                        if dec is not None:
                                            resolved = True
                                            if is_push:
                                                profit = 0.0
                                            elif is_win:
                                                profit = (float(dec) - 1.0) * stake
                                            else:
                                                profit = -stake
                                except Exception:
                                    pass

                        if resolved:
                            for key in ("Overall", tier):
                                b = buckets[key]
                                b["resolved"] += 1
                                if is_push:
                                    b["pushes"] += 1
                                elif is_win:
                                    b["wins"] += 1
                                else:
                                    b["losses"] += 1
                                b["stake_total"] += stake
                                b["profit_total"] += profit

                        # Pick-level details for UI
                        if include_picks:
                            try:
                                # Attach actuals and closing lines if available.
                                home_pts = float(hp) if (hp is not None and not pd.isna(hp)) else None
                                away_pts = float(ap) if (ap is not None and not pd.isna(ap)) else None
                                final_total = (home_pts + away_pts) if (home_pts is not None and away_pts is not None) else None
                                final_margin = (home_pts - away_pts) if (home_pts is not None and away_pts is not None) else None

                                closing_home_spread = None
                                closing_total = None
                                closing_home_ml = None
                                closing_away_ml = None
                                if isinstance(godds, pd.DataFrame) and not godds.empty:
                                    try:
                                        o = godds[(godds.get("home_team").astype(str) == home) & (godds.get("visitor_team").astype(str) == away)]
                                        if not o.empty:
                                            closing_home_spread = o.iloc[0].get("home_spread")
                                            closing_total = o.iloc[0].get("total")
                                            closing_home_ml = o.iloc[0].get("home_ml")
                                            closing_away_ml = o.iloc[0].get("away_ml")
                                    except Exception:
                                        closing_home_spread = closing_total = closing_home_ml = closing_away_ml = None

                                # Recommendation score: prefer explicit score/best_edge_value.
                                # If we're not using an authoritative snapshot, do NOT derive a faux 0-100 score
                                # from EV/edge, because that produces misleading low numbers like 2-6/100.
                                score_val = None
                                try:
                                    if "score" in rec.columns:
                                        score_val = r.get("score")
                                    elif "best_edge_value" in rec.columns:
                                        score_val = r.get("best_edge_value")
                                    if score_val is not None and not pd.isna(score_val):
                                        score_val = float(score_val)
                                    else:
                                        score_val = None
                                except Exception:
                                    score_val = None

                                games_out["picks"].append({
                                    "game_id": (None if ("game_id" not in rec.columns) else (None if pd.isna(r.get("game_id")) else r.get("game_id"))),
                                    "market": market,
                                    "home": home,
                                    "away": away,
                                    "side": side,
                                    "line": (None if pd.isna(r.get("line")) else r.get("line")) if "line" in rec.columns else (r.get("line") if hasattr(r, "get") else None),
                                    "price": (None if pd.isna(r.get("price")) else r.get("price")) if "price" in rec.columns else (r.get("price") if hasattr(r, "get") else None),
                                    "ev": (None if pd.isna(ev) else ev),
                                    "edge": (None if pd.isna(edge) else edge),
                                    "score": score_val,
                                    "tier": tier,
                                    "why_explain": (None if ("why_explain" not in rec.columns) else (None if pd.isna(r.get("why_explain")) else r.get("why_explain"))),
                                    "score_explain": (None if ("score_explain" not in rec.columns) else (None if pd.isna(r.get("score_explain")) else r.get("score_explain"))),
                                    "score_components": (None if ("score_components" not in rec.columns) else (None if pd.isna(r.get("score_components")) else r.get("score_components"))),
                                    "home_pts": home_pts,
                                    "away_pts": away_pts,
                                    "final_total": final_total,
                                    "final_margin": final_margin,
                                    "closing_home_spread": (None if closing_home_spread is None or (isinstance(closing_home_spread, float) and pd.isna(closing_home_spread)) else closing_home_spread),
                                    "closing_total": (None if closing_total is None or (isinstance(closing_total, float) and pd.isna(closing_total)) else closing_total),
                                    "closing_home_ml": (None if closing_home_ml is None or (isinstance(closing_home_ml, float) and pd.isna(closing_home_ml)) else closing_home_ml),
                                    "closing_away_ml": (None if closing_away_ml is None or (isinstance(closing_away_ml, float) and pd.isna(closing_away_ml)) else closing_away_ml),
                                    "resolved": bool(resolved),
                                    "result": ("Push" if is_push else ("Win" if is_win else "Loss")) if resolved else None,
                                    "stake": float(stake) if resolved else None,
                                    "profit": float(profit) if resolved else None,
                                })
                            except Exception:
                                pass
                    except Exception:
                        continue

            games_out["buckets"] = {k: _finalize(v) for k, v in buckets.items()}

            # ---------- Props ----------
            props_out: dict[str, Any] = {"available": False, "recon_available": False, "snapshot_used": False, "buckets": {}, "picks": []}
            pbuckets = {k: _empty() for k in ["Overall", "High", "Medium", "Low"]}
            best_props_path = proc / f"best_edges_props_{dstr}.csv"
            props_path = best_props_path if best_props_path.exists() else (proc / f"props_recommendations_{dstr}.csv")
            try:
                props_out["snapshot_used"] = bool(props_path.name.startswith("best_edges_props_"))
            except Exception:
                props_out["snapshot_used"] = False
            recon_props_path = proc / f"recon_props_{dstr}.csv"
            if props_path.exists():
                props_out["available"] = True
            # Always count available prop picks; settle if recon exists.
            props_df = None
            recon_df = None
            if props_path.exists():
                try:
                    props_df = pd.read_csv(props_path)
                except Exception:
                    props_df = None
            if props_path.exists() and recon_props_path.exists():
                props_out["recon_available"] = True
                try:
                    recon_df = pd.read_csv(recon_props_path)
                except Exception:
                    recon_df = None

            # Build recon index (player, team) -> stat totals
            recon_index: dict[tuple[str, str], dict[str, float]] = {}
            if isinstance(recon_df, pd.DataFrame) and not recon_df.empty:
                def _norm_name(s):
                    return str(s or "").strip().lower()

                for _, rr in recon_df.iterrows():
                    key = (_norm_name(rr.get("player_name")), str(rr.get("team_abbr") or "").strip().upper())
                    recon_index[key] = {
                        "pts": float(pd.to_numeric(rr.get("pts"), errors="coerce") or 0.0),
                        "reb": float(pd.to_numeric(rr.get("reb"), errors="coerce") or 0.0),
                        "ast": float(pd.to_numeric(rr.get("ast"), errors="coerce") or 0.0),
                        "threes": float(pd.to_numeric(rr.get("threes"), errors="coerce") or 0.0),
                        "pra": float(pd.to_numeric(rr.get("pra"), errors="coerce") or 0.0),
                    }

            def _top_play_from_row(row: pd.Series):
                try:
                    plays = _parse_obj(row.get("plays"))
                    if not (isinstance(plays, list) and plays):
                        return None

                    def _evp(p):
                        try:
                            v = p.get("ev_pct")
                            if v is not None and not pd.isna(v):
                                return float(v)
                            ve = p.get("ev")
                            return (float(ve) * 100.0) if (ve is not None and not pd.isna(ve)) else -1e9
                        except Exception:
                            return -1e9

                    cand = list(plays)
                    cand.sort(key=lambda p: (_evp(p), abs(p.get("edge") or 0.0)), reverse=True)
                    return cand[0]
                except Exception:
                    return None

            def _tri_team(v):
                try:
                    tri = _get_tricode(v)
                    return (tri.upper() if isinstance(tri, str) and tri else str(v).strip().upper())
                except Exception:
                    return str(v).strip().upper()

            if isinstance(props_df, pd.DataFrame) and not props_df.empty:
                # If using best_edges_props_*.csv, rows are already flattened picks.
                using_best_props = (props_path.name.startswith("best_edges_props_"))
                for _, pr in props_df.iterrows():
                    try:
                        if using_best_props:
                            player = str(pr.get("player") or "").strip()
                            team = _tri_team(pr.get("team"))
                            mkt = str(pr.get("market") or "").lower()
                            side = str(pr.get("side") or "").upper()
                            ln = pr.get("line")
                            try:
                                ln = float(ln) if ln is not None and not pd.isna(ln) else None
                            except Exception:
                                ln = None
                            ev = pr.get("ev")
                            edge = pr.get("edge")
                            score = pr.get("score")
                            try:
                                score = float(score) if score is not None and not pd.isna(score) else None
                            except Exception:
                                score = None
                            tier = _clean_tier(pr.get("tier"))
                            if tier == "Low":
                                tier = _tier_for_row("PROPS", ev, edge)
                            price = pr.get("price")
                            why_explain = pr.get("why_explain")
                        else:
                            tp = _top_play_from_row(pr)
                            if not isinstance(tp, dict) or not tp:
                                continue
                            player_raw = pr.get("player")
                            player = str(player_raw or "").strip()
                            team = _tri_team(pr.get("team"))
                            ev = tp.get("ev")
                            edge = tp.get("edge")
                            tier = _clean_tier(pr.get("tier"))
                            if tier == "Low":
                                # if tier not present or unrecognized, fallback to EV/edge heuristic
                                tier = _tier_for_row("PROPS", ev, edge)
                            mkt = str(tp.get("market") or "").lower()
                            side = str(tp.get("side") or "").upper()
                            ln = tp.get("line")
                            try:
                                ln = float(ln) if ln is not None and not pd.isna(ln) else None
                            except Exception:
                                ln = None
                            score = pr.get("score")
                            try:
                                score = float(score) if score is not None and not pd.isna(score) else None
                            except Exception:
                                score = None
                            price = tp.get("price")
                            why_explain = None

                        for key in ("Overall", tier):
                            pbuckets[key]["total"] += 1

                        pick_detail: dict[str, Any] = {
                            "player": player,
                            "team": team,
                            "market": mkt,
                            "side": side,
                            "line": ln,
                            "price": price,
                            "ev": ev,
                            "edge": edge,
                            "tier": tier,
                            "score": score,
                            "score_explain": (None if ("score_explain" not in props_df.columns) else (None if pd.isna(pr.get("score_explain")) else pr.get("score_explain"))),
                            "score_components": (None if ("score_components" not in props_df.columns) else (None if pd.isna(pr.get("score_components")) else pr.get("score_components"))),
                            "why_explain": (None if (why_explain is None or (isinstance(why_explain, float) and pd.isna(why_explain))) else why_explain),
                            "resolved": False,
                            "actual": None,
                            "result": None,
                            "stake": None,
                            "profit": None,
                        }

                        # Settle if recon exists for this player+team
                        stats = None
                        try:
                            stats = recon_index.get((str(player or "").strip().lower(), str(team or "").strip().upper()))
                        except Exception:
                            stats = None
                        if isinstance(stats, dict) and stats and (ln is not None):
                            actual = None
                            if mkt == "pts":
                                actual = stats.get("pts")
                            elif mkt == "reb":
                                actual = stats.get("reb")
                            elif mkt == "ast":
                                actual = stats.get("ast")
                            elif mkt in {"3pt", "threes"}:
                                actual = stats.get("threes")
                            elif mkt == "pra":
                                actual = stats.get("pra")
                            elif mkt == "pr":
                                actual = (stats.get("pts", 0.0) + stats.get("reb", 0.0))
                            elif mkt == "ra":
                                actual = (stats.get("reb", 0.0) + stats.get("ast", 0.0))
                            elif mkt == "pa":
                                actual = (stats.get("pts", 0.0) + stats.get("ast", 0.0))

                            if actual is not None:
                                is_push = abs(float(actual) - float(ln)) < 1e-9
                                is_win = False
                                if not is_push:
                                    if side == "OVER":
                                        is_win = (float(actual) > float(ln))
                                    elif side == "UNDER":
                                        is_win = (float(actual) < float(ln))

                                stake = 1.0
                                dec = _american_to_decimal(price) or 1.909090909
                                if is_push:
                                    profit = 0.0
                                elif is_win:
                                    profit = (float(dec) - 1.0) * stake
                                else:
                                    profit = -stake

                                pick_detail.update({
                                    "resolved": True,
                                    "actual": float(actual),
                                    "result": "Push" if is_push else ("Win" if is_win else "Loss"),
                                    "stake": float(stake),
                                    "profit": float(profit),
                                })

                                for key in ("Overall", tier):
                                    b = pbuckets[key]
                                    b["resolved"] += 1
                                    if is_push:
                                        b["pushes"] += 1
                                    elif is_win:
                                        b["wins"] += 1
                                    else:
                                        b["losses"] += 1
                                    b["stake_total"] += stake
                                    b["profit_total"] += profit

                        if include_picks:
                            props_out["picks"].append(pick_detail)
                    except Exception:
                        continue

            props_out["buckets"] = {k: _finalize(v) for k, v in pbuckets.items()}

            items.append({
                "date": dstr,
                "games": games_out,
                "props": props_out,
            })

        payload = {
            "version": "recaps-v1",
            "window": {"since": ds.date().isoformat(), "until": de.date().isoformat()},
            "items": items,
        }
        return jsonify(_to_jsonable(payload))
    except Exception as e:  # noqa: BLE001
        return jsonify({"error": str(e)}), 500


def _recommendations_summary_props():
    """Return props reliability summary computed from data/processed artifacts.

    Prefers reliability_props_summary.json for speed. Falls back to parsing
    reliability_props.csv and computing a concise summary.

    Query params (optional):
      - days: override window size description in payload (does not recompute)
    """
    try:
        proc = DATA_PROCESSED_DIR
        json_path = proc / "reliability_props_summary.json"
        csv_path = proc / "reliability_props.csv"
        # Prefer JSON if available
        if json_path.exists():
            try:
                with open(json_path, "r", encoding="utf-8") as f:
                    data = json.load(f)
                # Attach basic provenance
                data_out = {
                    "version": "props-reliability-v1",
                    "source": str(json_path),
                    "bins": len(data.get("top_roi_bins", [])) + len(data.get("largest_calibration_gap_bins", [])),
                    "summary": data,
                }
                return jsonify(data_out)
            except Exception:
                pass
        # Fallback: parse CSV bins and compute minimal summary inline
        if not csv_path.exists():
            return jsonify({"error": "missing reliability_props.csv"}), 404
        try:
            df = pd.read_csv(csv_path)
        except Exception as e:
            return jsonify({"error": f"failed to read csv: {e}"}), 500
        # Required columns
        req = {"n","hit_rate","avg_model_prob","roi"}
        if not req.issubset(set(df.columns)):
            return jsonify({"error": "csv schema missing required columns"}), 500
        # Compute calibration gap and weighted metrics
        try:
            df["calibration_gap"] = pd.to_numeric(df["hit_rate"], errors="coerce") - pd.to_numeric(df["avg_model_prob"], errors="coerce")
            w = pd.to_numeric(df["n"], errors="coerce").fillna(0)
            hit = pd.to_numeric(df["hit_rate"], errors="coerce").fillna(0.0)
            mp = pd.to_numeric(df["avg_model_prob"], errors="coerce").fillna(0.0)
            roi = pd.to_numeric(df["roi"], errors="coerce").fillna(0.0)
            gap = pd.to_numeric(df["calibration_gap"], errors="coerce").fillna(0.0)
            total_bets = int(w.sum())
            def _wavg(x):
                try:
                    return float(np.average(x, weights=w))
                except Exception:
                    return float(pd.Series(x).mean())
            weighted_hit = _wavg(hit)
            weighted_model_prob = _wavg(mp)
            weighted_roi = _wavg(roi)
            rmse_calibration = float(np.sqrt(_wavg(gap**2)))
            # Top ROI bins and largest calibration gaps
            cols = [c for c in ["bin_low","bin_high","n","roi","hit_rate","avg_model_prob","calibration_gap"] if c in df.columns]
            top_roi_bins = df.sort_values("roi", ascending=False).head(3)[cols].to_dict(orient="records")
            largest_gap_bins = df.reindex(df["calibration_gap"].abs().sort_values(ascending=False).index).head(3)[cols].to_dict(orient="records")
            out = {
                "version": "props-reliability-v1",
                "source": str(csv_path),
                "bins": int(len(df)),
                "summary": {
                    "total_bets": total_bets,
                    "weighted": {
                        "hit_rate": weighted_hit,
                        "model_prob": weighted_model_prob,
                        "roi": weighted_roi,
                        "rmse_calibration": rmse_calibration,
                    },
                    "top_roi_bins": top_roi_bins,
                    "largest_calibration_gap_bins": largest_gap_bins,
                },
            }
            return jsonify(out)
        except Exception as e:
            return jsonify({"error": f"failed to compute summary: {e}"}), 500
    except Exception as e:  # noqa: BLE001
        return jsonify({"error": str(e)}), 500


def _recommendations_summary_props_calibration():
    """Report windowed props calibration artifacts and basic metrics.

    Returns stats for 30/60/90-day windows when files exist:
      - reliability_csv, calibration_json, total_bets, rmse_calibration
    """
    try:
        proc = DATA_PROCESSED_DIR
        windows = [30, 60, 90]
        items = []
        for d in windows:
            rel_csv = proc / f"reliability_props_{d}.csv"
            calib_json = proc / f"props_prob_calibration_{d}.json"
            if (not rel_csv.exists()) or (not calib_json.exists()):
                items.append({"days": d, "available": False})
                continue
            # Load bins to compute RMSE
            try:
                df = pd.read_csv(rel_csv)
                df["n"] = pd.to_numeric(df.get("n"), errors="coerce").fillna(0)
                df["avg_model_prob"] = pd.to_numeric(df.get("avg_model_prob"), errors="coerce").fillna(0.0)
                df["hit_rate"] = pd.to_numeric(df.get("hit_rate"), errors="coerce").fillna(0.0)
                total_bets = int(df["n"].sum())
            except Exception:
                df = None
                total_bets = None
            try:
                import json as _json
                with open(calib_json, "r", encoding="utf-8") as fh:
                    calib = _json.load(fh)
                xs = calib.get("x") or []
                ys = calib.get("y") or []
                rmse = None
                if isinstance(df, pd.DataFrame) and isinstance(xs, list) and isinstance(ys, list) and len(xs) == len(ys) and len(xs) >= 2:
                    import bisect, numpy as _np
                    def _interp(p: float) -> float:
                        p = max(0.0, min(1.0, float(p)))
                        i = bisect.bisect_left(xs, p)
                        if i <= 0:
                            return float(ys[0])
                        if i >= len(xs):
                            return float(ys[-1])
                        x0 = float(xs[i-1]); x1 = float(xs[i]); y0 = float(ys[i-1]); y1 = float(ys[i])
                        t = (p - x0) / (x1 - x0) if (x1 > x0) else 0.0
                        return float(y0 + t * (y1 - y0))
                    w = df["n"].astype(float).values
                    mp = df["avg_model_prob"].astype(float).values
                    hr = df["hit_rate"].astype(float).values
                    pred = _np.array([_interp(p) for p in mp], dtype=float)
                    rmse = float(_np.sqrt(_np.average((pred - hr) ** 2, weights=w))) if float(_np.sum(w)) > 0 else None
            except Exception:
                rmse = None
            items.append({
                "days": d,
                "available": True,
                "reliability_csv": rel_csv.name,
                "calibration_json": calib_json.name,
                "total_bets": total_bets,
                "rmse_calibration": rmse,
            })
        return jsonify({"version": "props-calibration-windows-v1", "windows": items})
    except Exception as e:  # noqa: BLE001
        return jsonify({"error": str(e)}), 500


def _recommendations_summary_games_calibration():
    """Report windowed games calibration artifacts and basic metrics.

    Returns stats for 30/60/90-day windows when files exist:
      - reliability_csv, calibration_json, total_games, rmse_calibration
    """
    try:
        proc = DATA_PROCESSED_DIR
        windows = [30, 60, 90]
        items = []
        for d in windows:
            rel_csv = proc / f"reliability_games_{d}.csv"
            calib_json = proc / f"games_prob_calibration_{d}.json"
            # Backward-compatible fallback for older non-windowed filenames
            if d == 60 and ((not rel_csv.exists()) or (not calib_json.exists())):
                rel_csv2 = proc / "reliability_games.csv"
                calib_json2 = proc / "games_prob_calibration.json"
                if rel_csv2.exists() and calib_json2.exists():
                    rel_csv = rel_csv2
                    calib_json = calib_json2
            if (not rel_csv.exists()) or (not calib_json.exists()):
                items.append({"days": d, "available": False})
                continue
            # Load bins to compute RMSE
            try:
                df = pd.read_csv(rel_csv)
                df["avg_model_prob"] = pd.to_numeric(df.get("avg_model_prob"), errors="coerce").fillna(0.0)
                df["hit_rate"] = pd.to_numeric(df.get("hit_rate"), errors="coerce").fillna(0.0)
                df["n"] = pd.to_numeric(df.get("n"), errors="coerce").fillna(0)
                # Some variants may not have n; fallback to uniform weights
                if float(df["n"].sum()) <= 0:
                    df["n"] = 1.0
                total_games = int(df["n"].sum())
            except Exception:
                df = None
                total_games = None
            try:
                import json as _json
                with open(calib_json, "r", encoding="utf-8") as fh:
                    calib = _json.load(fh)
                xs = calib.get("x") or []
                ys = calib.get("y") or []
                rmse = None
                if isinstance(df, pd.DataFrame) and isinstance(xs, list) and isinstance(ys, list) and len(xs) == len(ys) and len(xs) >= 2:
                    import bisect, numpy as _np

                    def _interp(p: float) -> float:
                        p = max(0.0, min(1.0, float(p)))
                        i = bisect.bisect_left(xs, p)
                        if i <= 0:
                            return float(ys[0])
                        if i >= len(xs):
                            return float(ys[-1])
                        x0 = float(xs[i - 1]); x1 = float(xs[i]); y0 = float(ys[i - 1]); y1 = float(ys[i])
                        t = (p - x0) / (x1 - x0) if (x1 > x0) else 0.0
                        return float(y0 + t * (y1 - y0))

                    w = df["n"].astype(float).values
                    mp = df["avg_model_prob"].astype(float).values
                    hr = df["hit_rate"].astype(float).values
                    pred = _np.array([_interp(p) for p in mp], dtype=float)
                    rmse = float(_np.sqrt(_np.average((pred - hr) ** 2, weights=w))) if float(_np.sum(w)) > 0 else None
            except Exception:
                rmse = None
            items.append({
                "days": d,
                "available": True,
                "reliability_csv": rel_csv.name,
                "calibration_json": calib_json.name,
                "total_games": total_games,
                "rmse_calibration": rmse,
            })
        return jsonify({"version": "games-calibration-windows-v1", "windows": items})
    except Exception as e:  # noqa: BLE001
        return jsonify({"error": str(e)}), 500


@app.route("/api/evaluate/games")
def api_evaluate_games():
    """Evaluate games recommendations accuracy/ROI over the last N days.

    Query params:
      - days: integer window (default 30)
      - markets: comma-separated subset of {ML,ATS,TOTAL}; default all
      - tier: Overall|High|Medium|Low filter (optional)
      - since/until: override window; if provided, 'days' is ignored
    """
    try:
        from datetime import datetime, timedelta
        def _parse_date(s: str):
            try:
                return datetime.strptime(s, "%Y-%m-%d")
            except Exception:
                return None
        def _american_to_decimal(a):
            try:
                aa = float(a)
            except Exception:
                return None
            if aa == 0:
                return None
            if aa > 0:
                return 1.0 + (aa/100.0)
            return 1.0 + (100.0/abs(aa))

        days = int(request.args.get("days") or 30)
        since_q = (request.args.get("since") or "").strip()
        until_q = (request.args.get("until") or "").strip()
        mkts_q = (request.args.get("markets") or "").strip()
        tiers_q = (request.args.get("tier") or "").strip()
        want_mkts = set([m.strip().upper() for m in mkts_q.replace(";", ",").split(",") if m.strip()])
        tier_filter = tiers_q if tiers_q in {"Overall","High","Medium","Low"} else None
        now = datetime.utcnow()
        if since_q and until_q:
            ds = _parse_date(since_q) or (now - timedelta(days=days))
            de = _parse_date(until_q) or now
        else:
            de = now
            ds = now - timedelta(days=days)
        if de < ds:
            ds, de = de, ds
        proc = DATA_PROCESSED_DIR
        # Discover files within window
        rec_files = []
        if proc.exists():
            for p in sorted(proc.glob("recommendations_*.csv")):
                try:
                    dstr = p.stem.replace("recommendations_", "")
                    d = _parse_date(dstr)
                    if d and ds.date() <= d.date() <= de.date():
                        rec_files.append((dstr, p))
                except Exception:
                    continue
        # Buckets
        def _empty():
            return {"total":0,"resolved":0,"wins":0,"losses":0,"pushes":0,"stake_total":0.0,"profit_total":0.0}
        buckets = {k: _empty() for k in ["Overall","High","Medium","Low"]}
        # Local tier helper based on probability/edge
        def _tier_for_row(market: str, ev: any, edge: any) -> str:
            try:
                if (market or "").upper() == "ML":
                    v = float(ev)
                    if v >= 0.04: return "High"
                    if v >= 0.02: return "Medium"
                    return "Low"
            except Exception:
                pass
            try:
                if (market or "").upper() in {"ATS","TOTAL"}:
                    e = abs(float(edge))
                    if e >= 4.0: return "High"
                    if e >= 2.0: return "Medium"
                    return "Low"
            except Exception:
                pass
            return "Low"

        for dstr, fp in rec_files:
            try:
                rec = pd.read_csv(fp)
            except Exception:
                continue
            # Finals and odds
            gfin = None; godds = None
            try:
                gpath = DATA_PROCESSED_DIR / f"recon_games_{dstr}.csv"
                if gpath.exists():
                    gfin = pd.read_csv(gpath)
            except Exception: gfin = None
            try:
                op = _find_game_odds_for_date(dstr)
                if op is not None:
                    godds = pd.read_csv(op)
            except Exception: godds = None

            cols = {c.lower(): c for c in rec.columns}
            def _col(*names):
                for n in names:
                    c = cols.get(str(n).lower());
                    if c: return c
                return None
            home_col = _col("home","home_team"); away_col = _col("away","visitor_team")
            side_col = _col("side","pick"); market_col = _col("market")
            ev_col = _col("ev"); edge_col = _col("edge"); odds_col = _col("price","odds")

            for _, r in rec.iterrows():
                try:
                    market = str((r.get(market_col) if market_col else "") or "").upper()
                    if want_mkts and (market not in want_mkts):
                        continue
                    home = str(r.get(home_col) if home_col else r.get("home") or "").strip()
                    away = str(r.get(away_col) if away_col else r.get("away") or "").strip()
                    side = str(r.get(side_col) if side_col else r.get("side") or "").strip()
                    ev = r.get(ev_col) if ev_col else None
                    edge = r.get(edge_col) if edge_col else None
                    tier = _tier_for_row(market, ev, edge)
                    if tier_filter and tier != tier_filter:
                        continue
                    for key in ("Overall", tier):
                        buckets[key]["total"] += 1

                    hp = ap = None
                    if isinstance(gfin, pd.DataFrame) and not gfin.empty:
                        try:
                            row = gfin[(gfin.get("home_team").astype(str) == home) & (gfin.get("visitor_team").astype(str) == away)]
                            if row.empty:
                                row = gfin[(gfin.get("home_team").astype(str) == away) & (gfin.get("visitor_team").astype(str) == home)]
                            if not row.empty:
                                hp = pd.to_numeric(row.iloc[0].get("home_pts"), errors="coerce")
                                ap = pd.to_numeric(row.iloc[0].get("visitor_pts"), errors="coerce")
                                if pd.isna(hp) or pd.isna(ap): hp = ap = None
                        except Exception: hp = ap = None
                    resolved = False; is_win = False; is_push = False; stake = 1.0; profit = 0.0
                    if market == "ML":
                        if hp is None or ap is None:
                            pass
                        else:
                            resolved = True
                            home_won = (float(hp) > float(ap))
                            pick_home = (side == home)
                            dec = None
                            if isinstance(godds, pd.DataFrame) and not godds.empty:
                                try:
                                    o = godds[(godds.get("home_team").astype(str) == home) & (godds.get("visitor_team").astype(str) == away)]
                                    if not o.empty:
                                        dec = _american_to_decimal(o.iloc[0].get("home_ml")) if pick_home else _american_to_decimal(o.iloc[0].get("away_ml"))
                                except Exception:
                                    dec = None
                            if dec is None: dec = 2.0
                            if pick_home == home_won:
                                is_win = True; profit = (float(dec) - 1.0) * stake
                            else:
                                profit = -stake
                    elif market in {"ATS","TOTAL"}:
                        if isinstance(godds, pd.DataFrame) and not godds.empty and (hp is not None and ap is not None):
                            try:
                                o = godds[(godds.get("home_team").astype(str) == home) & (godds.get("visitor_team").astype(str) == away)]
                                if not o.empty:
                                    dec = None; default_dec = 1.909090909
                                    if market == "ATS":
                                        hsp = pd.to_numeric(o.iloc[0].get("home_spread"), errors="coerce")
                                        line_home = hsp if pd.notna(hsp) else None
                                        margin = float(hp) - float(ap)
                                        if side == home and line_home is not None:
                                            diff = margin + float(line_home); is_push = abs(diff) < 1e-9; is_win = diff > 0; dec = default_dec
                                        elif side == away and line_home is not None:
                                            diff = -margin - float(line_home); is_push = abs(diff) < 1e-9; is_win = diff > 0; dec = default_dec
                                    else:  # TOTAL
                                        tot = pd.to_numeric(o.iloc[0].get("total"), errors="coerce")
                                        if pd.notna(tot):
                                            pts = float(hp) + float(ap)
                                            diff = (pts - float(tot)) if str(side).lower().startswith("o") else (float(tot) - pts)
                                            is_push = abs(diff) < 1e-9; is_win = diff > 0; dec = default_dec
                                    if dec is not None:
                                        resolved = True
                                        if is_push: profit = 0.0
                                        elif is_win: profit = (float(dec) - 1.0) * stake
                                        else: profit = -stake
                            except Exception:
                                pass
                    if resolved:
                        for key in ("Overall", tier):
                            b = buckets[key]; b["resolved"] += 1
                            if is_push: b["pushes"] += 1
                            elif is_win: b["wins"] += 1
                            else: b["losses"] += 1
                            b["stake_total"] += stake; b["profit_total"] += profit
                except Exception:
                    continue
        # Finalize metrics
        def _wilson_ci(k: int, n: int, z: float = 1.96) -> tuple[float | None, float | None]:
            try:
                if n <= 0:
                    return None, None
                p = 0.0 if k < 0 else (float(k) / float(n))
                denom = 1.0 + (z*z)/n
                center = p + (z*z)/(2.0*n)
                rad = z * math.sqrt((p*(1.0-p)/n) + (z*z)/(4.0*n*n))
                low = max(0.0, (center - rad) / denom)
                high = min(1.0, (center + rad) / denom)
                return low, high
            except Exception:
                return None, None
        def _finalize(b):
            try:
                res = int(b["resolved"]) or 0
                acc = (float(b["wins"]) / float(res)) if res > 0 else None
                roi = (float(b["profit_total"]) / float(b["stake_total"])) if float(b["stake_total"]) > 0 else None
                b["accuracy_pct"] = (round(100.0 * acc, 2) if acc is not None else None)
                b["roi_pct"] = (round(100.0 * roi, 2) if roi is not None else None)
                low, high = _wilson_ci(int(b["wins"]), res)
                b["accuracy_ci_low_pct"] = (round(100.0 * low, 2) if low is not None else None)
                b["accuracy_ci_high_pct"] = (round(100.0 * high, 2) if high is not None else None)
            except Exception:
                b["accuracy_pct"] = None; b["roi_pct"] = None; b["accuracy_ci_low_pct"] = None; b["accuracy_ci_high_pct"] = None
            return b
        out = {k: _finalize(v) for k, v in buckets.items()}
        return jsonify({"window": {"since": ds.date().isoformat(), "until": de.date().isoformat()}, "markets": sorted(list(want_mkts)) if want_mkts else ["ML","ATS","TOTAL"], "tier": (tier_filter or "All"), "buckets": out})
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/evaluate/props")
def api_evaluate_props():
    """Evaluate props recommendations accuracy/ROI over the last N days.

    Query params:
      - days: integer window (default 30)
      - tier: Overall|High|Medium|Low filter (optional)
      - regular_only: 1 to restrict to regular-price top plays (default 1)
      - since/until: override window; if provided, 'days' is ignored
    """
    try:
        from datetime import datetime, timedelta
        def _parse_date(s: str):
            try:
                return datetime.strptime(s, "%Y-%m-%d")
            except Exception:
                return None
        def _american_to_decimal(a):
            try:
                aa = float(a)
            except Exception:
                return None
            if aa == 0:
                return None
            if aa > 0:
                return 1.0 + (aa/100.0)
            return 1.0 + (100.0/abs(aa))
        def _tier_for_row(ev: any, edge: any) -> str:
            try:
                v = float(ev)
                if v >= 0.04: return "High"
                if v >= 0.02: return "Medium"
            except Exception:
                pass
            try:
                e = abs(float(edge))
                if e >= 4.0: return "High"
                if e >= 2.0: return "Medium"
            except Exception:
                pass
            return "Low"
        days = int(request.args.get("days") or 30)
        since_q = (request.args.get("since") or "").strip()
        until_q = (request.args.get("until") or "").strip()
        tier_filter = (request.args.get("tier") or "").strip()
        regular_only = str(request.args.get("regular_only", "1") or "1").strip().lower() in {"1","true","yes"}
        calib_window = (request.args.get("calib_window") or "").strip()
        now = datetime.utcnow()
        if since_q and until_q:
            ds = _parse_date(since_q) or (now - timedelta(days=days))
            de = _parse_date(until_q) or now
        else:
            de = now; ds = now - timedelta(days=days)
        if de < ds: ds, de = de, ds
        proc = DATA_PROCESSED_DIR
        rec_files = []
        if proc.exists():
            for p in sorted(proc.glob("props_recommendations_*.csv")):
                try:
                    dstr = p.stem.replace("props_recommendations_", "")
                    d = _parse_date(dstr)
                    if d and ds.date() <= d.date() <= de.date():
                        rec_files.append((dstr, p))
                except Exception:
                    continue
        def _empty():
            return {"total":0,"resolved":0,"wins":0,"losses":0,"pushes":0,"stake_total":0.0,"profit_total":0.0, "brier_sum":0.0, "brier_n":0, "logloss_sum":0.0, "logloss_n":0}
        buckets = {k: _empty() for k in ["Overall","High","Medium","Low"]}
        # Load props calibration mapping (supports windowed selection and auto)
        _props_calib = None
        try:
            import json as _json
            chosen_fp = None
            _calib_selected_via = "default"
            if calib_window and calib_window in {"30","60","90"}:
                fp = DATA_PROCESSED_DIR / f"props_prob_calibration_{calib_window}.json"
                if fp.exists():
                    chosen_fp = fp; _calib_selected_via = "param"
            elif calib_window == "auto":
                _calib_selected_via = "auto"
            if chosen_fp is None:
                summary_fp = DATA_PROCESSED_DIR / "props_prob_calibration_windows.json"
                if summary_fp.exists():
                    try:
                        with open(summary_fp, "r", encoding="utf-8") as fh:
                            win_sum = _json.load(fh)
                        wins = win_sum.get("windows") or []
                        best = None
                        for it in wins:
                            if not isinstance(it, dict): continue
                            if not it.get("days"): continue
                            if it.get("rmse_calibration") is None: continue
                            if best is None or float(it["rmse_calibration"]) < float(best["rmse_calibration"]): best = it
                        if isinstance(best, dict) and best.get("days"):
                            dwin = str(best["days"]).strip()
                            fp2 = DATA_PROCESSED_DIR / f"props_prob_calibration_{dwin}.json"
                            if fp2.exists(): chosen_fp = fp2; _calib_selected_via = "auto"
                    except Exception: pass
            if chosen_fp is None:
                chosen_fp = DATA_PROCESSED_DIR / "props_prob_calibration.json"; _calib_selected_via = "default"
            if chosen_fp.exists():
                with open(chosen_fp, "r", encoding="utf-8") as fh:
                    _props_calib = _json.load(fh)
        except Exception:
            _props_calib = None
        def _calibrate_prob(p_raw: float) -> float:
            try:
                pv = max(0.0, min(1.0, float(p_raw)))
                if not isinstance(_props_calib, dict): return pv
                xs = _props_calib.get("x") or []; ys = _props_calib.get("y") or []
                if not (isinstance(xs, list) and isinstance(ys, list) and len(xs) == len(ys) and len(xs) >= 2): return pv
                import bisect
                i = bisect.bisect_left(xs, pv)
                if i <= 0: return float(ys[0])
                if i >= len(xs): return float(ys[-1])
                x0 = float(xs[i-1]); x1 = float(xs[i]); y0 = float(ys[i-1]); y1 = float(ys[i])
                t = (pv - x0) / (x1 - x0) if (x1 > x0) else 0.0
                return float(y0 + t * (y1 - y0))
            except Exception:
                return float(p_raw)
        import ast as _ast, json as _json
        def _parse_obj(val):
            if isinstance(val, (list, dict)): return val
            s = str(val or "")
            if s.strip() in {"", "None", "nan"}: return None
            try: return _json.loads(s)
            except Exception:
                try: return _ast.literal_eval(s)
                except Exception: return None
        def _is_regular_price(p) -> bool:
            try:
                v = float(p); return (v >= -150.0) and (v <= 150.0)
            except Exception: return False
        def _is_regular_market(m) -> bool:
            mm = str(m or "").lower(); return mm not in {"dd","td"}
        for dstr, fp in rec_files:
            recon_props_path = DATA_PROCESSED_DIR / f"recon_props_{dstr}.csv"
            if not recon_props_path.exists():
                continue
            try:
                props_df = pd.read_csv(fp); recon_df = pd.read_csv(recon_props_path)
            except Exception:
                continue
            # Build player/team index
            def _norm_name(s): return str(s or "").strip().lower()
            def _tri_team(v):
                try:
                    tri = _get_tricode(v); return (tri.upper() if isinstance(tri, str) and tri else str(v).strip().upper())
                except Exception: return str(v).strip().upper()
            recon_df = recon_df.copy(); recon_df["_pname"] = recon_df.get("player_name", "").astype(str).str.lower(); recon_df["_team"] = recon_df.get("team_abbr", "").astype(str).str.upper()
            recon_index: dict[tuple[str,str], dict[str,float]] = {}
            for _, rr in recon_df.iterrows():
                key = (_norm_name(rr.get("player_name")), str(rr.get("team_abbr") or "").strip().upper())
                recon_index[key] = {
                    "pts": float(pd.to_numeric(rr.get("pts"), errors="coerce") or 0.0),
                    "reb": float(pd.to_numeric(rr.get("reb"), errors="coerce") or 0.0),
                    "ast": float(pd.to_numeric(rr.get("ast"), errors="coerce") or 0.0),
                    "threes": float(pd.to_numeric(rr.get("threes"), errors="coerce") or 0.0),
                    "stl": float(pd.to_numeric(rr.get("stl"), errors="coerce") or 0.0),
                    "blk": float(pd.to_numeric(rr.get("blk"), errors="coerce") or 0.0),
                    "tov": float(pd.to_numeric(rr.get("tov"), errors="coerce") or 0.0),
                    "pra": float(pd.to_numeric(rr.get("pra"), errors="coerce") or 0.0),
                }
            # Evaluate each card top play
            for _, pr in props_df.iterrows():
                try:
                    plays = _parse_obj(pr.get("plays"))
                    if isinstance(plays, list) and plays:
                        regular = [p for p in plays if _is_regular_market(p.get("market")) and _is_regular_price(p.get("price"))]
                        cand = (regular if regular else plays) if regular_only else plays
                        if not cand: continue
                        # Sort by ev_pct desc then ev desc
                        def _evp(p):
                            try:
                                v = p.get("ev_pct");
                                if v is not None and not pd.isna(v): return float(v)
                                ve = p.get("ev"); return (float(ve)*100.0 if ve is not None and not pd.isna(ve) else -1e9)
                            except Exception: return -1e9
                        cand.sort(key=lambda p: (_evp(p), abs(p.get("edge") or 0.0)), reverse=True)
                        tp = cand[0]
                    else:
                        continue
                    player = _norm_name(pr.get("player")); team = _tri_team(pr.get("team"))
                    stats = recon_index.get((player, team))
                    ev = tp.get("ev"); edge = tp.get("edge")
                    tier = _tier_for_row(ev, edge)
                    if str(tier_filter or "") and tier != tier_filter: continue
                    for key in ("Overall", tier): buckets[key]["total"] += 1
                    # Resolve vs line
                    mkt = str(tp.get("market") or "").lower(); side = str(tp.get("side") or "").upper(); ln = tp.get("line")
                    try: ln = float(ln) if ln is not None and not pd.isna(ln) else None
                    except Exception: ln = None
                    actual = None
                    if isinstance(stats, dict) and stats:
                        if mkt == "pts": actual = stats.get("pts")
                        elif mkt == "reb": actual = stats.get("reb")
                        elif mkt == "ast": actual = stats.get("ast")
                        elif mkt == "threes": actual = stats.get("threes")
                        elif mkt == "pra": actual = stats.get("pra")
                        elif mkt == "pr": actual = (stats.get("pts",0.0)+stats.get("reb",0.0))
                        elif mkt == "ra": actual = (stats.get("reb",0.0)+stats.get("ast",0.0))
                        elif mkt == "pa": actual = (stats.get("pts",0.0)+stats.get("ast",0.0))
                    is_push = False; is_win = False
                    if (ln is None) or (actual is None):
                        # unresolved
                        pass
                    else:
                        is_push = (abs(float(actual) - float(ln)) < 1e-9)
                        if not is_push:
                            if side == "OVER": is_win = (float(actual) > float(ln))
                            elif side == "UNDER": is_win = (float(actual) < float(ln))
                        # stake/profit
                        stake = 1.0; profit = 0.0; dec = _american_to_decimal(tp.get("price")) or 1.909090909
                        # Brier and log-loss using calibrated probability if ev_pct is present
                        try:
                            evp = tp.get("ev_pct")
                            if evp is not None and not pd.isna(evp):
                                p_raw = max(0.0, min(1.0, float(evp)/100.0))
                                p = _calibrate_prob(p_raw)
                                y = 1.0 if is_win else 0.0
                                buckets["Overall"]["brier_sum"] += (p - y) ** 2; buckets["Overall"]["brier_n"] += 1
                                buckets[tier]["brier_sum"] += (p - y) ** 2; buckets[tier]["brier_n"] += 1
                                # log-loss with clipping
                                eps = 1e-9
                                p_clip = max(eps, min(1.0 - eps, p))
                                ll = - (y * math.log(p_clip) + (1.0 - y) * math.log(1.0 - p_clip))
                                buckets["Overall"]["logloss_sum"] += ll; buckets["Overall"]["logloss_n"] += 1
                                buckets[tier]["logloss_sum"] += ll; buckets[tier]["logloss_n"] += 1
                        except Exception:
                            pass
                        for key in ("Overall", tier):
                            b = buckets[key]; b["resolved"] += 1; b["total"] += 1
                            if is_push: b["pushes"] += 1
                            elif is_win: b["wins"] += 1; profit = (float(dec) - 1.0) * stake
                            else: b["losses"] += 1; profit = -stake
                            b["stake_total"] += stake; b["profit_total"] += profit
                except Exception:
                    continue
        def _wilson_ci(k: int, n: int, z: float = 1.96) -> tuple[float | None, float | None]:
            try:
                if n <= 0:
                    return None, None
                p = 0.0 if k < 0 else (float(k) / float(n))
                denom = 1.0 + (z*z)/n
                center = p + (z*z)/(2.0*n)
                rad = z * math.sqrt((p*(1.0-p)/n) + (z*z)/(4.0*n*n))
                low = max(0.0, (center - rad) / denom)
                high = min(1.0, (center + rad) / denom)
                return low, high
            except Exception:
                return None, None
        def _finalize(b):
            try:
                res = int(b["resolved"]) or 0
                acc = (float(b["wins"]) / float(res)) if res > 0 else None
                roi = (float(b["profit_total"]) / float(b["stake_total"])) if float(b["stake_total"]) > 0 else None
                b["accuracy_pct"] = (round(100.0 * acc, 2) if acc is not None else None)
                b["roi_pct"] = (round(100.0 * roi, 2) if roi is not None else None)
                low, high = _wilson_ci(int(b["wins"]), res)
                b["accuracy_ci_low_pct"] = (round(100.0 * low, 2) if low is not None else None)
                b["accuracy_ci_high_pct"] = (round(100.0 * high, 2) if high is not None else None)
                # finalize brier/logloss
                try:
                    brier_n = int(b.get("brier_n") or 0)
                    logloss_n = int(b.get("logloss_n") or 0)
                    b["brier"] = (float(b.get("brier_sum") or 0.0) / float(brier_n)) if brier_n > 0 else None
                    b["logloss"] = (float(b.get("logloss_sum") or 0.0) / float(logloss_n)) if logloss_n > 0 else None
                except Exception:
                    b["brier"] = None; b["logloss"] = None
            except Exception:
                b["accuracy_pct"] = None; b["roi_pct"] = None; b["accuracy_ci_low_pct"] = None; b["accuracy_ci_high_pct"] = None; b["brier"] = None; b["logloss"] = None
            return b
        out = {k: _finalize(v) for k, v in buckets.items()}
        return jsonify({"window": {"since": ds.date().isoformat(), "until": de.date().isoformat()}, "tier": (tier_filter or "All"), "regular_only": regular_only, "calibration_used": ("auto" if calib_window == "auto" else (calib_window or "default")), "buckets": out})
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/accuracy-market")
@app.route("/api/accuracy_market")
def api_accuracy_market():
    """Daily pregame market accuracy for games + props.

    Uses existing production artifacts under data/processed:
      - Games: recommendations_<date>.csv + recon_games_<date>.csv
      - Props: props_recommendations_<date>.csv + recon_props_<date>.csv

    Query params:
      - date: YYYY-MM-DD (optional; if provided returns a single day)
      - days: integer window length (default 30)
      - since/until: YYYY-MM-DD overrides window (inclusive)
    """

    def _parse_date(s: str):
        try:
            return datetime.strptime(str(s).strip(), "%Y-%m-%d").date()
        except Exception:
            return None

    def _american_to_decimal(a: Any) -> float | None:
        try:
            aa = float(a)
        except Exception:
            return None
        if aa == 0:
            return None
        if aa > 0:
            return 1.0 + (aa / 100.0)
        return 1.0 + (100.0 / abs(aa))

    def _norm(s: Any) -> str:
        return re.sub(r"\s+", " ", str(s or "").strip().lower())

    def _init_bucket() -> dict[str, Any]:
        return {
            "bets": 0,
            "resolved": 0,
            "wins": 0,
            "losses": 0,
            "pushes": 0,
            "stake_total": 0.0,
            "profit_total": 0.0,
        }

    def _finalize_bucket(b: dict[str, Any]) -> dict[str, Any]:
        res = int(b.get("resolved") or 0)
        wins = int(b.get("wins") or 0)
        stake = float(b.get("stake_total") or 0.0)
        profit = float(b.get("profit_total") or 0.0)
        acc = (float(wins) / float(res)) if res > 0 else None
        roi = (profit / stake) if stake > 0 else None
        out = dict(b)
        out["accuracy"] = acc
        out["accuracy_pct"] = (round(100.0 * acc, 3) if acc is not None else None)
        out["roi"] = roi
        out["roi_pct"] = (round(100.0 * roi, 3) if roi is not None else None)
        return out

    def _apply_result(b: dict[str, Any], result: str | None, price: Any) -> None:
        b["bets"] += 1
        if not result:
            return
        b["resolved"] += 1
        stake = 1.0
        dec = _american_to_decimal(price) or 1.909090909
        profit = 0.0
        if result == "push":
            b["pushes"] += 1
            profit = 0.0
        elif result == "win":
            b["wins"] += 1
            profit = (float(dec) - 1.0) * stake
        elif result == "loss":
            b["losses"] += 1
            profit = -stake
        b["stake_total"] += stake
        b["profit_total"] += float(profit)

    def _score_games_day(ds: str, proc: Path) -> dict[str, Any]:
        rec_fp = proc / f"recommendations_{ds}.csv"
        recon_fp = proc / f"recon_games_{ds}.csv"
        if (not rec_fp.exists()) or (not recon_fp.exists()):
            return {"available": False}
        try:
            rec = pd.read_csv(rec_fp)
            recon = pd.read_csv(recon_fp)
        except Exception:
            return {"available": False}

        # (home, away) -> (home_pts, away_pts)
        fin: dict[tuple[str, str], tuple[float, float]] = {}
        try:
            for _, r in recon.iterrows():
                home = _norm(r.get("home_team"))
                away = _norm(r.get("visitor_team"))
                hp = pd.to_numeric(r.get("home_pts"), errors="coerce")
                ap = pd.to_numeric(r.get("visitor_pts"), errors="coerce")
                if home and away and pd.notna(hp) and pd.notna(ap):
                    fin[(home, away)] = (float(hp), float(ap))
        except Exception:
            fin = {}

        overall = _init_bucket()
        by_market: dict[str, dict[str, Any]] = {}

        for _, r in rec.iterrows():
            try:
                market = str(r.get("market") or "").strip().upper()
                side = str(r.get("side") or "").strip()
                home = _norm(r.get("home"))
                away = _norm(r.get("away"))
                price = r.get("price")
                line = pd.to_numeric(r.get("line"), errors="coerce")
                if not market or not home or not away:
                    continue
                hp = ap = None
                if (home, away) in fin:
                    hp, ap = fin[(home, away)]
                elif (away, home) in fin:
                    # defensive: swap if rec file flipped
                    ap, hp = fin[(away, home)]
                if hp is None or ap is None:
                    _apply_result(overall, None, price)
                    continue

                result = None
                if market == "TOTAL":
                    if pd.notna(line):
                        act_total = float(hp) + float(ap)
                        if abs(act_total - float(line)) < 1e-9:
                            result = "push"
                        else:
                            s = str(side or "").strip().lower()
                            if s.startswith("o"):
                                result = "win" if act_total > float(line) else "loss"
                            elif s.startswith("u"):
                                result = "win" if act_total < float(line) else "loss"
                elif market == "ATS":
                    if pd.notna(line):
                        side_n = _norm(side)
                        margin = float(hp) - float(ap)
                        if side_n == home:
                            diff = margin + float(line)
                        elif side_n == away:
                            diff = (float(ap) - float(hp)) + float(line)
                        else:
                            diff = None
                        if diff is not None:
                            if abs(diff) < 1e-9:
                                result = "push"
                            else:
                                result = "win" if diff > 0 else "loss"
                elif market == "ML":
                    side_n = _norm(side)
                    home_won = float(hp) > float(ap)
                    away_won = float(ap) > float(hp)
                    if home_won or away_won:
                        if side_n == home:
                            result = "win" if home_won else "loss"
                        elif side_n == away:
                            result = "win" if away_won else "loss"

                if market not in by_market:
                    by_market[market] = _init_bucket()
                _apply_result(overall, result, price)
                _apply_result(by_market[market], result, price)
            except Exception:
                continue

        return {
            "available": True,
            "overall": _finalize_bucket(overall),
            "by_market": {k: _finalize_bucket(v) for k, v in by_market.items()},
        }

    def _score_props_day(ds: str, proc: Path) -> dict[str, Any]:
        rec_fp = proc / f"props_recommendations_{ds}.csv"
        recon_fp = proc / f"recon_props_{ds}.csv"
        if (not rec_fp.exists()) or (not recon_fp.exists()):
            return {"available": False}
        try:
            props_df = pd.read_csv(rec_fp)
            recon_df = pd.read_csv(recon_fp)
        except Exception:
            return {"available": False}

        def _parse_obj(val):
            if isinstance(val, (list, dict)):
                return val
            s = str(val or "")
            if s.strip() in {"", "None", "nan"}:
                return None
            try:
                return json.loads(s)
            except Exception:
                try:
                    import ast as _ast

                    return _ast.literal_eval(s)
                except Exception:
                    return None

        def _norm_name(s: Any) -> str:
            return str(s or "").strip().lower()

        recon_index: dict[tuple[str, str], dict[str, float]] = {}
        try:
            for _, rr in recon_df.iterrows():
                key = (_norm_name(rr.get("player_name")), str(rr.get("team_abbr") or "").strip().upper())
                recon_index[key] = {
                    "pts": float(pd.to_numeric(rr.get("pts"), errors="coerce") or 0.0),
                    "reb": float(pd.to_numeric(rr.get("reb"), errors="coerce") or 0.0),
                    "ast": float(pd.to_numeric(rr.get("ast"), errors="coerce") or 0.0),
                    "threes": float(pd.to_numeric(rr.get("threes"), errors="coerce") or 0.0),
                    "pra": float(pd.to_numeric(rr.get("pra"), errors="coerce") or 0.0),
                }
        except Exception:
            recon_index = {}

        def _actual_for_market(stats: dict[str, float], mkt: str) -> float | None:
            mm = str(mkt or "").strip().lower()
            if not stats:
                return None
            if mm in {"pts", "reb", "ast", "threes", "stl", "blk", "tov", "pra"}:
                return stats.get(mm)
            if mm == "pr":
                return float(stats.get("pts", 0.0) + stats.get("reb", 0.0))
            if mm == "ra":
                return float(stats.get("reb", 0.0) + stats.get("ast", 0.0))
            if mm == "pa":
                return float(stats.get("pts", 0.0) + stats.get("ast", 0.0))
            return None

        def _pick_top_play(plays: list[dict[str, Any]]) -> dict[str, Any] | None:
            if not plays:
                return None
            # Prefer regular price range, else fall back.
            def _is_regular_price(p: Any) -> bool:
                try:
                    v = float(p)
                    return (v >= -150.0) and (v <= 150.0)
                except Exception:
                    return False

            def _is_regular_market(m: Any) -> bool:
                mm = str(m or "").strip().lower()
                return mm not in {"dd", "td"}

            regular = [p for p in plays if _is_regular_market(p.get("market")) and _is_regular_price(p.get("price"))]
            cand = regular if regular else plays

            def _score(p: dict[str, Any]) -> float:
                try:
                    evp = p.get("ev_pct")
                    if evp is not None and not pd.isna(evp):
                        return float(evp)
                except Exception:
                    pass
                try:
                    ev = p.get("ev")
                    return float(ev) * 100.0 if ev is not None and not pd.isna(ev) else -1e18
                except Exception:
                    return -1e18

            cand = sorted(cand, key=_score, reverse=True)
            return cand[0] if cand else None

        overall = _init_bucket()
        by_market: dict[str, dict[str, Any]] = {}

        for _, pr in props_df.iterrows():
            try:
                plays = _parse_obj(pr.get("plays") or pr.get("_plays_list"))
                plays_list = plays if isinstance(plays, list) else []
                tp = _pick_top_play(plays_list)
                if not isinstance(tp, dict):
                    continue
                mkt = str(tp.get("market") or "").strip().lower()
                side = str(tp.get("side") or "").strip().upper()
                ln = pd.to_numeric(tp.get("line"), errors="coerce")
                price = tp.get("price")
                if not mkt or (not side) or (not pd.notna(ln)):
                    _apply_result(overall, None, price)
                    continue

                player = _norm_name(pr.get("player"))
                team = str(pr.get("team") or "").strip().upper()
                stats = recon_index.get((player, team))
                actual = _actual_for_market(stats or {}, mkt)
                result = None
                if actual is not None:
                    if abs(float(actual) - float(ln)) < 1e-9:
                        result = "push"
                    else:
                        if side == "OVER":
                            result = "win" if float(actual) > float(ln) else "loss"
                        elif side == "UNDER":
                            result = "win" if float(actual) < float(ln) else "loss"

                if mkt not in by_market:
                    by_market[mkt] = _init_bucket()
                _apply_result(overall, result, price)
                _apply_result(by_market[mkt], result, price)
            except Exception:
                continue

        return {
            "available": True,
            "overall": _finalize_bucket(overall),
            "by_market": {k: _finalize_bucket(v) for k, v in by_market.items()},
        }

    try:
        # Window selection
        single = (request.args.get("date") or "").strip()
        if single:
            d0 = _parse_date(single)
            if not d0:
                return jsonify({"ok": False, "error": "invalid date"}), 400
            since = until = d0
        else:
            days = int(request.args.get("days") or 30)
            since_q = (request.args.get("since") or "").strip()
            until_q = (request.args.get("until") or "").strip()
            if since_q and until_q:
                since = _parse_date(since_q)
                until = _parse_date(until_q)
            else:
                # Default to settled window ending yesterday (UTC) to reduce partial-day noise.
                until = (datetime.utcnow().date() - timedelta(days=1))
                since = until - timedelta(days=max(1, days) - 1)
            if not since or not until:
                return jsonify({"ok": False, "error": "invalid since/until"}), 400
            if until < since:
                since, until = until, since

        proc = DATA_PROCESSED_DIR
        rows: list[dict[str, Any]] = []
        sum_games = _init_bucket()
        sum_props = _init_bucket()

        d = since
        while d <= until:
            ds = d.isoformat()
            g = _score_games_day(ds, proc)
            p = _score_props_day(ds, proc)

            g_over = g.get("overall") if isinstance(g, dict) else None
            p_over = p.get("overall") if isinstance(p, dict) else None
            if isinstance(g_over, dict):
                for k in sum_games.keys():
                    sum_games[k] += float(g_over.get(k) or 0.0) if k in {"stake_total", "profit_total"} else int(g_over.get(k) or 0)
            if isinstance(p_over, dict):
                for k in sum_props.keys():
                    sum_props[k] += float(p_over.get(k) or 0.0) if k in {"stake_total", "profit_total"} else int(p_over.get(k) or 0)

            combined = _init_bucket()
            if isinstance(g_over, dict):
                for k in combined.keys():
                    combined[k] += float(g_over.get(k) or 0.0) if k in {"stake_total", "profit_total"} else int(g_over.get(k) or 0)
            if isinstance(p_over, dict):
                for k in combined.keys():
                    combined[k] += float(p_over.get(k) or 0.0) if k in {"stake_total", "profit_total"} else int(p_over.get(k) or 0)

            rows.append(
                {
                    "date": ds,
                    "games": g,
                    "props": p,
                    "combined": {"available": bool(g.get("available") or p.get("available")), "overall": _finalize_bucket(combined)},
                }
            )
            d = d + timedelta(days=1)

        combined_sum = _init_bucket()
        for k in combined_sum.keys():
            combined_sum[k] = sum_games[k] + sum_props[k]

        payload = {
            "ok": True,
            "version": "accuracy-market-v1",
            "window": {"since": since.isoformat(), "until": until.isoformat()},
            "days": rows,
            "summary": {
                "games": {"available": True, "overall": _finalize_bucket(sum_games)},
                "props": {"available": True, "overall": _finalize_bucket(sum_props)},
                "combined": {"available": True, "overall": _finalize_bucket(combined_sum)},
            },
            "generated_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
        }
        return jsonify(payload)
    except Exception as e:  # noqa: BLE001
        return jsonify({"ok": False, "error": str(e)}), 500


@app.route("/api/live_lens_accuracy")
@app.route("/api/live_lens_side_accuracy")
def api_live_lens_accuracy():
    """Daily Live Lens accuracy (live games + props), with tag breakdowns.

    Reads Live Lens JSONL (signals) and settles vs recon_* for each date using the
    same logic as tools/daily_live_lens_audit.py.

    Query params:
      - date: YYYY-MM-DD (optional; if provided returns a single day)
      - days: integer window length (default 7)
      - since/until: YYYY-MM-DD overrides window (inclusive)
    """

    def _parse_date(s: str):
        try:
            return datetime.strptime(str(s).strip(), "%Y-%m-%d").date()
        except Exception:
            return None

    def _hit_summary(df: pd.DataFrame) -> dict[str, Any]:
        if df is None or df.empty:
            return {"n": 0, "wins": 0, "losses": 0, "pushes": 0, "hit_rate": None}
        d2 = df[df.get("result").notna()].copy() if "result" in df.columns else pd.DataFrame()
        if d2 is None or d2.empty:
            return {"n": int(len(df)), "wins": 0, "losses": 0, "pushes": 0, "hit_rate": None}
        wins = int((d2["result"].astype(str) == "win").sum())
        losses = int((d2["result"].astype(str) == "loss").sum())
        pushes = int((d2["result"].astype(str) == "push").sum())
        denom = wins + losses
        hr = (float(wins) / float(denom)) if denom > 0 else None
        return {"n": int(len(df)), "wins": wins, "losses": losses, "pushes": pushes, "hit_rate": hr, "hit_rate_pct": (round(100.0 * hr, 3) if hr is not None else None)}

    def _by_key(df: pd.DataFrame, col: str) -> list[dict[str, Any]]:
        if df is None or df.empty or col not in df.columns:
            return []
        out: list[dict[str, Any]] = []
        for key, g in df.groupby(df[col].fillna(""), dropna=False):
            k = str(key) if str(key) else "(blank)"
            s = _hit_summary(g)
            out.append({"key": k, **s})
        out.sort(key=lambda r: (-(r.get("n") or 0), str(r.get("key") or "")))
        return out

    def _by_tag(df: pd.DataFrame) -> list[dict[str, Any]]:
        if df is None or df.empty or "tags" not in df.columns:
            return []
        try:
            tmp = df.copy()
            tmp["tags"] = tmp["tags"].apply(lambda x: x if isinstance(x, list) else ([] if x is None else [str(x)]))
            ex = tmp.explode("tags")
            ex = ex[ex["tags"].notna()]
            ex["tags"] = ex["tags"].astype(str)
            out: list[dict[str, Any]] = []
            for tag, g in ex.groupby("tags"):
                s = _hit_summary(g)
                out.append({"tag": str(tag), **s})
            out.sort(key=lambda r: (-(r.get("n") or 0), str(r.get("tag") or "")))
            return out
        except Exception:
            return []

    def _score_day(ds: str) -> pd.DataFrame:
        import sys as _sys

        tools_dir = BASE_DIR / "tools"
        if str(tools_dir) not in _sys.path:
            _sys.path.insert(0, str(tools_dir))
        import daily_live_lens_audit as _audit  # type: ignore

        # De-dup repeated tick signals: grade the first BET per decision key.
        return _audit._score_day(ds, dedup_policy="first_bet")

    def _signals_info(ds: str) -> dict[str, Any]:
        try:
            base = _live_lens_artifacts_dir()
            fp = base / f"live_lens_signals_{ds}.jsonl"
            if not fp.exists():
                return {"exists": False, "lines": 0, "bytes": 0, "path": str(fp)}
            b = int(fp.stat().st_size)
            n = _count_lines_in_file(fp)
            return {"exists": True, "lines": int(n), "bytes": b, "path": str(fp)}
        except Exception:
            return {"exists": False, "lines": 0, "bytes": 0}

    def _artifacts_dir_info() -> dict[str, Any]:
        try:
            base = _live_lens_artifacts_dir()
            env_val = (
                os.getenv(getattr(LEAGUE, "live_lens_env", "WNBA_LIVE_LENS_DIR"))
                or os.getenv(getattr(LEAGUE, "legacy_live_lens_env", "NBA_LIVE_LENS_DIR"))
                or os.getenv("LIVE_LENS_DIR")
                or ""
            ).strip()
            # Heuristic: on Render, missing env var means we fall back to repo data/processed (ephemeral).
            running_on_render = bool(os.getenv("RENDER") or os.getenv("RENDER_EXTERNAL_URL") or os.getenv("RENDER_SERVICE_ID"))
            persisted_configured = bool(env_val)
            warnings: list[str] = []
            if running_on_render and (not persisted_configured):
                warnings.append("live_lens_dir_env_missing")
            return {
                "path": str(base),
                "env_configured": persisted_configured,
                "running_on_render": running_on_render,
                "warnings": warnings,
            }
        except Exception:
            return {"path": None, "env_configured": False, "running_on_render": False, "warnings": ["artifacts_dir_unknown"]}

    try:
        single = (request.args.get("date") or "").strip()
        if single:
            d0 = _parse_date(single)
            if not d0:
                return jsonify({"ok": False, "error": "invalid date"}), 400
            since = until = d0
        else:
            days = int(request.args.get("days") or 7)
            since_q = (request.args.get("since") or "").strip()
            until_q = (request.args.get("until") or "").strip()
            if since_q and until_q:
                since = _parse_date(since_q)
                until = _parse_date(until_q)
            else:
                until = (datetime.utcnow().date() - timedelta(days=1))
                since = until - timedelta(days=max(1, days) - 1)
            if not since or not until:
                return jsonify({"ok": False, "error": "invalid since/until"}), 400
            if until < since:
                since, until = until, since

        rows: list[dict[str, Any]] = []
        all_frames: list[pd.DataFrame] = []
        d = since
        while d <= until:
            ds = d.isoformat()
            sig = _signals_info(ds)
            df = _score_day(ds)
            if isinstance(df, pd.DataFrame) and not df.empty:
                df = df.copy()
                df["_date"] = ds
                all_frames.append(df)
            warnings: list[str] = []
            try:
                if isinstance(sig, dict) and sig.get("exists") and int(sig.get("lines") or 0) > 0:
                    if int(sig.get("lines") or 0) < 500:
                        warnings.append("signals_file_small")
            except Exception:
                pass
            day_payload = {
                "date": ds,
                "available": bool(isinstance(df, pd.DataFrame) and not df.empty),
                "signals": sig,
                "warnings": warnings,
                "summary": _hit_summary(df),
                "by_market": _by_key(df, "market"),
                "by_horizon": _by_key(df, "horizon"),
                "by_klass": _by_key(df, "klass"),
                "by_stat": _by_key(df, "stat_key"),
                "by_tag": _by_tag(df),
            }
            rows.append(day_payload)
            d = d + timedelta(days=1)

        all_df = pd.concat(all_frames, ignore_index=True) if all_frames else pd.DataFrame()

        payload = {
            "ok": True,
            "version": "live-lens-accuracy-v1",
            "artifacts_dir": _artifacts_dir_info(),
            "window": {"since": since.isoformat(), "until": until.isoformat()},
            "days": rows,
            "summary": {
                "available": bool(not all_df.empty),
                "summary": _hit_summary(all_df),
                "by_market": _by_key(all_df, "market"),
                "by_horizon": _by_key(all_df, "horizon"),
                "by_klass": _by_key(all_df, "klass"),
                "by_stat": _by_key(all_df, "stat_key"),
                "by_tag": _by_tag(all_df),
            },
            "generated_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
        }
        return jsonify(payload)
    except Exception as e:  # noqa: BLE001
        return jsonify({"ok": False, "error": str(e)}), 500


# ---- Live Lens ROI analytics (NCAAB-style; split by lens) ----
def _ll_parse_ymd(s: Any) -> Optional[datetime.date]:
    try:
        return datetime.strptime(str(s).strip(), "%Y-%m-%d").date()
    except Exception:
        return None


def _ll_arg_bool(name: str, default: bool = False) -> bool:
    try:
        raw = request.args.get(name)
        if raw is None:
            return bool(default)
        return str(raw).strip().lower() in {"1", "true", "yes"}
    except Exception:
        return bool(default)


def _ll_arg_int(name: str, default: int, lo: int, hi: int) -> int:
    try:
        raw = request.args.get(name)
        if raw is None or str(raw).strip() == "":
            return int(max(lo, min(hi, int(default))))
        v = int(float(str(raw).strip()))
        return int(max(lo, min(hi, v)))
    except Exception:
        return int(max(lo, min(hi, int(default))))


def _ll_arg_float(name: str, default: float) -> float:
    try:
        raw = request.args.get(name)
        if raw is None or str(raw).strip() == "":
            return float(default)
        v = float(str(raw).strip())
        return float(v)
    except Exception:
        return float(default)


def _ll_assume_price() -> float:
    # Accept either -110 or 110 (normalize to negative).
    try:
        p = float(_ll_arg_float("assume_price", -110.0))
        if not math.isfinite(p) or p == 0:
            p = -110.0
        if p > 0:
            p = -abs(p)
        return float(p)
    except Exception:
        return -110.0


def _ll_window_params(*, default_days: int = 14) -> tuple[datetime.date, datetime.date, int] | tuple[None, None, int]:
    try:
        start_q = (request.args.get("start") or "").strip()
        end_q = (request.args.get("end") or "").strip()
        days = _ll_arg_int("days", int(default_days), 1, 120)

        if start_q and end_q:
            start = _ll_parse_ymd(start_q)
            end = _ll_parse_ymd(end_q)
            if not start or not end:
                return None, None, days
        else:
            end = _ll_parse_ymd(end_q) if end_q else (datetime.utcnow().date() - timedelta(days=1))
            if not end:
                return None, None, days
            start = end - timedelta(days=max(1, int(days)) - 1)

        if end < start:
            start, end = end, start
        days_out = int((end - start).days + 1)
        # Hard clamp to avoid accidental huge windows.
        if days_out > 120:
            start = end - timedelta(days=119)
            days_out = 120
        return start, end, days_out
    except Exception:
        return None, None, int(default_days)


def _ll_profit_units(price: float, result: str | None) -> float | None:
    try:
        r = str(result or "").strip().lower()
        if r not in {"win", "loss", "push"}:
            return None
        if r == "push":
            return 0.0
        if r == "loss":
            return -1.0
        p = float(price)
        if not math.isfinite(p) or p == 0:
            return None
        if p > 0:
            return float(p / 100.0)
        return float(100.0 / abs(p))
    except Exception:
        return None


def _ll_tag_is_meta(tag: str) -> bool:
    t = str(tag or "").strip().lower()
    return t.startswith("market:") or t.startswith("horizon:") or t.startswith("klass:") or t.startswith("stat:")


def _ll_tag_type(tag: str) -> str:
    try:
        t = str(tag or "").strip().lower()
        if ":" in t:
            return t.split(":", 1)[0]
        return t
    except Exception:
        return ""


def _ll_canonical_tag(tag: str) -> str:
    # Low-cardinality canonicalization: preserve type, wildcard value.
    try:
        t = str(tag or "").strip().lower()
        if not t:
            return ""
        if ":" not in t:
            return t
        return t.split(":", 1)[0] + ":*"
    except Exception:
        return ""


def _ll_driver_from_type(tag_type: str) -> str:
    t = str(tag_type or "").strip().lower()
    if not t:
        return ""
    if t in {"injury"}:
        return "injury"
    if t in {"rot", "rot_off"}:
        return "rotation"
    if t in {"pf"}:
        return "foul_trouble"
    if t in {"proj_min", "rem_min", "mp"}:
        return "minutes"
    if t in {"sim"}:
        return "sim"
    if t in {"risk", "support"}:
        return "adjustment"
    if t in {"line_src", "line_age", "books", "market_span", "hold", "bettable", "bet_score", "gate"}:
        return "market_quality"
    if t in {"edge_sigma"}:
        return "signal_strength"
    if t in {"pace_mult", "role_mult", "hot", "foul_adj"}:
        return "player_adjustment"
    if t in {"shrink"}:
        return "shrink"
    if t in {"interval_drift", "interval_drift_mag"}:
        return "interval_drift"
    if t in {"recent_window", "recent_window_w"}:
        return "recent_window"
    if t in {"endgame_foul", "endgame_foul_mag"}:
        return "endgame_foul"
    if t in {"time"}:
        return "time"
    if t in {"mgn"}:
        return "margin"
    if t in {"pace", "poss", "ppp"}:
        return "pace_eff"
    if t in {"spr", "ats_side"}:
        return "spread"
    if t in {"ctx", "scope"}:
        return "context"
    return t


def _ll_load_audit_module():
    import sys as _sys

    tools_dir = BASE_DIR / "tools"
    if str(tools_dir) not in _sys.path:
        _sys.path.insert(0, str(tools_dir))
    import daily_live_lens_audit as _audit  # type: ignore

    return _audit


def _ll_enrich_signal_tags(body: dict[str, Any]) -> dict[str, Any]:
    if not isinstance(body, dict):
        return body
    obj = dict(body)
    try:
        audit = _ll_load_audit_module()
        market = str(obj.get("market") or "").strip().lower()
        if not market:
            return obj

        horizon = str(obj.get("horizon") or "").strip().lower() or None
        klass = str(obj.get("klass") or "").strip().upper() or None

        stat_key = None
        if market == "player_prop":
            try:
                stat_key = str(obj.get("stat") or "").strip().lower() or None
            except Exception:
                stat_key = None
            try:
                if stat_key:
                    stat_key = str(audit._live_stat_key(stat_key))
            except Exception:
                pass

        interval_on = recent_on = foul_on = None
        try:
            interval_on, recent_on, foul_on = audit._flag_adjustments(obj.get("context"))
        except Exception:
            interval_on, recent_on, foul_on = None, None, None

        tags = audit._derive_tags(
            obj=obj,
            market=market,
            horizon=horizon,
            klass=klass,
            stat_key=stat_key,
            interval_drift_on=interval_on,
            recent_window_on=recent_on,
            endgame_foul_on=foul_on,
        )
        tags = tags if isinstance(tags, list) else ([] if tags is None else [str(tags)])
        tags = [str(t) for t in tags if t is not None and str(t).strip()]
        if not tags:
            return obj

        driver_tags = [t for t in tags if not _ll_tag_is_meta(t)]
        driver_types = sorted({t for t in (_ll_tag_type(x) for x in driver_tags) if t})
        drivers = sorted({_ll_driver_from_type(t) for t in driver_types if t})

        obj["tags"] = tags
        obj["driver_tags"] = driver_tags
        if driver_types:
            obj["driver_types"] = driver_types
        if drivers:
            obj["drivers"] = drivers
            obj["driver"] = drivers[0]
    except Exception:
        return obj
    return obj


def _ll_load_jsonl(path: Path) -> list[dict[str, Any]]:
    if not path.exists():
        return []
    out: list[dict[str, Any]] = []
    try:
        with path.open("r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                try:
                    obj = json.loads(line)
                except Exception:
                    continue
                if isinstance(obj, dict):
                    out.append(obj)
    except Exception:
        return []
    return out


def _ll_canon_gid10(game_id: Any) -> str:
    try:
        raw = str(game_id or "").strip()
    except Exception:
        return ""
    digits = "".join([c for c in raw if c.isdigit()])
    if digits and len(digits) < 10:
        return digits.zfill(10)
    if len(digits) == 8:
        return "00" + digits
    if len(digits) == 9:
        return "0" + digits
    return digits


def _ll_is_canon_gid(gid: str | None) -> bool:
    g = str(gid or "").strip()
    return len(g) == 10 and g.isdigit()


def _ll_resolve_gid(obj: dict[str, Any], ds: str) -> str | None:
    try:
        gid0 = _ll_canon_gid10(obj.get("game_id_canon") or obj.get("game_id"))
        if _ll_is_canon_gid(gid0):
            return gid0
    except Exception:
        pass
    try:
        gid = _resolve_live_lens_canon_gid(obj, ds)
        if gid and _ll_is_canon_gid(str(gid)):
            return str(gid)
    except Exception:
        pass
    return None


def _ll_prep_recon_games(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()
    out = df.copy()
    if "game_id" in out.columns:
        out["_gid"] = out["game_id"].map(_ll_canon_gid10)
    else:
        out["_gid"] = ""
    for c in ("home_tri", "away_tri"):
        if c in out.columns:
            out[c] = out[c].astype(str).str.strip().str.upper()
    return out


def _ll_prep_recon_quarters(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()
    out = df.copy()
    if "game_id" in out.columns:
        out["_gid"] = out["game_id"].map(_ll_canon_gid10)
    else:
        out["_gid"] = ""
    for c in ("home_tri", "away_tri"):
        if c in out.columns:
            out[c] = out[c].astype(str).str.strip().str.upper()
    return out


def _ll_prep_recon_props(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()
    out = df.copy()
    if "game_id" in out.columns:
        out["_gid"] = out["game_id"].map(_ll_canon_gid10)
    else:
        out["_gid"] = ""
    if "player_name" in out.columns:
        out["_name_key"] = out["player_name"].astype(str).map(_norm_player_name)
    else:
        out["_name_key"] = ""

    # Ensure numeric stat cols
    for c in ("pts", "reb", "ast", "threes", "stl", "blk", "tov", "pra"):
        if c in out.columns:
            out[c] = pd.to_numeric(out[c], errors="coerce")

    # Derive combos if absent
    if all(c in out.columns for c in ("pts", "reb")) and "pr" not in out.columns:
        out["pr"] = out["pts"] + out["reb"]
    if all(c in out.columns for c in ("pts", "ast")) and "pa" not in out.columns:
        out["pa"] = out["pts"] + out["ast"]
    if all(c in out.columns for c in ("reb", "ast")) and "ra" not in out.columns:
        out["ra"] = out["reb"] + out["ast"]
    if all(c in out.columns for c in ("pts", "reb", "ast")) and "pra" not in out.columns:
        out["pra"] = out["pts"] + out["reb"] + out["ast"]
    return out


def _ll_build_recon_indexes(ds: str) -> dict[str, Any]:
    rg = pd.DataFrame()
    rq = pd.DataFrame()
    rp = pd.DataFrame()
    try:
        p = DATA_PROCESSED_DIR / f"recon_games_{ds}.csv"
        if p.exists():
            rg = _ll_prep_recon_games(pd.read_csv(p))
    except Exception:
        rg = pd.DataFrame()
    try:
        p = DATA_PROCESSED_DIR / f"recon_quarters_{ds}.csv"
        if p.exists():
            rq = _ll_prep_recon_quarters(pd.read_csv(p))
    except Exception:
        rq = pd.DataFrame()
    try:
        p = DATA_PROCESSED_DIR / f"recon_props_{ds}.csv"
        if p.exists():
            rp = _ll_prep_recon_props(pd.read_csv(p))
    except Exception:
        rp = pd.DataFrame()

    rg_by_gid: dict[str, dict[str, Any]] = {}
    rg_by_ha: dict[tuple[str, str], dict[str, Any]] = {}
    if not rg.empty:
        for r in rg.to_dict(orient="records"):
            gid = str(r.get("_gid") or "").strip()
            h = str(r.get("home_tri") or "").strip().upper()
            a = str(r.get("away_tri") or "").strip().upper()
            if gid and gid not in rg_by_gid:
                rg_by_gid[gid] = r
            if h and a and (h, a) not in rg_by_ha:
                rg_by_ha[(h, a)] = r

    rq_by_gid: dict[str, dict[str, Any]] = {}
    rq_by_ha: dict[tuple[str, str], dict[str, Any]] = {}
    if not rq.empty:
        for r in rq.to_dict(orient="records"):
            gid = str(r.get("_gid") or "").strip()
            h = str(r.get("home_tri") or "").strip().upper()
            a = str(r.get("away_tri") or "").strip().upper()
            if gid and gid not in rq_by_gid:
                rq_by_gid[gid] = r
            if h and a and (h, a) not in rq_by_ha:
                rq_by_ha[(h, a)] = r

    rp_by_gid_name: dict[tuple[str, str], dict[str, Any]] = {}
    if not rp.empty:
        for r in rp.to_dict(orient="records"):
            gid = str(r.get("_gid") or "").strip()
            nk = str(r.get("_name_key") or "").strip().upper()
            if gid and nk and (gid, nk) not in rp_by_gid_name:
                rp_by_gid_name[(gid, nk)] = r

    return {
        "rg_ok": bool(not rg.empty),
        "rq_ok": bool(not rq.empty),
        "rp_ok": bool(not rp.empty),
        "rg_by_gid": rg_by_gid,
        "rg_by_ha": rg_by_ha,
        "rq_by_gid": rq_by_gid,
        "rq_by_ha": rq_by_ha,
        "rp_by_gid_name": rp_by_gid_name,
    }


def _ll_actual_total(*, market: str, horizon: str | None, gid: str | None, home: str | None, away: str | None, idx: dict[str, Any]) -> float | None:
    try:
        m = str(market or "").strip().lower()
        hz = str(horizon or "").strip().lower() or None
        if m == "total":
            row = None
            if gid:
                row = (idx.get("rg_by_gid") or {}).get(str(gid))
            if row is None and home and away:
                row = (idx.get("rg_by_ha") or {}).get((str(home).upper(), str(away).upper()))
            if not row:
                return None
            return _number(row.get("total_actual"))

        if m in {"half_total", "quarter_total"}:
            row = None
            if gid:
                row = (idx.get("rq_by_gid") or {}).get(str(gid))
            if row is None and home and away:
                row = (idx.get("rq_by_ha") or {}).get((str(home).upper(), str(away).upper()))
            if not row:
                return None
            if m == "half_total":
                if hz == "h1":
                    return _number(row.get("actual_h1_total"))
                if hz == "h2":
                    return _number(row.get("actual_h2_total"))
                return None
            if m == "quarter_total":
                if hz in {"q1", "q2", "q3", "q4"}:
                    return _number(row.get(f"actual_{hz}_total"))
                return None
    except Exception:
        return None
    return None


def _ll_actual_ats_margin_home(*, gid: str | None, home: str | None, away: str | None, idx: dict[str, Any]) -> float | None:
    row = None
    try:
        if gid:
            row = (idx.get("rg_by_gid") or {}).get(str(gid))
        if row is None and home and away:
            row = (idx.get("rg_by_ha") or {}).get((str(home).upper(), str(away).upper()))
        if not row:
            return None
        hp = _number(row.get("home_pts"))
        ap = _number(row.get("visitor_pts"))
        if hp is None or ap is None:
            return None
        return float(hp) - float(ap)
    except Exception:
        return None


def _ll_actual_prop(*, gid: str | None, name_key: str | None, stat_key: str, idx: dict[str, Any]) -> float | None:
    try:
        if not gid or not name_key:
            return None
        row = (idx.get("rp_by_gid_name") or {}).get((str(gid), str(name_key).upper()))
        if not row:
            return None
        return _number(row.get(stat_key))
    except Exception:
        return None


def _ll_settle_over_under(*, actual: float | None, line: float | None, side: str | None) -> str | None:
    if actual is None or line is None:
        return None
    s = str(side or "").strip().upper()
    if s not in {"OVER", "UNDER"}:
        return None
    if float(actual) == float(line):
        return "push"
    if s == "OVER":
        return "win" if float(actual) > float(line) else "loss"
    return "win" if float(actual) < float(line) else "loss"


def _ll_settle_ats(*, margin_home: float | None, line: float | None, pick_team: str | None, home: str | None, away: str | None) -> str | None:
    if margin_home is None or line is None or not pick_team or not home or not away:
        return None
    side = str(pick_team).strip().upper()
    h = str(home).strip().upper()
    a = str(away).strip().upper()
    if side not in {h, a}:
        return None
    diff = None
    if side == h:
        diff = float(margin_home) + float(line)
    else:
        diff = (-float(margin_home)) + float(line)
    if diff is None:
        return None
    if abs(float(diff)) < 1e-9:
        return "push"
    return "win" if float(diff) > 0 else "loss"


def _ll_dedup_first(signals: list[dict[str, Any]]) -> list[dict[str, Any]]:
    # De-dup repeated tick logs: grade the first BET per decision key.
    def _ts_key(obj: dict[str, Any], idx: int) -> tuple[float, int]:
        for k in ("received_at", "ts", "created_at"):
            v = obj.get(k)
            if not v:
                continue
            try:
                dt = pd.to_datetime(str(v), errors="coerce", utc=True)
                if pd.isna(dt):
                    continue
                return (float(dt.to_pydatetime().timestamp()), int(idx))
            except Exception:
                continue
        return (float(idx), int(idx))

    def _key(obj: dict[str, Any]) -> tuple[Any, ...] | None:
        try:
            market = str(obj.get("market") or "").strip().lower()
            if market not in {"total", "half_total", "quarter_total", "ats", "player_prop"}:
                return None
            gid = obj.get("_gid") or _ll_canon_gid10(obj.get("game_id_canon") or obj.get("game_id"))
            horizon = str(obj.get("horizon") or "").strip().lower() or None
            if market == "player_prop":
                name_key = _norm_player_name(str(obj.get("name_key") or obj.get("player") or ""))
                stat_key = str(obj.get("stat") or "").strip().lower()
                side = str(obj.get("side") or "").strip().upper() or None
                if not name_key or not stat_key or not side:
                    return None
                return (market, gid, name_key, stat_key, side)
            if market in {"total", "half_total", "quarter_total"}:
                side = str(obj.get("side") or "").strip().upper() or None
                if not side:
                    return None
                return (market, gid, horizon, side)
            if market == "ats":
                side = str(obj.get("side") or "").strip().upper() or None
                if not side:
                    return None
                return (market, gid, side)
        except Exception:
            return None
        return None

    groups: dict[tuple[Any, ...], tuple[int, dict[str, Any]]] = {}
    for i, obj in enumerate(signals):
        if not isinstance(obj, dict):
            continue
        k = _key(obj)
        if k is None:
            continue
        cur = groups.get(k)
        if cur is None:
            groups[k] = (i, obj)
            continue
        # pick the earlier one
        if _ts_key(obj, i) < _ts_key(cur[1], cur[0]):
            groups[k] = (i, obj)
    picked = [it for _, it in sorted(groups.values(), key=lambda x: x[0])]
    return picked


def _ll_score_day(ds: str, *, allowed_markets: set[str], assume_price: float) -> tuple[pd.DataFrame, dict[str, Any]]:
    base = _live_lens_artifacts_dir()
    sig_path = base / f"live_lens_signals_{ds}.jsonl"
    sigs = _ll_load_jsonl(sig_path)
    if not sigs:
        return pd.DataFrame(), {"signals": {"exists": False, "raw": 0, "filtered": 0, "dedup": 0}, "path": str(sig_path)}

    # Filter BET rows and allowed markets.
    filtered: list[dict[str, Any]] = []
    for obj in sigs:
        try:
            market = str(obj.get("market") or "").strip().lower()
            if market not in allowed_markets:
                continue
            if str(obj.get("klass") or "").strip().upper() != "BET":
                continue
            # Exclude model fallback prop lines (diagnostic-only).
            if market == "player_prop":
                try:
                    if str(obj.get("line_source") or "").strip().lower() == "model":
                        continue
                except Exception:
                    pass
            gid = _ll_resolve_gid(obj, ds)
            obj2 = dict(obj)
            if gid:
                obj2["_gid"] = gid
            filtered.append(obj2)
        except Exception:
            continue

    deduped = _ll_dedup_first(filtered)

    idx = _ll_build_recon_indexes(ds)
    audit = _ll_load_audit_module()

    rows: list[dict[str, Any]] = []
    for obj in deduped:
        try:
            market = str(obj.get("market") or "").strip().lower()
            horizon = str(obj.get("horizon") or "").strip().lower() or None
            gid = str(obj.get("_gid") or "").strip() or None
            home = _canonical_team_tri(obj.get("home")) or None
            away = _canonical_team_tri(obj.get("away")) or None
            klass = str(obj.get("klass") or "").strip().upper() or None
            elapsed = _number(obj.get("elapsed"))
            remaining = _number(obj.get("remaining"))

            # Normalize line fields.
            if market == "player_prop":
                live_line = _number(obj.get("line"))
                if live_line is None:
                    live_line = _number(obj.get("live_line"))
            else:
                live_line = _number(obj.get("live_line"))

            edge = _number(obj.get("edge_adj"))
            if edge is None:
                edge = _number(obj.get("edge"))

            side = None
            stat_key = None
            player = None
            name_key = None

            if market == "player_prop":
                player = str(obj.get("player") or "").strip() or None
                try:
                    stat_key = str(obj.get("stat") or "").strip().lower() or None
                except Exception:
                    stat_key = None
                # Normalize stat key to the audit's compact naming.
                try:
                    if stat_key:
                        stat_key = str(audit._live_stat_key(stat_key))
                except Exception:
                    pass
                name_key = _norm_player_name(str(obj.get("name_key") or player or "")) or None
                side = str(obj.get("side") or "").strip().upper() or None
            elif market in {"total", "half_total", "quarter_total"}:
                side = str(obj.get("side") or "").strip().upper() or None
            elif market == "ats":
                side = str(obj.get("side") or "").strip().upper() or None

            # Settle.
            result = None
            if market in {"total", "half_total", "quarter_total"}:
                actual = _ll_actual_total(market=market, horizon=horizon, gid=gid, home=home, away=away, idx=idx)
                result = _ll_settle_over_under(actual=actual, line=live_line, side=side)
            elif market == "ats":
                margin_home = _ll_actual_ats_margin_home(gid=gid, home=home, away=away, idx=idx)
                result = _ll_settle_ats(margin_home=margin_home, line=live_line, pick_team=side, home=home, away=away)
            elif market == "player_prop":
                actual = _ll_actual_prop(gid=gid, name_key=name_key, stat_key=str(stat_key or ""), idx=idx)
                result = _ll_settle_over_under(actual=actual, line=live_line, side=side)

            profit_units = _ll_profit_units(assume_price, result)

            # Tags: reuse audit's low-cardinality derived tags.
            ctx = obj.get("context")
            interval_on = recent_on = foul_on = None
            try:
                interval_on, recent_on, foul_on = audit._flag_adjustments(ctx)
            except Exception:
                interval_on, recent_on, foul_on = None, None, None

            tags = []
            try:
                tags = audit._derive_tags(
                    obj=obj,
                    market=market,
                    horizon=horizon,
                    klass=klass,
                    stat_key=stat_key if market == "player_prop" else None,
                    interval_drift_on=interval_on,
                    recent_window_on=recent_on,
                    endgame_foul_on=foul_on,
                )
            except Exception:
                tags = []
            tags = tags if isinstance(tags, list) else ([] if tags is None else [str(tags)])
            tags = [str(t) for t in tags if t is not None and str(t).strip()]

            driver_tags = [t for t in tags if not _ll_tag_is_meta(t)]
            driver_types = sorted({t for t in (_ll_tag_type(x) for x in driver_tags) if t})
            drivers = sorted({_ll_driver_from_type(t) for t in driver_types if t})
            driver = drivers[0] if drivers else ""

            # Lens field used by the split pages:
            # - game lens: horizon
            # - player props lens: stat_key
            lens = ""
            if market == "player_prop":
                lens = str(stat_key or "")
            else:
                lens = str(horizon or "")

            rows.append(
                {
                    "date": str(obj.get("date") or ds),
                    "market": market,
                    "horizon": horizon,
                    "game_id": gid,
                    "home": home,
                    "away": away,
                    "player": player,
                    "name_key": name_key,
                    "stat": stat_key,
                    "side": side,
                    "klass": klass,
                    "elapsed": elapsed,
                    "remaining": remaining,
                    "live_line": live_line,
                    "edge": edge,
                    "result": result,
                    "profit_units": profit_units,
                    "lens": lens,
                    "driver": driver,
                    "driver_tags": driver_tags,
                    "tags": tags,
                }
            )
        except Exception:
            continue

    df = pd.DataFrame(rows) if rows else pd.DataFrame()
    meta = {
        "signals": {
            "exists": True,
            "raw": int(len(sigs)),
            "filtered": int(len(filtered)),
            "dedup": int(len(deduped)),
            "path": str(sig_path),
        },
        "recon": {"games": bool(idx.get("rg_ok")), "quarters": bool(idx.get("rq_ok")), "props": bool(idx.get("rp_ok"))},
    }
    return df, meta


def _ll_summary(df: pd.DataFrame) -> dict[str, Any]:
    if df is None or df.empty:
        return {
            "status": "empty",
            "n_settled": 0,
            "wins": 0,
            "losses": 0,
            "pushes": 0,
            "win_rate": None,
            "roi_units_per_bet": None,
        }
    d = df.copy()
    if "result" not in d.columns:
        return {
            "status": "empty",
            "n_settled": 0,
            "wins": 0,
            "losses": 0,
            "pushes": 0,
            "win_rate": None,
            "roi_units_per_bet": None,
        }
    settled = d[d["result"].isin(["win", "loss", "push"])].copy()
    wins = int((settled["result"] == "win").sum())
    losses = int((settled["result"] == "loss").sum())
    pushes = int((settled["result"] == "push").sum())
    n_settled = int(wins + losses + pushes)
    profit_total = float(pd.to_numeric(settled.get("profit_units"), errors="coerce").fillna(0.0).sum())
    roi = (profit_total / float(n_settled)) if n_settled > 0 else None
    wr = (float(wins) / float(wins + losses)) if (wins + losses) > 0 else None
    return {
        "status": "ok" if n_settled > 0 else "empty",
        "n_settled": n_settled,
        "wins": wins,
        "losses": losses,
        "pushes": pushes,
        "win_rate": wr,
        "roi_units_per_bet": roi,
        "profit_units": profit_total,
    }


def _ll_group_stats(df: pd.DataFrame, key_cols: list[str], key_out: list[str]) -> list[dict[str, Any]]:
    if df is None or df.empty:
        return []
    d = df[df["result"].isin(["win", "loss", "push"])].copy() if "result" in df.columns else pd.DataFrame()
    if d.empty:
        return []
    rows: list[dict[str, Any]] = []
    for keys, g in d.groupby(key_cols, dropna=False):
        if not isinstance(keys, tuple):
            keys = (keys,)
        s = _ll_summary(g)
        row = {k: ("" if v is None else str(v)) for k, v in zip(key_out, keys)}
        rows.append({**row, "n": int(s.get("n_settled") or 0), "wins": int(s.get("wins") or 0), "losses": int(s.get("losses") or 0), "pushes": int(s.get("pushes") or 0), "win_rate": s.get("win_rate"), "roi_units_per_bet": s.get("roi_units_per_bet")})
    rows.sort(key=lambda r: (-(r.get("n") or 0), str(r.get(key_out[0]) or ""), str(r.get(key_out[-1]) or "")))
    return rows


def _ll_by_driver_tag(df: pd.DataFrame, *, top_n: int = 80) -> list[dict[str, Any]]:
    if df is None or df.empty or "driver_tags" not in df.columns:
        return []
    d = df[df["result"].isin(["win", "loss", "push"])].copy() if "result" in df.columns else pd.DataFrame()
    if d.empty:
        return []
    d["driver_tags"] = d["driver_tags"].apply(lambda x: x if isinstance(x, list) else ([] if x is None else [str(x)]))
    ex = d.explode("driver_tags")
    ex = ex[ex["driver_tags"].notna()]
    ex["driver_tags"] = ex["driver_tags"].astype(str)
    ex = ex[ex["driver_tags"].astype(str).str.len() > 0]
    out = _ll_group_stats(ex.rename(columns={"driver_tags": "tag"}), ["tag"], ["tag"])
    return out[: int(max(0, top_n))]


def _ll_by_driver_tagset(df: pd.DataFrame, *, top_n: int = 80) -> list[dict[str, Any]]:
    if df is None or df.empty or "driver_tags" not in df.columns:
        return []
    d = df[df["result"].isin(["win", "loss", "push"])].copy() if "result" in df.columns else pd.DataFrame()
    if d.empty:
        return []

    def _mk(x: Any) -> str:
        try:
            tags = x if isinstance(x, list) else ([] if x is None else [str(x)])
            tags2 = [str(t) for t in tags if t is not None and str(t).strip()]
            tags2 = sorted(set(tags2))
            if not tags2:
                return ""
            return "|".join(tags2[:4])
        except Exception:
            return ""

    d["tagset"] = d["driver_tags"].apply(_mk)
    d2 = d[d["tagset"].astype(str).str.len() > 0]
    out = _ll_group_stats(d2, ["tagset"], ["tagset"])
    return out[: int(max(0, top_n))]


def _ll_by_driver_canonical(df: pd.DataFrame, *, top_n: int = 80) -> list[dict[str, Any]]:
    if df is None or df.empty or "driver_tags" not in df.columns:
        return []
    d = df[df["result"].isin(["win", "loss", "push"])].copy() if "result" in df.columns else pd.DataFrame()
    if d.empty:
        return []
    d["driver_tags"] = d["driver_tags"].apply(lambda x: x if isinstance(x, list) else ([] if x is None else [str(x)]))
    ex = d.explode("driver_tags")
    ex = ex[ex["driver_tags"].notna()]
    ex["tag"] = ex["driver_tags"].astype(str).map(_ll_canonical_tag)
    ex = ex[ex["tag"].astype(str).str.len() > 0]
    out = _ll_group_stats(ex, ["tag"], ["tag"])
    return out[: int(max(0, top_n))]


def _ll_by_driver_tag_type(df: pd.DataFrame, *, top_n: int = 80) -> list[dict[str, Any]]:
    if df is None or df.empty or "driver_tags" not in df.columns:
        return []
    d = df[df["result"].isin(["win", "loss", "push"])].copy() if "result" in df.columns else pd.DataFrame()
    if d.empty:
        return []
    d["driver_tags"] = d["driver_tags"].apply(lambda x: x if isinstance(x, list) else ([] if x is None else [str(x)]))
    ex = d.explode("driver_tags")
    ex = ex[ex["driver_tags"].notna()]
    ex["type"] = ex["driver_tags"].astype(str).map(_ll_tag_type)
    ex = ex[ex["type"].astype(str).str.len() > 0]
    out = _ll_group_stats(ex, ["type"], ["type"])
    return out[: int(max(0, top_n))]


def _ll_by_driver(df: pd.DataFrame, *, top_n: int = 80) -> list[dict[str, Any]]:
    if df is None or df.empty or "driver_tags" not in df.columns:
        return []
    d = df[df["result"].isin(["win", "loss", "push"])].copy() if "result" in df.columns else pd.DataFrame()
    if d.empty:
        return []

    def _drivers(x: Any) -> list[str]:
        try:
            tags = x if isinstance(x, list) else ([] if x is None else [str(x)])
            types = {_ll_tag_type(t) for t in tags if t}
            ds = {_ll_driver_from_type(t) for t in types if t}
            return sorted([z for z in ds if z])
        except Exception:
            return []

    d["_drivers"] = d["driver_tags"].apply(_drivers)
    ex = d.explode("_drivers")
    ex = ex[ex["_drivers"].notna()]
    ex["driver"] = ex["_drivers"].astype(str)
    ex = ex[ex["driver"].astype(str).str.len() > 0]
    out = _ll_group_stats(ex, ["driver"], ["driver"])
    return out[: int(max(0, top_n))]


def _ll_attach_breakdowns(summary: dict[str, Any], df: pd.DataFrame) -> dict[str, Any]:
    d = dict(summary or {})
    d["by_lens_side"] = _ll_group_stats(df, ["lens", "side"], ["lens", "side"])
    d["by_driver_tag"] = _ll_by_driver_tag(df)
    d["by_driver_tagset"] = _ll_by_driver_tagset(df)
    d["by_driver_tag_canonical"] = _ll_by_driver_canonical(df)
    d["by_driver_tag_type"] = _ll_by_driver_tag_type(df)
    d["by_driver"] = _ll_by_driver(df)
    return d


@app.route("/api/live_lens_analytics")
@app.route("/api/live_game_lens_analytics")
def api_live_game_lens_analytics():
    try:
        start, end, days = _ll_window_params(default_days=14)
        if not start or not end:
            return jsonify({"ok": False, "error": "invalid date window"}), 400
        assume_price = _ll_assume_price()
        full_game_only = _ll_arg_bool("full_game_only", False)
        include_rows = _ll_arg_bool("include_rows", False)
        max_rows = _ll_arg_int("max_rows", 2000, 100, 20000)

        allowed_markets = {"total", "half_total", "quarter_total", "ats"}
        all_days: list[pd.DataFrame] = []
        per_day: list[dict[str, Any]] = []
        meta_days: list[dict[str, Any]] = []

        d = start
        while d <= end:
            ds = d.isoformat()
            try:
                df_day, meta = _ll_score_day(ds, allowed_markets=allowed_markets, assume_price=assume_price)
                if isinstance(df_day, pd.DataFrame) and not df_day.empty:
                    if full_game_only:
                        df_day = df_day[df_day["market"].isin(["total", "ats"])].copy()
                    all_days.append(df_day)
                meta_days.append({"date": ds, **(meta or {})})

                # Split per-day summaries
                tot = df_day[df_day["market"].isin(["total", "half_total", "quarter_total"])].copy() if (isinstance(df_day, pd.DataFrame) and not df_day.empty) else pd.DataFrame()
                if full_game_only and not tot.empty:
                    tot = tot[tot["market"] == "total"].copy()
                ats = df_day[df_day["market"] == "ats"].copy() if (isinstance(df_day, pd.DataFrame) and not df_day.empty) else pd.DataFrame()
                per_day.append({"date": ds, "totals": _ll_summary(tot), "ats": _ll_summary(ats)})
            except Exception as e:
                per_day.append({"date": ds, "totals": _ll_summary(pd.DataFrame()), "ats": _ll_summary(pd.DataFrame()), "error": str(e)})
                meta_days.append({"date": ds, "error": str(e)})
            d = d + timedelta(days=1)

        all_df = pd.concat(all_days, ignore_index=True) if all_days else pd.DataFrame()

        totals_df = all_df[all_df["market"].isin(["total", "half_total", "quarter_total"])].copy() if not all_df.empty else pd.DataFrame()
        if full_game_only and not totals_df.empty:
            totals_df = totals_df[totals_df["market"] == "total"].copy()
        ats_df = all_df[all_df["market"] == "ats"].copy() if not all_df.empty else pd.DataFrame()

        totals_summary = _ll_attach_breakdowns(_ll_summary(totals_df), totals_df)
        ats_summary = _ll_attach_breakdowns(_ll_summary(ats_df), ats_df)

        history = None
        if include_rows and not all_df.empty:
            h = all_df[all_df["result"].isin(["win", "loss", "push"])].copy() if "result" in all_df.columns else pd.DataFrame()
            if not h.empty:
                h = h.sort_values(["date", "market", "game_id"], ascending=[False, True, True])
                h = h.head(int(max_rows))
                history = {
                    "rows": [
                        {
                            "date": r.get("date"),
                            "market": r.get("market"),
                            "game_id": r.get("game_id"),
                            "lens": r.get("lens"),
                            "side": r.get("side"),
                            "live_line": r.get("live_line"),
                            "edge": r.get("edge"),
                            "elapsed": r.get("elapsed"),
                            "remaining": r.get("remaining"),
                            "result": r.get("result"),
                            "profit_units": r.get("profit_units"),
                            "driver": r.get("driver"),
                            "driver_tags": r.get("driver_tags"),
                        }
                        for r in h.to_dict(orient="records")
                    ]
                }

        if totals_summary.get("n_settled", 0) <= 0 and ats_summary.get("n_settled", 0) <= 0:
            return jsonify(
                _to_jsonable(
                    {
                        "ok": True,
                        "status": "empty",
                        "message": "No settled BET rows (missing signals and/or recon outputs).",
                        "meta": {
                            "start": start.isoformat(),
                            "end": end.isoformat(),
                            "days": int(days),
                            "assume_price": assume_price,
                            "full_game_only": bool(full_game_only),
                            "include_rows": bool(include_rows),
                            "max_rows": int(max_rows),
                        },
                        "overall": {"totals": totals_summary, "ats": ats_summary},
                        "per_day": per_day,
                        "history": history,
                        "debug": {"days": meta_days},
                        "generated_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
                    }
                )
            )

        return jsonify(
            _to_jsonable(
                {
                    "ok": True,
                    "status": "ok",
                    "meta": {
                        "start": start.isoformat(),
                        "end": end.isoformat(),
                        "days": int(days),
                        "assume_price": assume_price,
                        "full_game_only": bool(full_game_only),
                        "include_rows": bool(include_rows),
                        "max_rows": int(max_rows),
                    },
                    "overall": {"totals": totals_summary, "ats": ats_summary},
                    "per_day": per_day,
                    "history": history,
                    "debug": {"days": meta_days},
                    "generated_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
                }
            )
        )
    except Exception as e:  # noqa: BLE001
        return jsonify({"ok": False, "error": str(e)}), 500


