                            team_mkt_overlap = sum(1 for cc in portfolio_cards if str(cc.get("team") or "").strip().upper() == team and str(((cc.get("top_play") or {}).get("market")) or "").lower() == mk)
                            team_pen = max(0.0, min(0.25, 0.08 * float(max(0, team_mkt_overlap))))
